window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-028.json"] = [{"name":"波多黎各蝇霸鹟","english_name":"Puerto Rican Flycatcher","scientific_name":"Myiarchus antillarum","overview":"波多黎各蝇霸鹟（英文名：Puerto Rican Flycatcher，学名：Myiarchus antillarum），是雀形目霸鹟科蝇霸鹟属的鸟类。曾被视为憨蝇霸鹟的一个亚种，现为波多黎各及维京群岛特有种。体型中等，约18.5至20厘米长，拥有扁平宽大的喙和灰色腹部，与较暗的背部形成鲜明对比。其本地名'juí'源自其哀婉的下降调叫声，传统上被认为是吉凶预兆。尽管不是优先保护对象，但长期研究显示其种群可能正在减少。","appearance":"波多黎各蝇霸鹟具有典型的Myiarchus属特征，中等体型，头顶部呈深烟灰棕色（接近暗红褐色），其余上部更显橄榄棕色。尾巴深色，尾羽尖端较淡，边缘略带灰棕色。下部灰白色，与背部形成强烈对比。腹部无黄色斑纹，翼条纹极淡或无。头部两侧和颈部烟灰棕色，颈部更显灰色，面颊区、下巴、喉咙和胸部浅灰色，胸侧类似但略带橄榄棕色。下部白色，通常微微泛黄，尤其在两胁和尾下覆羽。腋下和翼下覆羽淡黄色，飞羽内缘带肉桂色。喙黑褐，基部更偏褐色；虹膜棕色；腿脚黑褐色。","call":"波多黎各蝇霸鹟的鸣声包括快速的‘tsee-ick’声和拉长的、哀怨的‘pheeeee’声。","habits":"栖息于森林地带、红树林和咖啡种植园，偏好树木覆盖的环境。飞行特点及活动范围未知，但据观察在树冠层活动。","breeding":"洞穴筑巢。","identification":"与加勒比拟霸鹟（未详述）相似，但后者较小，下部有明显的黄色。在波多黎各和维京群岛范围内，无其他Myiarchus属物种与其重叠，易于识别。","protection":"IUCN：LC（无危）","distribution":"主要分布于波多黎各和维京群岛。","other":"曾被归为憨蝇霸鹟的一个亚种，现已确认为独立物种。"},{"name":"安岛蝇霸鹟","english_name":"Lesser Antillean Flycatcher","scientific_name":"Myiarchus oberi","overview":"安岛蝇霸鹟（英文名：Lesser Antillean Flycatcher，学名：Myiarchus oberi），是雀形目霸鹟科蝇霸鹟属的鸟类。中等体型的霸鹟科鸟类，具有相对温顺的性格，主要栖息于小安的列斯群岛的林地和高灌木丛中。其最显著的外部特征是灰色的胸部、黄色的腹部以及红棕色的下尾羽。该物种于1877年被首次命名，已收录于《世界自然保护联盟》名录中。","appearance":"成鸟体长19至22厘米，体重介于21.3至37克之间。指名亚种为典型的橄榄绿色冠部和上体，尾上覆羽边缘呈红褐色；眼周、耳羽和面部略显灰色；翅膀为棕色，主要飞羽和次级飞羽边缘有明显的红褐色斑点，大翼覆羽和中翼覆羽尖端模糊地带有灰白色或红褐色（形成微弱的翼带）；内侧尾羽内侧有宽阔的红褐色条纹；喉咙和胸部为灰色，腹部为黄色，侧面带有轻微的绿褐色，与胸部灰色过渡自然；胫部羽毛为橄榄棕色；下翼覆羽为黄色；虹膜深色，喙和腿均为深色。","call":"常通过其哀婉、拉长的‘pheee’或‘pheeuuu’歌声被首次察觉，也会发出一系列‘pip’声和滚动的颤音叫声。","habits":"通常静止于树冠下方的枝头，然后突然飞出捕食猎物。栖息于林地和高大的灌木丛中，活动范围覆盖小安的列斯群岛。","breeding":"繁殖期从三月至七月，例如五月份在多米尼加发现有蛋的巢。巢由植物纤维、羽毛和植物绒毛松散构建，位于树洞中；也有报告称在树叉处建造类似杯状的巢，但可靠性有待证实。一窝产3到4枚蛋，蛋壳颜色为奶油色，带有深紫色和紫灰色的重叠斑点，尺寸大约为23.5至24.3毫米×18.6至18.9毫米（指名亚种为标准）。","identification":"与其他相似物种区别的关键特征是灰色的胸部、黄色的腹部以及红棕色的下尾羽。不同亚种之间存在大小和腹部颜色的细微差异。","protection":"IUCN：LC（无危）","distribution":"主要分布于小安的列斯群岛，包括但不限于多米尼加等地区。"},{"name":"火红霸鹟","english_name":"Flammulated Flycatcher","scientific_name":"Ramphotrigon flammulatum","overview":"火红霸鹟（英文名：Flammulated Flycatcher，学名：Ramphotrigon flammulatum），是雀形目霸鹟科扁嘴雀属的鸟类。曾被归类至Deltarhynchus属，后基于遗传分析移至Ramphotrigon属。该物种为墨西哥太平洋沿岸干燥森林、干旱灌木丛和灌木林的特有种。体型中等偏大，羽色以橄榄灰至灰棕色为主，胸部淡灰色带模糊条纹，腹部浅黄色，喉部白色，翅膀暗褐色，边缘呈淡肉桂色。","appearance":"火红霸鹟体长约15至17厘米，上体灰橄榄色，尾羽深灰褐色，边缘肉桂色。翅膀暗褐色，翼覆羽宽端肉桂色。喉部和下颏灰白色，胸部淡灰色，有隐约的暗色条纹。腹部浅黄色。幼鸟尾羽边缘更宽的肉桂色。喙黑色，腿脚黑色。","call":"火红霸鹟的鸣唱特征为哀怨的哨声，随后是一段短暂而快速的滚动声。它也能发出哀伤、含糊的'chew'叫声，通常连续下降3至5次。两性的叫声相同，用于定位、个体识别、报警和划定领地。","habits":"栖息于干燥落叶林、干旱和半干旱灌木丛及灌木林，海拔约1000至1400米。非迁徙性，主要以昆虫为食，通过从暴露的枝干观察并迅速飞向猎物的方式觅食。","breeding":"繁殖季节约为每年六月，筑巢于树洞中，接近地面，巢由细小的植物纤维、干叶和树皮碎片构成，产三枚乳白至粉红色、带有棕灰色斑点的蛋。","identification":"与Myiarchus属的鸟类相似，但具有白色的上眼线和下眼新月形斑，胸部有暗色条纹，翅膀和尾巴边缘呈淡肉桂色，喙较宽。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥的太平洋低地，从锡那罗亚到西部恰帕斯州，可能延伸至危地马拉，但尚未得到确认。","other":"火红霸鹟在兴奋时会竖起头部羽毛形成类似冠状的形状，但不会像Myiarchus属鸟类那样在展示时点头。"},{"name":"大头扁嘴霸鹟","english_name":"Large-headed Flatbill","scientific_name":"Ramphotrigon megacephalum","overview":"大头扁嘴霸鹟（英文名：Large-headed Flatbill，学名：Ramphotrigon megacephalum），是雀形目霸鹟科扁嘴雀属的小型鸟类。亦被称为竹林扁嘴霸鹟。仅栖息于南美洲亚马逊雨林西北部、南部及东南部的湿润森林低层竹丛中。其最显著的特征为头部较大，背部、头部及胸部呈橄榄绿色，眼周有一圈独特的黄色眉纹，喙宽而扁，色彩两调。腹部颜色较浅，呈淡黄色。","appearance":"大头扁嘴霸鹟体长约12.5至13.2厘米，体重约13至15克。眼睛棕色，喙黑色且扁平，基部三分之一处下颚呈淡粉色，腿灰色，头部略显厚重。上体暗橄榄色，具白色至黄色的超眶纹、眼环和淡色后眶纹，与灰暗的额部形成对比；翅膀和尾巴灰暗，有两道明显的橙褐色翼带，飞羽和尾羽边缘呈黄橄榄色；喉咙白色至黄色，胸灰色橄榄色，带有淡黄色条纹，腹部淡黄色。雌雄外观相似。委内瑞拉亚种比指名亚种颜色更深，翼部标记更偏肉桂色；pectocale亚种胸部更棕色，腹部黄色面积更大；bolivianum亚种胸部更棕色，腹部颜色更暗淡。","call":"其鸣唱为独特柔和的哨声‘feeww-fuu’，连续重复，持续时间较长。","habits":"大头扁嘴霸鹟偏好生活在亚马逊雨林中的湿润森林低层，很少与其他物种混群。它们的栖息地主要集中在南美洲的阿根廷、玻利维亚、巴西、哥伦比亚、厄瓜多尔、巴拉圭、秘鲁和委内瑞拉。","identification":"与暗尾扁嘴霸鹟相比，大头扁嘴霸鹟体型较小，色彩略淡，具有独特的浅色超眶纹。","protection":"IUCN：LC（无危）","distribution":"大头扁嘴霸鹟分布于南美洲的亚马逊雨林西北部、南部以及东南部，具体国家包括阿根廷、玻利维亚、巴西、哥伦比亚、厄瓜多尔、巴拉圭、秘鲁和委内瑞拉。","other":"系统学历史未提及，需进一步探索其分类学细节。"},{"name":"棕尾扁嘴霸鹟","english_name":"Rufous-tailed Flatbill","scientific_name":"Ramphotrigon ruficauda","overview":"棕尾扁嘴霸鹟（英文名：Rufous-tailed Flatbill，学名：Ramphotrigon ruficauda），是雀形目霸鹟科扁嘴雀属的鸟类。主要分布在南美的亚马逊雨林地带，常见于奥里诺科河和亚马逊河流域的低地森林中。该鸟以橄榄色的身体、醒目的棕红色尾巴和黑色翅膀边缘为显著特征，通常通过其独特的鸣叫声被发现。","appearance":"该鸟体型中等偏小，总长度约15-16厘米，体重平均20克左右。上体呈橄榄绿色，尾羽上方覆盖着亮丽的棕红色，翅膀为黑色，翼缘带有明亮的棕红色。下体颜色较淡，喉部灰白色，胸部有黄色斑点，腹部中央呈淡黄色，尾羽下方的覆羽也是棕红色。喙宽而扁，虹膜深棕色，跗跖和趾为蓝灰色或灰色。","call":"其鸣叫声为低沉的哨音，被描述为柔和的长音weeeaaaweee，有时会接续一个低沉的音符，具有嘶哑的质感，类似低沉起伏或略带颤音的喵喵声：meeooo，或在结尾处强调：meeooo'OO。","habits":"栖息于亚马逊地区的湿润低地常绿森林，偏好开阔林下层的环境，主要在森林中层活动。它较为孤独，常见于瓦尔泽亚和特拉弗梅低地湿润森林的开阔地带。","identification":"与暗尾扁嘴霸鹟相比，棕尾扁嘴霸鹟的尾羽和飞羽更加明亮，胸腹部条纹较少，更容易识别。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲的亚马逊雨林，具体国家包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。"},{"name":"暗尾扁嘴霸鹟","english_name":"Dusky-tailed Flatbill","scientific_name":"Ramphotrigon fuscicauda","overview":"暗尾扁嘴霸鹟（英文名：Dusky-tailed Flatbill，学名：Ramphotrigon fuscicauda），是雀形目霸鹟科扁嘴雀属的鸟类。主要分布于南美洲西部亚马逊雨林地区的小片区域，包括哥伦比亚、厄瓜多尔、秘鲁和巴西。其特征为橄榄棕色的体羽，下腹部带有黄色条纹，翼下覆羽边缘呈锈色。","appearance":"暗尾扁嘴霸鹟具有典型的扁嘴霸鹟体型，头大尾长，橄榄绿色的上体与黄色的下体形成对比。喉部和上胸带有模糊的橄榄色条纹，下胸至腹部则呈现黄色，带有橄榄绿色的细纹。尾羽和翅膀颜色较暗，翼上有红褐色的斑纹。成鸟两性相似，但雄鸟略大。","call":"发出一系列口哨式的鸣叫，主要歌曲由三部分组成：下降的哨声，随后是颤音，最后再次上升的哨声，通常描述为‘tew, tetrrrrrr-tew-tew-tew...’。","habits":"偏好低海拔潮湿森林中的竹丛或次生植被，尤其在水源附近。常在密集的藤蔓生长区活动。通过其特有的口哨叫声被发现。","breeding":"具体繁殖信息不详，但根据同科物种推测可能在繁殖季节筑巢于树冠层。","identification":"与大头扁嘴霸鹟相似，但暗尾扁嘴霸鹟体型更大，具窄黄眉纹，喉部和胸部有模糊的橄榄色条纹，尾羽颜色更暗而非橄榄色。绿扁嘴霸鹟下体无条纹，翅膀和尾巴更橄榄色，缺乏翼斑。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲西部亚马逊雨林的西南部，包括哥伦比亚、厄瓜多尔、秘鲁和巴西的部分地区。","other":"暗尾扁嘴霸鹟在野外较为罕见，主要在其特定的栖息环境中发现。"},{"name":"褐尾阿蒂霸鹟","english_name":"Rufous-tailed Attila","scientific_name":"Attila phoenicurus","overview":"褐尾阿蒂霸鹟（英文名：Rufous-tailed Attila，学名：Attila phoenicurus），是雀形目霸鹟科阿蒂霸鹟属的鸟类。主要栖息在南美洲的湿润森林中，包括巴西东南部至亚马孙雨林和阿根廷东北部。其最显著的特征是深红褐色的上体与灰色头部形成鲜明对比，橙色腹部更为淡雅，喉部为红褐色，与灰头阿蒂霸鹟相区别。","appearance":"成年褐尾阿蒂霸鹟体长约17.6-18厘米，体重32.3-34.5克。眼睛深邃，喙部暗褐色至黑色，较短且圆润，与其它阿蒂霸鹟种类不同。头部和颈背呈深灰色，与深红褐色的背部形成对比，尾羽上覆羽颜色略浅，尾羽本身为红褐色。初级飞羽黑褐色，下体为肉桂红褐色，下巴有小白斑，胸带深红褐色但不明显。雄雌外观相似。","call":"其鸣叫声为悠长的口哨声“fee-fee-fii”，一整天反复鸣叫，声音传播远。","habits":"褐尾阿蒂霸鹟栖息于各种湿度较高的森林环境，包括Araucaria森林。它们通常几乎不动地站立，但在繁殖季节外会向北迁移至亚马逊北部，分布于巴西、阿根廷东北部、巴拉圭东部，冬季时分散在玻利维亚东部、巴西中部乃至委内瑞拉南部。","breeding":"具体繁殖行为细节未详述。","identification":"与黄腹阿蒂霸鹟相比，褐尾阿蒂霸鹟具有红褐色喉部，背部与头部颜色对比更强烈，臀部颜色更深。","protection":"IUCN：LC（无危）","distribution":"繁殖于巴西东南部至里奥格兰德杜苏尔州，可能也在阿根廷东北部（米西奥内斯省）和巴拉圭东部；非繁殖季节时广泛分散于巴拉圭、玻利维亚东部、巴西中部，北至委内瑞拉南部。","other":"分子遗传学研究表明，褐尾阿蒂霸鹟与桂红阿蒂霸鹟关系密切。"},{"name":"桂红阿蒂霸鹟","english_name":"Cinnamon Attila","scientific_name":"Attila cinnamomeus","overview":"桂红阿蒂霸鹟（英文名：Cinnamon Attila，学名：Attila cinnamomeus），是雀形目霸鹟科阿蒂霸鹟属的鸟类。以深红褐色的羽毛和大型头部为显著特征。分布于南美的亚马逊盆地，包括哥伦比亚东部、委内瑞拉西部、南部及东北部、圭亚那、厄瓜多尔东部、秘鲁东部、玻利维亚北部及亚马逊地区的巴西。","appearance":"体长约19.5至20.3厘米，体重28至45克。眼睛呈红棕色，喙黑色，腿灰色。上体为深红褐色，无明显臀部对比色；翼羽基部黑色，边缘宽阔的红褐色；腹部偏黄色，下体红肉桂色。尾巴比同属其他物种更长。雌雄外观相似。","call":"主要鸣叫为响亮的鹰鸣式哨音，先是上升后下降并逐渐减弱，常持续重复。还有另一种‘whoo-whoo-wheeeyeér’的叫声，更接近其属的典型声音。歌曲为高升哨音，重复‘weary weary weary weer-ry’，或是缓慢的芦苇般三声以上的上升哨音。","habits":"栖息于湿地和近水地带，如泛滥平原、沼泽森林边缘、沙丘间、旧湖泊和牛轭湖附近、缓流溪流和河岛，也见于湿润的种植园、河流三角洲的沼泽棕榈林和红树林。通常在中层树冠活动，偶尔在低处或高处。以较大昆虫和小型两栖动物为主食，偶尔食用水果。捕食时静立或缓慢移动，然后突然飞扑捕捉食物。","breeding":"繁殖期在4月至5月，观察到9月筑巢。巢由一对中的一个成员单独建造，位于树干裂缝或树干与凤梨科植物之间，用小枯枝搭建，内衬根须，通常筑2-3枚蛋，但缺乏更多信息。","identification":"与钝顶阿蒂霸鹟相比，桂红阿蒂霸鹟有黑眼和不同的叫声。尾巴比同类物种长。","protection":"IUCN：LC（无危）","distribution":"分布于整个亚马逊-奥里诺科盆地，包括哥伦比亚东部、委内瑞拉西部、南部及东北部、圭亚那、厄瓜多尔东部、秘鲁东部、玻利维亚北部及亚马逊地区的巴西。","other":"在Jaú国家公园（巴西）、Caño Colorado（委内瑞拉）、Tinigua国家公园（哥伦比亚）、Tambopata-Candamo保护区（秘鲁）、Beni生物圈保护区和Madidi、Noel Kempff Mercado国家公园（玻利维亚）、Rio Cristalino森林保护区和Tapajós国家公园（巴西）等众多国家公园和保护区中发现。"},{"name":"赭色阿蒂霸鹟","english_name":"Ochraceous Attila","scientific_name":"Attila torridus","overview":"赭色阿蒂霸鹟（英文名：Ochraceous Attila，学名：Attila torridus），是雀形目霸鹟科阿蒂霸鹟属的鸟类。主要分布在厄瓜多尔西部、秘鲁西北部以及哥伦比亚西南部的少量地区。拥有鲜明的橙褐色外观，腹部呈黄色，翅膀暗色带有棕色翼纹。","appearance":"赭色阿蒂霸鹟体长20-22厘米，体重约46克，眼睛红褐色，喙呈暗色，腿灰色。其头部和上身橙褐色，臀部和尾基黄色，初级飞羽黑色，有两道由暗色翼羽形成的独特翼纹，下方黄赭色，腹部最亮。雄雌外观相似。","call":"鸣叫时发出响亮清晰的下滑哨音“whoeeeer”，有时延伸为“whoeeeer, wheéu, whit-whit”，亦会发出尖锐的“wheek”或“keek”。歌唱是一系列上升的哨音，节奏与桂红阿蒂霸鹟相似。","habits":"栖息于湿润和半湿润森林边缘，次生林及周边空地和种植园，海拔高度可达1000米，偶尔高达2400米。可能为留鸟，但在季节性移动的性质上存在不确定性。主要以节肢动物（如蜘蛛）和水果为食，单独或成对在森林中层至树冠觅食，静止时几乎不动，突然短距离飞扑或在枝叶间翻飞捕食。","breeding":"繁殖信息未知，推测可能在雨季（1月至3月）繁殖。","identification":"与桂红阿蒂霸鹟相比，赭色阿蒂霸鹟颜色更淡更黄，头部和上身肉桂赭色，下体黄赭色，腹部尤为黄色。","protection":"IUCN：NT（近危）。全球种群数量正在严重下降，因持续的森林砍伐导致栖息地丧失，尤其在海拔900米以下，厄瓜多尔西部仅剩4.4%的原始森林覆盖。在厄瓜多尔和秘鲁的保护区外，森林破坏仍在继续。","distribution":"分布于南美洲，从哥伦比亚西南部至秘鲁西北部，包括厄瓜多尔的局部地区（从埃斯梅拉达斯至洛哈省）和秘鲁的塔姆贝斯省。在厄瓜多尔的马查利拉国家公园、茹安内切生物研究站等地较为常见。","other":"在较高海拔的分布范围内，森林破坏速度较慢，但仍受到放牧、伐木和农业开垦的影响。"},{"name":"黄腹阿蒂霸鹟","english_name":"Citron-bellied Attila","scientific_name":"Attila citriniventris","overview":"黄腹阿蒂霸鹟（英文名：Citron-bellied Attila，学名：Attila citriniventris），是雀形目霸鹟科阿蒂霸鹟属的鸟类。主要分布于南美洲的亚马逊雨林西部，包括巴西、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉，栖息于热带或亚热带湿润低地森林。","appearance":"该鸟体长约18至18.5厘米，体重约30至38克。眼睛呈暗红棕色，上喙灰白色，下喙基部淡角质色至粉红色，尖端灰色，腿脚灰色。头部和颈背深灰，背部转为赤褐色，除较淡的肉桂色臀部外；翅膀暗淡无翼斑；喉咙灰白，下体明亮的赭黄色，喉部和胸部有淡淡的暗色条纹，腹部更显黄色。","call":"鸣唱为一系列大约4至6个响亮、快速且略升调的‘whee’哨音，随后是音调较低的‘wu’，也有平调的连续‘whee’哨音，常常持续重复。播放回应时，歌声可延长至10个音符以上。","habits":"生活在亚马逊雨林内部及边缘的湿润森林，主要在中层觅食，偶尔加入混合物种的鸟群。其生态习性包括迁徙、飞行特点、活动范围和觅食方式等尚未详细记载。","breeding":"关于繁殖习性的具体信息未详述，包括繁殖期、求偶、营巢、交配、产卵、孵化和育雏等细节。","identification":"与褐尾阿蒂霸鹟相比，头部灰色较浅，臀部颜色较浅，喉部更白；与亮腰阿蒂霸鹟相比，后者具有明显的翼带、鲜艳的黄色臀部以及条纹状胸部","protection":"IUCN状态未知。目前未被列入华盛顿保护条约(CITES)或中国国家重点保护野生动物名录。","distribution":"分布于南美洲的亚马逊雨林西部，具体包括哥伦比亚东部、委内瑞拉南部（含亚马逊州）、厄瓜多尔东部、秘鲁东北部（洛雷托和乌卡亚利）、巴西西北部亚马逊地区（东至黑河，局部至马代拉河）以及玻利维亚东北极区。","other":"有关黄腹阿蒂霸鹟的其他重要信息，如种群动态、生态角色和遗传多样性等，尚待进一步研究。"},{"name":"暗顶阿蒂霸鹟","english_name":"White-eyed Attila","scientific_name":"Attila bolivianus","overview":"暗顶阿蒂霸鹟（英文名：White-eyed Attila，学名：Attila bolivianus），是雀形目霸鹟科阿蒂霸鹟属的鸟类。体型较大的霸鹟科鸟类，主要分布在南美洲亚马逊雨林的南部和西南部地区，常见于湿润的雨林中层。其最显著的特征是明亮的黄白色眼睛，头部及上体呈红褐色，背部颜色略灰，尾部短小，喙部粗壮，下颚带粉色。雄雌外观相似。","appearance":"暗顶阿蒂霸鹟长约19至22厘米，体重40至45克。头部和上体为红褐色，顶部颜色较深，近似栗色，臀部和尾部呈现亮丽的肉桂色。翅膀上的大覆羽和初级飞羽主要为黑色，腹部颜色较浅，下体为肉桂色，腹部更显淡色，下颚处有轻微的灰色痕迹。喙部角质色，下部微带粉色，腿脚蓝灰色。与亚马逊地区的其他阿蒂霸鹟相比，本种体型更大，尾巴和喙较长，下体颜色统一为肉桂色。雌雄外观相似，但亚种nattereri整体颜色更深，顶部更接近赭石色。","call":"主要鸣唱为一系列4到8声悠扬上升的“whéep”哨音，随后是较弱且音调更低的“wheeuu”。通常与几声“wée-per”交替出现，声音显得忧郁，没有亮腰阿蒂霸鹟那种上扬的双音节特点。受到惊扰时会发出响亮、尖锐、快速的断音‘tu-tu-tu-tu-tu’。","habits":"主要栖息于亚马逊河沿岸的沼泽森林和边缘地带，也可见于巴西马托格罗索州的泛滥平原画廊森林中，海拔高度可达300米。它们可能具有定居习性。以较大昆虫和其他节肢动物为主食，偶尔食用果实。单独或成对觅食，有时加入混合物种的小群，在开放森林的下层和中层寻找食物。安静地站立，几乎不动，然后突然出击短距离或振翅悬停以从植被和树枝上捕获猎物。","breeding":"繁殖季节在9月于秘鲁东南部观察到性腺增大。哥伦比亚发现的巢穴位于距水面1.3米高的寄生植物基部，由根须、苔藓和植物纤维制成，巢呈锈色杯状。一窝产2枚卵。关于繁殖行为的其他信息尚缺乏。","identification":"与其他阿蒂霸鹟的区别在于更大的体型、更长的喙和尾巴，以及一致的肉桂色下体。与亮腰阿蒂霸鹟的红褐色形态相比，本种的下体颜色更为均匀。","protection":"IUCN：LC（无危）。在分布区内较为罕见至相当常见。由于其相对广阔的栖息地大部分保持未受干扰，故无严重威胁。在多个国家公园和保护区中存在，如厄瓜多尔的Sacha和Yarina旅馆，秘鲁的Explornapo Lodge、Manu国家公园和生物圈保护区、Tambopata-Candamo保留区，玻利维亚的Beni和Pilón Lajas生物圈保护区、Madidi和Noel Kempff Mercado国家公园，以及巴西的Mamirauá保护区。","distribution":"分布于南美洲亚马逊雨林的南部和西南部，包括巴西、秘鲁、玻利维亚、哥伦比亚，可能还存在于厄瓜多尔的部分地区。","other":"本种首次由法国鸟类学家Frédéric de Lafresnaye于1848年描述。国际鸟类学会和Clements清单认可两个亚种：nattereri，以奥地利自然学家Johann Natterer命名。"},{"name":"灰头阿蒂霸鹟","english_name":"Grey-hooded Attila","scientific_name":"Attila rufus","overview":"灰头阿蒂霸鹟（英文名：Grey-hooded Attila，学名：Attila rufus），是雀形目霸鹟科阿蒂霸鹟属的鸟类。主要分布于巴西东南部沿海地带的热带雨林中。其显著特征包括灰色头部和深红褐色背部，以及独特的黄色腹部。该物种受到《世界自然保护联盟》（IUCN）的保护。","appearance":"灰头阿蒂霸鹟体长约20至21厘米，体重在36.5至51.5克之间。拥有暗色眼睛，较长的喙，下颌呈灰白色到白色，腿部为灰色。头部和颈背呈现灰色，与深红褐色背部形成鲜明对比，臀部和尾巴颜色较淡，为肉桂红褐色。黑色的初级飞羽，喉咙灰色带有白色条纹，与红褐色胸部和较淡的黄腹部形成对比。幼鸟喙为黑色，成年后与成鸟无明显性别差异。巴伊亚地区的亚种喉部多为红褐色，下巴白色。","call":"灰头阿蒂霸鹟的叫声为‘éé-ew’的哨音。其远传而悦耳的歌曲由6至13个缓慢发出的‘wee’或‘ewéé’哨音组成，音调和音量逐渐升高，在最后一个哨音处降低。还有一种较柔和的‘wee, tee-tee-pu’哨音，有时会与前述歌曲交替出现。警告声为尖锐的‘tserétek, tsek’。","habits":"灰头阿蒂霸鹟主要以较大的节肢动物为食，如蚂蚁、蝴蝶等，也会捕食树蛙，偶尔吃水果。它们通常单独或成对觅食，有时加入混杂物种群，从地面到树冠各层都能发现它们的身影。它们会静静地站立在枝头几乎不动，然后突然短距离出击或在空中盘旋以从树叶和树枝上捕捉猎物。有报告指出，它们也会敲击腐烂的木头。","identification":"与褐尾阿蒂霸鹟相比，体型较大，喙较长，喉部为灰色且带有浅白色条纹。与亮腰阿蒂霸鹟相比，后者具有明显的翼带和条纹状胸部，而灰头阿蒂霸鹟的翅膀和胸部无明显标记。","protection":"IUCN：LC（无危）","distribution":"灰头阿蒂霸鹟的分布局限于南美洲巴西的东部和东南部，主要在其沿岸的亚热带或热带湿润低地森林和山地森林中。"},{"name":"亮腰阿蒂霸鹟","english_name":"Bright-rumped Attila","scientific_name":"Attila spadiceus","overview":"亮腰阿蒂霸鹟（英文名：Bright-rumped Attila，学名：Attila spadiceus），是雀形目霸鹟科阿蒂霸鹟属的小型鸟类，分布广泛，自墨西哥西部至南美洲亚马逊雨林及巴西东部，包括中美洲和南美洲热带与亚热带森林地带。具有橄榄绿头部、栗色背部和醒目的亮黄色臀部。","appearance":"此鸟体型较大，约18厘米长，重约40克，头大，喙钩状微上翘，站立姿态挺拔。头部呈橄榄绿色，带有黑色条纹，背部颜色从栗色到橄榄色不等，臀部鲜黄，尾羽棕色。翅膀深棕色，具两道浅色翼斑，边缘较淡。喉部和胸部白色或黄色，常有深色条纹。腹部白色，靠近尾部渐变为黄色。虹膜红色。雌雄相似，幼鸟冠羽边缘呈肉桂色，眼色为褐色。","call":"叫声包括响亮的“beat-it, beat-it”和哀怨的“ooo weery weery weery weery woo”。在歌唱时几乎不动，因此很难被发现。","habits":"亮腰阿蒂霸鹟常见于海拔2,100米以下的低地森林、次生林、牧场、种植园带树的环境及阴凉花园。它能适应一定程度的栖息地破坏。食性广泛，包括昆虫、蜘蛛、青蛙、蜥蜴，有时也会在地上追逐猎物或跟随蚁群。此外，它也吃果实（如来自gumbo-limbo树的果实）和种子。","breeding":"繁殖期主要在3月至7月，筑巢由雌鸟负责，巢为深杯状，由苔藓、树叶和植物纤维构成，通常建于离地面3米以下的附生植物中、树根间或河岸。一窝通常产3-4枚淡紫色或锈色斑点的蛋，由雌鸟孵化18-19天，幼鸟再过18天左右离巢。","identification":"与其他阿蒂霸鹟属物种的区别在于其下方的条纹和明显的翼斑。幼鸟与成鸟在冠羽和眼色上有差异。","protection":"IUCN状态未知。","distribution":"分布于中美洲至南美洲，包括墨西哥西部至巴西东部的亚马逊雨林地区。"},{"name":"红冠伞鸟","english_name":"Red-crested Cotinga","scientific_name":"Ampelion rubrocristatus","overview":"红冠伞鸟（英文名：Red-crested Cotinga，学名：Ampelion rubrocristatus），是雀形目伞鸟科红冠伞鸟属的鸟类。体重47-80克，体色以灰色为主，头黑、喙白尖黑、虹膜深红。最显著特征为其紫红色羽冠，平日紧贴颈背，激动时会竖起展示。常见于南美洲云雾林边缘，从委内瑞拉西部到玻利维亚，能适应多种生境。","appearance":"红冠伞鸟体长约21-21.5厘米，雄鸟重51-80克，雌鸟重47-67克。整体呈灰色调，头部颜色较深，翅膀和尾巴为棕褐色，尾下覆羽有白色条纹。羽冠为鲜艳的栗色，可竖起展示。嘴基白色，尖端灰黑色，腿色为黑色或深灰色。两性羽毛相似，幼鸟较淡，具浅色羽缘和散射的棕色头部及颈部。","call":"主要发出粗哑的蛙鸣声'rrrreh'，受惊时会连续发出柔和的鼻音'eh-eh-eh...'。","habits":"栖息于海拔2200至3900米的亚热带或热带湿润山地森林，偶尔降至2200米。不需完整高质森林，可生存于农业区的树木丛中。以果实为主食，偶尔捕食昆虫，通过空中俯冲摘取果实，也会从栖木上捕捉飞虫。有时以六只左右的小群体活动。","breeding":"繁殖季节不确定，已知在秘鲁1月和玻利维亚11月有筑巢记录。求偶时雄鸟会展开羽冠，抬起尾巴并鞠躬。巢由苔藓、地衣和枝条构成的大杯状，建于1.3-3米高的灌木或低树上。雏鸟数量未知，但有观察到单个雏鸟和两只刚离巢的幼鸟。孵化和离巢期未记录。","identification":"红冠伞鸟的羽冠是其与其它物种的主要区别，尤其是羽冠竖立时的视觉效果。此外，其体型、颜色模式和栖息环境也有助于识别。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，具体为哥伦比亚圣玛尔塔山脉，委内瑞拉西部至玻利维亚的安第斯山脉。在哥伦比亚东部安第斯山脉，海拔主要在2500至3900米，偶尔下降至2200米。","other":"红冠伞鸟广泛分布在南美洲多个保护区，包括委内瑞拉的Sierra Nevada国家公园、哥伦比亚的Munchique国家公园和厄瓜多尔的Podocarpus国家公园。"},{"name":"栗冠伞鸟","english_name":"Chestnut-crested Cotinga","scientific_name":"Ampelion rufaxilla","overview":"栗冠伞鸟（英文名：Chestnut-crested Cotinga，学名：Ampelion rufaxilla），是雀形目伞鸟科红冠伞鸟属的鸟类。分布于南美洲的安第斯山脉，从哥伦比亚中部到玻利维亚北部的湿润山地森林中。在适宜的环境中通常以树冠层为栖息地，数量不多但容易被发现。","appearance":"栗冠伞鸟拥有中等体型，头部圆润，喙部相对粗壮呈灰色。其最显著的特征包括黑色的额头、栗色的喉咙和脸颊两侧，以及蓬松的栗色羽冠，下胸部和腹部为黄色，广泛地带有黑色条纹。背部和上胸部橄榄灰色，翅膀和尾羽黑色，翼盖呈栗色。","call":"它的叫声与红冠伞鸟相似，由一系列深沉的‘chucks’声组成，最后以持续一秒的嘎吱声结束。","habits":"主要栖息于安第斯山脉的湿润山地森林中，偏好在树冠层活动，通常单独或成对出现。","breeding":"关于繁殖行为的信息有限，但已知在哥伦比亚可能于1月至7月开始换羽，而在秘鲁则可能在8月至12月。一对在秘鲁南部照料巢穴的栗冠伞鸟中，雄鸟拥有新的飞羽并在进行身体换羽，而雌鸟则有磨损的飞羽并处于轻度的身体换羽状态。","identification":"与红冠伞鸟在大小和形状上相似，但红冠伞鸟主要生活在较高海拔，成年个体主要是暗灰色，易于与栗冠伞鸟区分。红冠伞鸟的幼鸟颜色较淡，有灰暗的条纹，表面上与栗冠伞鸟更相似，但缺乏栗冠伞鸟明显的栗色特征，且尾部有一白色横带。","protection":"IUCN：LC（无危）","distribution":"分布在南美的安第斯山脉，具体范围从哥伦比亚到玻利维亚，包括哥伦比亚、厄瓜多尔和秘鲁。"},{"name":"燕尾伞鸟","english_name":"Swallow-tailed Cotinga","scientific_name":"Phibalura flavirostris","overview":"燕尾伞鸟（英文名：Swallow-tailed Cotinga，学名：Phibalura flavirostris），是雀形目伞鸟科燕尾伞鸟属的鸟类。是燕尾伞鸟属的唯一成员。该鸟种拥有极长的深叉尾，雄鸟头黑、背呈绿黑白斑驳，喉橙黄；雌鸟色泽暗淡而尾较短。燕尾伞鸟分为两个亚种：指名亚种分布于巴西东南部、东巴拉圭和东北阿根廷的大西洋森林，玻利维亚亚种见于玻利维亚拉巴斯省阿波洛附近。二者因栖息地丧失均受威胁，玻利维亚亚种被IUCN列为濒危。","appearance":"全长21–23.5厘米，雄鸟尾长106–125 毫米，雌鸟尾长96–104 毫米。雄鸟头黑色带暗红后冠，背橄榄绿具黑色斑点，翼与尾蓝黑色，喉黄色呈刷状，胸白具黑条，腹白泛黄并具黑鳞斑；尾深叉、外羽向外弯曲。雌鸟似雄但色暗，翼多橄榄色，尾叉较浅。幼鸟黑区褐暗，胸腹横斑粗重，喉羽具黑斑，翼尾羽缘绿色。玻利维亚亚种雄鸟尾更长，喉黄色减少，后腹黑横斑较窄，脚更橙，虹膜芥黄色，雌雄差异较小。","call":"指名亚种极少鸣叫，记录到高而喉音的哨声“gut gut”及轻微金属声的“pik”。玻利维亚亚种叫声活跃，常见粗糙弱音间隔约1秒，平均每分钟可达80次，另有重复旋律的鸣唱，持续2分钟以上，是区分两亚种的重要依据。","habits":"指名亚种栖息于大西洋森林边缘、半落叶林、林窗、花园及山地草原，海拔0–2000 米；玻利维亚亚种限于玻利维亚安第斯山麓1300–2040 m的半湿润开阔林及山地稀树草原。前者在巴西东南部呈部分迁徙：9月末至3月在南部繁殖，冬季北移；后者为留鸟。两者均以果实为主食，兼食昆虫。觅食高度多在林冠及上层，偶降至1–2 米；玻利维亚亚种平均觅食高5.4 米，果食多在午后，昆虫在晨昏。指名亚种常集冬季大群15–22只，玻利维亚亚种多为成对或小群。","breeding":"繁殖期：玻利维亚亚种9–3月，指名亚种10–翌年1月。巢为浅杯状，由地衣及细枝构成，置于树叉或水平粗枝上，距地1.4–18 米，偶筑于岩隙。每窝2–3枚卵，卵淡绿或淡蓝具红褐斑；孵化期17–19天，雌雄共孵，雄鸟夜间离巢。育雏期25–30天，双亲共同喂养。巢成功率低，主要因捕食及暴雨。","identification":"燕尾伞鸟以极长深叉尾、短三角嘴及长尖翼在伞鸟科中极具特色，飞行亦易辨识。与体型更小、尾短的燕嘴唐纳雀雌鸟及幼雄仅略似，但后者尾无深叉。巴西东南部易与冠食果伞鸟和黑头食果伞鸟混淆，然其黄白腹并密黑横斑为重要鉴别特征；玻利维亚个体亦可能与Pipreola属食果伞鸟混看，但尾叉及腹斑可区分。","protection":"指名亚种 IUCN: NT（近危）；阿根廷列为易危，巴西圣保罗及埃斯皮里图桑托州亦列为易危。玻利维亚亚种 IUCN: EN（濒危）。","distribution":"繁殖区：指名亚种分布于巴西东南部（巴伊亚中部至南里奥格兰德州）、东巴拉圭及阿根廷米西奥内斯省；玻利维亚亚种仅限玻利维亚拉巴斯省阿波洛附近。非繁殖区：指名亚种冬季北迁至巴西中部及沿海岛屿，巴拉圭及阿根廷记录均为冬候鸟。","other":"燕尾伞鸟属长期被视为单型属，基因研究确认其隶属伞鸟科；玻利维亚亚种因形态、鸣声及行为差异曾被提议提升为独立种，但首例基因研究未发现分子差异。该属与安第斯伞鸟属（Ampelion、Doliornis）构成姐妹群，提示大西洋森林与安第斯之间历史扩散或趋同演化。"},{"name":"黄眼燕尾伞鸟","english_name":"Palkachupa Cotinga","scientific_name":"Phibalura boliviana","overview":"黄眼燕尾伞鸟（英文名：Palkachupa Cotinga，学名：Phibalura boliviana），是雀形目伞鸟科燕尾伞鸟属的鸟类。于1902年在玻利维亚被首次收集到样本，1930年被描述为燕尾伞鸟的一个亚种。该物种在2000年被重新发现，此前已有98年未有相关记录。黄眼燕尾伞鸟的分布仅限于玻利维亚的阿波罗附近，其数量因栖息地丧失而受到威胁，因此被列入濒危物种名单。","appearance":"黄眼燕尾伞鸟具有独特的外部特征，最显著的是其黄色的眼睛，更弯曲的喙，脚和跗跖的颜色，以及较长的尾巴。这些特征使其与燕尾伞鸟明显区分开来。","habits":"黄眼燕尾伞鸟是一种定居型鸟类，不同于部分迁徙的燕尾伞鸟，后者在南半球冬季时常会向低海拔地区迁移。","identification":"黄眼燕尾伞鸟与燕尾伞鸟的区别在于眼色、喙的曲度、脚和跗跖的颜色、尾长以及不同的叫声。此外，黄眼燕尾伞鸟的栖息习性与燕尾伞鸟也有所不同。","protection":"IUCN：EN（濒危）","distribution":"黄眼燕尾伞鸟的分布局限于南美洲的玻利维亚西部，具体为阿波罗周边地区。","other":"现为燕尾伞鸟亚种。"},{"name":"白颊伞鸟","english_name":"White-cheeked Cotinga","scientific_name":"Zaratornis stresemanni","overview":"白颊伞鸟（英文名：White-cheeked Cotinga，学名：Zaratornis stresemanni），是雀形目伞鸟科白颊伞鸟属的鸟类。罕见的伞鸟科鸟类，仅见于秘鲁西部安第斯山脉高海拔森林，主要栖息于Polylepis-Gynoxys林区，海拔3250-4400米，非繁殖季节会降至2000米的混合林区。其以槲寄生浆果为主要食物，可能是当地槲寄生种子的主要传播者。","appearance":"白颊伞鸟体型与鸫鸟相近，通体呈褐色，冠部黑色或黑褐色。背部和腹部的羽毛为淡棕色，带有暗色条纹。最显著的特征是白色的脸颊斑块，喉咙和上胸部灰棕色，无条纹。翼部深棕色，次级飞羽有浅橙色边缘。尾部深棕色。","call":"其典型鸣唱为一系列急促的刺耳声，先加速后减速。","habits":"白颊伞鸟主要栖息于秘鲁西部安第斯山脉的高海拔森林，偏好Polylepis-Gynoxys林区。饮食几乎完全依赖槲寄生（Tristerix、Ligaria）的浆果，长时间不在进食时会静止于暴露的树枝上。","identification":"与红冠伞鸟幼鸟相似，但后者更灰色，无白色脸颊，冠部灰色或棕色，尾部有白色亚端带。与栗冠伞鸟也有相似之处，但后者具有突出的锈色喉部和颈圈，缺乏白色脸颊斑块，下体更黄色。","protection":"IUCN：NT（近危）","distribution":"分布于南美洲秘鲁西部的安第斯山脉，主要在3250-4400米的高海拔地区。","other":"白颊伞鸟是其属下的唯一物种，对于当地槲寄生生态链有重要影响。"},{"name":"栗腹伞鸟","english_name":"Chestnut-bellied Cotinga","scientific_name":"Doliornis remseni","overview":"栗腹伞鸟（英文名：Chestnut-bellied Cotinga，学名：Doliornis remseni），是雀形目伞鸟科栗腹伞鸟属的鸟类。主要分布在南美的哥伦比亚、厄瓜多尔和北秘鲁的安第斯山脉高海拔地区。以灰暗色调为主，雄鸟头部黑色，腹部呈独特的栗色，雌鸟头部有较宽的灰色边缘。","appearance":"体长约21.5厘米，雄鸟体重58.5至72克，雌鸟略重。雄鸟头部顶部黑色，颈部有暗橙红色的颈冠（通常隐藏或大部分隐藏），其余头部深灰色，背部更暗，接近黑色；胸部深灰，其余下体为丰富的红栗色。雌鸟头部有广泛的灰色羽缘。幼鸟与成年鸟相似。","call":"叫声特征了解不多，但已有的录音显示其发出沙哑的单音‘rrreh’，间隔重复。","habits":"栖息于高山树线附近的矮木林地带，海拔高度在2875至3650米之间，大多位于3100米以上。偏好湿润的亚热带或热带山地森林和高海拔草原。","identification":"与类似物种相比，具有更深的头部颜色和更加鲜艳的红栗色下体。","protection":"IUCN：NT（近危）。全球数量估计少于15,000只，面临中等程度的人口下降，主要是由于栖息地丧失和退化。","distribution":"在哥伦比亚的昆迪奥地区和厄瓜多尔的卡尔奇东南部至萨莫拉-钦奇佩有零星分布，推测在北秘鲁的Cordillera Las Lagunillas也可能存在，但尚未记录。","other":"自1989年首次发现以来，目前仅知大约10到14个分布点，其中两个在哥伦比亚，至少八个在厄瓜多尔。"},{"name":"栗肛伞鸟","english_name":"Bay-vented Cotinga","scientific_name":"Doliornis sclateri","overview":"栗肛伞鸟（英文名：Bay-vented Cotinga，学名：Doliornis sclateri），是雀形目伞鸟科栗腹伞鸟属的鸟类。仅分布于南美洲秘鲁中部的高海拔森林边缘地带。其最显著的特征是拥有栗色的肛周羽毛，雄鸟具有黑色的冠羽和隐藏的红色羽冠，而雌鸟则缺少这一特征。","appearance":"成年栗肛伞鸟羽毛呈灰色，胸部和腹部为浅棕色，肛周区域为鲜明的栗色。雄鸟头部顶部为光泽的黑色，冠羽中心有红色羽冠，通常被遮盖。雌鸟相似，但头部顶部为暗灰色，冠羽颜色较暗淡。幼鸟主要为棕色，同样具有栗色的肛周羽毛。","call":"典型的叫声为间隔时间较长的短促金属摩擦声。","habits":"通常栖息在高处的树枝上，生活在秘鲁东部安第斯山脉的高海拔森林附近。关于其生态习性的具体细节目前研究有限。","identification":"与红冠伞鸟在地理分布上有重叠，但后者具有灰白的下体和尾部白色横带，易于区分。与栗腹伞鸟相似，但两者地理分布分离，栗腹伞鸟腹部颜色更偏向栗色。","protection":"IUCN：NT（近危）","distribution":"分布于南美秘鲁中部，主要在高海拔森林区域。","other":"尽管近年来对该物种的研究有所增加，但其生态学仍知之甚少。"},{"name":"秘鲁割草鸟","english_name":"Peruvian Plantcutter","scientific_name":"Phytotoma raimondii","overview":"秘鲁割草鸟（英文名：Peruvian Plantcutter，学名：Phytotoma raimondii），是雀形目伞鸟科割草鸟属的鸟类。其分布仅限于秘鲁西北部的干燥低地森林。这种鸟具有显著的雌雄异型，以植物为食。雄鸟拥有灰色体羽，腹部和前额呈红色，翼上有白色条纹；雌鸟则呈现灰褐色，有黑色斑纹。其独特之处在于松散的冠羽和黄色的眼睛。","appearance":"成年秘鲁割草鸟体长约18.5厘米，体重介于36至44克。雄鸟头部上方有一处肉桂红棕色斑点，其余头部和背部为暗灰，翼部黑色，带有白色小翼覆羽和明显的白色大翼覆羽尖端。雌鸟全身灰褐色，背部有黑色条纹，下体有浓重的黑褐色条纹，翼部有两道狭窄的白色翼纹。幼鸟特征未详述。","call":"秘鲁割草鸟发出奇特、类似吹口哨的‘errrrrrr’声，重复数次，音符逐渐缩短并降低音调，与红胸割草鸟的叫声相似但更尖锐，听起来不那么机械。","habits":"栖息于秘鲁沿海的沙漠灌木丛和大部分贫瘠的海岸沙丘，海拔从海平面到550米。偏好生长有algarrobo树（Prosopis pallida）、Acacia macrocantha和Cucurbita的干燥雾林。它们通常以Prosopis和其他树木及灌木的芽、嫩枝和叶片为食，偶尔也会吃一些果实，通常成对或小群活动。","breeding":"繁殖季节可能在3月至4月间，巢穴位于Prosopis树上，离地面2至2.5米高。巢由细枝搭建，较为脆弱，平均产卵数为2至4枚。卵呈短椭圆形，表面光滑，颜色从浅黄褐色到橄榄灰色不等，卵的较大端有深褐色的斑点。","identification":"秘鲁割草鸟的性别差异明显，雄鸟的红色腹部和白色翼纹是识别的关键。雌鸟则以其灰褐色和黑色条纹区别于其他鸟类。","protection":"IUCN：VU（易危）。秘鲁割草鸟的分布范围非常小且严重碎片化，自1990年代以来，仅在八个地点被记录。全球估计数量为1000至2500只，成熟个体约670至1600只。","distribution":"秘鲁西北部沿海地区，包括塔拉拉附近、博斯克德波马克历史保护区和派詹周边。在塔拉拉附近，估计有400至600只；博斯克德波马克历史保护区约有500只；派詹周围约有200至400只。","other":"由于栖息地丧失的威胁，秘鲁割草鸟的生存状况令人担忧。"},{"name":"红胸割草鸟","english_name":"White-tipped Plantcutter","scientific_name":"Phytotoma rutila","overview":"红胸割草鸟（英文名：White-tipped Plantcutter，学名：Phytotoma rutila），是雀形目伞鸟科割草鸟属的鸟类。中等体型、特征明显的割草鸟。主要分布于南美洲中南部和东南部，常见于干燥开阔的林地和草地，尤其是密集灌木丛地区。也可见于农业地带和灌木丛生区域。","appearance":"雄鸟头部和背部呈灰白色，下体拥有醒目的红橙色羽毛。雌鸟总体呈褐色，密布深色条纹。成鸟特征明显，具短冠，眼虹膜明显，喙短而结实，边缘细锯齿状。雄鸟的头部前额为赤褐色，翅膀和尾巴为暗黑色，两对宽阔的白色翼带，尾羽尖端显著白色（中央一对除外）。雌鸟头部和上体黑褐色，翼部具1-2条狭窄白翼带，下体淡黄至赭色，布满深褐色条纹。幼鸟上体灰褐，下体统一的淡黄褐色。","call":"通常叫声为机械式的‘errrrrrr’，类似旧式闹钟发条声，有时重复数次，有时后跟较低沉且较短的‘errrr’。觅食时也会发出刮擦声。","habits":"栖息于查科林地、开放林地边缘、河岸灌木丛、潘帕斯草原、干旱低地和山地灌木丛，以及半开放的有刺灌木林，如金合欢和其它多刺灌木。活动于海拔海平面至1800米的多数范围内，在安第斯山脉可达600-3600米。以叶食性为主，主要食物为各种植物的芽、嫩枝和叶子，也食用果实和花朵。成对、家庭群、小群体甚至大群觅食，通常在树和灌木的3-4米高处，偶尔地面活动。","identification":"雄鸟和雌鸟的色彩差异明显，幼鸟与成鸟也有区别，尤其是下体颜色。种族emangustirostris/em具有更强壮的喙和更宽的白色尾尖。","protection":"IUCN：LC（无危）。物种在阿根廷、玻利维亚和巴拉圭的多个保护区中都有分布。种族emangustirostris/em由于自然灌木植被的广泛破坏而数量减少，仅在一个保护区（Palmacito）中被记录。","distribution":"分布于南美洲的中南部和东南部，主要在安第斯山脉东侧的低地，也深入到玻利维亚的高地。"},{"name":"棕尾割草鸟","english_name":"Rufous-tailed Plantcutter","scientific_name":"Phytotoma rara","overview":"棕尾割草鸟（英文名：Rufous-tailed Plantcutter，学名：Phytotoma rara），是雀形目伞鸟科割草鸟属的鸟类。分布于南美洲南部的鸟类。体型中等，约19厘米长，具有黑色长尾和红色基部。雄鸟上体灰褐色，头顶及胸部呈栗色，面部有深色标记；雌鸟相似，但无栗色头顶，腹部有条纹。两性均有翼杠，雄鸟白色，雌鸟淡黄色。该物种广泛分布，常见于智利和阿根廷西部，从马加兰斯至阿塔卡马，以及从圣克鲁斯至门多萨。","appearance":"棕尾割草鸟体长约18至20厘米，体重38至44克，特征鲜明，有短小的冠羽，明亮的眼睛，喙短而粗，锥形，边缘微锯齿状。雄鸟具栗色头顶，黑褐色侧面，后颈及上体灰褐色，带有宽幅的黑褐条纹，翅膀黑褐色，有白色翼杠，尾巴黑色，内侧红色，下体橙红，腹部最浅，下翼覆羽黑褐色；尾下覆羽暗色，有微小的红灰色尖端和外侧尾羽上的宽幅红棕色亚端带。雌鸟头部侧面和上体淡灰褐色，有宽幅的黑褐色条纹，两道窄淡黄色翼杠，下体淡黄色，有深褐色条纹，腹部较单一。幼鸟整体灰褐色，有窄淡黄色翼杠。","call":"发出机械般的嘶声，初始音节加速上升，音量和音调略增，最后的‘errrrrrrr’如同老式闹钟上弦的声音。联系叫声为机械式的‘rara-rara’。","habits":"栖息于开阔的多刺灌木丛、森林边缘、诺托法古斯森林的空地和次生林，也见于农田、树篱、果园、葡萄园和花园。食性以草本植物为主，如芽、嫩枝和叶片，尤其是豆科植物，偶尔食用果实和浆果；也会捕食昆虫。偏好食用单子叶植物的嫩叶，如小麦和燕麦。浆果包括欧洲接骨木、智利樱桃、秘鲁香膏和细叶假连翘。雏鸟几乎完全以昆虫为食。繁殖季节成对觅食，其余时间成群活动，群大小6至12只。既在地上也在树叶中觅食。","breeding":"繁殖季节有两个，分别为10月至11月和12月至1月；卵期出现在1月和10月至12月，雏鸟期在11月。巢为浅杯形，直径14至18厘米，高7至9厘米，由薄干枝松散构建，内垫根纤维，通常置于1至3米高的浓密多刺灌木内，有时位于树的高位，通常在水平枝的分叉处。每窝产卵2至4枚，旧报告中的5至6枚被认为不可靠；孵化期约为两周；雏鸟期未记录。","identification":"雄鸟的栗色头部和明显的翼杠，以及雌鸟的条纹下体和淡黄色翼杠是辨识的关键。与同属其他物种相比，其特有的红色眼和尾部基部的红棕色是显著特征。","protection":"IUCN：LC（无危）","distribution":"分布于智利和阿根廷西部，从马加兰斯地区北至阿塔卡马，从圣克鲁斯北至门多萨。","other":"由于它倾向于侵扰菜园和果园，棕尾割草鸟被人类视为害鸟，常遭猎杀。尽管如此，它在城市和破碎的森林环境中生存良好，其中灌木是最主要的植被。周边森林的保护对其他地区的鸟类物种更为重要，因为它们具有高度的特有性。人类侵占栖息地，如木材农业和商业伐木，导致了森林碎片化和斑块形成。一般而言，斑块大小的减少导致了生物多样性的下降，影响了许多该地区的鸟类物种；然而，由于棕尾割草鸟能适应由人类侵占造成的环境条件，其种群基本未受影响。"},{"name":"冠食果伞鸟","english_name":"Hooded Berryeater","scientific_name":"Carpornis cucullata","overview":"冠食果伞鸟（英文名：Hooded Berryeater，学名：Carpornis cucullata），是雀形目伞鸟科食浆果伞鸟属的鸟类。主要分布在巴西东南部，从埃斯皮里图桑托州至里奥格兰德杜苏尔州的山区森林中。具有独特的黑头黄腹外观，以及长长的尾巴，是当地特有种。","appearance":"成年雄性冠食果伞鸟拥有黑色的头部和胸部，黄色的颈圈和腹部，以及带有黑色和黄色边缘的栗色背部。翅膀和尾巴呈黑色，翼上具橄榄绿色边缘和两道淡黄色的翼斑。雌鸟颜色较为暗淡，头部和身体带有橄榄色。幼鸟类似于雌鸟，但头部的黑色更少，翅膀覆羽呈绿色而非黑色带绿边，喉咙和胸部的黄色较暗且更多条纹。","call":"雄鸟的领地叫声为典型的四音节短语，柔和而圆润，'wo-op, wot-chuí'。两性都会发出向内的，摩擦声般的音符。","habits":"栖息于湿润的低地和山地森林，包括棕榈树林，海拔高度在400至1600米之间。通常单独活动，以软果实为主食，偶尔也会捕食大昆虫。它偏好原始森林环境，对森林碎片化非常敏感。","breeding":"关于繁殖的信息有限，但从换羽周期推测，繁殖可能发生在9月至10月间。","identification":"与黑头食果伞鸟相比，冠食果伞鸟的上体颜色不同，下体无条纹，喙较窄且腹背压缩程度较低，尾巴相对更长。","protection":"IUCN：LC（无危）。这种限制范围的物种在大西洋森林低地EBA中存在，由于农业扩张、人类定居和城市化导致栖息地破坏，现在几乎仅限于山地森林。在几个保护区如Serra dos Órgãos国家公园、Augusto Ruschi生物保护区和Intervales、Serra do Mar州立公园内可见。","distribution":"南美洲巴西东南部，覆盖从埃斯皮里图桑托州至里奥格兰德杜苏尔州的地区。","other":"冠食果伞鸟对于维持大西洋森林的生态网络至关重要，被视为关键物种。"},{"name":"黑头食果伞鸟","english_name":"Black-headed Berryeater","scientific_name":"Carpornis melanocephala","overview":"黑头食果伞鸟（英文名：Black-headed Berryeater，学名：Carpornis melanocephala），是雀形目伞鸟科食浆果伞鸟属的鸟类。大型且结实的伞鸟科鸟类，常见于巴西东部湿润森林的树冠层，以其黑色头部与红色眼虹膜形成鲜明对比而著称。","appearance":"雄鸟头部至颈背黑色，下喉部黄色细环；背部和翅膀橄榄绿，尾巴颜色相似；下体橄榄黄，腹部更淡，带有细微的暗橄榄条纹。雌鸟类似雄鸟，头部可能带有橄榄色。成年鸟体重介于62.7克至66克之间，雌鸟体重约为64克，体长约20.5至21厘米。幼鸟与雌鸟相似，头部黑色较浅，喉咙和胸部颜色较暗，条纹更明显。","call":"雄鸟领地鸣叫为响亮的哨音‘tuhweéo’。","habits":"栖息于低海拔湿润森林，最高可达约700米，但通常低于300米。偏好茂密植被，如多藤蔓和棘榈的干燥沙质地带。以果实为主食，偶尔捕食昆虫，如7厘米长的竹节虫。飞行中摘取果实的可能性比近缘种更高。","breeding":"繁殖信息有限，据推测可能在南半球夏季繁殖。雌鸟单独孵卵，巢建于树叉，高度约4米，由干叶和枝条构成，外观似一堆空中落叶。蛋呈淡角白色，一端略带灰色，布有棕色小斑点和条纹，尺寸约32.2mm×23.5mm。","identification":"与冠食果伞鸟的区别在于上体颜色、下体条纹，以及更为扁平和背腹压缩的喙型，相对短的尾巴。","protection":"IUCN：NT（近危）。依赖低地森林，因森林破坏而受到威胁。总数量较低且分布严重碎片化，估计已显著减少。主要分布在保护区，如Alagoas的Murici生态保护区、Bahia的Monte Pascoal国家公园、Espírito Santo的Sooretama生物保护区和São Paulo的Intervales州立公园。","distribution":"分布于巴西东部，从Alagoas南部至Bahia，沿海岸至东北Paraná。主要栖息地为低海拔湿润森林。","other":"黑头食果伞鸟在巴西国家级别被列为易危物种。森林砍伐和棕榈果采集对其生境造成持续威胁，不受控制的火灾亦损害其栖息地。"},{"name":"绿黑食果伞鸟","english_name":"Green-and-black Fruiteater","scientific_name":"Pipreola riefferii","overview":"绿黑食果伞鸟（英文名：Green-and-black Fruiteater，学名：Pipreola riefferii），是雀形目伞鸟科食果伞鸟属的鸟类。分布于南美，从委内瑞拉北部至秘鲁北部，常见于森林环境，特别是亚热带和温带地区的山地森林。体型丰满，以绿色和黑色为主色调，雄鸟头部和胸部呈黑色，腹部黄色并带有杂乱的绿色条纹。","appearance":"绿黑食果伞鸟是一种体型健壮的鸟，身长17.5至20厘米，体重46至61克。雄鸟具有黑色头部和胸部，边缘有黄色项圈（颈部后方除外），上部绿色，翼羽端白色，下部黄色，带有密集的绿色条纹，雌鸟全身几乎全绿，缺乏雄鸟的黑色头部和项圈。两性均具红色喙和腿，眼色深红棕色。幼鸟上部暗橄榄绿，下部淡橄榄色，带有黄色条纹，成年羽毛似乎在离巢不久后获得。不同亚种在体型和颜色上有细微差异。","call":"鸣声为非常尖锐的、嘶嘶声的‘ti-ti-ti-ti’，可持续长达5秒，逐渐减弱；tallmanorum亚种的鸣叫声独特，尾音细而高。","habits":"栖息于海拔1000至2900米的山地森林、森林边缘和次生林地。以果实为食，已知在哥伦比亚东部安第斯山脉食用16种植物的果实，来自8个不同的植物家族。通常在静止站立或笨拙地悬停时摘食果实，常随混合物种觅食群行动。","breeding":"繁殖期在哥伦比亚西部为2月至8月。筑巢为一个稳固的杯状结构，几乎全部由苔藓构成，内部衬以黑色根须，置于灌木或小树上1至2米高的位置。一窝产2枚蛋，关于孵化期和雏鸟成长期的信息尚无记录。","identification":"与相似的斑尾食果伞鸟相比，绿黑食果伞鸟尾部更平，下体斑纹较少。雌鸟头部、前体至胸部均为单一绿色，无黑色头部和项圈。不同亚种在翅膀对比度、下体绿色条纹量以及雄鸟头部颜色上有差异。","protection":"IUCN：LC（无危）。绿黑食果伞鸟虽不常见，但分布广泛，种群数量稳定，出现在多个保护区。","distribution":"绿黑食果伞鸟原产于南美洲东部安第斯山脉的低地和中地山林，分布范围从委内瑞拉南部延伸至秘鲁北部，海拔高度在1500至2700米之间。"},{"name":"斑尾食果伞鸟","english_name":"Band-tailed Fruiteater","scientific_name":"Pipreola intermedia","overview":"斑尾食果伞鸟（英文名：Band-tailed Fruiteater，学名：Pipreola intermedia），是雀形目伞鸟科食果伞鸟属的鸟类。体型丰满的绿色鸟类，拥有珊瑚红色的喙和腿。雄鸟头部黑色，胸前有一圈黄色颈环，身体绿色，腹部带有鳞片状图案；雌鸟全身绿色，腹部有类似的鳞状纹路，通常具有完整的黄色眼环。分布于南美洲的秘鲁到玻利维亚，常见于山地森林。","appearance":"斑尾食果伞鸟长约19厘米，雄鸟体重44-59克，雌鸟44-51克。雄鸟头部黑色延伸至胸部，颈部有微弱的黄色颈环（除颈背外）；上身绿色，三级飞羽白色尖端，尾部有黑色亚末端横带和白色尖端；下身黄色，侧腹绿色，黑色斑点形成鳞状和斑点外观；虹膜棕色，有时灰色；喙鲜红色，有时黑色的鼻脊；腿红或橙红色。雌鸟无黑色头罩，头部至胸部前部均为绿色，仅有淡黄色颈环的暗示，亦有黄色眼环。幼鸟描述未详。","call":"发出极高音调的颤鸣声，例如“tsi-tsi-tsi-tsiiiii”，持续约4-5秒，与绿黑食果伞鸟的鸣叫类似。","habits":"仅以果实为食。在秘鲁和玻利维亚的山地森林中单独或成对出现，栖息于海拔2,300至3,000米的热带湿润山地森林，南部边缘可能出现在较低海拔。与绿黑食果伞鸟相比，斑尾食果伞鸟通常栖息在更高海拔。","identification":"与绿黑食果伞鸟相似但略大，绿黑食果伞鸟缺乏斑尾食果伞鸟尾部的黑色末端横带和白色尖端。雄性斑尾食果伞鸟下体图案更重，雌鸟的黄色眼环更明显。","protection":"IUCN：LC（无危）。斑尾食果伞鸟在马迪迪国家公园（Bolivia）、马丘比丘历史保护区（Peru，Cuzco）和卡皮什山口（Huánuco）常见，其保护状况稳定。","distribution":"分布于南美的秘鲁至玻利维亚，主要栖息在安第斯山脉东部的山地森林，一般海拔从2,300至3,000米，在其分布范围的南部可能出现在更低的海拔。"},{"name":"横斑食果伞鸟","english_name":"Barred Fruiteater","scientific_name":"Pipreola arcuata","overview":"横斑食果伞鸟（英文名：Barred Fruiteater，学名：Pipreola arcuata），是雀形目伞鸟科食果伞鸟属的鸟类。大型、短尾、扁头的食果伞鸟，体羽呈绿黑相间的图案。雄鸟头部和胸部黑色，腹部淡黄色并带有明显的深色条纹，上体橄榄绿色，翅膀上有显著的淡色斑点。雌鸟头部与背部颜色一致，全身覆盖着黄黑相间的条纹。分布于南美洲的山地森林，自委内瑞拉西部至玻利维亚，常见于亚热带和温带森林地带。","appearance":"体长约23厘米，重112至128克。雄鸟头部、胸部黑色，上体橄榄绿色，翅膀具大块黄色斑点；尾部有黑色亚端斑和白色尖端。雌鸟全身橄榄绿色，全身遍布黄黑条纹。两性均有红色喙和腿，眼色变异较大，从橙色到灰色再到白色。幼鸟描述未详。","call":"发出极高、细薄、几乎嘶嘶声的\"se-e-e-e-e-e-a-a-a-a\"，音调下降，持续约2.5秒。","habits":"生活在山地森林及林缘，海拔1200至3350米。行动缓慢，通常安静地栖息在森林中层，偶尔加入混群。以果实为食，偶尔会聚集在结果的树周围。极少加入混种群。","breeding":"已知幼鸟出现在1月的玻利维亚和7月的厄瓜多尔，其余繁殖信息未知。","identification":"雄鸟头部和胸部黑色，雌鸟头部与背部颜色一致，均为橄榄绿色，全身遍布黄黑条纹。与同属的其他物种区别明显，特别是其独特的下体条纹。","protection":"IUCN：LC（无危）；在多个保护区中出现，例如委内瑞拉的Sierra Nevada和Guaramacal国家公园，哥伦比亚的Munchique国家公园，以及厄瓜多尔的Podocarpus国家公园。","distribution":"分布于南美洲的山地，从委内瑞拉西部至玻利维亚，主要栖息于亚热带和温带的湿润山地森林。","other":"数量稳定，相较于绿黑食果伞鸟更为罕见，两者在分布范围、海拔地带和栖息环境上有大量重叠。"},{"name":"金胸食果伞鸟","english_name":"Golden-breasted Fruiteater","scientific_name":"Pipreola aureopectus","overview":"金胸食果伞鸟（英文名：Golden-breasted Fruiteater，学名：Pipreola aureopectus），是雀形目伞鸟科食果伞鸟属的鸟类。特征为绿色和黄色的身体，橙色的眼睛和小橙色喙。雄鸟具有黑色的面部区域，明亮的黄色喉咙和胸部，而雌鸟的下面部无黑色，呈淡黄色带绿纹。常见于哥伦比亚和委内瑞拉的山地森林中。","appearance":"金胸食果伞鸟体长约17厘米，体重介于46至60克。雄鸟的头部有暗色区域，上身绿色，翼羽有白色尖端，喉部和上胸部为鲜艳的黄色，腹部柠檬黄色，两胁有绿色条纹。雌鸟上体亮绿色，翼羽淡色，下体黄绿色条纹明显。眼睛橙黄色，喙橙色，腿灰绿色。幼鸟描述未详。","call":"金胸食果伞鸟发出高音、嘶嘶声的叫声，长达3秒，先是上升然后缓慢下降，最后再次上升并突然停止，之后短暂停顿，再跟两个短促音节，被描述为“pseéééeeeeeeeeaaaeeeéét tic tic”。有时发出较短版本的叫声。","habits":"栖息于海拔800至3100米的湿润山地和前山森林。常被观察到与混种群一同活动，以果实为食。","breeding":"繁殖信息有限，已知在1月至6月间有繁殖条件的个体，也有9月份的记录。具体繁殖细节未知。","identification":"雌鸟通过下体绿色条纹而非斑点与丽色食果伞鸟相区分。不同亚种之间存在大小和下体条纹颜色的差异。","protection":"IUCN：LC（无危）。在整个北部分布区较为常见，但在哥伦比亚安第斯山脉中稀少且局部分布。","distribution":"分布于南美洲的东北部哥伦比亚和北部委内瑞拉的东侧安第斯山脉，以及哥伦比亚西侧山脉的局部区域。"},{"name":"橙胸食果伞鸟","english_name":"Orange-breasted Fruiteater","scientific_name":"Pipreola jucunda","overview":"橙胸食果伞鸟（英文名：Orange-breasted Fruiteater，学名：Pipreola jucunda），是雀形目伞鸟科食果伞鸟属的鸟类。体型丰满、色彩鲜艳的伞鸟科食果伞鸟属鸟类，分布于南美洲西部安第斯山脉的云雾森林中。雄鸟以其橙色的胸部和黑色头部易于识别，而雌鸟的鉴别较为困难，其黑色脚和淡色眼睛帮助区分于绿黑食果伞鸟雌鸟。成年鸟约18厘米长。","appearance":"雄鸟拥有光泽的黑色头冠，绿色上体、翅膀和尾巴；胸部有显著的橙色斑块，向颈部两侧延伸，下方由一条细黑线勾勒；侧胸为纯绿色，其余下体呈黄色，与绿色的两胁相融。雌鸟全身绿色，喉部和下颌有绿色调，下体有黄绿相间的条纹。幼鸟尚未详细描述。","call":"发出极高音的哨声，持续2至2.5秒，有时是短促的，有时则拉长且拖音。","habits":"栖息于海拔600至2300米的山地森林，偏好湿润的苔藓森林。以果实为食，常在树中层觅食，有时成对出现，偶尔加入混种群。飞行笨拙。","breeding":"在哥伦比亚和厄瓜多尔记录到的繁殖活动包括巢穴发现和喂养幼鸟。巢为杯状，由活苔藓和枯苔藓构成，内部有细枝和蕨类纤维，位于树上约4.5米高处。在野外，繁殖期可能始于3月，雌鸟携带食物。圈养条件下，产卵数为2枚，孵化期16至17天。","identification":"雄鸟的黑色头部和橙色胸部是其主要特征，与绿黑食果伞鸟相比，缺乏头部的绿色调，胸部颜色更为鲜亮。雌鸟通过其脚和眼色区别于绿黑食果伞鸟雌鸟。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲哥伦比亚西南部（自乔科省南部起）和厄瓜多尔（南至瓜亚斯省东部）。在哥伦比亚的La Planada自然保护区和Río Ñambí自然保护区有记录。","other":"橙胸食果伞鸟在适宜的苔藓云雾森林生境中相对常见，但在全球范围内并不受威胁。"},{"name":"黑胸食果伞鸟","english_name":"Black-chested Fruiteater","scientific_name":"Pipreola lubomirskii","overview":"黑胸食果伞鸟（英文名：Black-chested Fruiteater，学名：Pipreola lubomirskii），是雀形目伞鸟科食果伞鸟属的鸟类。这种较为罕见的食果伞鸟在南美洲的云雾森林中发现，分布于厄瓜多尔、哥伦比亚南部至秘鲁北部安第斯山脉东坡。其显著特征为雄鸟的黑色头部和上胸部，与绿色的上体和黄色下体形成鲜明对比。","appearance":"黑胸食果伞鸟长约18厘米，雄鸟具亮黑色的头、喉部和上胸部，绿色的上体，侧胸至腹侧为绿色，其余下体为黄色，侧翼至腹部有断裂的黑色线条。雌鸟全身绿色，上体和颏至胸上部绿色，下体黄绿相间条纹。虹膜黄色，喙橙红至珊瑚红色，腿绿灰至橄榄褐色。幼鸟未详述。","call":"发出高亢、尖细、拉长的‘pseeeeeeeét’声，结尾较强；也有较短的‘pseeet’叫声。","habits":"栖息于海拔1500至2300米的亚热带和热带湿润山地森林，以浆果为食，常在森林中层到上层觅食。飞行特点、活动范围等细节尚待观察记录。","breeding":"关于繁殖期、求偶、营巢、交配、产卵、孵化和育雏等具体繁殖信息目前资料有限。","identification":"与绿黑食果伞鸟的区别在于后者雄鸟胸侧有黄色边缘，翅膀上有白色斑点，虹膜和腿的颜色也不同。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲安第斯山脉东坡，从哥伦比亚南部的马格达莱纳河谷源头至厄瓜多尔和秘鲁北部，最南至秘鲁卡哈马卡北部，包括查尼亚河谷西坡和亚马逊中部。在秘鲁马腊尼翁省南部和卡哈马卡西部也有局部分布。","other":"尽管分布范围有限，黑胸食果伞鸟的数量似乎稳定。"},{"name":"花脸食果伞鸟","english_name":"Masked Fruiteater","scientific_name":"Pipreola pulchra","overview":"花脸食果伞鸟（英文名：Masked Fruiteater，学名：Pipreola pulchra），是雀形目伞鸟科食果伞鸟属的中型鸟类。雄鸟拥有亮丽橙色的喙和黑色面部，颈部带有黄色橙色饰带，腹部下部为黄色；雌鸟几乎全身绿色，腹部有淡黄色条纹，喙色较暗。分布于秘鲁安第斯山脉东坡的亚热带或热带湿润山地森林。","appearance":"成年花脸食果伞鸟体长约18厘米，雄鸟体重约54至63克，雌鸟体重介于42至63克。雄鸟头部黑色微带绿调，上体绿色，翅膀和尾巴同样绿色；胸部有橙黄色斑块延伸至颈部两侧，下方有细黑线边框；侧胸纯绿色，其余下体黄色，两胁宽幅绿色条纹；虹膜黄色；喙红色；腿绿色。雌鸟上体全绿，下体绿色与黄色相间条纹。幼鸟特征未详述。","call":"发出高音的‘psee-pseeee’声。","habits":"栖息于秘鲁东部安第斯山脉海拔1,600至2,400米的湿润山地森林中，常在果实丰富的树木周围隐蔽栖息，偶尔加入混群鸟群。","breeding":"繁殖信息未提及。","identification":"与类似种橙胸食果伞鸟的区别在于头部带绿调，胸部橙色较淡。雌鸟腿部颜色和腹部条纹而非斑点图案，可将其与橙腿雌性红胸食果伞鸟区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁安第斯山脉东部，南美：秘鲁。"},{"name":"红胸食果伞鸟","english_name":"Scarlet-breasted Fruiteater","scientific_name":"Pipreola frontalis","overview":"红胸食果伞鸟（英文名：Scarlet-breasted Fruiteater，学名：Pipreola frontalis），是雀形目伞鸟科食果伞鸟属的鸟类。体型丰满，色彩鲜艳，常见于南美洲安第斯山脉东坡的云雾森林，分布自厄瓜多尔北部至玻利维亚。其显著特征为绿色和黄色的羽毛，雄鸟拥有醒目的红色喉部和胸部。","appearance":"红胸食果伞鸟体长约15.5至16.5厘米，体重在38.5至47克之间。雄鸟具有深绿至蓝绿色头部，绿色背部，翅膀和尾巴，翼羽有黄色尖端，胸部有一大块红色斑块，其余下部主要为黄色，两胁带绿色。雌鸟的头部和喉咙部分带有黄色，胸部几乎无标记，腹部下方的羽毛呈现更多的绿色，形成鳞片状外观。雄鸟和雌鸟的腿和脚均为橙色或粉红色。","call":"红胸食果伞鸟发出高音调的鸣叫，包括上升的‘tsweeet’声和短暂的‘pseet’声，有时会伴有颤音。","habits":"栖息于山地森林的中层和亚冠层，偶尔出现在边缘地带，高度范围大约在670至2300米之间，较为罕见低于1000米或高于1700米。它们通常以果实为食，常加入多种鸟类组成的混合群，尤其喜欢与唐纳雀科鸟类一起活动。","breeding":"关于繁殖的详细信息较少，已知的巢穴呈碗状，直径约18厘米，由苔藓和地衣构成，位于森林边缘的亚冠层树枝分叉处，高度约15米。记录到的繁殖活动包括雄鸟在巢中以及雌鸟处于繁殖状态的情况。","identification":"与红喉食果伞鸟相比，红胸食果伞鸟的雌鸟个体更大，喙为橙色而非黑色。雄鸟个体头部颜色更深，喉部红色面积较小。","protection":"IUCN：LC（无危）","distribution":"分布于南美安第斯山脉东部斜坡，范围从厄瓜多尔北部至玻利维亚中部。在厄瓜多尔，分布于纳波省；在秘鲁，分布从科迪勒拉阿祖尔和塞罗斯德尔西拉山脉向南至中部地区；在玻利维亚，分布于圣克鲁斯西部。","other":"红胸食果伞鸟在多个自然保护区内被记录，包括厄瓜多尔的Podocarpus国家公园和Sumaco-Napo Galeras国家公园，秘鲁的Manu国家公园和生物圈保护区，以及玻利维亚的Madidi国家公园。"},{"name":"红喉食果伞鸟","english_name":"Fiery-throated Fruiteater","scientific_name":"Pipreola chlorolepidota","overview":"红喉食果伞鸟（英文名：Fiery-throated Fruiteater，学名：Pipreola chlorolepidota），是雀形目伞鸟科食果伞鸟属的鸟类。分布于南美洲的安第斯山脉东部云雾森林，自哥伦比亚南部延伸至秘鲁。红喉食果伞鸟因其独特的色彩和稀少的数量而备受关注。","appearance":"红喉食果伞鸟体长约12.5厘米，是其属中最小的物种。雄鸟具有鲜亮的绿色头部和上体，翼羽的三级飞羽尖端呈白色，鲜明的橙红色喉部与胸部形成对比，其余下体绿色，腹部中央带黄色。雌鸟的上体与雄鸟相似，胸绿色，腹部带有绿色和黄色的斑纹。两性的眼睛均为淡灰色，喙粉橙色带暗色尖端，腿橙色。","call":"红喉食果伞鸟发出非常短促、高音调的‘tsi’声。","habits":"栖息于海拔600至1200米的热带湿润森林，偶尔在更高的海拔观察到。以浆果为食，通常在森林的中上层活动，常以成对的形式出现。","breeding":"具体繁殖信息尚不详尽。","identification":"与红胸食果伞鸟相比较，红喉食果伞鸟体型更小，雄鸟腹部颜色较绿。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲的安第斯山脉东坡，从哥伦比亚南部（东南卡乌卡、西卡奎塔）向南至秘鲁中部和东南部（南至帕斯科，极东普诺也有孤立记录）。","other":"红喉食果伞鸟在其分布区内面临严重的栖息地压力，包括农业扩张、牧场开发、伐木和其他商业活动威胁。"},{"name":"丽色食果伞鸟","english_name":"Handsome Fruiteater","scientific_name":"Pipreola formosa","overview":"丽色食果伞鸟（英文名：Handsome Fruiteater，学名：Pipreola formosa），是雀形目伞鸟科食果伞鸟属的中等体型的鸟类，以其绿色与黄色相间的独特体羽和醒目的白色翼斑而著称。雄鸟头部黑色，腹部呈鲜艳的黄色，胸带模糊的红色；雌鸟头部绿色，腹部黄色并带有绿色条纹。分布于委内瑞拉沿海山脉的潮湿森林中。","appearance":"丽色食果伞鸟身长约16至18厘米，体重在43至49克之间。雄鸟具有黑色的头和喉咙，绿色的上部，以及橙色胸部和黄色腹部，翼上有显著的白色斑点。雌鸟的头部和喉咙为绿色，胸前有黄色新月形斑块，其余腹部为绿色和黄色的细条纹。幼鸟特征未详述。存在不同的亚种，其胸红色调和翼斑大小有所差异。","call":"发出高而尖细的'pik'声和连续的'ti-ti-ti-ti-ti...'声，歌声以高音的'peeééé-eeeeeee-e-e-e-e'开始，逐渐减弱。","habits":"通常单独或成对出现，安静地栖息在森林的不同高度。常见于海拔800至2200米的湿润森林中。主要以小型果实为食，既在停歇时进食，也在短暂的悬停飞行中捕食。偶尔加入混种群觅食。","breeding":"关于其繁殖习性的了解有限，但观察到在6月和7月换羽，推测在此之前已繁殖。","identification":"雄鸟的橙色胸部在同域物种中独一无二。雌鸟与金胸食果伞鸟的区别在于后者无黄色胸斑，且腹部有条纹而非丽色食果伞鸟的条纹。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲委内瑞拉北部的两个分离山区，位于沿海山脉。"},{"name":"红斑食果伞鸟","english_name":"Red-banded Fruiteater","scientific_name":"Pipreola whitelyi","overview":"红斑食果伞鸟（英文名：Red-banded Fruiteater，学名：Pipreola whitelyi），是雀形目伞鸟科食果伞鸟属的鸟类。南美洲特普伊山脉特有种。其最显著的特征是雄鸟拥有独特的灰绿色上体，对比鲜明的棕色翅膀和冠部，以及醒目的红色胸带，雌鸟则全身呈绿色，具有黄色颈侧斑块，腹部白色并饰有绿色条纹。仅分布于特普伊高山区（海拔1000米以上）的湿润森林。","appearance":"体长约16.6厘米，雄鸟上体灰绿，有金色眉纹环绕眼周至耳羽，胸带橙红，腹灰，尾下覆羽黄赭；雌鸟头侧有类似标记，颈侧黄，上体苔绿，无胸带，下体灰白带黑条纹。喙腿粉灰，雄鸟虹膜橙色，雌鸟虹膜赭色。","call":"发出绵长、高音且细薄的‘pss-ee-ee-ee-ee-ee-ee’声，持续约2-3秒，间隔时间长；兴奋时会发出高音的‘ti’声，常成短系列。","habits":"栖息于热带雨林树冠层，偏好湿度高的森林，主要以果实为食，有时访问林缘，通常单独或成对出现，有时加入混合食果鸟群。活动缓慢，长时间保持静止。","identification":"雄鸟与雌鸟在外形上有明显差异，雄鸟胸带及颜色组合独特，雌鸟下体具黑色条纹。与同属其他种类相比，外形特征明显。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲特普伊山脉，具体为委内瑞拉东南部和圭亚那西部的高山森林，海拔1200至2250米之间。"},{"name":"鳞斑食果伞鸟","english_name":"Scaled Fruiteater","scientific_name":"Ampelioides tschudii","overview":"鳞斑食果伞鸟（英文名：Scaled Fruiteater，学名：Ampelioides tschudii），是雀形目伞鸟科鳞斑食果伞鸟属的鸟类。是伞鸟科唯一的成员，属中小型鸟类，具有28属68种108个亚种。其特征是短尾、扁头，身披苔绿色与黑色相间的鳞状羽毛，长度约19-20厘米。分布于南美的安第斯山脉，自委内瑞拉西部至玻利维亚。","appearance":"雄鸟拥有光泽黑帽至颈背，耳羽及口裂；上体黑色，具橄榄色鳞纹，翼橄榄色宽带明显。雌鸟头部黑色替换为橄榄色，上体和翼覆羽更少黑色，外观更橄榄色。成年个体体长19-20厘米，雄鸟体重74-95克，雌鸟71.5-80克。","call":"领地歌曲是一系列响亮的向下弯曲的哨声，起初上升，类似猛禽叫声。飞行中发出咔嗒声。","habits":"主要栖息于安第斯山脉的高海拔热带森林，活动于中上层林冠，通常在果实丰富的树附近活动，偶尔加入混种群鸟群。食谱主要包括水果、昆虫，有时也食用树栖蜗牛。","breeding":"繁殖季节，雄鸟建立领地吸引雌鸟，巢由植物纤维构成，雌鸟产卵两枚，孵化期约两周，双亲共同育雏。","identification":"雄鸟与雌鸟的主要区别在于头部颜色和体羽的差异，雄鸟头部全黑，雌鸟头部橄榄色，雌鸟上体和翼覆羽黑色较少，外观更橄榄色。","protection":"IUCN：LC（无危）","distribution":"分布于南美安第斯山脉，包括委内瑞拉西部至玻利维亚，局部出现在哥伦比亚、厄瓜多尔、秘鲁。","other":"在多个保护区中可见，如哥伦比亚的La Planada自然保护区和Río Ñambí自然保护区，以及玻利维亚的Madidi国家公园。"},{"name":"圭亚那冠伞鸟","english_name":"Guianan Cock-of-the-rock","scientific_name":"Rupicola rupicola","overview":"圭亚那冠伞鸟（英文名：Guianan Cock-of-the-rock，学名：Rupicola rupicola），是雀形目伞鸟科动冠伞鸟属的鸟类。以其鲜艳的橙色雄鸟和独特的半圆形头饰而闻名。雌鸟呈暗烟灰色，体型较重，喙宽基部明显，头部带有月牙状羽冠。生活在亚马逊雨林的岩石地带，主要以水果为食。","appearance":"雄性圭亚那冠伞鸟全身鲜亮橙色，头顶部有半圆形的盘状羽冠，延伸至颈部，冠羽上有细窄的赤褐色带。初级飞羽灰黑，有宽阔的白色基部。最外侧的初级飞羽尖端细长。次级飞羽宽大，内侧次级飞羽有长而丝质的橙色边缘。尾羽黑色，末端有橙色小尖。雌鸟主要是暗烟灰色，头冠较小。一岁的雄鸟幼鸟类似雌鸟，但体表有橙色斑点。两岁雄鸟主要为橙色，带有些许棕色斑点。三岁时达到成年羽毛。雌鸟幼鸟外观与成年雌鸟相似。","call":"在繁殖季节，雄鸟会发出一系列响亮的鸡鸣般叫声，有时在觅食时也会发出类似鸭子被掐住的声音。","habits":"栖息于低地雨林中的岩石地带，常见于靠近提供筑巢场所的岩层附近。主要以水果为食，偶尔也食用小型脊椎动物和其他物品。它们在繁殖季节聚集在繁殖场，雄鸟会进行复杂的展示吸引雌鸟。","breeding":"繁殖期通常在早春，雌鸟会在岩石悬崖上用泥和植物材料筑巢，每次产卵1到2枚。雌鸟负责筑巢、孵化和育雏，雄鸟不参与。雄鸟在繁殖场进行展示，吸引雌鸟进行交配。","identification":"与安第斯冠伞鸟相比，雄性圭亚那冠伞鸟羽毛更橙，翅膀上没有黑色部分，而安第斯冠伞鸟的羽毛偏红，翅膀大部分为黑色。雌鸟两者颜色差异明显，圭亚那冠伞鸟为暗烟灰色，而安第斯冠伞鸟为红棕色。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲的亚马逊雨林北部区域，包括法属圭亚那、苏里南、圭亚那、委内瑞拉南部、哥伦比亚东部以及巴西北部亚马逊地区的森林。"},{"name":"安第斯冠伞鸟","english_name":"Andean Cock-of-the-rock","scientific_name":"Rupicola peruvianus","overview":"安第斯冠伞鸟（英文名：Andean Cock-of-the-rock，学名：Rupicola peruvianus），是雀形目伞鸟科动冠伞鸟属的鸟类。属于伞鸟科，是南美洲安第斯山脉云雾林中的标志性鸟种。秘鲁的国鸟，与近亲圭亚那冠伞鸟没有共同分布区。雄鸟拥有显著的圆盘状头冠和鲜亮的橙红或血红色羽毛，雌鸟则较为暗淡，呈深褐色。","appearance":"雄性安第斯冠伞鸟体长约30.5-32厘米，重约265克，拥有独特的圆盘状头部羽毛冠，体羽鲜亮，呈橙红色或血红色，尾羽和翅膀为黑色，肩羽为银灰色。雌鸟体型较小，羽毛颜色较暗，主要为深褐色，头部羽毛冠比雄鸟小，眼睛颜色各异，从浅蓝色到白色。雄鸟的喙为金黄色，雌鸟的喙则为暗色，尖端带黄色。","call":"雄鸟在求偶场发出响亮的'youii'叫声，叫声不如圭亚那冠伞鸟那样刺耳，同时还会发出连续的'kip-kip-kip'的咯咯声。觅食时，不论雌雄，受到惊扰会发出响亮的'ankk'叫声。","habits":"栖息于海拔500-2400米的山地森林，尤其是峡谷和溪流旁。以水果、大型昆虫、小型脊椎动物为食，偏好Lauraceae、Annonaceae和Rubiaceae科的果实。它们会在飞行中摘取果实。小蜥蜴和青蛙是喂养雏鸟的重要食物，被拍打和咀嚼后喂给雏鸟。","breeding":"繁殖季节因地区而异，主要在2月至7月间，在哥伦比亚南部和厄瓜多尔及玻利维亚则可能在8月筑巢。雄鸟在求偶场进行集体展示，吸引雌鸟。雌鸟独自筑巢，通常建在岩石壁上，形状类似截顶锥体，巢内铺垫粗纤维。每窝产2枚蛋，孵化期约为28天，雏鸟至少42至48天后离巢。","identification":"与圭亚那冠伞鸟相比，安第斯冠伞鸟的雄鸟颜色更为鲜艳，雌鸟颜色更暗。亚种之间在羽毛颜色深浅、内侧次级飞羽的灰色程度和眼睛颜色上有差异。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的云雾林，从委内瑞拉西部至玻利维亚，包括哥伦比亚、厄瓜多尔、秘鲁等地。","other":"安第斯冠伞鸟在一些国家公园内得到保护，如哥伦比亚的Cueva de los Guácharos国家公园、厄瓜多尔的Podocarpus国家公园和秘鲁的Machu Picchu历史保护区。"},{"name":"圭亚那红伞鸟","english_name":"Guianan Red Cotinga","scientific_name":"Phoenicircus carnifex","overview":"圭亚那红伞鸟（英文名：Guianan Red Cotinga，学名：Phoenicircus carnifex），是雀形目伞鸟科红伞鸟属的鸟类。雄鸟色彩鲜艳，以亮红色与深棕色羽毛著称；雌鸟颜色较为暗淡，但仍具红棕色羽衣和类似拟啄木鸟的身形。主要栖息于低地热带雨林，分布于南美洲东北部，包括圭亚那、苏里南、法属圭亚那、委内瑞拉东南部及巴西亚马逊河流域。","appearance":"雄鸟体长约22厘米，重约82克；雌鸟稍大，体长约24厘米，重约95克。其特征明显，额前羽毛向前生长，半遮住鼻孔，上下喙基部有突出的毛状羽，胫骨内侧覆羽，外趾与中趾仅末端分离。雄鸟头部、下背至尾部以及胸部以下的下体呈鲜红色，其余部分黑色至酒红棕色，翅膀大部分呈赤褐色，初级飞羽暗色，尾端有深棕色横斑；雌鸟体型较大，整体橄榄色，头部和尾部略带暗红色，胸部以下玫瑰红色。幼鸟似雌鸟，但红色更深，翅膀较短。","call":"雄鸟展示叫声为三音节‘pee-chew-eet’，空中展示时发出尖锐哨声，前有翼振声伴随；在兴奋或警戒时发出单音节‘wheep’。","habits":"栖息于湿润森林，高度可达约600米。通常独居，以多种果实为食，包括棕榈科、樟科、桑科、西番莲科、桃金娘科、藤黄科、梅龙木科和大戟科的果实，通过短暂飞行或站立位置摘取。","breeding":"繁殖季节在苏里南为12月至次年5月，可能更晚。雄鸟在繁殖场展示，与数个其他雄鸟（不一定视觉接触）一起，从约8至12米高的树上发出嘈杂的叫声，身体略微前倾，翅膀下垂，尾巴降低露出鲜红臀部，频繁地从一个栖枝飞向另一个，采用俯冲式降落。巢建于树干裂缝中，距地面约2.7米，由泥和细枝构成，内衬根须和黄色纤维。","identification":"与黑颈红伞鸟的分布有轻微重叠，但可通过更棕色的羽色和不那么整洁的外观来区分。","protection":"IUCN：LC（无危）。在整个分布区内较为罕见，原因不明；在圭亚那局部地区较为常见。在委内瑞拉的伊马塔卡森林保护区和埃尔多拉多等地有记录，很可能在其他保护区内也有分布。","distribution":"分布于南美洲东北部，包括委内瑞拉东南部（玻利瓦尔州东部）、圭亚那、苏里南、法属圭亚那和巴西的亚马逊河下游地区，以及帕拉州和阿马帕州的部分地区。在马拉若岛及帕拉州东北部也有记录。","other":"其分类学历史追溯到1743年乔治·爱德华兹的首次描述，当时被归入Lanius属，后来被Swainson重新分类至Phoenicircus属。"},{"name":"黑颈红伞鸟","english_name":"Black-necked Red Cotinga","scientific_name":"Phoenicircus nigricollis","overview":"黑颈红伞鸟（英文名：Black-necked Red Cotinga，学名：Phoenicircus nigricollis），是雀形目伞鸟科红伞鸟属的鸟类。拥有黑色翅膀和尾尖的黑色带纹，分布于巴西、哥伦比亚、厄瓜多尔、秘鲁以及委内瑞拉南部亚马逊州边境地区的西部亚马逊盆地。栖息于热带低地湿润森林。","appearance":"雄性黑颈红伞鸟长约22厘米，重约93克，雌鸟略大，达24厘米。雄鸟具有鲜艳的红冠、背部至尾部以及胸部至腹部的红色羽毛，其余部分为光泽的黑色，尾羽末端有黑色横纹。雌鸟则主要呈橄榄绿色，头部和尾部呈暗淡的红色，腹部红色。幼鸟类似雌鸟，但红色更深，翼较短。","call":"雄鸟的典型叫声为响亮而略带鼻音的'whea'声，常由柔和的'wur'声前导。在飞行展示中，有时会发出简短版的'whea'声，紧接着是口哨般的翅膀嗡鸣声。还有单音节的'yip'声在兴奋或警戒时发出。","habits":"栖息于高湿度森林的中层到次冠层，高度可达400米。主要以果实为食，已知的食物包括Trichilia属的果实。偶尔在果实丰富的树上可见其身影。","breeding":"繁殖信息缺乏。在秘鲁东北部，雄鸟会在森林中层的藤蔓水平段等3至5个喜爱的栖息处展示，与其他雄鸟保持听觉联系，头部上下摆动，进行扭曲的展示飞行。","identification":"雄鸟与雌鸟在颜色上有显著差异，雄鸟红黑相间，雌鸟橄榄绿带暗红。与同属的圭亚那红伞鸟相比，仅在塔帕若斯河下游四分之一流域有交集。","protection":"IUCN：LC（无危）。一般较为罕见且分布零散，仅在委内瑞拉两个地点有记录。在一些保护区如哥伦比亚的Amacayacu国家公园和厄瓜多尔的Cuyabeno保护区有分布。某些土著民族对红色羽毛的追求可能减少了东厄瓜多尔的数量。","distribution":"分布于南美洲西部亚马逊盆地，包括巴西、哥伦比亚、厄瓜多尔、秘鲁以及委内瑞拉南部亚马逊州边境地区。具体分为西北部和中西南部两个主要分布区。","other":"黑颈红伞鸟与同属的圭亚那红伞鸟在塔帕若斯河流域下游四分之一区域内有交集，但两物种的分布范围相对独立。"},{"name":"秀丽伞鸟","english_name":"Lovely Cotinga","scientific_name":"Cotinga amabilis","overview":"秀丽伞鸟（英文名：Lovely Cotinga，学名：Cotinga amabilis），是雀形目伞鸟科伞鸟属的鸟类。在中美洲热带湿润低地森林中生活的鸟类。其分布区域从墨西哥东南部一直延伸到哥斯达黎加。雄鸟以耀眼的蓝绿色羽毛著称，而雌鸟则呈现灰褐色外观。","appearance":"雄性秀丽伞鸟身长约19厘米，全身呈现鲜艳的蓝绿色，头部、背部、翅膀和腹部均为这种色彩，翅膀和尾巴边缘黑色，腹部有一块紫色斑块。雌鸟则为暗淡的灰褐色，上体带有白色鳞片状斑纹，下体白色，带有褐色斑点。雄鸟的翼展宽大，尾巴相对短小。","call":"通常保持沉默，但在飞行时会发出轻微的颤音，尤其在繁殖季节较为频繁。","habits":"秀丽伞鸟偏好居住在高大的森林树冠层，主要以果实为食，有助于种子传播。它们的活动范围广泛，常在早晨出现在树冠上方的突出枝条上。","identification":"雄鸟与蓝伞鸟相似，但缺乏黑眼环，且紫色斑块更大。雌鸟与蓝伞鸟雌鸟类似，但下体的斑点更为灰色，而非鳞片状。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥东南部至哥斯达黎加，包括中美洲国家如危地马拉、洪都拉斯、尼加拉瓜和巴拿马。","other":"由于它们安静的生活习性，关于秀丽伞鸟的行为和社会组织了解有限。"},{"name":"绿伞鸟","english_name":"Turquoise Cotinga","scientific_name":"Cotinga ridgwayi","overview":"绿伞鸟（英文名：Turquoise Cotinga，学名：Cotinga ridgwayi），是雀形目伞鸟科伞鸟属的鸟类。以其独特而醒目的深蓝色羽毛著称，分布于中美洲的哥斯达黎加和巴拿马西部的热带湿润森林中。","appearance":"雄鸟身长17至18.5厘米，重约51.5至54克，羽毛主要呈现深邃的电光蓝，喉部和腹部有紫色斑块，翅膀黑色边缘微蓝，尾巴黑色被长尾羽覆盖。雌鸟体型略大，重约63.2至65.7克，颜色为暗棕色，上部边缘淡黄色，翅膀和尾巴为暗褐色，下部淡黄带灰色斑点。两性差异显著，雌鸟明显大于雄鸟。","call":"通常保持沉默，雌鸟受惊时会发出粗糙的尖叫声。雄鸟飞行时会产生柔和的啾啾声。","habits":"绿伞鸟栖息于热带湿润森林，单独或成对活动。它们缓慢移动，常在树冠顶部显眼地停栖，或在果实丰富的树木中不引人注目地觅食。","identification":"雄鸟与秀丽伞鸟相比体型稍小，尾羽上覆羽较短；与蓝伞鸟的区别在于喙的比例，缺乏黑色眼圈，喉部斑块颜色较浅，初级飞羽结构不同。","protection":"IUCN：VU（易危）","distribution":"绿伞鸟的分布局限于哥斯达黎加太平洋斜坡南部（自Nicoya湾以南）和巴拿马西部极小区域（Chiriquí西部）。在哥斯达黎加，主要出现在Las Cruces和Las Alturas生物站、Carara国家公园、Osa半岛（包括Corcovado国家公园）以及东部山脚地带；在巴拿马，则仅在Santa Clara地区（Volcán以西）和El Chorogo发现。","other":"森林的大规模破坏严重减少了绿伞鸟的数量和分布范围，特别是在巴拿马，而在哥斯达黎加，剩余的栖息地保护不足。"},{"name":"蓝伞鸟","english_name":"Blue Cotinga","scientific_name":"Cotinga nattererii","overview":"蓝伞鸟（英文名：Blue Cotinga，学名：Cotinga nattererii），是雀形目伞鸟科伞鸟属的鸟类。引人注目的伞鸟。雄鸟以深邃天空般的蓝色羽毛著称，喉部和腹部呈深紫色，翅膀主要是黑色。雌鸟外观差异显著，呈暗褐色，带有鳞片状斑纹。该物种分布于中美洲东部巴拿马至南美洲西北部厄瓜多尔，常见于低地森林的树冠层。","appearance":"雄性蓝伞鸟体长约18-20厘米，羽毛底色为深蓝绿色，眼圈黑色，翅膀边缘呈蓝色，尾羽几乎被上覆羽遮掩。喉部与胸部有大片紫黑色斑块。雌鸟则为暗棕色，上覆羽边缘淡色，下体带鳞状斑点，尾下覆羽淡肉桂色。幼鸟类似雌鸟，但飞羽尖端有淡色。成年雄鸟约一年后与成鸟相似，但可能略显淡色。","call":"雄性蓝伞鸟似乎无鸣唱，但在飞行时会发出哨声般的翼鸣。雌鸟在巢边会发出响亮的尖叫。","habits":"蓝伞鸟主要栖息于热带湿润低地森林的树冠层，偶尔会在海拔300米以上，最高可达1400米的地方发现它们。它们主要以果实为食，通常在短暂的飞翔中摘取。有时会小群聚集，最多约10只一起觅食。","breeding":"繁殖记录显示，蓝伞鸟在巴拿马的二月开始筑巢。巢建在离地面28米高的沙箱树上，由兰花形成的角状结构支撑。巢中曾观察到两只雏鸟，推测每次产卵2枚。除此之外，繁殖行为信息稀缺。","identification":"雄性蓝伞鸟与雌鸟在外观上有显著差异。与近似种如绿伞鸟相比，蓝伞鸟的分布区域不同，且具有更小的喙，黑色的眼圈，以及结构不同的初级飞羽。","protection":"IUCN：LC（无危）。尽管其分布广泛，但在某些地区，如厄瓜多尔，由于低地森林的大量破坏，蓝伞鸟数量已大幅减少，变得非常罕见。","distribution":"蓝伞鸟的分布范围从巴拿马东部延伸至哥伦比亚、委内瑞拉西部以及厄瓜多尔西北部。在哥伦比亚，它们的分布可达1000米，局部地区高达1400米。","other":"蓝伞鸟的种群数量因低地森林的大规模破坏而受到威胁，尤其是在厄瓜多尔，那里的蓝伞鸟现在极为罕见。"},{"name":"斑喉伞鸟","english_name":"Plum-throated Cotinga","scientific_name":"Cotinga maynana","overview":"斑喉伞鸟（英文名：Plum-throated Cotinga，学名：Cotinga maynana），是雀形目伞鸟科伞鸟属的鸟类。居住在低地热带森林中的蓝色伞鸟。其分布范围涵盖南美洲亚马逊地区的中心和西部，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔和秘鲁。偏好生活在亚热带或热带湿润的低地森林、沼泽地带以及重度退化后的森林环境中。","appearance":"雄性斑喉伞鸟全身呈现纯净的天蓝色，拥有紫色喉咙和明亮的眼睛；雌鸟则为淡褐色，带有微弱的鳞状花纹。雄鸟的下体闪耀着青绿色，羽基呈粉紫色；肩羽相同，但羽基为黑褐色。尾巴为黑色，边缘泛蓝，收拢时尾羽显现蓝色。翅膀覆羽青绿色，飞羽黑色，内侧羽毛末端有宽大的蓝色边缘，使收拢的翅膀主要呈现蓝色。雌鸟上体为暗灰褐色，下体较浅，喉部和胸部有均匀的淡褐色鳞状花纹，腹部和尾下覆羽为亮丽的肉桂棕色，边缘较暗，形成斑驳效果。","habits":"斑喉伞鸟栖息于森林树冠层，通常在高处的暴露枝条上或果实丰富的树木周围被发现。它们能产生由特殊翼羽发出的机械声音，常与其他种类的伞鸟如辉伞鸟共同觅食。","identification":"雄性斑喉伞鸟与相似的辉伞鸟相比，具有更深的蓝色羽毛，缺乏深色头纹，眼色更亮黄。雌鸟比辉伞鸟的雌鸟颜色更暖，后者偏冷灰色，且有时有像雄鸟一样的淡色眼睛。雌鸟的尾下覆羽在飞行中显露出亮丽的肉桂色，这与其它两种伞鸟的暗淡肉桂色形成鲜明对比。","protection":"IUCN：LC（无危）","distribution":"南美：广泛分布在亚马逊雨林西部，包括但不限于巴西、秘鲁、哥伦比亚、玻利维亚和厄瓜多尔的低地热带森林。"},{"name":"紫胸伞鸟","english_name":"Purple-breasted Cotinga","scientific_name":"Cotinga cotinga","overview":"紫胸伞鸟（英文名：Purple-breasted Cotinga，学名：Cotinga cotinga），是雀形目伞鸟科伞鸟属的小型鸟类。雄鸟在良好光照下极具辨识度，雌鸟全身布满明显的斑纹。分布于南美的亚马孙雨林东北部，包括巴西、哥伦比亚、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。栖息于热带湿润低地森林。","appearance":"雄鸟上体深钴蓝色，从头顶至尾上覆羽，下体被一大片连续的深紫色羽毛覆盖喉至腹部，其余部位蓝色，翼和尾黑色。雌鸟暗褐色，具白色尖端和边缘，下体淡黄褐色，喉咙较浅色，胸部有更深的鳞状斑纹。幼鸟似雌鸟，雄鸟成熟时开始出现鲜艳的紫蓝羽毛。","call":"发出哀伤的哨声，类似暗顶蝇霸鹟的叫声。","habits":"一般单独或成对出现在低地森林中的果木或高裸枝上。以短促的振翅方式取食果实。","breeding":"关于其繁殖行为的知识非常有限。","identification":"雄鸟的紫色羽毛区在喉至腹部连成一片，区别于其他蓝伞鸟属物种。雌鸟的下方斑纹比近缘种更明显。","protection":"IUCN：LC（无危）","distribution":"南美洲亚马逊雨林东北部，分布于巴西、哥伦比亚、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。","other":"该物种的分布存在不确定性，近年来在已知范围以外的南部和西部地区有零星目击报告。"},{"name":"斑伞鸟","english_name":"Banded Cotinga","scientific_name":"Cotinga maculata","overview":"斑伞鸟（英文名：Banded Cotinga，学名：Cotinga maculata），是雀形目伞鸟科伞鸟属的鸟类，以其惊艳的色彩著称。雄鸟呈现钴蓝与紫色，雌鸟则为暗褐色，上部有白色斑点，下部淡色带黑斑。分布于巴西东南部低地大西洋森林，因栖息地破坏，种群数量急剧减少至不足1500只，目前被列为IUCN：EN（濒危）。","appearance":"雄性斑伞鸟拥有明亮的钴蓝色上体，背部有显著的黑色斑点，腹部主要为紫色，胸部有一条蓝色带，下腹蓝色，中央有紫色条纹延伸至蓝色尾下覆羽。雌鸟上体暗棕色，下体较浅，有较大的暗色羽心。翅膀和尾巴均为黑色。雌雄差异显著，雌鸟体型略小。","call":"通常沉默，但在飞行中，雄鸟会发出机械性的翼音。","habits":"栖息于热带湿润低地森林的树冠层，以种子、浆果、果实、毛虫和其他昆虫为食。与橘黄巨嘴鸟和针尾娇鹟等特有种共存。不迁徙，其巢穴为简单的杯状。","breeding":"繁殖信息有限，已知巢穴为简单杯状结构。","identification":"雄性斑伞鸟的色彩组合独特，雌鸟与白翅伞鸟雌鸟相似，但可通过灰白翼纹、淡色虹膜和整体更灰暗的外观区分。","protection":"IUCN：CR（极危）。主要受威胁于栖息地丧失和持续的森林碎片化。","distribution":"主要分布在巴西东南部，包括巴伊亚州，偶尔出现在米纳斯吉拉斯州。可能曾存在于里约热内卢和圣灵州，但已灭绝于此。","other":"保护区内如RPPN Estação Veracel和Reserva Serra Bonita是该物种的重要庇护所。"},{"name":"辉伞鸟","english_name":"Spangled Cotinga","scientific_name":"Cotinga cayana","overview":"辉伞鸟（英文名：Spangled Cotinga，学名：Cotinga cayana），是雀形目伞鸟科伞鸟属的鸟类。是南美洲亚马逊雨林中广泛分布的伞鸟科物种。雄鸟以亮蓝色的羽毛和黑色斑点装饰著称，雌鸟则呈现灰褐色调。栖息于热带森林的树冠层，以其鲜艳的羽毛吸引着世界各地的观鸟爱好者。","appearance":"辉伞鸟雄鸟拥有亮丽的淡青绿色羽毛，头部、背部、臀部及上覆羽皆为鲜明的淡青绿色，黑色的羽毛基底在头、背和臀部形成独特的斑点效果。肩羽黑色，边缘淡青绿；尾羽黑色，细边青蓝；翅膀黑色，翼覆羽和内侧飞羽尖端和边缘青绿；喉咙紫色至酒红色；下体类似上体，但黑斑较少；下尾黑色；下翼覆羽黑色，边缘细粉蓝；其余下翼黑色，飞羽基部白色。雌鸟主要为暗灰色至褐色，腹部稍浅，喉部灰褐色，无斑点；下尾覆羽无斑点，略带肉桂棕色调；翼覆羽有淡色的土黄色边缘。","call":"雄鸟发出柔和的中音\"hooo\"声，重复2至3次。飞行中的雄鸟在正常飞行时产生轻微的哨声翼响，在展示飞行中更响亮。","habits":"辉伞鸟居住在低地热带森林的树冠和次冠层，海拔通常低于600米，局部可达1350米。它们以果实为主食，偏爱槲寄生和月桂科植物，偶尔捕食昆虫，主要是飞蚁和白蚁。它们会在水果丰富的树木上聚集，与其他果食性鸟类一同觅食。","breeding":"据推测，辉伞鸟在旱季筑巢，巢小而杯状或碟状，由枝条和根须构成，外表涂覆真菌。巢高建于11至15米的大树上，仅观察到雌鸟筑巢和后续的亲代照料。每窝产一枚蓝白色带有锈色斑点的相对较大的蛋。","identification":"雄性辉伞鸟与同域的斑喉伞鸟可通过颜色较淡的蓝色、更广泛的黑色斑点、更深的翅膀颜色、更大的喉咙斑块和棕色虹膜来区分。雌鸟较为难辨，斑喉伞鸟雌鸟的下体颜色较浅，腹面更明亮，下翼覆羽更亮的肉桂色，下尾覆羽更明亮的肉桂色，下体部分更斑驳。","protection":"IUCN：LC（无危）","distribution":"辉伞鸟遍布亚马逊盆地，从哥伦比亚东部安第斯山脉以东，到委内瑞拉南部和东部，圭亚那、苏里南和法属圭亚那，再到厄瓜多尔、秘鲁、巴西和玻利维亚北部的亚马逊雨林。","other":"辉伞鸟的羽毛曾被亚马逊盆地的原住民用于制作饰品。"},{"name":"肉垂钟伞鸟","english_name":"Three-wattled Bellbird","scientific_name":"Procnias tricarunculatus","overview":"肉垂钟伞鸟（英文名：Three-wattled Bellbird，学名：Procnias tricarunculatus），是雀形目伞鸟科钟伞鸟属的独特鸟类。雄鸟拥有醒目的外观，头部与胸部呈白色，身体其余部分为深赤褐色，最显著的是从上喙基部长出的三根细长、黑灰色肉垂。雌鸟则整体橄榄绿色，腹部有黄色条纹，缺乏雄鸟的特征性肉垂，使它们能更好地融入森林环境中。该物种主要分布于中美洲的山林中，从洪都拉斯到巴拿马一带。","appearance":"雄性肉垂钟伞鸟体型较大，长约30-33厘米，体重约220克，头部和胸部白色，身体其他部位为深赤褐色。其特征性的三根肉垂从上喙基部垂下，最长可达10厘米。雌鸟较小，约25厘米长，体重约145克，全身橄榄绿色，腹部有黄色条纹，无肉垂。幼鸟外观更接近雌鸟，但雄鸟幼鸟会有较小的肉垂，随年龄增长逐渐增大。","call":"雄性肉垂钟伞鸟发出的叫声独特而响亮，如同铃声般清脆，尤其在繁殖季节，这种声音可以远距离传播，成为森林中的标志性声音。","habits":"肉垂钟伞鸟主要栖息于山地森林的树冠层，它们通常在繁殖季节活跃，非繁殖季则迁徙至低地森林。以果实为食，特别是在Lauraceae家族的树木上觅食，扮演着种子传播者的角色。","breeding":"繁殖期主要集中在3月至6月，雄鸟通过独特的叫声吸引雌鸟。雌鸟独自营巢并孵化卵，承担起育儿的责任。","identification":"雄性肉垂钟伞鸟的外观极其独特，很难与其他物种混淆。雌鸟与同属的其他种类如须钟伞鸟、白钟伞鸟和Naked throated bellbird在外观上有相似之处，但可以通过肉垂的存在与否以及颜色细节加以区分。","protection":"IUCN：VU（易危）","distribution":"繁殖区位于中美洲的山地森林，包括洪都拉斯、尼加拉瓜、哥斯达黎加和巴拿马。非繁殖季则迁徙至低海拔的森林。","other":"由于森林砍伐，尤其是Lauraceae树种的减少，肉垂钟伞鸟的生存面临威胁。"},{"name":"白钟伞鸟","english_name":"White Bellbird","scientific_name":"Procnias albus","overview":"白钟伞鸟（英文名：White Bellbird，学名：Procnias albus），是雀形目伞鸟科钟伞鸟属的鸟类。中型鸟类。以其嘹亮的鸣声而闻名，雄鸟通体洁白无瑕，雌鸟则为橄榄绿色，常见于南美洲亚马逊雨林的东北部，尤其是高海拔的森林地带。","appearance":"雄性白钟伞鸟身长约为28.5厘米，雌鸟略小，约27.5厘米。雄鸟全身纯白，拥有独特的黑色肉垂，由上喙基部长出，缀以短小白羽，雌鸟则为橄榄绿色，腹部带有黄色条纹，其头部轮廓长而倾斜，与同属的其他种类相比，嘴较短。幼鸟外观类似雌鸟，成年雄鸟的羽毛逐渐发育成熟，肉垂在大约1岁时已显现但较小。","call":"雄性白钟伞鸟的鸣叫声极其响亮，如同清脆的钟声，最高可达125.4分贝，是世界上已知叫声最响亮的鸟类之一。鸣唱时，雄鸟会从树梢发出尖锐的‘ding-ding’声，有时也会发出更悠长、音乐般的‘doing doing’声。","habits":"白钟伞鸟主要栖息于湿润的热带或亚热带森林，通常在海拔约1250米的高度活动，偏好在高处的森林中生活。它们主要以果实为食，常在空中捕食，偶尔在停歇时取食。雄鸟会在树顶展示其膨胀的肉垂并发出响亮的鸣叫声。","breeding":"关于白钟伞鸟的繁殖信息尚不充分。雌鸟曾被观察到在2月间折断细枝，可能是用于筑巢的材料。据推测，繁殖季节可能在2月至6月间，但具体细节仍需更多研究。雄鸟在展示期间，肉垂会显著扩张，发出叫声时头部和身体保持不动，或者在倾斜身体时发出单音节的叫声。","identification":"雄性白钟伞鸟由于其独特的全白色羽毛和肉垂结构，几乎无法与任何其他鸟类混淆。雌鸟则与同属的须钟伞鸟相似，但可通过其嘴部的差异和平均体型稍小来区分。","protection":"IUCN：LC（无危）","distribution":"白钟伞鸟主要分布在南美的亚马逊雨林东北部，包括巴西、法属圭亚那、圭亚那、苏里南、特立尼达和多巴哥以及委内瑞拉的部分地区。在委内瑞拉的Canaima国家公园（面积30,000平方公里）受到保护。","other":"尽管白钟伞鸟数量不多，分布稀疏且难以观察，但其总人口估计较大。然而，由于森林砍伐导致的潜在轻微下降。"},{"name":"须钟伞鸟","english_name":"Bearded Bellbird","scientific_name":"Procnias averano","overview":"须钟伞鸟（英文名：Bearded Bellbird，学名：Procnias averano），是雀形目伞鸟科钟伞鸟属的鸟类。是南美洲北部特有种，以独特的外观和响亮的鸣叫声著称。雄鸟个体长约28厘米，除棕色头部和黑色翅膀外，全身羽毛白色；雌鸟较小，橄榄绿上部，黄色下部带绿色条纹，腹部黄色。雄鸟的喉部挂有黑色的肉垂。","appearance":"雄性须钟伞鸟体长约28厘米，羽毛大部分为白色或淡灰色，头部为温暖的棕色，翅膀为黑色。其最显著的特征是喉部挂着一串黑色、无毛的肉垂，犹如胡须。雌鸟体型略小，约27厘米长，上体橄榄绿色，头部颜色较深，下体黄绿色条纹，腹区纯黄色。两者均拥有深色眼睛、黑色喙和灰至黑色的腿脚。","call":"雄性须钟伞鸟的叫声极为响亮，是一种重复的、金属质感的‘bock’声，以及稍弱的、类似锤子敲击铁砧的‘tonk-tonk-tonk-tonk’声，可重复20至30次。此外，还存在多种区域性叫声，例如委内瑞拉南部的嘶哑、几乎像嘶嘶声的‘bisset’，以及委内瑞拉北部的双音节‘teek-terong’。","habits":"须钟伞鸟主要栖息于湿润的热带森林和林地，它们几乎完全以果实和浆果为食，尤其偏爱樟科（Lauraceae）和金合欢科（Burseraceae）的植物。雄鸟会通过其独特的歌声吸引配偶。","breeding":"雌鸟独自建造由细枝构成的脆弱巢穴，通常位于孤立树木的外枝上。繁殖期产一枚带有斑点的浅褐色蛋，孵化任务完全由雌鸟承担。繁殖季节在特立尼达岛为4月至11月，在委内瑞拉北部为5月至9月。","identification":"雄性须钟伞鸟与雌鸟在外形上有明显差异，雌鸟与裸喉钟伞鸟和白钟伞鸟的雌鸟相似，但在冠部颜色上有所不同，须钟伞鸟雌鸟的冠部颜色更深。","protection":"IUCN：LC（无危）","distribution":"须钟伞鸟分布在委内瑞拉、哥伦比亚东北极、圭亚那西部、特立尼达和多巴哥以及巴西东北部。在委内瑞拉局部且数量稀少，在特立尼达较为常见。巴西种群因栖息地破坏严重和笼鸟贸易的影响而被认为是易危物种。","other":"须钟伞鸟的巢通常建在半清空区域的独立树木上，可能为了减少来自丛林中的有效巢穴捕食者的风险，如猴子、巨嘴鸟和蛇。"},{"name":"裸喉钟伞鸟","english_name":"Bare-throated Bellbird","scientific_name":"Procnias nudicollis","overview":"裸喉钟伞鸟（英文名：Bare-throated Bellbird，学名：Procnias nudicollis），是雀形目伞鸟科钟伞鸟属的鸟类。分布于南美洲东部的伞鸟科钟伞鸟属鸟类。雄鸟通体雪白，拥有独特的蓝绿色裸露面部和喉咙；雌鸟橄榄绿上体，腹部条纹，灰褐色头部。其分布区域自巴西东部至巴拉圭东部，延伸至巴西南部和阿根廷东北部。","appearance":"雄鸟全身雪白，脸和喉咙裸露，呈蓝绿色，喙短而宽，第八初级飞羽尖端凹陷。雌鸟体型较小，上体橄榄色，冠部和喉咙暗色，下体黄绿色条纹。幼鸟类似雌鸟，亚成年雄鸟开始显现蓝色裸露喉咙，叫声特征明显，直至三年后获得成年白色羽毛。","call":"雄鸟发出金属般响亮的‘boink’声，声音爆炸性且极为响亮，可从高树冠层的显眼位置听到。","habits":"栖息于湿润的亚热带和热带森林，季节性迁徙至不同海拔以适应水果生产周期，偏好原始森林，但在有果树的次生林和废弃橡胶园也能生存。主要以果实为食，帮助森林树木种子传播。","breeding":"繁殖季节从九月持续到二月，雄鸟在高枝上发出响亮叫声吸引雌鸟。","identification":"雄鸟的全白色羽毛和蓝绿色裸露面部及喉咙使其独特。雌鸟与须钟伞鸟雌鸟相比，具有更暗的冠部和喉咙，特别是在喉部差异明显。亚成年雄鸟通过蓝色裸露喉咙和叫声与雌鸟区分。","protection":"IUCN：NT（近危）","distribution":"分布于巴西东部至巴拉圭东部，巴西南部和阿根廷东北部，季节性迁徙于巴西东部和巴拉圭的不同海拔地区，偶尔在阿根廷出现。","other":"因森林砍伐和非法捕捉作为笼鸟交易，面临严重威胁，尤其是在巴西南部Bahia、São Paulo和Santa Catarina以及Paraguay的Asunción市场。"},{"name":"黑黄伞鸟","english_name":"Black-and-gold Cotinga","scientific_name":"Lipaugus ater","overview":"黑黄伞鸟（英文名：Black-and-gold Cotinga，学名：Lipaugus ater），是雀形目伞鸟科皮哈伞鸟属的鸟类。雄鸟外观壮观，全身黑色，翅膀上有一片醒目的金色斑块。雌鸟通体橄榄绿，腹部略带黄色。分布于南美巴西东南部，主要栖息于海拔1200至2050米的山地森林。","appearance":"雄鸟体型较大，全身黑色，翼上有大片金黄色斑块，眼虹膜红褐色，喙橙色，腿深棕色。雌鸟呈均匀的橄榄绿色，翼羽边缘及腹部略带黄色，喙色较暗。幼鸟羽毛类似于雌鸟，随成长逐步换为成年羽毛。","call":"雄鸟发出高亢、纯净的哨音，每次鸣叫持续约3秒，间歇2秒，多个雄鸟交替鸣叫形成连续的哨声，可在远距离听到。","habits":"栖息于山地森林的亚冠层，主要以果实为食，偶尔捕食昆虫。活动范围有限，有时会迁移到较低海拔。捕食时通常从停驻位置取食果实，偶尔在飞行中摘取，昆虫则在空中短暂飞行中捕获。","breeding":"关于繁殖的资料有限，已知雌鸟在12月开始换羽，推测可能在9月至11月繁殖，与区域内其他物种相似。巢穴记录较少。","identification":"雄鸟与雌鸟显著性二态，雄鸟黑色带金黄翼斑，雌鸟橄榄绿色。与栗顶伞鸟相比，黑黄伞鸟体型更大，喙更厚实，翼羽黄色而非灰色。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东南部，具体为圣保罗州东部、米纳斯吉拉斯州南部和里约热内卢州南部。在Itatiaia和Serra dos Órgãos国家公园较为常见。","other":"曾被归类于Tijuca属，后根据分子系统发育研究归入Lipaugus属。"},{"name":"灰翅伞鸟","english_name":"Grey-winged Cotinga","scientific_name":"Lipaugus conditus","overview":"灰翅伞鸟（英文名：Grey-winged Cotinga，学名：Lipaugus conditus），是雀形目伞鸟科皮哈伞鸟属的鸟类。分布于巴西东南部的里约热内卢州，特有于Serra dos Órgãos和Serra do Tinguá山系的云雾森林。其自然栖息地为热带湿润高山森林。","appearance":"体型较大的伞鸟，总长约为24厘米。雄鸟具有灰暗的脸部和上喉部，橄榄绿色的背部，臀部更显黄色，翅膀和尾巴较深呈棕色，飞羽外缘银灰色；腹部和翼下覆羽橄榄黄色，腹部更黄；虹膜棕色，上喙深灰色，下喙橄榄黄色，腿脚暗角质色。雌鸟比雄鸟小，羽毛颜色较暗淡，与雌鸟的区别在于体型较小、色彩更鲜艳、飞羽银白色。幼鸟特征未详述。","call":"雄鸟发出响亮的双音节哨声，重音在第二个音节，声音类似“sooee-wheee”，持续约1.25秒；远处仅能听到第二个音节。","habits":"栖息于非常湿润的高山云雾森林，常见有多种凤梨科植物。主要分布在海拔1560至2105米处，偶尔降至1340米。生活在巴西东南部，特有于里约热内卢州的特定山区。","breeding":"关于生长繁殖的信息尚未提供。","identification":"与黑黄伞鸟雌鸟区别明显，灰翅伞鸟体型更小，色彩更为明亮，飞羽有银色，而黑黄伞鸟雌鸟的翅膀为橄榄绿色。同时，灰翅伞鸟的喙更小、更精致，腿和脚也更细。","protection":"IUCN：VU（易危）","distribution":"分布于巴西东南部，主要在里约热内卢州的Serra dos Órgãos和Serra do Tinguá山系，已知的分布还包括Araras Biological Reserve和Nova Caledônia。","other":"曾被归入Tijuca属，但分子系统发育研究显示Tijuca嵌入Lipaugus属中，因此将其并入Lipaugus属。"},{"name":"栗顶伞鸟","english_name":"Chestnut-capped Piha","scientific_name":"Lipaugus weberi","overview":"栗顶伞鸟（英文名：Chestnut-capped Piha，学名：Lipaugus weberi），是雀形目伞鸟科皮哈伞鸟属的罕见而濒危的鸟类。其特征为几乎通体灰色，头顶栗色，眼圈淡黄色。分布于哥伦比亚中安第斯山脉北部非常小的区域内，是该地区的特有种。","appearance":"体长24至25厘米，体重约72克。雄鸟具栗色冠羽，全身其余部位呈板岩灰色，下方稍淡，下体有浅肉桂色的下尾羽覆羽。初级飞羽6和7的外网羽枝加粗硬化，不相互锁合。虹膜深棕色，眼圈黄褐色，喙黑色，腿灰色。雌鸟与雄鸟相似，但初级飞羽不加粗。幼鸟与成鸟类似，但次级飞羽和最外侧初级飞羽有宽阔的锈红色边缘。","call":"发出空灵的尖叫，音调先升高后突然下降，通常以一秒间隔重复，有时在激动时会快速连续发出。还有相对安静、鼻音的“咯咯”声，可能是接触或警报信号。","habits":"栖息于中到高海拔的云雾林中间层到上层，偏好大片的云雾林。活动于海拔1400至1925米之间，以果实为主食，偶尔捕食大型无脊椎动物。飞行时通过短暂的滑翔来摘取果实，有时在空中旋转以摘取果子，偶尔在栖息时摘食。","breeding":"繁殖季节可能在每年上半年，已知的繁殖信息有限，但有观察到可能的求偶场，以及新羽化的小鸟。具体繁殖行为、巢穴、交配和育雏细节尚不清楚。","identification":"与更广泛的暗色伞鸟相比，栗顶伞鸟具有眼圈和冠羽，后者在野外很少可见。两物种在地理上不重叠。","protection":"IUCN：CR（极危）","distribution":"分布在哥伦比亚中安第斯山脉的东北部和北部斜坡，具体位于Antioquia省的Porce和Nechí山谷附近。","other":"自1999年发现以来，该物种已被正式描述，并被认为处于极度濒危状态。目前全球估计数量可能少于250只。"},{"name":"暗色伞鸟","english_name":"Dusky Piha","scientific_name":"Lipaugus fuscocinereus","overview":"暗色伞鸟（英文名：Dusky Piha，学名：Lipaugus fuscocinereus），是雀形目伞鸟科皮哈伞鸟属的鸟类。们拥有灰色的朴素羽毛，缺乏明显的性别差异，主要分布在哥伦比亚至秘鲁的安第斯山脉，海拔高度约在2000至3000米之间。","appearance":"暗色伞鸟体长33厘米，体重120至138克，是其属中体型最大的，尾部相对较长。雄鸟呈灰色，翅膀和尾巴颜色较深；初级飞羽5至7根的外网中部有延长且硬化、不相互锁定的羽枝；下体较浅灰，自胸向下逐渐变为褐色；眼睛深棕色，喙暗棕色或黑色，下颚基部较浅；腿灰色。雌鸟与雄鸟相似，但初级飞羽无特殊变化。幼鸟翼覆羽尖端呈锈色，可能是幼鸟羽毛的残留。","call":"发出响亮的‘pee-a-weeee’或‘pee-a-weeee-a-weeee’叫声，最后一个音节下滑。展示时会制造出明显的翼拍声。","habits":"暗色伞鸟栖息于湿润的云雾森林，通常在林中至林冠层的中间位置低调地停留。常见于果实丰富的树木附近，有时会在小型群体中活动，常伴随混合物种的觅食群。","breeding":"已知繁殖信息有限，仅记录到3月底在厄瓜多尔东部的一个巢中有一枚蛋。巢呈扁平杯状，主要由紧密卷曲的干藤蔓构成，建于稀疏的长木棍平台上，位于Vismia tomentosa树的水平分叉处，距地面约8.5米。蛋壳呈淡米色，有粗大的棕色和淡紫色斑点，集中在较大的一端，尺寸为39.4毫米×29.0毫米。","identification":"暗色伞鸟可能与大棕鸫混淆，两者大小和颜色相似，但暗色伞鸟的腿和喙为暗色，且具有长尾、短喙和圆头的特点。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚、厄瓜多尔和秘鲁的西部安第斯山脉，以及厄瓜多尔和秘鲁北部的东坡。"},{"name":"镰翅伞鸟","english_name":"Scimitar-winged Piha","scientific_name":"Lipaugus uropygialis","overview":"镰翅伞鸟（英文名：Scimitar-winged Piha，学名：Lipaugus uropygialis），是雀形目伞鸟科皮哈伞鸟属的鸟类。罕见的伞鸟科鸟类，发现于秘鲁东南部和玻利维亚安第斯山脉东坡的湿润森林中。其独特的外观特征包括大部分灰色羽毛，胸侧和臀部呈栗色，拥有异常形状的翅膀。分布区域狭窄，数量稀少。","appearance":"雄鸟上半身灰暗，下半身颜色较浅，胸侧至臀部为红栗色，尾巴下方覆羽亦为红栗色。翅膀形状独特，初级飞羽高度变形，弯曲并拉长，形成镰刀状，每片飞羽长度依次递减至P9和P10显著加长。雌鸟类似雄鸟，可能略大，但翅膀变形程度较低。幼鸟特征未详述。","call":"通常沉默，但在激动时会发出柔和的尖叫和咯咯声，具体表现为‘wheeo, wheeo, whee-wheé’等音节，但叫声来源的个体是否属于本物种尚待确认。","habits":"栖息于湿润森林的中层，偶尔加入混种群鸟群。以浆果和水果为主食，也可能摄食昆虫，但具体信息缺乏。曾在混种群鸟群中被记录。","breeding":"关于繁殖习性的信息缺失。","identification":"镰翅伞鸟最明显的特征是其镰刀状的翅膀，以及独特的红栗色臀部和胸侧，这些特征使其与同类中的其他物种区分开来。","protection":"IUCN：VU（易危）。受到森林破坏和生境碎片化的严重威胁，尤其是在受干扰的森林区域，人口数量估计在1000至2500只之间。在秘鲁的Megantoni国家保护区和玻利维亚的Madidi、Isiboro-Sécure、Carrasco、Amboró及Cotapata国家公园，以及Pilón Lajas生物圈保护区有所记录。","distribution":"分布于秘鲁东南部（库斯科北部，普诺东部）和玻利维亚（拉巴斯、科恰班巴），主要栖息在安第斯山脉东坡的湿润森林。"},{"name":"棕伞鸟","english_name":"Rufous Piha","scientific_name":"Lipaugus unirufus","overview":"棕伞鸟（英文名：Rufous Piha，学名：Lipaugus unirufus），是雀形目伞鸟科皮哈伞鸟属的鸟类。伞鸟科中唯一真正分布于安第斯山两侧的成员。体型似鸫，通体亮锈红色，具淡色眼圈，常栖于中低海拔潮湿常绿林的中上层。其嘹亮的哨音“PEE-HAH”远播，可借拍手声诱出。分布自墨西哥南部经中美洲至哥伦比亚北部及厄瓜多尔西北部，偶入红树林边缘。","appearance":"成鸟体长22.9–24.1厘米，体重约75克，雌雄同型。通体呈明亮的红褐色至肉桂褐色，略淡的下体与稍深的胸部形成反差；眼圈色浅，面部羽毛略显蓬松。飞羽内缘及腋羽深赭黄色。雏鸟覆稀疏灰色绒羽。虹膜深褐；上喙暗灰色，下喙浅褐端灰；跗跖及趾灰至褐色带绿灰鳞纹。","call":"鸣声极为响亮而具爆发性，常被形容为“刺耳而自信的 peeer 或 wheeeooo”，亦作较长 whee-er-wet 或 wheeoweet，以及柔和 where-weet、pee-ha 和一连串厚重金属感的 chrrrg。雌鸟及雏鸟发出较弱哨音。鸣叫间隔长且不规律，突发巨响亦可触发其回应。","habits":"终年留居，极少下地。主要活动于潮湿低地及低山常绿林的林冠及中层，偶至林窗或红树林边缘。长时间静止直立停栖，突然飞扑至叶层摘取昆虫、蜘蛛、小型蝎子或果实，多悬停取食；亦在悬停中吞食地面食物。通常单独活动，罕见混群。","breeding":"繁殖期3–8月。雄鸟于林冠层鸣唱求偶，为一雄多雌制，但两性外形相同。雌鸟独力营巢，巢为小碗状，由藤蔓、细枝及纤维松散编织，距地5–10米，空间仅容一枚卵。卵灰褐、密布深褐斑，约31×22毫米；孵化期25–26天，雌鸟约75%时间抱卵。雏鸟28–29天离巢，雌鸟当年可育两窝，离巢后即拆毁旧巢。","identification":"与体型较小、更纤细的棕悲霸鹟极为相似，但棕伞鸟较大且壮，喉部色淡，头更大、嘴更厚。整体似鸫但头与嘴比例更大。亚种 castaneotinctus 较指名亚种上体更暗栗色。","protection":"IUCN: LC（无危）。全球种群约五万只，分布面积四十六万平方千米，但持续缓慢下降。中美洲及哥伦比亚—厄瓜多尔西北部因大规模毁林局部已明显减少，甚至从巴拿马巴罗科罗拉多岛消失。","distribution":"繁殖区：墨西哥南部（自韦拉克鲁斯南部及瓦哈卡北部东向）经中美洲至巴拿马，再沿安第斯山西坡至哥伦比亚北部及厄瓜多尔西北部（埃斯梅拉达斯）。非繁殖区：无迁徙，全年留居。","other":"属名 Lipaugus 在伞鸟科系统发育中，与暗色伞鸟及黑黄伞鸟构成一支持度高的分支，但三者在分子系统树上呈多歧状态。"},{"name":"尖声伞鸟","english_name":"Screaming Piha","scientific_name":"Lipaugus vociferans","overview":"尖声伞鸟（英文名：Screaming Piha，学名：Lipaugus vociferans），是雀形目伞鸟科皮哈伞鸟属的鸟类。亚马逊低地最具标志性的声音之一。这种灰褐色的伞鸟虽然常见但难以一见真容，以其极响亮的鸣叫声闻名于世。在亚马逊南美洲和巴西大西洋森林广泛分布，雄鸟常聚集于森林中的小鸣场，发出尖锐的叫声吸引雌鸟。","appearance":"尖声伞鸟体长约25厘米，全身呈均匀的灰色调，腹部略淡，尾巴较深。雌雄两性外观相似，均具有较长的尾巴、较短的跗跖和比鸫更宽大的喙。成鸟的翅膀和尾羽颜色稍暗，而幼鸟的翼覆羽和尾羽尖端带有肉桂红褐色。","call":"尖声伞鸟最显著的特征是其极为响亮的鸣叫声，可达116分贝，仅次于白铃鸟。叫声包括一系列轻柔的呼噜声，随后是一连串撕裂耳膜的“SQUEE, SQUEE-AH”。在繁殖季节，多达十只雄鸟可能聚集在松散的鸣场，通过歌唱吸引雌鸟。","habits":"尖声伞鸟主要栖息于海拔500米以下的亚马逊雨林中层和下层树冠，或在委内瑞拉和安第斯山麓高达1000米的地区。它们通常独居，偶尔加入混合物种觅食群。以果实为主食，也捕食昆虫，有时会从栖息处飞出，像啄木鸟一样悬停在空中捕捉猎物。","breeding":"在繁殖季节，雄性尖声伞鸟会聚集在松散的鸣场，通过歌唱吸引雌鸟。具体繁殖细节尚未详细记录。","identification":"与灰悲霸鹟类似，但尖声伞鸟体型更大，颜色较浅，喙部更大更宽。灰哀鸟体型较小，喙部细小，虹膜呈红棕色而非灰色或灰棕色，常与混种鸟群活动，而尖声伞鸟很少参与。","protection":"IUCN：LC（无危）","distribution":"尖声伞鸟分布于南美洲的亚马逊雨林和巴西东部的大西洋森林。"},{"name":"红肛伞鸟","english_name":"Cinnamon-vented Piha","scientific_name":"Lipaugus lanioides","overview":"红肛伞鸟（英文名：Cinnamon-vented Piha，学名：Lipaugus lanioides），是雀形目伞鸟科皮哈伞鸟属的鸟类。体型较大的类似鸫的鸟类，全身呈灰褐色，头部和背部有轻微鳞状外观，翅膀和尾巴颜色更深，下体为淡灰色，尾下覆羽呈现特有的肉桂色，这一特征也赋予了其中文名称。红肛伞鸟主要分布在巴西东南部的山地森林中。","appearance":"红肛伞鸟体长约28厘米，体重在85至110克之间。其羽毛总体上为灰色，头部有较弱的鳞片状图案，上体带有棕色调，尤其在翅膀和尾巴处颜色最深。下体主要为浅灰棕色，有细小的白色羽轴条纹，尾下覆羽为肉桂色。虹膜为深棕色，喙为暗棕色或黑色，下颌基部较浅，嘴内部为粉黄色，腿为灰色。雄雌外表相似，幼鸟的正式描述未给出。","call":"通常保持沉默，但会周期性地发出响亮的哨声，由几个音符组成，典型的序列为“skeeo-skeeo, skeeo-skeeo, skeeo-sheét”，各段之间间隔较长。","habits":"红肛伞鸟栖息在山地湿润森林中，海拔高度从山脚到1400米，主要活动在500至1000米的范围内。以果实为主食，也捕食大型昆虫。观察显示，其饮食中约86%为果实，14%为昆虫，果实种类多样，主要来自38种植物，尤以Euterpe棕榈为主。在繁殖季节，雏鸟最初12至14天仅以昆虫为食，之后逐渐增加水果比例。","breeding":"繁殖记录显示，筑巢期大约在9月至次年3月，产卵时间集中在12月至次年2月。巢为极小的薄平台型，由细枝搭建，通常位于离地面7至8米高的小树水平枝和侧枝上。每窝产一枚蛋，孵化期约为26天，雏鸟离巢期为25至26天。","identification":"与尖声伞鸟相比，红肛伞鸟并非均匀灰色，尾下覆羽的肉桂色是其显著特征。","protection":"IUCN：LC（无危）","distribution":"红肛伞鸟分布于巴西东南部，从巴伊亚州东南部、米纳斯吉拉斯州东北部和埃斯皮里托桑托州向南延伸至圣卡塔琳娜州东北部。","other":"红肛伞鸟的分布范围在过去几十年中已缩减至原来的十分之一，数量大幅减少，主要是由于巴西东部沿海森林的广泛破坏。目前在多个私人和公共保护区中尚存，其中在Augusto Ruschi生物保护区的数量最多，估计有几百只。"},{"name":"红领伞鸟","english_name":"Rose-collared Piha","scientific_name":"Lipaugus streptophorus","overview":"红领伞鸟（英文名：Rose-collared Piha，学名：Lipaugus streptophorus），是雀形目伞鸟科皮哈伞鸟属的鸟类。中等体型的灰鸟，雄鸟拥有独特的粉红色领圈和尾下覆羽，而雌鸟则缺乏这一特征。该鸟种主要分布在南美洲特普伊山脉的高海拔森林中，常见于委内瑞拉东南部、巴西北部和圭亚那西部。","appearance":"雄性红领伞鸟的上体呈暗灰色，下体稍淡，尤其是腹部。最显著的特征是其环绕颈部的鲜艳粉红至品红色领圈，以及相似颜色的尾下覆羽。雌鸟体型略小于雄鸟，无粉色领圈，尾下覆羽为肉桂色。幼鸟特征未详述。成年鸟的长度约为22.5厘米（9英寸）。","call":"主要鸣叫声为清晰的哨声，先上升后下降，常以不完整的形式发出，有时会变成尖锐下滑的‘sueeet-suéééeeeeoo’音调。此外，还有一种描述为响亮尖锐的‘skreeyr’叫声，间隔时间较长，可能是展示中的雄鸟所发的啸鸣声。","habits":"主要栖息于特普伊山脉的高海拔森林中，活动于森林中层和冠层，通常在800米以上的斜坡上。它们以果实为主食，尤其是Melastomataceae科植物的果实，偶尔捕食昆虫。飞行时捕食果实，行动缓慢，不易被发现，除非鸣叫。","breeding":"关于繁殖习性的具体信息未提供。","identification":"雄鸟的外观独特，难以与其他物种混淆。雌鸟与尖声伞鸟的雌鸟相似，但后者没有肉桂色的肛周区域，且叫声明显不同。","protection":"IUCN：LC（无危）。红领伞鸟的分布范围有限，但在其范围内相对常见，种群数量稳定，未面临特定威胁。","distribution":"红领伞鸟分布于南美洲特普伊山脉，包括委内瑞拉东南部（Bolívar州）、巴西北部（Roraima山和Uei-tepui）和圭亚那西部。在委内瑞拉的Canaíma国家公园内也有记录。","other":"红领伞鸟是特有种，仅限于特普伊山脉的生态环境，是当地特有的物种。"},{"name":"黑脸伞鸟","english_name":"Black-faced Cotinga","scientific_name":"Conioptilon mcilhennyi","overview":"黑脸伞鸟（英文名：Black-faced Cotinga，学名：Conioptilon mcilhennyi），是雀形目伞鸟科黑脸伞鸟属的鸟类。分布于南美洲亚马逊盆地的东部秘鲁，以及巴西西部和玻利维亚西北部邻近区域。其自然栖息地为热带湿润低地森林。","appearance":"体长约23厘米，体重介于81至91克之间。喙基部宽大，尖端略呈钩状，具有发达的鼻须，部分羽毛尖端硬化发亮。全身覆盖白色粉末状绒毛，头部除外。头和喉部黑色，由耳羽后方的白色新月形边界环绕；上体深灰色，翅膀和尾巴颜色更深；下体灰色，渐变为腹部下方和尾下覆羽的白色；虹膜深红棕色；喙暗灰棕色；腿脚深橄榄灰色。性别相似，雌鸟平均体型较小，腹面可能稍淡。幼鸟描述未详。","call":"鸣唱为上扬的‘briiing’声；另一种用于配对间频繁对话的叫声为柔和、向下弯曲的‘peuw’声。","habits":"栖息于潮湿森林，偏好湖泊和河流边缘的沼泽或季节性泛滥森林；在巴西，也记录于远离泛洪平原的坚固森林。偏好烧毁的森林。活动高度可达300米，偶尔达到450米。以果实为主食，飞行中摘取；亦食昆虫，记录有翅蚂蚁；偶尔取食花部。常与其他食果鸟种在果实丰富的树上聚集，尤其是大型无花果树。","identification":"独特的羽色和叫声使其易于识别。黑色面部，周围环绕白色新月形边界，以及上体的深灰色和下体的灰色是其显著特征。","protection":"IUCN：LC（无危）；该物种生活在人类干扰较少的环境中，出现在秘鲁的马努国家公园和生物圈保护区。","distribution":"分布于秘鲁东南部低地，巴西西部（阿克雷州的上尤鲁阿河），以及玻利维亚（潘多省）。在南美亚马孙雨林的西南部有记录。"},{"name":"灰尾伞鸟","english_name":"Grey-tailed Piha","scientific_name":"Snowornis subalaris","overview":"灰尾伞鸟（英文名：Grey-tailed Piha，学名：Snowornis subalaris），是雀形目伞鸟科异皮哈伞鸟属的鸟类。体型类似鸫鸟的伞鸟科物种，主要分布在南美洲安第斯山脉东坡的哥伦比亚南部、厄瓜多尔和秘鲁，偏好湿润和多苔藓的森林环境。其显著特征为橄榄色外表、斑驳的白色眼环以及灰色腹部和尾巴。","appearance":"灰尾伞鸟拥有约23厘米的身长，头部呈暗灰色，眼周有一圈淡黄色的裸露皮肤环。上体为橄榄绿色，臀部及尾羽呈灰色调。下体颜色较浅，带有淡绿色条纹，腹部呈现灰色，翼下覆羽为柠檬黄色。雌雄差异在于雌鸟的冠羽可能更小或不存在，胸羽的黄色部分也较小。幼鸟特征尚未详细描述。","call":"偶尔发出响亮、清脆的‘suWEE’声，有助于定位这种隐蔽的鸟类。","habits":"灰尾伞鸟栖息于海拔600至1400米的亚热带或热带湿润山地森林中，通常独居或偶尔加入混种觅食群。它主要以昆虫为食，也会吃水果，飞行特征为从静止的栖木突然飞出捕食空中昆虫或悬停取食树叶上的昆虫。","breeding":"关于灰尾伞鸟的繁殖信息目前知之甚少，自然史的许多方面尚待研究。","identification":"与近缘种橄榄绿伞鸟相比，灰尾伞鸟的腹部更黄，尾部为橄榄色而非灰色，两者在安第斯山脉东坡的分布区有重叠，但主要在海拔高度上有差异。","protection":"IUCN：LC（无危），种群数量将下降25-30%。","distribution":"南美洲：从哥伦比亚南部向南延伸到秘鲁，主要分布于安第斯山脉东侧。","other":"灰尾伞鸟和橄榄绿伞鸟曾被归入Lathria属，后确定属于Lipaugus属组，但最近的研究表明它们属于独立的Snowornis属。"},{"name":"橄榄绿伞鸟","english_name":"Olivaceous Piha","scientific_name":"Snowornis cryptolophus","overview":"橄榄绿伞鸟（英文名：Olivaceous Piha，学名：Snowornis cryptolophus），是雀形目伞鸟科异皮哈伞鸟属的鸟类。相较于其近亲灰尾伞鸟，橄榄绿伞鸟分布更为广泛，通常在安第斯山脉云雾森林的较高海拔处取代灰尾伞鸟。","appearance":"橄榄绿伞鸟是一种体型较大的绿色鸟类，长尾，外观略似鸫鸟，但拥有整体绿色的羽毛、较长的尾巴、较短的跗跖和宽大的喙。头部为橄榄色，耳羽更亮一些，顶冠中央有半隐秘的黑色条纹，上体橄榄绿色，臀部最亮。翅膀棕色，边缘橄榄色，尾羽比背部和臀部更棕或灰色，边缘橄榄色。下体一般为橄榄色，喉部、胸部和腹部有浅色的羽毛轴纹，部分覆羽呈柠檬黄色。雌鸟与雄鸟相似，但顶冠显著减少或缺失，且颜色更偏褐色。","call":"不同于其他伞鸟，橄榄绿伞鸟通常保持沉默，很少鸣叫。","habits":"橄榄绿伞鸟主要栖息于安第斯山脉的云雾森林中层，偶尔会加入混合物种群。它们的生态习性仍有许多未知，尤其是声音，这使得观察它们变得相当困难。","breeding":"最近的研究基于厄瓜多尔西北部的观察，揭示了橄榄绿伞鸟的繁殖生物学。它们会建造开放式的杯状巢，通常产一枚蛋。","identification":"橄榄绿伞鸟与灰尾伞鸟容易混淆，两者地理分布重叠，但在不同海拔处。橄榄绿伞鸟全身橄榄绿色，腹面黄绿色，尾羽橄榄色；而灰尾伞鸟的腹面和尾羽为灰色。","protection":"IUCN：LC（无危）","distribution":"南美洲：从哥伦比亚至秘鲁，主要分布在安第斯山脉的云雾森林。","other":"虽然橄榄绿伞鸟与灰尾伞鸟在地理上大致共存，但两者很少在同一地点出现，橄榄绿伞鸟通常在较高海拔处取代灰尾伞鸟。"},{"name":"紫喉伞鸟","english_name":"Purple-throated Cotinga","scientific_name":"Porphyrolaema porphyrolaema","overview":"紫喉伞鸟（英文名：Purple-throated Cotinga，学名：Porphyrolaema porphyrolaema），是雀形目伞鸟科紫喉伞鸟属的鸟类。分布于南美洲亚马逊雨林西部和中南部，拥有独特的美丽外表。雄鸟上身黑色，翼白边，深紫色喉部，腹部白色；雌鸟则为淡黄色带黑斑，喉部红棕色。此鸟种生活在成熟雨林的树冠层，偏好水边环境。","appearance":"紫喉伞鸟长约18-18.5厘米，平均体重约60克。雄鸟上半身为黑色，翅膀和尾巴亦然，背部至尾羽覆羽有白色边缘，翼上有明显白色条纹，深紫色喉部，腹部白色，侧腹有黑色条纹。雌鸟上半身暗棕色，下半身淡黄色带黑斑，喉部红棕色，体羽质地较松散，尾羽较长且尖。幼鸟似雌鸟，但颜色更淡。","call":"紫喉伞鸟的鸣声为高音、哀怨的‘preeeeeer’，持续1-2秒，常从树顶重复发出。","habits":"紫喉伞鸟栖息于成熟的亚马逊雨林树冠，偏好靠近水源的地带。它们主要以森林树木果实为食，偶尔也会捕食小型昆虫。此鸟种不迁徙，常见于湿润森林的树冠层，海拔高度从低地到900米，但主要分布在400米以下。","breeding":"紫喉伞鸟的繁殖行为知之甚少，但据推测可能全年都有繁殖活动。已知的巢穴位于树冠下方约20米处，由雌鸟负责孵卵，雄鸟则在附近警戒。","identification":"紫喉伞鸟雄鸟的深紫色喉部和雌鸟的红棕色喉部是其显著特征，与其它伞鸟科物种的辨识点在于体型、色彩及生活习性的差异。","protection":"IUCN：LC（无危）","distribution":"紫喉伞鸟分布于南美洲西部亚马逊雨林，具体包括哥伦比亚南部、厄瓜多尔东部、秘鲁东部至马德雷德迪奥斯地区，以及巴西西部亚马逊地区和玻利维亚北部（拉巴斯）。"},{"name":"白翅紫伞鸟","english_name":"Pompadour Cotinga","scientific_name":"Xipholena punicea","overview":"白翅紫伞鸟（英文名：Pompadour Cotinga，学名：Xipholena punicea），是雀形目伞鸟科白翅伞鸟属的鸟类。生活在南美洲亚马逊雨林中。雄鸟以其醒目的纯白色翅膀和酒红色头部与身体而闻名，雌鸟则呈灰暗色调。该物种分布于亚马逊盆地，覆盖巴西、秘鲁、哥伦比亚、委内瑞拉和圭亚那等地。","appearance":"雄性白翅紫伞鸟拥有黄色的眼睛，明亮的白色主翼覆羽与黑色翼尖，以及光泽十足的酒红色头部和身体。雌鸟则呈现淡灰色，喉咙和腹部尤为浅淡，翅膀和尾巴较黑，二级飞羽和大覆羽边缘显著白色。幼鸟类似雌鸟，但眼睛颜色较深。成年雄鸟的鲜艳羽毛由大量类胡萝卜素色素沉积和羽毛结构修饰共同形成。","call":"雄性白翅紫伞鸟发出响亮的、似蛙鸣的嘎嘎声，较为罕见；展示飞行时会发出沙沙的机械翼音。两性都能发出响亮的“purp”声。","habits":"白翅紫伞鸟主要栖息于亚马逊雨林的树冠层，偏好沙质地森林，以水果为主食，偶尔捕食昆虫，如飞行蚂蚁和白蚁。它们通常在无叶树枝上高处栖息或在树冠上方飞行，有时加入混合物种觅食群。","breeding":"繁殖季节不确定，雄鸟会在树梢表演短暂的展示飞行。已知的巢穴为小型但深邃的开放型杯状巢，由几根木质藤蔓构成，位于竹子枝丫间，高度约18米。巢中通常仅有一枚蛋。雌鸟独自抚育幼鸟。","identification":"雄性白翅紫伞鸟的独特外观使其易于识别，而雌鸟则通过其矮胖体型和整体灰暗色系区分。雄鸟与雌鸟的明显差异在于色彩和形态。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊雨林区域，包括哥伦比亚东部至瓦乌佩斯河北部，委内瑞拉南部和东部，圭亚那群岛，巴西亚马逊地区的北部和中部，秘鲁东北部（洛雷托），以及玻利维亚东北部的Serranía de Huanchaca。有零星记录显示出现在厄瓜多尔东南部和哥伦比亚东北部（阿劳卡）。","other":"白翅紫伞鸟的复杂羽毛色素是由八种不同的类胡萝卜素组成，其中六种为该物种特有。"},{"name":"白尾伞鸟","english_name":"White-tailed Cotinga","scientific_name":"Xipholena lamellipennis","overview":"白尾伞鸟（英文名：White-tailed Cotinga，学名：Xipholena lamellipennis），是雀形目伞鸟科白翅伞鸟属的鸟类。令人惊叹的美丽鸟类，雄鸟拥有光泽黑羽，配以白色翅膀和尾巴，雌鸟则为灰色，胸斑点状，翼羽边缘泛白。广泛分布在巴西亚马逊雨林的东南部，特别是在低地湿润森林中。","appearance":"雄性白尾伞鸟长约19至20厘米，全身覆盖着带有强烈胡萝卜素沉积的硬质光泽羽毛，头部和身体呈紫黑色，尾部和大部分翅膀为白色。二级飞羽的覆羽长而僵硬，尖端白色，虹膜淡黄色，喙暗褐色，腿为棕黑色，足底呈肉色。雌鸟上身灰暗，翅膀和尾巴较黑，次级飞羽和二级覆羽的外缘明显白色，中覆羽灰白，下体浅灰，胸部略带斑点，眼圈窄白。幼鸟外观似雌鸟，需经历两到三次翼羽更换才能达到成年雄鸟的羽毛状态。","call":"两性都会发出响亮的‘purp’声。","habits":"白尾伞鸟栖息在湿润森林的树冠层，海拔可达400米。其饮食习惯几乎未知，有记录显示可能以果实为主，曾观察到食用Phytolacca果实。白尾伞鸟的叫声为响亮的‘purp’。","breeding":"相关信息尚未记录。","identification":"雌性白尾伞鸟很难与白翅紫伞鸟雌鸟区分开，但它们的分布范围并不重叠。","protection":"IUCN：NT（近危）","distribution":"白尾伞鸟的分布限于亚马逊盆地东南部，具体为巴西境内亚马逊河以南的低地，从帕拉州西部至马拉尼昂州东部，涵盖托坎廷斯-阿拉瓜亚河系统的下游三分之一流域，最东端至大西洋。"},{"name":"白翅伞鸟","english_name":"White-winged Cotinga","scientific_name":"Xipholena atropurpurea","overview":"白翅伞鸟（英文名：White-winged Cotinga，学名：Xipholena atropurpurea），是雀形目伞鸟科白翅伞鸟属的鸟类。特有于巴西东部。雄鸟拥有深紫黑色的羽毛，翼展白色醒目；雌鸟呈灰调，翼羽边缘泛白。栖息于湿润森林及偶尔的林缘地带。","appearance":"雄鸟身长19厘米，体重约58至65克，雌鸟略小，体重56至67克。雄鸟的羽毛闪耀着黑紫色光泽，翼部白色明显；雌鸟灰褐色，翼羽边缘白色突出。喙宽而稍扁，尖端微钩，无须状羽。雄鸟全成长成需经四到五次换羽。","call":"雄鸟发出类似‘chíu’的高音鸣叫，也有嘶哑的叫声，雌雄皆能发出响亮的‘purp’声。飞行中可听到翼鸣。","habits":"栖息于密林，偏好湿润环境，有时出现在较开阔的森林边缘，海拔从海平面至900米。以水果为主食，辅以昆虫，偏好直径4至12毫米的果实。活动范围受限，无迁徙记录。","breeding":"繁殖季节记录于10月至次年2月。雄鸟在树顶展示飞行，伴随响亮翼鸣。巢为小型杯状，由根须构建，高悬于树叉间，已知巢位高度15至20米。每窝仅产一卵，孵化和育雏周期未知。","identification":"雄鸟的紫黑色羽毛和白色翅膀极为独特，雌鸟灰调带白边翼羽。与近似种区别在于体型、色彩和翼鸣。","protection":"IUCN：VU（易危）；CITES附录I。主要分布于13个保护区，总面积约992平方公里。因低地森林破坏，数量显著减少。全球成熟个体估计3400至13000只。","distribution":"沿海岸线分布于巴西东部，从Paraíba至Rio de Janeiro北部。","other":"曾被评估为极危，后下调至易危。关键保护区包括Pedra Talhada、Una和Sooretama生物保护区，Desengano州立公园及Monte Pascoal国家公园。"},{"name":"南美白伞鸟","english_name":"Black-tipped Cotinga","scientific_name":"Carpodectes hopkei","overview":"南美白伞鸟（英文名：Black-tipped Cotinga，学名：Carpodectes hopkei），是雀形目伞鸟科白伞鸟属的鸟类。又称白色伞鸟，雄鸟个体通体雪白，翼尖和尾羽中央具小黑点，眼色红艳，翼宽而圆，尾短方。雌鸟则呈灰暗色调，翼羽边缘泛白。分布于巴拿马东南至厄瓜多尔西北的低地和山麓森林。","appearance":"雄性南美白伞鸟体型约23.5至25厘米，全身洁白，仅翼端和尾羽中央有微小黑斑。雌鸟体长约22至23.5厘米，上半身灰暗，翅膀和尾巴黑色，翼羽和内部飞羽边缘白色，腹部逐渐变为白色。雄鸟拥有橙色到深红色的眼睛，喙及腿均为黑色。","habits":"南美白伞鸟栖息于潮湿森林，包括红树林，偶尔出现在次生林地旁，海拔高度可达900米。以果实为主要食物，常在Cecropia树附近被观察到，有时会组成5-6只的小群体。","breeding":"关于其繁殖习性的详细信息目前尚不清楚。","identification":"雄性南美白伞鸟在外观上极易识别，其纯白的羽毛与翼尖、尾羽的黑斑形成鲜明对比。雌鸟与同属其他物种的区别在于上半身更暗，翼羽边缘的白色较少。","protection":"IUCN：LC（无危）。虽然全球数量可能因低地森林破坏而减少，尤其是厄瓜多尔西北部，但目前尚未达到易危标准。","distribution":"分布于巴拿马东南部（达连省）、哥伦比亚西部沿海低地及厄瓜多尔西北部（最南至皮钦查省南部）。","other":"南美白伞鸟曾在1450米的高度被记录，但通常活跃于低地和山麓森林。"},{"name":"中美白伞鸟","english_name":"Snowy Cotinga","scientific_name":"Carpodectes nitidus","overview":"中美白伞鸟（英文名：Snowy Cotinga，学名：Carpodectes nitidus），是雀形目伞鸟科白伞鸟属的中等体型鸟类。雄鸟通体雪白，雌鸟呈淡灰色，两性均容易识别。","appearance":"雄鸟长约20厘米，全身雪白，头部和背部带有轻微的蓝灰色调。雌鸟上体淡棕灰，翅膀较暗，边缘泛白，眼周有一圈白色，下体灰白。两性的喙均为蓝灰色，与黄色喙的黄嘴白伞鸟相区别。","call":"文献未提供详细鸣叫特征。","habits":"栖息于低海拔湿润森林的树冠层，常见于森林边缘及附近的大树旁，高度可达约450米。以果实为主食，常在果树林中活动。","breeding":"繁殖资料仅来自哥斯达黎加，筑巢于树冠层，巢由小干枝和木质藤蔓构成，高7.5至12米，一窝产一枚卵，孵化期至少27天。","identification":"雄鸟与黄嘴白伞鸟区别在于喙色；雌鸟需与黑顶蒂泰霸鹟和花脸蒂泰霸鹟区分开，后两者头部色彩更为丰富。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，自洪都拉斯西南部至巴拿马西部，主要栖息于低地湿润森林。","other":"无"},{"name":"黄嘴白伞鸟","english_name":"Yellow-billed Cotinga","scientific_name":"Carpodectes antoniae","overview":"黄嘴白伞鸟（英文名：Yellow-billed Cotinga，学名：Carpodectes antoniae），是雀形目伞鸟科白伞鸟属的中型鸟类，仅分布于哥斯达黎加西南部和巴拿马西部相邻地区。雄鸟全身雪白，喙呈黄色；雌鸟上体灰白，下体较淡，翼羽边缘显白色，喙基黄色。栖息于森林树冠和红树林。","appearance":"雄性黄嘴白伞鸟通体雪白，头部顶部略带珍珠灰色，背部和臀部有淡灰色斑点。翅膀覆羽、飞羽、尾羽和其余羽毛皆为白色。喙明亮黄色，带有黑色条纹。雌鸟前额和头顶灰白，上体浅灰，下体淡灰白至白色，翼和尾黑褐色，翼羽边缘宽白，次级飞羽不如雄鸟宽。喙基黄色，可能渐变至黑色。幼鸟外观类似雌鸟，但体型较小，喙全暗色。","call":"关于黄嘴白伞鸟的鸣叫特征，现有资料较为有限。","habits":"黄嘴白伞鸟栖息于低地森林和红树林，常出现在结果实的树木周围，有时在开阔乡村的孤立树木上被发现。飞行时翼拍深而缓慢，具有独特性。行为习性研究较少。","breeding":"黄嘴白伞鸟的繁殖生态信息尚不充分，已知在红树林中筑巢，具体繁殖细节待进一步研究。","identification":"雄性黄嘴白伞鸟与中美白伞鸟相似，但后者喙全暗色。雌鸟与中美白伞鸟雌鸟相似，但具黄色喙基，以及更淡的下体颜色。与同域的绿伞鸟雌鸟可通过鳞状羽毛和棕色调区分。","protection":"IUCN：NT（近危）。黄嘴白伞鸟面临栖息地破坏的威胁，尤其是在红树林转化为虾塘、牧场和稻田的过程中。","distribution":"分布于中美洲，主要集中在哥斯达黎加西南部和巴拿马西部。在哥斯达黎加的塔尔科尔斯河口、卡拉拉国家公园、戈尔福杜尔塞和奥斯半岛附近有较大种群。巴拿马也有零星记录。","other":"黄嘴白伞鸟数量估计在150至700只成熟个体之间，且数量正在下降。"},{"name":"裸颈果伞鸟","english_name":"Bare-necked Fruitcrow","scientific_name":"Gymnoderus foetidus","overview":"裸颈果伞鸟（英文名：Bare-necked Fruitcrow，学名：Gymnoderus foetidus），是雀形目伞鸟科裸颈果伞鸟属的唯一物种，主要分布在南美的亚马逊雨林，尤其常见于河流附近。其特征明显，全身主要呈黑色，雄鸟具有独特的灰蓝色彩色颈部褶皱和闪亮的灰白色翅膀，飞行时尤为显眼。","appearance":"雄性裸颈果伞鸟体型中等，长度约34至38厘米，体重331至359克；雌鸟略小，长度约30至34厘米，已知一例体重220克。头部羽毛密集、短而绒软，两翼银灰色，颈部大部分无羽，皮肤蓝色或蓝白色，形成复杂的褶皱。雄鸟拥有灰白至暗红变化的虹膜，喙灰黑，腿铅灰色。雌鸟几乎全灰，颈部褶皱发育不如雄鸟明显。幼鸟主要为白色，随成长经历多个阶段，最终在第三次翼羽更换后获得成年羽毛。","call":"发出深沉的号角般‘oooooooo’的叫声，类似雾笛声，与亚马逊伞鸟的叫声相似。","habits":"栖息于亚马逊地区的河流和湖泊岸畔的森林以及季节性泛滥的森林，海拔可达500米。主要以果实为食，包括Oenocarpus、Cecropia和Euterpe等，偶尔也捕食大型昆虫，如螳螂和蝗虫，以及飞蚁或白蚁。与其它伞鸟不同，它会在树干上活跃奔跑觅食。","breeding":"繁殖期可能在南部地区为9月至次年2月，基于换羽记录推测。在哥伦比亚、巴西和玻利维亚分别有记录到孵化中的雌鸟。巢为小型浅杯状，由苔藓和细藤构成，放置于离地面6至10米的粗壮横枝上。已知一次观察到的巢穴位于一棵Ceiba树的薄冠层枝条上，高达40米，内有一只雏鸟。每次产卵数量几乎确定为一枚。","identification":"与其它伞鸟相比，裸颈果伞鸟的喙更小、扁平，腿部和脚部强壮，头部羽毛质地特殊。雄鸟的独特颈部皮肤颜色和褶皱有助于辨识。","protection":"IUCN：LC（无危）。沿亚马逊主要河流分布较为普遍，形成20只以上的群体，但在圭亚那地区数量较少。在多个保护区中存在，如巴西的Anavilhanas生态站和Rio Cristalino森林保护区，以及秘鲁的Tambopata-Candamo保留区和Manu国家公园及生物圈保护区。","distribution":"主要分布在亚马逊流域的低地森林，范围涵盖从哥伦比亚东南部、委内瑞拉南部、圭亚那、厄瓜多尔东部、秘鲁东部、巴西至马托格罗索州南部，包括巴拉圭河上游流域，以及玻利维亚中部。北部地区相对稀少，特别是在亚马逊河北部。","other":"虽然种群数量似乎正在下降，但由于下降幅度不足30%，故未被列入易危名单。"},{"name":"紫喉果伞鸟","english_name":"Purple-throated Fruitcrow","scientific_name":"Querula purpurata","overview":"紫喉果伞鸟（英文名：Purple-throated Fruitcrow，学名：Querula purpurata），是雀形目伞鸟科紫喉果伞鸟属的鸟类。其体型较大，全身羽毛呈深黑色，雄鸟具有醒目的紫色喉咙。分布于中美洲南部至南美洲亚马逊雨林地区，以昆虫和果实为主要食物来源。","appearance":"紫喉果伞鸟体长约28厘米，羽毛光泽黑亮。雄鸟的喉咙部分有一块显眼的深紫色或红紫色斑块，羽毛形状独特，略窄且硬挺，扩展如盾牌状。雌鸟整体颜色较暗，通常缺乏雄鸟的紫色喉咙。幼鸟羽毛呈哑光黑色，翼覆羽带褐色。喙部呈灰白色，虹膜和跗跖为深色。","call":"紫喉果伞鸟发出独特的呼噜声鸣叫，如“prr-woop, prr-woop”。叫声响亮且多变。","habits":"栖息于低地湿润森林，活动于树冠层，常以3-8只的小群体出现，跟随混合物种群。它们的社会性较强，会集体巡逻树冠，迁徙模式不详，但活动范围广泛。","breeding":"紫喉果伞鸟是合作繁殖的鸟类，巢穴明显且由社群持续看守。繁殖季节不明确，但在尼加拉瓜南部至亚马逊雨林的分布区内进行。","identification":"与伞鸟相比，紫喉果伞鸟体型较小，无蓬松的冠羽，叫声更为频繁。与Caciques的区别在于身形更圆润，腿较短，叫声不同。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲南部，从尼加拉瓜至南美洲亚马逊雨林地区，包括巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。","other":"紫喉果伞鸟是唯一一种社会性的伞鸟科鸟类，也是唯一一种进行合作繁殖的伞鸟科成员。"},{"name":"绯红果伞鸟","english_name":"Crimson Fruitcrow","scientific_name":"Haematoderus militaris","overview":"绯红果伞鸟（英文名：Crimson Fruitcrow，学名：Haematoderus militaris），是雀形目伞鸟科绯红果伞鸟属的大型鸟类。雄鸟全身闪耀着鲜艳的红色，雌鸟头部和下体为较淡的绯红色，上体为暗褐色。分布于南美洲亚马孙雨林东北部，包括巴西、法属圭亚那、圭亚那、苏里南和委内瑞拉的部分地区。由于其广泛的分布和相对较高的种群密度，目前并未被列为易危物种。","appearance":"雄鸟长约34厘米，拥有光泽鲜亮的红色羽毛覆盖头部、背部和胸部，羽毛长而硬，形成独特的蓬松红色冠羽。翅膀和尾巴呈深棕色至黑色，尾部部分被长尾覆羽遮掩。雌鸟和未成年雄鸟头部、喉咙及下体为较浅的绯红色，背部、翅膀和尾巴为深褐色，羽毛质地更为柔软。两性均具有厚实的暗红色喙。","call":"通常较为沉默，但能发出类似猫头鹰的低沉呼噜声，以及尖锐的“bok”叫声。","habits":"栖息于热带低地雨林的树冠层，偏好在森林边缘活动。飞行姿态悠闲且呈波浪状，已知有螺旋上升后长滑翔的展示飞行。以大型昆虫为主食，如蝉、甲虫和蚱蜢，辅以果实。","identification":"与同科其他种类相比，绯红果伞鸟的体型较大，雄鸟全身红色鲜明，雌鸟及幼鸟具独特色彩组合。鸣叫声也是识别的重要特征。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲东北部亚马孙雨林地区，包括巴西东北部、法属圭亚那、圭亚那、苏里南和委内瑞拉南部，偶尔在巴西西部和委内瑞拉东部有记录。","other":"尽管分布广泛，但其种群数量可能正在缓慢下降。"},{"name":"红领果伞鸟","english_name":"Red-ruffed Fruitcrow","scientific_name":"Pyroderus scutatus","overview":"红领果伞鸟（英文名：Red-ruffed Fruitcrow，学名：Pyroderus scutatus），是雀形目伞鸟科红领果伞鸟属的鸟类。南美洲最大的鸣禽之一。1792年首次被Shaw命名为Coracias scutata，后改为现名。此物种有五种亚种。","appearance":"雄鸟体长43-46厘米，体重413-419克；雌鸟体长36-39厘米，体重300-390克。头部有强健的喙，类似乌鸦，有弯曲的须状羽。雄鸟体羽黑亮，喉至胸部橙红色，带红色羽尖；雌鸟较小，眼色较暗，喙色深灰至黑色。幼鸟与成鸟相似，但红色羽毛光泽较弱。不同亚种在羽毛颜色上有所差异。","call":"雄鸟求偶时发出两声短暂而强烈的空洞脉冲声。","habits":"栖息于森林和森林边缘地带，偏好湿润和山地森林，偶尔出现在低地和干燥森林，如委内瑞拉和圭亚那的低地，哥伦比亚的引进白蜡木林。以果实为主食，也会捕食大型昆虫。飞行时会短距离掠食或停歇捕食。曾观察到捕食青蛙。","breeding":"繁殖期为3月至7月，高峰期在4月至5月。雄鸟会在离地面约6米高的树枝上聚集，通过鸣叫吸引雌鸟。巢呈浅杯状，由树枝和蕨类植物叶片构成，位于树梢。每窝产一卵，孵化期未知；雏鸟起初主要喂食昆虫，10天后逐渐增加水果比例，离巢期为30-35天。","identification":"雄鸟与雌鸟体型和颜色有明显区别，与紫喉果伞鸟外观相似但体型较大。亚种间在羽毛色彩上有细微差别。","protection":"IUCN：LC(无危)。在巴西里奥格兰德苏尔州、圣保罗州、米纳斯吉拉斯州和里约热内卢州列为濒危物种。","distribution":"分布于南美洲北部、西北部、东部和东南部，包括委内瑞拉东北部、圭亚那、秘鲁东安第斯山脉、厄瓜多尔西北部、哥伦比亚、委内瑞拉西部、委内瑞拉沿海山脉、巴西东南部大西洋森林、巴拉圭东部、阿根廷东北部。在巴西东南部大西洋森林中数量较多。","other":"在某些地区，因森林砍伐导致种群减少。在多个保护区中出现，如委内瑞拉的Sierra Nevada国家公园、哥伦比亚的Ucumarí区域公园、巴西的Serra da Canastra国家公园、Rio Doce州立公园和Augusto Ruschi生物保护区、巴拉圭的Ybicuí国家公园等。"},{"name":"三色伞鸟","english_name":"Capuchinbird","scientific_name":"Perissocephalus tricolor","overview":"三色伞鸟（英文名：Capuchinbird，学名：Perissocephalus tricolor），是雀形目伞鸟科三色伞鸟属的鸟类。大型、奇特的伞鸟科鸟类，以其独特的外观和奇异的叫声著称。其分布局限于南美洲东北部的热带雨林，尤其在圭亚那高地一带。成鸟拥有裸露的蓝灰色头部和厚重的喙，全身大部分呈橙褐色，腹部和尾下覆羽呈红栗色，翅膀和尾巴则为黑色，下翼覆羽为奶油白色。","appearance":"三色伞鸟体型庞大，约40厘米长，体重介于340至420克之间，雌雄羽色相似，但雄鸟体型更大，尾下覆羽更长且呈橙红色，能像球状橙色‘尾灯’一样竖起，雌鸟尾下覆羽则较短。幼鸟头部长有稀疏绒毛，成鸟则头部裸露。喙部上颌为黑色，下颌为灰色，虹膜深棕色，脚趾和跗跖为暗蓝灰色。","call":"三色伞鸟的叫声独特，被形容为类似远处电锯声或小牛哞叫，是鸟类世界中最不可思议的声音之一。","habits":"它们主要栖息在高达1400米的湿润森林中，以果实为主食，也会捕食昆虫。三色伞鸟聚集在求偶场（lek）进行求偶鸣唱。","breeding":"繁殖季节，雄鸟会在求偶场上展示其独特的叫声吸引雌鸟，巢穴通常建在靠近求偶场的位置。","identification":"三色伞鸟的特征在于其裸露的、小而蓝灰色的头部，以及橙褐色的身体，与其他伞鸟科鸟类明显不同。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲东北部，主要位于亚马逊河以北，包括哥伦比亚、委内瑞拉、巴西和圭亚那地区。","other":"尽管三色伞鸟数量不多，但由于其广泛分布列为‘无危’。"},{"name":"裸颈伞鸟","english_name":"Bare-necked Umbrellabird","scientific_name":"Cephalopterus glabricollis","overview":"裸颈伞鸟（英文名：Bare-necked Umbrellabird，学名：Cephalopterus glabricollis），是雀形目伞鸟科耳垂伞鸟属的易危鸟类。分布于中美洲的哥斯达黎加和巴拿马的森林中，以水果为主食。雄鸟具有独特的‘Mohican’式冠羽覆盖头部和喙，喉部和颈部裸露呈红色，雌鸟体型较小，缺乏红色裸露皮肤和蓬松的冠羽。","appearance":"裸颈伞鸟是一种大型黑色鸟类，雄鸟平均长度41厘米，体重450克；雌鸟稍小，平均36厘米，重320克。头部大，带有紧密的窄而蓬松的冠羽，翅膀宽长，尾巴较短。雄鸟的下巴下方羽毛为黑色，拥有独特的红喉囊，当膨胀时可见到悬挂的黑尖羽毛。雌鸟全身呈深棕色至黑色，腹部更偏褐色，喉部没有红色裸露皮肤，冠羽较小。","habits":"裸颈伞鸟栖息于热带湿润低地和山地森林，主要生活在森林的次生林和密集的灌木层，接近果实丰富的树木。其饮食以水果为主，包括Marcgraviaceae、Urticaceae、Arecaceae、Lauraceae和Annonaceae等科的浆果，偶尔也吃小型脊椎动物和昆虫。它会根据果实的可获得性进行年度海拔迁移。","breeding":"繁殖季节通常在3月至6月间，此时伞鸟会迁移到海拔较高的地区（1000-1500米），与高果量区域相吻合。雄鸟通过展示和鸣叫吸引雌鸟，进行繁殖行为。然而，关于其繁殖细节的资料极为有限。","identification":"雄性裸颈伞鸟的独特红喉囊和‘Mohican’式的冠羽使其易于识别。雌鸟与紫喉果伞鸟的雌鸟相似，但后者体型更小，雄鸟有紫色喉部羽毛而非红色裸露皮肤。","protection":"IUCN：EN（濒危）","distribution":"分布于中美洲的哥斯达黎加和巴拿马的森林中，近期也有在尼加拉瓜南部的记录。"},{"name":"亚马孙伞鸟","english_name":"Amazonian Umbrellabird","scientific_name":"Cephalopterus ornatus","appearance":"雄鸟体长可达48至51厘米，体重约500克，拥有庞大的羽冠，喙大似鸦，全身黑色带有蓝绿色光泽，腹部颜色较暗淡。头部伞状羽冠向外卷曲，末端有发丝般的羽枝，白色羽轴在羽冠竖起时尤为醒目。雌鸟体型较小，羽冠和喉囊显著缩小，羽轴无白色。幼鸟特征不详。","call":"雄鸟发出深沉悦耳、传播远的鸣声，两性皆能发出各种低沉而不响亮的声音，如喉音或低吼声。雌鸟还会发出连续的双音节叫声，如“goh-ahh, go-uh”，第二音节有时会延长数秒。","habits":"栖息于沿河岸的高大雨林和季节性泛洪森林，海拔多低于300米，但在安第斯山脉脚下的湿润森林则分布在900至1300米之间。主要以果实和大型昆虫为食，偶尔也会捕食蜥蜴。通常在树冠层单独、成对或小群体活动，飞行起伏，类似啄木鸟。","breeding":"繁殖记录在巴西和厄瓜多尔的7月和10月。雄鸟在树上展示，倾斜身体向前，展开羽冠，膨胀喉囊。巢由细枝搭建，结构稀疏，位于小树冠顶，高度8至12米。每次产一枚蛋，颜色为卡其色，带有多色斑点。","identification":"亚马逊伞鸟与同科其他种类的区别在于其巨大的体型、独特的羽冠和喉囊，以及浅色的眼睛。雌雄间主要通过体型大小、羽冠和喉囊的差异进行区分。","protection":"IUCN：LC（无危）。列入CITES III。在部分地区数量稀少或罕见，但由于人类捕猎和栖息地破坏，数量已减少。在多个保护区中得到保护。","distribution":"广泛分布于亚马孙雨林，从哥伦比亚、厄瓜多尔、秘鲁和玻利维亚的安第斯山脉东坡到委内瑞拉南部、圭亚那西南部和巴西的内格罗河与Xingú河流域，南至马托格罗索州南部，接近巴拉圭河源头。"},{"name":"长耳垂伞鸟","english_name":"Long-wattled Umbrellabird","scientific_name":"Cephalopterus penduliger","appearance":"雄性长耳垂伞鸟高40-42厘米，雌鸟略小，高35-37厘米。雄鸟拥有长达35厘米、由短羽毛覆盖的可伸缩肉垂，雌鸟肉垂较小或几乎不存在。雄鸟全身黑色，带有蓝绿色光泽，腹部颜色较暗；雌鸟体型更小，肉垂不发达。幼鸟信息较少，至少存在一个亚成年阶段，直至雄鸟获得完整成年羽毛。","call":"雄鸟发出响亮的‘boooh’声，间隔19至63秒，可传播约400米，还发出低沉的哼鸣声。雌鸟发出‘aaugh’声，可能是在警报时。","habits":"栖息于海拔80至1800米的湿润森林，偶尔出现在次生林和传统农田。主要食用棕榈、肉豆蔻和月桂果实，偶尔捕食昆虫。雄鸟在树上展示，雌鸟单独选择配偶。通常在果实丰富的树木或已知的展示地点聚集。","breeding":"雄鸟在传统的展示场展示，雌鸟独自行筑巢和育雏。巢由干枝构成，内部铺垫细枝、苔藓等，位于树蕨顶端，离地面5米。每窝产一枚蛋，孵化期27至28天，雌鸟独自承担喂养工作，主要喂食小型脊椎动物、大昆虫及可能的果实。","identification":"雄性长耳垂伞鸟的显著特征是其可伸缩的肉垂和大型头冠，雌鸟肉垂小或缺失，体型较小。与同类物种相比，其肉垂的长度和头部羽毛的形状是主要的辨识特征。","protection":"IUCN：VU（易危）。CITES III级。全球估计数量为10,000至20,000只，受栖息地破坏和人类捕猎威胁，分布区日益碎片化。","distribution":"分布于南美洲的哥伦比亚西南部至厄瓜多尔西部，主要栖息在安第斯山脉西侧的热带雨林，海拔1500至1800米。在哥伦比亚，主要集中在考卡河谷和纳里尼奥南部，包括卡利的法拉隆内斯国家公园；在厄瓜多尔，主要分布在埃斯梅拉达斯东部、皮钦查和伊姆巴布拉相邻地区。","other":"长耳垂伞鸟在一些保护区中生存，但其分布范围正逐渐缩小。尽管它似乎能容忍退化的栖息地和人类活动，但在觅食和展示时可能更偏好成熟的森林环境。"},{"name":"侏霸娇鹟","english_name":"Dwarf Tyrant-Manakin","scientific_name":"Tyranneutes stolzmanni","overview":"侏霸娇鹟（英文名：Dwarf Tyrant-Manakin，学名：Tyranneutes stolzmanni），是雀形目娇鹟科小霸娇鹟属的小型鸟类，分布于南美洲亚马逊雨林的西部和南部，偏好成熟雨林的中层环境。","appearance":"该鸟体型微小，全身呈现暗淡的橄榄绿色，腹部转为较浅的黄橄榄色，尾部短小，腿脚呈深灰色。其最显著的外部特征是短尾和中层栖息的习惯。","call":"虽难以直接目击，但其特有的两音节叫声——类似打喷嚏的“cool-whip！”声，易于辨认。","habits":"侏霸娇鹟偏好亚马逊雨林的成熟地带，包括高地和洪水平原，它们在森林中层活动，很少出现在森林边缘，更倾向于在森林深处的中层栖息。","identification":"它比其他同类物种更为小巧，通常在森林中层较高位置觅食，这一特征有助于与其它种类区分。","distribution":"分布范围覆盖委内瑞拉南部、哥伦比亚东部、厄瓜多尔、秘鲁、玻利维亚北部以及巴西西北和东北部，东至白河，南至马托格罗索州南部。"},{"name":"小霸娇鹟","english_name":"Tiny Tyrant-Manakin","scientific_name":"Tyranneutes virescens","overview":"小霸娇鹟（英文名：Tiny Tyrant-Manakin，学名：Tyranneutes virescens），是雀形目娇鹟科小霸娇鹟属的小型热带雨林鸟类。在亚马孙雨林东北部常见，虽体型微小且尾巴短小，但在其生境中却颇为常见，只是听到其声音的机会远多于见到其身影。","appearance":"小霸娇鹟体型极为小巧，尾巴短促。雄鸟的头部有一片鲜黄色的冠羽，但这通常难以从下方观察到。其羽毛色彩并不显眼，缺乏明显的野外辨识特征。","call":"通过追踪雄鸟在树冠下的歌唱位置，可以定位到小霸娇鹟。它们长时间静止不动，反复吟唱其独特的歌曲。","habits":"小霸娇鹟主要栖息于亚马孙热带雨林的低海拔潮湿森林中。它们的活动范围和觅食方式尚待更多研究。","breeding":"关于小霸娇鹟的繁殖生态细节，目前的科学文献中记录有限。","identification":"在野外，小霸娇鹟最显著的辨识特征在于雄鸟的黄色冠羽，但这通常难以观察到。其歌声是定位这一物种的最佳方式。","distribution":"分布于南美洲的东北部亚马逊雨林区域，具体包括委内瑞拉（东北部与东南部的玻利瓦尔州）、圭亚那、法属圭亚那、苏里南以及巴西的东北亚马逊地区（从白河和黑河下游东至阿马帕州）。"},{"name":"黄冠霸娇鹟","english_name":"Saffron-crested Tyrant-Manakin","scientific_name":"Neopelma chrysocephalum","overview":"黄冠霸娇鹟（英文名：Saffron-crested Tyrant-Manakin，学名：Neopelma chrysocephalum），是雀形目娇鹟科霸娇鹟属的独特鸟类。以鲜黄色的冠羽而著称，广泛分布于南美洲的低地热带雨林，主要集中在巴西、秘鲁和玻利维亚等地。","appearance":"黄冠霸娇鹟是一种小型的短尾娇鹟，体长约10至11厘米，胸部呈淡黄色。其最显著的特征是头部的鲜黄色冠羽，与身体的羽毛颜色相呼应。黑色的翅膀和尾巴上带有黄色标记，眼睛深色，喙短而粗壮。","call":"这种鸟的叫声非常鼻音，包含一系列重复的'wraaang'、'skeeehh'和'eerhhh'声音。","habits":"黄冠霸娇鹟栖息于热带森林和灌木地带，常见于南美洲北部，包括圭亚那地区、委内瑞拉南部、亚马逊盆地西北部。它们在热带雨林中觅食，主要以昆虫、小果实和浆果为食，展现快速捕捉昆虫的能力。","identification":"与苍白腹霸娇鹟的区别在于更橙色的眼睛和更黄的腹部。","protection":"IUCN状态未提供。","distribution":"主要分布在南美的亚马逊雨林北部，包括巴西的阿马帕州、亚马逊州和罗赖马州南部，以及秘鲁北部沿河源头地区。"},{"name":"黄腹霸娇鹟","english_name":"Sulphur-bellied Tyrant-Manakin","scientific_name":"Neopelma sulphureiventer","overview":"黄腹霸娇鹟（英文名：Sulphur-bellied Tyrant-Manakin，学名：Neopelma sulphureiventer），是雀形目娇鹟科霸娇鹟属的鸟类。主要分布在南美洲亚马逊盆地的玻利维亚、巴西和秘鲁地区，其自然栖息地为亚热带或热带湿润低地森林。","appearance":"作为一种体型较大的霸娇鹟，它拥有较长的尾巴和更为挺拔的站立姿态，区别于其他较小的同类。其体色以土黄色为主，腹部呈鲜艳的硫磺色，这是其得名的原因之一。雄鸟和雌鸟的具体外观差异尚未详细描述。","call":"其叫声独特，具有鼻音的笑声，是识别该物种的重要特征。","habits":"黄腹霸娇鹟通常单独或成对活动，偏好在密集、藤蔓缠绕的次生森林的低层至中层区域觅食，尤其沿着河流地带。在竹林丰富的区域，它们几乎仅限于竹林斑块中活动。","breeding":"关于其生长繁殖的详细信息暂未提供。","identification":"与其他小型霸娇鹟相比，黄腹霸娇鹟的体型更大，尾巴更长，站立姿势更为挺立，腹部的硫磺色是其显著的辨识特征。","protection":"IUCN状态未提供。","distribution":"主要分布于南美洲的亚马逊盆地，具体包括秘鲁东南部（从洛雷托省西南部至马德雷德迪奥斯省）、玻利维亚北部和中部（南至科恰班巴和圣克鲁斯北部）以及巴西西部相邻地区。"},{"name":"淡腹霸娇鹟","english_name":"Pale-bellied Tyrant-Manakin","scientific_name":"Neopelma pallescens","overview":"淡腹霸娇鹟（英文名：Pale-bellied Tyrant-Manakin，学名：Neopelma pallescens），是雀形目娇鹟科霸娇鹟属的鸟类。外形略似捕蝇鸟，上部橄榄绿，下部灰色，胸部有微弱的条纹。头部具有显著的黄色冠羽，腹部呈奶油白色，喉部微白带灰。分布于南美洲巴西东部、中部及玻利维亚东北部。","appearance":"体长约14厘米，体重16至20.5克。外表不显眼，类似捕蝇鸟，喙和尾相对较长。头部中央有大块亮黄色的冠羽，边缘暗色突出，其余部分上部橄榄绿色，喉部微白带灰条纹，胸部浅橄榄灰色，腹部淡奶油白色。虹膜淡灰紫色，喙和腿棕色至灰褐色。雄雌相似，幼鸟特征未详述。","call":"雄鸟的广告叫声柔和低沉，鼻音明显，发出‘wraah, wra-wra’的声音。","habits":"栖息于落叶林和画廊林，常在藤蔓密集的区域。活动范围可达700米高度。食物以昆虫为主，四份胃内容分析显示全部为昆虫残骸，也会食用梅拉斯特木属（Miconia）的果实。","breeding":"在巴西东部观察到11月初收集筑巢材料的行为。雄鸟独自在低枝上展示，偶尔向上跳跃，有时会反向着陆。关于繁殖的其他信息缺失。","identification":"与同类物种的区别在于体型较大，腹部更白。","protection":"IUCN：LC（无危）。虽不普遍，但因低调而易被忽视，真实分布范围可能未完全了解。在巴西的Chapada Diamantina国家公园和玻利维亚的Noel Kempff Mercado国家公园有其分布。","distribution":"主要分布在南美洲巴西东部、中部以及玻利维亚东北部的Serranía de Huanchaca（圣克鲁斯东北部）。"},{"name":"巴西霸娇鹟","english_name":"Wied's Tyrant-Manakin","scientific_name":"Neopelma aurifrons","overview":"巴西霸娇鹟（英文名：Wied's Tyrant-Manakin，学名：Neopelma aurifrons），是雀形目娇鹟科霸娇鹟属的鸟类。特征包括橄榄绿色背部，灰色喉咙，黄色腹部，黄冠斑通常被遮掩。分布于巴西东南部的潮湿森林内部。","appearance":"全长约13厘米，外观较为暗淡，似霸鹟，具有相对较长的喙和尾巴。头部和整个上体呈橄榄绿色，喉部灰白，上胸橄榄灰色，下胸至腹部为浅硫磺黄色。虹膜淡灰紫色，喙和腿灰色。雌雄相似，幼鸟特征未详述。","call":"雄鸟广告叫声为简单的四音符短语，间隔规律重复，比的叫声更短更简单。","habits":"栖息于未受干扰或轻微干扰的森林，通常在森林内部，但有时也会在边缘觅食。海拔从海平面到约1000米。以小型果实和昆虫为主食，偶尔观察到捕捉竹节虫。在离地面约7米内的树叶中抓取或捕获食物。","breeding":"雄鸟在遮阴的下层林中平直的细枝上唱歌，高度一般在3.5至7米。巢址可能位于河岸下方或悬垂根部之下。关于繁殖的其他信息未知。","identification":"与巴西黄冠霸娇鹟相比，尾较短，翼和喙较长，冠纹不明显。与淡腹霸娇鹟相比，体型较小，腹部颜色更深，黄色较少。通过鸣声可有效区分。","protection":"IUCN：NT（近危）。自1990年后记录稀少，历史上的分布点现在许多已无记录。由于低地大西洋森林的大规模破坏，种群数量大幅减少。预计气候变化将导致其分布区丧失70%以上。","distribution":"分布于巴西东南部，从巴伊亚南部至米纳斯吉拉斯东部，埃斯皮里图桑托和里约热内卢（至少以前存在）。","other":"曾被认为与同种，现已分离为独立物种。"},{"name":"巴西黄冠霸娇鹟","english_name":"Serra do Mar Tyrant-Manakin","scientific_name":"Neopelma chrysolophum","overview":"巴西黄冠霸娇鹟（英文名：Serra do Mar Tyrant-Manakin，学名：Neopelma chrysolophum），是雀形目娇鹟科霸娇鹟属的鸟类。较为不起眼的鸟类，可能因外观与伯劳相似而易混淆。最显著的特征是其黄色的冠羽和较淡的下巴。","appearance":"整体呈橄榄绿色，头部顶部有一束醒目的黄色羽毛，下巴颜色较浅。体型适中，性别差异不大，幼鸟的特征与成鸟类似，但色彩较为暗淡。","call":"鸣唱由一系列尖锐的音符开始，随后是较长的音节，具体表现为“chip, chip, dree-zee-zee, zéw”的旋律。","habits":"栖息于湿润森林边缘和次生林地带，偏好有竹子的区域，通常避开森林内部。活动范围广泛，飞行敏捷，以昆虫为主要食物来源。","breeding":"繁殖习性尚未详尽研究，一般在繁殖季节会展示特定的求偶行为，筑巢于灌木丛中，孵化和育雏细节有待进一步观察。","identification":"与同属其他物种相比，巴西黄冠霸娇鹟的黄色冠羽是最显著的辨识特征。此外，其鸣叫声也有助于在野外辨别。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲巴西东南部，范围从米纳斯吉拉斯州东部和里约热内卢向南至圣保罗州极南部，可能还包括邻近的巴拉那州东部。"},{"name":"黄头绿娇鹟","english_name":"Yellow-headed Manakin","scientific_name":"Chloropipo flavicapilla","overview":"黄头绿娇鹟（英文名：Yellow-headed Manakin，学名：Chloropipo flavicapilla），是雀形目娇鹟科Chloropipo的鸟类。珍稀的鸟类，显著特征为头部金黄色，体羽橄榄色，腹部呈淡黄色。分布于南美洲的云雾森林中，约1,200至2,400米的海拔高度，主要见于哥伦比亚与厄瓜多尔的安第斯山脉地带。","appearance":"体长约12至13厘米，体重约15.3至19.5克。雄鸟拥有金色的冠部和颈背，上体鲜亮的橄榄色，面部、喉部和胸部较浅且偏黄，腹部为淡黄色，翼下覆羽白色，虹膜呈淡橙至红色，上喙黑色，下喙蓝灰色，腿灰。雌鸟与雄鸟相似，但头部和胸部颜色较为暗淡。幼鸟与雌鸟类似，但色泽更为暗淡。","call":"未有详细记录，通常保持安静。","habits":"栖息于湿润的山地森林及成熟的次生林中，主要以果实为食，可能包括Palicourea属的果实。偶尔加入混合物种群落。","breeding":"繁殖资料稀少，巢穴最近在哥伦比亚的La Romera保护区被发现，位于小灌木分叉处，靠近狭窄的溪流，由干草条和蜘蛛网构建，内衬枯枝，含一枚有重斑点的乳白色蛋。繁殖季节似乎无明显季节性，雄鸟在一月有大睾丸，雌鸟在三月处于繁殖状态，五月有雌鸟喂养幼鸟，七月在卡利发现有育雏斑的雌鸟。","identification":"雄鸟的金黄色头部和橄榄绿色体羽是其独特之处，雌鸟和幼鸟色泽较暗，通过这些特征可与其他种类区分开来。","protection":"IUCN：VU（易危）","distribution":"分布于哥伦比亚的安第斯山脉西部（瓦勒和考卡省）、中部（安蒂奥基亚、托利马和胡伊拉省）以及可能的普图马约省东部，以及厄瓜多尔北部和中部（纳波和通古拉瓦省）。","other":"该物种数量稀少，面临栖息地丧失的威胁，特别是在其分布范围内大规模的森林砍伐，导致部分地区的局部灭绝。在至少8个保护区中得到保护，包括哥伦比亚的Los Nevados和Farallones de Cali国家公园，以及厄瓜多尔的Sumaco Napo-Galeras国家公园。"},{"name":"辉绿娇鹟","english_name":"Jet Manakin","scientific_name":"Chloropipo unicolor","overview":"辉绿娇鹟（英文名：Jet Manakin，学名：Chloropipo unicolor），是雀形目娇鹟科Chloropipo的鸟类。罕见的大型娇鹟，主要栖息于南美洲厄瓜多尔和秘鲁安第斯山脉东坡的湿润森林中的密集灌木层，特别是在山脊边缘地带。其自然栖息地为亚热带或热带湿润山地森林。","appearance":"雄性辉绿娇鹟全身黑色，翅膀下方有醒目的白色羽毛，当翅膀扇动或飞行时尤为明显，这在它所分布的区域内独一无二。雌鸟则全身棕色，体型较小，翅膀下方同样有白色羽毛，可能与schiffornis属的鸟类混淆。","call":"辉绿娇鹟最常通过其独特的叫声被注意到，发出一种带有鼻音的上升调‘tuwee！’声。","habits":"辉绿娇鹟主要栖息于南美洲安第斯山脉东坡的上部热带区域，偏好湿润的山地森林环境。","identification":"雄性辉绿娇鹟的全黑外观和白色翅膀下侧是识别的关键特征。雌鸟虽与schiffornis属鸟类相似，但体型更小，且有白色翅膀下侧。","distribution":"分布于南美洲厄瓜多尔（自纳波省向南）和秘鲁（南至普诺）。"},{"name":"鹊色盔娇鹟","english_name":"Araripe Manakin","scientific_name":"Chiroxiphia bokermanni","overview":"鹊色盔娇鹟（英文名：Araripe Manakin，学名：Chiroxiphia bokermanni），是雀形目娇鹟科红顶蓝背娇鹟属的鸟类。1996年发现的鸟类新种，仅见于巴西东北部Ceará州的Araripe高原周边山谷森林地带。雄鸟以白色为主调，拥有醒目的红色冠羽和黑色尾羽；雌鸟橄榄绿色，腹部颜色较淡。全球仅约800只，面临严重威胁，主要由于栖息地遭受砍伐。","appearance":"雄性鹊色盔娇鹟以白色为基底，头戴鲜艳的红色冠羽，背部至肩部亦有红色羽毛渐变。黑色的尾羽和飞羽对比鲜明，翅膀上部分羽毛的内侧为黑色。雌鸟个体则呈现橄榄绿色，上体颜色较深，下体尤其是腹部颜色偏灰。雄鸟全长约14.5厘米，雌鸟略小。喙、虹膜等裸露部位颜色为肉桂棕色至黑色。","call":"发出类似‘guru-uí’的愉悦叫声，与盔娇鹟的叫声相似。","habits":"栖息于靠近水源的林地，活动范围狭小。主要以小型果实为食，偶尔食用昆虫。在繁殖季节，雄鸟会参与展示以吸引雌鸟。","breeding":"繁殖期、求偶、营巢等信息尚不详。已知会在树上筑巢，繁殖地通常位于溪流附近。","identification":"雄性鹊色盔娇鹟与盔娇鹟的主要区别在于前者羽毛以白色为主，而后者为黑色。雌性鹊色盔娇鹟的下体颜色更灰，尤其在下巴、喉部、耳羽、腹部和下尾覆羽处。两物种在翼覆羽和上尾覆羽的形状上也有差异。","protection":"IUCN：CR（极危）。物种受到栖息地丧失的严重威胁。","distribution":"分布于巴西东北部的Ceará州，具体在Araripe高原的周边山谷森林中。繁殖区域与非繁殖区域一致，局限于这一狭窄地带。","other":"该物种的生存状况引起了国际关注，相关保护项目正在实施以减少栖息地破坏，如建立主题公园和限制人为干扰。"},{"name":"盔娇鹟","english_name":"Helmeted Manakin","scientific_name":"Chiroxiphia galeata","overview":"盔娇鹟（英文名：Helmeted Manakin，学名：Chiroxiphia galeata），是雀形目娇鹟科红顶蓝背娇鹟属的小型鸟类。雄鸟拥有光泽黑色的身体，醒目的红色前额、冠羽和背部，而雌鸟全身橄榄绿色，头部具有较小的冠羽。主要分布于南美洲的季节性干燥Cerrado大草原，包括巴西中部和南部、玻利维亚东北部及巴拉圭东部。该物种以独特的外观和栖息地偏好著称。","appearance":"雄性盔娇鹟体长13.9-14.5厘米，体重18-26.5克，拥有引人注目的红色前额至背部，黑色羽毛覆盖其余身体部分，眼睛深棕色，喙暗色，腿呈粉红色。雌鸟体型相似，但全身橄榄绿色，冠羽较小，下方略显淡黄色。幼鸟外观类似雌鸟。","call":"雄鸟的叫声是一系列快速、丰富、音乐般的音符，带有欢快的韵律，有许多变化，两性皆可发出喉咙式的‘wreee pur’声，首音上扬。","habits":"盔娇鹟主要栖息于巴西的Cerrado大草原中的画廊森林，经常伴随混合物种群落活动。它们以果实和昆虫为食，通过空中突袭的方式捕食昆虫。在巴西Cerrado的研究中，记录了它们食用16种植物的果实，多数为茜草科和梅兰科植物。","breeding":"繁殖期主要集中在8月至12月，尤其是在9月至11月。巢穴为浅杯状，由细枝、根须和树叶构成，外部悬挂有叶子，悬挂在树或灌木的水平叉上，离地面高度0.5-10米。每次产卵2枚，关于孵化和离巢期的信息未详。","identification":"盔娇鹟的识别要点在于其独特的冠羽和体色。雄鸟与雌鸟的明显差异在于颜色，雄鸟的黑色和红色与雌鸟的橄榄绿色形成鲜明对比。","protection":"IUCN：LC（无危）","distribution":"分布在南美洲的季节性干燥Cerrado大草原，具体包括巴西的中部和南部、玻利维亚的东北部以及巴拉圭的东部和巴西的东南部。","other":"盔娇鹟是Cerrado大草原中相对常见的物种，尽管其数量有所下降，但由于分布广泛，目前被列为IUCN的无危等级。"},{"name":"长尾娇鹟","english_name":"Long-tailed Manakin","scientific_name":"Chiroxiphia linearis","overview":"长尾娇鹟（英文名：Long-tailed Manakin，学名：Chiroxiphia linearis），是雀形目娇鹟科红顶蓝背娇鹟属的鸟类。具有吸引力的小型热带森林鸟，体型丰满，分布于中美洲干湿热带低地和山麓地带，从墨西哥南部到哥斯达黎加西北部。雄鸟以其独特的长尾和黑色羽毛、蓝色背部及红色冠羽引人注目，而雌鸟和幼鸟则通体呈橄榄绿色，尾巴相对较长。","appearance":"雄性长尾娇鹟全身黑色，翅膀上覆羽泛浅蓝紫色，头部有一片醒目的红色冠羽，最显著的特征是其两根与身体长度相仿的细长尾羽。雌鸟则整体呈现橄榄绿色，胸部和腹部颜色较淡，偏黄绿色。它们的虹膜呈黑色，嘴巴也是黑色，脚部为鲜艳的红色。","call":"长尾娇鹟的鸣叫声复杂，涉及响亮的哨声和两只雄鸟间的互动，但具体描述未详。","habits":"长尾娇鹟栖息于中美洲的热带和亚热带森林中，偏好干湿交替的低地和山麓地带。它们的活动范围广泛，从低地森林到退化森林均有发现。雄鸟在繁殖季节会形成长期合作的双雄或三雄组合，进行复杂的同步求偶舞蹈。","breeding":"长尾娇鹟的求偶过程独特，雌鸟仅在两只雄鸟组成的舞蹈队表演极为默契的求偶舞蹈后才接受求偶。舞蹈由‘师父’和‘学徒’组成，若求偶成功，仅‘师父’有交配权，而‘学徒’需继续学习，未来才能成为‘师父’。","identification":"长尾娇鹟与同属的蓝背娇鹟、燕尾娇鹟、玻利维亚娇鹟及尖尾娇鹟在外观和行为上相似，但它们的地理分布不重叠，可通过观察长尾娇鹟雄鸟的特长大尾羽来区分。","protection":"IUCN：LC（无危）","distribution":"长尾娇鹟主要分布在中美洲，包括墨西哥南部至哥斯达黎加西北部。它们的栖息地包括热带和亚热带的干燥和湿润低地森林。"},{"name":"尖尾娇鹟","english_name":"Lance-tailed Manakin","scientific_name":"Chiroxiphia lanceolata","overview":"尖尾娇鹟（英文名：Lance-tailed Manakin，学名：Chiroxiphia lanceolata），是雀形目娇鹟科红顶蓝背娇鹟属的小型鸟类。以引人注目的黑色羽毛、天蓝色背部和红色帽状头饰著称，雌鸟则呈现橄榄绿色。这种鸟分布在中美洲至南美洲北部，从哥斯达黎加西南部延伸至委内瑞拉北部。","appearance":"雄性尖尾娇鹟拥有独特的黑色羽衣，搭配天蓝色背部和红色头冠，橙色腿脚，而雌鸟和幼鸟则呈橄榄绿色，腹部颜色稍淡。最显著的特点是两根中央尾羽被拉长形成尖刺状，这一特征在繁殖季节尤为明显。","call":"尖尾娇鹟发出多种叫声，包括‘Toe-LEE-do’、‘curry-ho’以及展示时的类似青蛙的嗡嗡声。","habits":"栖息于干湿森林地带，通常位于树冠下方，偏好非雨林环境。它们主要以水果和昆虫为食，活动范围广泛。","breeding":"繁殖期在巴拿马为8月至9月。雄鸟在细枝上进行低空展示，有时由次级雄鸟加入，两者交替跳跃和短距离飞行。巢穴由雌鸟建造，位于灌木丛中的水平枝丫上，距地面约1米高，由草和叶纤维构成的小浅杯型巢。一窝产2枚蛋，孵化和离巢时间尚未详细记录。","identification":"与蓝背娇鹟相似，但蓝背娇鹟缺乏尖刺尾羽，雄鸟背部颜色更深。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲太平洋沿岸地区，包括哥斯达黎加西南部、巴拿马（含Coiba岛和Cébaco岛）、哥伦比亚加勒比海岸、委内瑞拉奥里诺科河以北（东至Paria半岛，含Margarita岛）。在哥伦比亚中部Magdalena谷地也有局部分布。","other":"在一些受保护区域中存在，例如哥伦比亚的泰罗纳国家公园和委内瑞拉的Henri Pittier和Guatopo国家公园。"},{"name":"蓝背娇鹟","english_name":"Blue-backed Manakin","scientific_name":"Chiroxiphia pareola","overview":"蓝背娇鹟（英文名：Blue-backed Manakin，学名：Chiroxiphia pareola），是雀形目娇鹟科红顶蓝背娇鹟属的鸟类。小型的热带南美洲鸟类，分布于哥伦比亚至巴西东南部的热带森林中，偏好干燥森林而非常绿雨林。成年雄鸟具黑色体羽、明亮的蓝色背部和红色或黄色的冠羽，雌鸟及幼鸟橄榄绿色，下体较淡。本物种广泛分布，数量相对稳定。","appearance":"雄鸟长12-12.5厘米，体重17-24.5克，具小黑前额羽冠、红冠斑、淡蓝色背部与肩羽，其余羽毛黑色，外侧三根初级飞羽尖锐，眼虹膜深红棕色，喙黑色，跗跖橙红色。雌鸟橄榄绿色，喉部较浅色，腹部及下尾覆羽黄白色，跗跖粉红色。幼鸟似雌鸟，亚成年雄鸟经历一系列中间羽毛变化。","call":"雄鸟发出滚动的‘wrrrr’叫声，常接以突然的单或双‘chup’声，还有二音节的‘joy-ee’声。雄鸟二重奏由一系列几乎完美同步的‘chup’音组成，求偶舞蹈中快速加速的弹拨音，以主导雄鸟非常响亮的‘swee-eeék’声结束。","habits":"栖息于湿润森林和成熟次生林带丰富的灌木层，也见于特立尼达岛、委内瑞拉和圭亚那的较干燥森林和灌木林，主要在低地至约500米高处。以小果实和昆虫为食，通过飞行捕捉或从植被中摘取食物。","breeding":"繁殖期在特立尼达岛为3月至7月，巴西北部9月至4月，巴西南部11月。雄鸟在细枝上表演跳跃和旋转的群体展示。巢建于树上离地面约2米处，深度大但结构松散，由根须构成，基部有枯叶，通常悬挂着干叶和纤维。每窝产2枚蛋，孵化期约17天，雏鸟在15天后离巢，由成鸟喂养数周。","identification":"与尖尾娇鹟相似，但后者具有延长的中央尾羽，雄鸟蓝色背部更鲜艳。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊地区和巴西东部，从哥伦比亚至巴西东南部，包括委内瑞拉、圭亚那、巴西东北部、亚马逊盆地的巴西、玻利维亚、厄瓜多尔和秘鲁，以及特立尼达岛。","other":"蓝背娇鹟在特立尼达岛的亚种C. p. atlantica体型较大，红冠和蓝背更加显著，曾被认为可能代表独立物种，但目前未被广泛认可。"},{"name":"玻利维亚娇鹟","english_name":"Yungas Manakin","scientific_name":"Chiroxiphia boliviana","overview":"玻利维亚娇鹟（英文名：Yungas Manakin，学名：Chiroxiphia boliviana），是雀形目娇鹟科红顶蓝背娇鹟属的鸟类。别称玻利维亚娇鹟。这种鸟以黑色为主，雄鸟的背部呈蓝色，头部有一片暗红色的冠羽，而雌鸟则全身呈现橄榄绿色。主要分布于南美洲的秘鲁南部至玻利维亚南部，生活在海拔600至2200米的山地森林中。","appearance":"雄性玻利维亚娇鹟的显著特征是黑色的身躯搭配蓝色的背部和暗红色的头顶。雌鸟则整体为橄榄绿色，上身稍带褐色，下体颜色略淡，腹部和尾下覆羽更浅。雄鸟的尾部相对较长，不同于其他近似种类，没有延长的中央尾羽。雌雄两性的眼睛均为深棕色。","call":"玻利维亚娇鹟的常见叫声是一种类似鞭打的‘tweew…tweew…tweew’，通常为双音节，有时为三音节。在进行求偶展示时，会发出嗡嗡的虫鸣般的颤音，似乎由翅膀产生。","habits":"这种鸟栖息于云雾缭绕的山地森林，偏好林下层环境，特别是在森林边缘地带。它们可能以果实为食，但具体的饮食习惯尚待研究。飞行时，可见其独特的翼部特征，外侧三个初级飞羽的轴异常增厚，羽毛减少。","breeding":"关于玻利维亚娇鹟的繁殖细节目前了解甚少。推测其繁殖习性与其他娇鹟相似，包括在特定的求偶场进行复杂的求偶展示。","identification":"与蓝背娇鹟相比，玻利维亚娇鹟的雄鸟具有更长的尾巴和更深的暗红色冠羽，而雌鸟的辨别较为困难。蓝背娇鹟的腿色较亮，而玻利维亚娇鹟的腿色偏暗。","protection":"IUCN：LC（无危）","distribution":"玻利维亚娇鹟主要分布在南美洲，从秘鲁南部延伸至玻利维亚南部，生活在海拔较高的安第斯山脉中。","other":"直到最近，玻利维亚娇鹟还被认为是蓝背娇鹟的一个亚种，但生态习性和叫声明显不同，现已确认为独立物种。"},{"name":"燕尾娇鹟","english_name":"Blue Manakin","scientific_name":"Chiroxiphia caudata","overview":"燕尾娇鹟（英文名：Blue Manakin，学名：Chiroxiphia caudata），是雀形目娇鹟科红顶蓝背娇鹟属的小型鸟类，广泛分布于南美洲巴西南部、东南部至巴拉圭东部和阿根廷东北部的热带雨林地带。雄鸟以鲜艳的蓝色身躯、黑色翅膀与头部以及醒目的红色头冠而闻名，雌鸟和幼鸟则呈橄榄绿色，拥有延长的中央尾羽。","appearance":"雄性燕尾娇鹟体长约15厘米，体重平均25.6克，全身亮丽的蓝色，头部黑色，头顶具有一条红色带纹，翅膀和尾部外缘黑色，尾巴中央两根羽毛显著延长。雌鸟与幼鸟体型略小，通体绿色，腹部颜色较淡，额头可能隐现橙黄色斑点。雄鸟幼鸟逐渐发展出成年雄鸟的特征，大约3岁时完全换上成年羽毛。","call":"雄性燕尾娇鹟发出双音节‘ptuwa ptuwa’的叫声，在求偶舞蹈时会发出响亮的喉音‘kwa-a-a-a’，结束舞蹈时则重复尖锐的‘eek’声，类似长尾娇鹟的叫声。两性在多种情境下会发出远距离传播的‘chorreeo cho-cho-cho’叫声。","habits":"燕尾娇鹟栖息于湿润森林和次生林木地带，海拔主要在1500米以下，偶尔可达1900米。它们主要以小果实和昆虫为食，常在空中捕食，有时也会在枝头觅食。它们似乎是定居的，不进行迁徙。","breeding":"繁殖期主要在8月至次年2月。雄鸟在细长的水平枝条上展示，通常由三只雄鸟轮流进行，当雌鸟到达时，雄鸟们会做出跳跃和盘旋的动作以吸引雌鸟。巢穴由干植物纤维和真菌根状物构成，悬挂在小树或灌木的低枝叉上。每次产卵2枚，关于孵化和离巢期的信息尚不详。","identification":"雄性燕尾娇鹟的蓝色羽毛和红色头冠使其与其他种类明显区分开来。雌鸟与蓝背娇鹟有明显的区别，后者主要生活在低地，而燕尾娇鹟则局限于海拔500米以上的山区森林。","protection":"IUCN：LC（无危）。燕尾娇鹟在其分布范围内普遍常见，尽管未来可能面临栖息地破坏的威胁，但其适应次生林和边缘栖息地的能力有助于其生存。该物种在多个保护区得到保护，如Paraguay的Ybicuí国家公园，Brazil的Serra dos Órgãos和Itatiaia国家公园，以及Brazil和Argentina的Iguaçu和Iguazú国家公园。","distribution":"燕尾娇鹟主要分布在南美的巴西东南部至巴拉圭东部和阿根廷东北部。在巴西南部和东南部、巴拉圭东部以及阿根廷东北部的热带雨林中广泛存在。","other":"燕尾娇鹟的求偶行为包括在特定区域内建立lek（求偶场），由一只主导雄鸟、一只次级雄鸟和其他几只较低等级的雄鸟共同维护，它们通过清理展示枝条周围的苔藓、树叶等，使其看起来更加显眼。"},{"name":"针尾娇鹟","english_name":"Pin-tailed Manakin","scientific_name":"Ilicura militaris","overview":"针尾娇鹟（英文名：Pin-tailed Manakin，学名：Ilicura militaris），是雀形目娇鹟科针尾娇鹟属的鸟类。是针尾娇鹟属的唯一物种。体型小巧，雄鸟具有醒目的红额、红臀和黑色背部，翅膀呈绿色，中央尾羽尖锐突出，雌鸟整体橄榄绿，腹部较淡。分布于巴西东南部的湿润森林，从巴伊亚州至里奥格兰德杜斯州。其鸣声为高音的'见-见-见'。","appearance":"雄性针尾娇鹟身长12.5厘米，雌鸟略小，约11厘米。雄鸟拥有红色额头斑块，红臀部至尾上覆羽，其余上体、尾羽及大部分翅膀黑色，内侧飞羽橄榄色；中央一对尾羽尖锐，超出其余尾羽21-25毫米；外侧初级飞羽端部异常宽大，基部狭窄；头部侧面后部灰白色，下体较淡，腹部最白，两胁有黑色条纹；虹膜暗橙色；喙角质色，嘴峰深灰色；腿粉色，带灰色调。雌鸟上体橄榄绿，面部和喉部灰色，下体浅灰橄榄色，中央尾羽尖端突出2-7毫米。幼鸟外观似雌鸟。","call":"雄性针尾娇鹟的广告鸣叫声为一连串5-8个高音、柔和的下降音符，'见-见-见-见-见'；远离展示区时，两性会发出类似系列的3-4个音符。飞行中的雄鸟还能制造旋转声和啪嗒声。","habits":"栖息于湿润森林和成熟的次生林木地带，海拔可达1200米；在其分布北界仅限于山区，但在南部可降至海平面。似乎是留鸟。以小果实和昆虫为食，常见于混合物种觅食群中。","breeding":"繁殖记录稀少。推测在11月至2月间产卵。雄鸟独自展示（但能听到其他一两个雄鸟的声音），在有许多纤细枝干的小型竞技场中，边歌唱边抬起臀部羽毛，做短暂快速飞行，对蹲伏于栖木上的雌鸟做短跳跃。巢为浅篮状，离地面约4米高。其他信息未知。","identification":"雄鸟通过其独特的红额、红臀和尖尾来辨认。雌鸟与幼鸟相似，主要通过橄榄绿色的上体和灰色的面部来区分。与同属其他物种相比，针尾娇鹟的中央尾羽更为突出。","protection":"IUCN：LC（无危）","distribution":"针尾娇鹟分布在南美洲巴西的东南部，具体范围从巴伊亚州延伸到里奥格兰德杜斯州的湿润大西洋森林。","other":"针尾娇鹟羽毛中的鲜艳红色来自类胡萝卜素色素—罗多黄素，这是一种罕见的红色色素，由鸟自身产生的4酮类胡萝卜素转化而来。"},{"name":"金翅娇鹟","english_name":"Golden-winged Manakin","scientific_name":"Masius chrysopterus","appearance":"雄性金翅娇鹟拥有深邃的煤黑色羽毛，头部前方的黄色冠羽直立，延伸至鼻孔上方，两旁有短黑角状突起，颈后有橙棕色或红色鳞片状羽毛，喉部有黄色斑点。飞行时，翅膀和尾羽外侧的亮黄色斑块显露无疑。雌鸟和幼年雄鸟为较为暗淡的橄榄绿色，但雌鸟的腹部和喉咙有黄色调，而幼年雄鸟则开始展现出黄色冠羽和绿色角状突起，直至成年时完全转变。","call":"雄鸟在展示时会发出高音的鸣叫声，伴随快速的嗡嗡声，同时进行翻飞、鞠躬和站立动作。平时则发出单一低沉的嘶哑叫声。","habits":"金翅娇鹟栖息于海拔800至2000米的热带云雾森林中，偏好较低层的林木环境。它们以小果实、浆果和昆虫为主要食物来源。雄鸟会在特定地点集体展示，吸引雌鸟。","breeding":"繁殖期未知，但雄鸟会在苔藓覆盖的森林地面围绕一根树干展示，发出一系列高音和快速的嗡嗡声。巢为杯状，悬挂在树枝上，通常位于溪流上方。","identification":"雄性金翅娇鹟的特征鲜明，几乎无法与其他物种混淆。雌鸟可能与雌性红顶娇鹟或白须娇鹟相似，但可通过其黄色腹部和喉咙以及较长的尾巴加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲北部安第斯山脉两侧，从委内瑞拉西北部至秘鲁北部，主要在800至2000米海拔的云雾森林。"},{"name":"白喉娇鹟","english_name":"White-throated Manakin","scientific_name":"Corapipo gutturalis","overview":"白喉娇鹟（英文名：White-throated Manakin，学名：Corapipo gutturalis），是雀形目娇鹟科白喉娇鹟属的鸟类。而雌鸟和年轻雄鸟的体型纤细，呈现两色相间的外观。主要分布在南美的特普伊山脉和亚马逊雨林东北部。","appearance":"白喉娇鹟的体型小巧，长度在8.5至9.5厘米之间，雄鸟体重约8.1克，雌鸟约8.8克。雄鸟具有白色的喉部，延伸至胸上部，形成尖端；其余羽毛呈蓝黑色光泽，内侧主飞羽内缘为白色，飞行时可见。眼睛深色，喙为淡灰色角质或淡粉色，上部颜色更深更灰；跗跖呈紫色。雌鸟上体暗橄榄色，下体大部分为灰白色，腹部颜色较淡，比大多数相似物种的雌鸟显得更为苍白，跗跖常为铅灰色或灰色。幼鸟似雌鸟；未成年雄鸟有白色喉部，之后逐渐长出身体上的黑色羽毛。","call":"白喉娇鹟的叫声为高而细的‘seeu-see’和‘chip’音符，两者都能发出。雄鸟的求偶叫声是延长版的‘seeu-see-ee-ee-ee’；在展示飞行至倒木时会发出2至10个‘seee’音符，着陆前瞬间有‘pop’的翅膀声，随后在反弹时发出复杂的‘tickee-yeah’叫声。","habits":"白喉娇鹟主要以小果实和昆虫为食，偏好梅拉斯托马科植物和茜草科植物的果实，这是其在法属圭亚那饮食中的主要成分。它们通常通过空中突袭获取食物，倾向于在较高的树冠层觅食，相比大多数其他娇鹟种类，它们更频繁地出现在混合物种觅食群中。","identification":"白喉娇鹟的雄鸟特征明显，与雌鸟和年轻雄鸟的辨识在于后者较为纤细的体型和双色外观。在同属物种中，白喉娇鹟的腹部颜色更为苍白，有助于区分。","protection":"IUCN：LC（无危）","distribution":"白喉娇鹟主要分布在南美洲，包括委内瑞拉南部（博利瓦尔州、北阿马索尼州）、圭亚那群岛和巴西北部（从罗赖马州东至阿马帕州，局部南至马瑙斯地区）。"},{"name":"中美白皱领娇鹟","english_name":"White-ruffed Manakin","scientific_name":"Corapipo altera","overview":"中美白皱领娇鹟（英文名：White-ruffed Manakin，学名：Corapipo altera），是雀形目娇鹟科白喉娇鹟属的小型热带鸟类。雄鸟全身蓝黑色，颈部有独特的白色皱领，雌鸟橄榄绿色，喉部灰白。广泛分布于中美洲至南美洲的洪都拉斯至哥伦比亚一带。","appearance":"雄性中美白皱领娇鹟长约10厘米，重约11克，拥有光泽蓝黑色羽毛，喉咙两侧有白色延长的羽毛形成皱领。雌鸟为橄榄绿色，喉部呈灰色，腹部淡黄色，腿铅灰色。幼鸟似雌鸟，但喉部更显灰色，可能带白色，第二年获得黑色面罩和部分白色皱领。","call":"雄鸟在展示时发出高而滚动的\"prreeet\"叫声，还有尖锐的\"seee\"声；在展示中，雄鸟着陆于木头上时会发出沉闷的翼拍声，紧接着是\"chee waa\"的叫声。","habits":"栖息于潮湿森林、高大的次生林及其边缘地带，海拔从海平面至1500米。部分群体在雨季会向低海拔迁移。主要以小果实为食，辅以少量昆虫和蜘蛛，常在空中捕食。有时加入混合物种觅食群。","breeding":"繁殖期为3月至6月，雄鸟在森林地面的木头上进行复杂的展示，包括陡峭上升后快速降落，雌鸟选择伴侣。巢由细丝或黑菌根构成，挂在离地5至7米高的树叉上，每窝产两枚蛋，孵化和育雏期间由雌鸟独自承担。","identification":"雄鸟的蓝色光泽羽毛和白色皱领，雌鸟的橄榄绿色及灰白喉部是其显著特征。与同属其他物种相比，可通过这些特征及栖息环境进行区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域从洪都拉斯延伸至哥伦比亚，包括中美洲和南美洲的部分地区。在非繁殖季节，部分群体会迁往低海拔地区。","other":"在哥斯达黎加的研究显示，尽管栖息地破碎化，中美白皱领娇鹟仍保持了较高的遗传连通性，表明它们能够跨越非森林区域进行扩散。"},{"name":"南美白皱领娇鹟","english_name":"White-bibbed Manakin","scientific_name":"Corapipo leucorrhoa","overview":"南美白皱领娇鹟（英文名：White-bibbed Manakin，学名：Corapipo leucorrhoa），是雀形目娇鹟科白喉娇鹟属的小型鸟类。雄鸟体羽蓝黑发亮，配以独特的白色喉部皱领，雌鸟上体橄榄绿，下体黄色，喉部灰白。分布于哥伦比亚北部和委内瑞拉西北部的热带森林地带。","appearance":"雄鸟体型小巧，全身蓝黑发亮，喉部有一圈延长的白色羽毛形成皱领；雌鸟上体橄榄绿色，下体黄绿色，喉部灰白色。幼鸟类似雌鸟，但喉部开始显现白色。成年雄鸟体长约9.4厘米，成年雌鸟体色较为暗淡，上体橄榄绿，下体颜色较浅，腹部偏黄。","call":"鸣叫声柔和，似昆虫鸣叫，‘s-e-e-e-e-e-e’，但在森林环境中不易听到。","habits":"栖息于低海拔至中海拔的热带森林，偏好湿润的原始森林和高大的次生林，常在果树林边缘和开阔地带活动。通常单独或成对出现，偶尔可见小群混合性别鸟群，觅食于森林中下层。具有季节性垂直迁移习性。","breeding":"繁殖信息未详，但据推测可能具备树冠展示飞行的行为，这是其同类物种的显著特征。具体繁殖行为需进一步观察。","identification":"雄鸟在分布区内无可混淆，雌鸟可通过灰白色的喉部与红顶娇鹟的雌鸟区分开，后者喉部颜色更深，上体颜色更淡。","protection":"IUCN：LC（无危）","distribution":"分布于南美的哥伦比亚北部和委内瑞拉西北部的热带森林地带。","other":"曾与中美白皱领娇鹟被视为同一物种，现已确认为独立物种。"},{"name":"橄榄绿娇鹟","english_name":"Olive Manakin","scientific_name":"Xenopipo uniformis","overview":"橄榄绿娇鹟（英文名：Olive Manakin，学名：Xenopipo uniformis），是雀形目娇鹟科黑娇鹟属的鸟类。体型小巧，全身覆盖橄榄绿色羽毛，眼周带有黄色环状斑纹。主要分布于南美洲亚马逊雨林北部的巴西、圭亚那和委内瑞拉，偏好高海拔的湿润森林地带。","appearance":"橄榄绿娇鹟拥有均匀的橄榄绿色羽毛，眼周的黄色环状斑纹是其显著特征。体型小，通常单独活动，难以察觉。雌雄羽毛颜色相似，幼鸟的羽毛细节可能有所不同。","call":"其鸣叫声包括一种高音调的喘息声，音调可能会有升降变化。","habits":"栖息于陡峭山地的潮湿森林底层，常见于海拔800米以上，偶尔在较低海拔也能发现。以果实为主要食物来源，活动范围有限，偏好独居，不易被观察到。","identification":"在较高海拔的山地，其独特的黄色眼环易于与其他曼尼金鸟区分。在低海拔地区，通过体型较小、尾巴较短和橄榄绿的羽毛可将其与橄榄色Schiffornis鸟区分开，同时雌性黑娇鹟的羽毛颜色和眼环特征也有助于区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美的亚马逊雨林北部，包括巴西、圭亚那和委内瑞拉的山区。"},{"name":"黑娇鹟","english_name":"Black Manakin","scientific_name":"Xenopipo atronitens","appearance":"雄性黑娇鹟全身黑色，具有相对长一些的尾巴，两性皆拥有蓝色的喙。体型较小，是干燥灌木丛生区内的雨林地带的特色鸟种。","call":"一群雄鸟会从分散的栖息处发出声音表演，通常深藏于植被之中。最常听到的叫声是一种不同寻常的、类似挤压声的咯咯笑，对于在茂密的灌木丛中寻找这种鸟时非常有用。","habits":"黑娇鹟栖息于低矮的森林和草原灌木丛中，偏好土壤极度风化、沙质的地区。它们主要以果实为食。","identification":"雄性黑娇鹟与亚马逊黑霸鹟相比，具有较短的喙，且二者很少在同一栖息地中出现。","protection":"IUCN状态未知。","distribution":"分布于南美洲的哥伦比亚东部、委内瑞拉南部和东南部、圭亚那、苏里南、法属圭亚那，以及巴西的亚马逊雨林（从黑河流域向东至阿马帕和阿拉瓜亚河）；局部分布在秘鲁东部（洛雷托、乌卡亚利、圣母河）、玻利维亚东北部（贝尼、圣克鲁斯东北部）和巴西南部亚马逊地区（亚马逊州南部、阿克雷、朗多尼亚）。","other":"黑娇鹟的自然栖息地主要是热带或亚热带湿润的低地森林和热带干灌木地。"},{"name":"绿娇鹟","english_name":"Green Manakin","scientific_name":"Cryptopipo holochlora","overview":"绿娇鹟（英文名：Green Manakin，学名：Cryptopipo holochlora），是雀形目娇鹟科Cryptopipo的鸟类。主要栖息于南美洲亚马逊盆地的低地和山麓雨林，分布范围包括哥伦比亚东部、厄瓜多尔东部和秘鲁东部。其橄榄绿色的羽毛均匀，男女两性相似，拥有灰色腿脚和较长的尾巴。","appearance":"绿娇鹟体型小巧，长度约11.5至12.5厘米，体重在10.6到18.3克之间。其羽毛呈一致的橄榄绿色，腹部偏黄，眼睛周围可能有一圈淡淡的环状纹。雄鸟和雌鸟的外观相似，但雄鸟的litae亚种通常更大，喙更短。幼鸟的描述资料较少，据说比成鸟更为暗淡。","call":"绿娇鹟平时较为安静，偶尔会发出尖细上升的哨声或是短暂的金属质感颤音。","habits":"绿娇鹟栖息在湿润和潮湿的森林环境中，海拔高度主要在900米以下，偶尔记录到高达1425米的栖息地。它们的饮食以水果为主，可能偏好Anthurium属植物。觅食时，绿娇鹟会采用典型的短距离悬停捕食技巧。","breeding":"绿娇鹟不同于其他娇鹟科鸟类，雄鸟不会形成求偶场，也不进行复杂的求偶展示。筑巢、孵化和喂养雏鸟的工作似乎全由雌鸟承担。繁殖期集中在9月至11月和2月至5月间，巢穴位于树叉中，用根须和苔藓构建，悬挂于森林小溪上空。","identification":"绿娇鹟与辉绿娇鹟雌鸟相似，但颜色更鲜亮，缺乏灰暗色调。通过更长的尾巴和灰色的腿脚可以将其与同类中的其他物种区分开来。","protection":"IUCN：LC（无危）","distribution":"绿娇鹟分布在南美的亚马逊盆地，包括哥伦比亚东部至秘鲁东南部的地区，主要在低地和山麓的湿润森林中。"},{"name":"乔科娇鹟","english_name":"Choco Manakin","scientific_name":"Cryptopipo litae","overview":"乔科娇鹟（英文名：Choco Manakin，学名：Cryptopipo litae），是雀形目娇鹟科Cryptopipo的小型鸟类，分布于中美洲东部巴拿马、南美洲西部哥伦比亚和西北部厄瓜多尔的低地和山麓雨林地带。其体羽呈现较为单一的橄榄绿色，腹部略显黄色，尾部相对较长，腿部和喙呈灰色。在繁殖区域内，该物种被认为是较为常见。","appearance":"乔科娇鹟体长约11至13厘米，重量约15至21克。全身羽毛颜色统一，头部、背部及中央尾羽为明亮的草绿色，与灰暗的飞羽和外侧尾羽形成对比，飞羽和外侧尾羽带有苔藓绿边缘。下体喉部、胸部和侧腹为橄榄色，下巴和腹部中央偏淡黄色，尾下覆羽也是橄榄色。翅膀下的覆羽呈灰橄榄色。嘴部黑色基部带暗灰色或全暗棕色，脚部颜色变化较大，可为深灰、粉灰或黑褐色。","call":"乔科娇鹟很少鸣叫，但有时会发出短促下降的哨声或一系列快速、噼啪的颤音。","habits":"主要栖息于低地和山麓的湿润森林，活动高度通常在海拔900米以下，偶尔可达1425米。以果实为主食，偏好Anthurium属植物。偶尔出现在混合物种觅食群中，采取果实时会进行短暂的悬停动作，然后返回到比食物源稍低的栖木上。","breeding":"繁殖习性的具体信息有限，但有报告指出它们的巢穴较小，雏鸟孵化初期被暗灰色绒毛覆盖。关于换羽和成长周期的资料非常少。","identification":"与雌鸟其他娇鹟种类相比，乔科娇鹟可通过更长的尾巴、较暗的裸露部位色彩和较大的体型来识别。它与Lepidothrix和Pipra属的其他雌鸟娇鹟的区别在于其较为暗淡的外观、更大的体型和更长的尾巴。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲东部巴拿马、南美洲西部哥伦比亚和西北部厄瓜多尔的低地和山麓雨林。在哥伦比亚的分布可达海拔900米，偶尔记录到1425米；在厄瓜多尔，记录到海拔1100米；在巴拿马，记录到海拔1250米。","other":"曾被认为与绿娇鹟同种，后基于分子遗传学研究，被确认为独立物种。"},{"name":"蓝冠娇鹟","english_name":"Blue-capped Manakin","scientific_name":"Lepidothrix coronata","appearance":"蓝冠娇鹟体长8至9厘米，体重约8.5克。雄鸟具亮蓝色头冠，全身其余部分为黑色或绿色（取决于亚种），眼睛呈较暗的红棕色，喙上部黑色，下部较浅的灰色，腿灰白色。雌鸟背部绿色，胸部颜色较淡，脸部和腹部灰白，腹部微带黄色。幼鸟似雌鸟，但颜色更为暗淡。成年雄鸟初期可能有蓝色头冠，体羽中有时可见黑色羽毛。","call":"雄性蓝冠娇鹟发出类似蛙鸣的“see-pur-wee”叫声，两性均能发出间隔均匀的“sweet”叫声。","habits":"蓝冠娇鹟栖息于低地森林的下层，海拔高度通常低于1000米，最高可达1400米。它们主要以小果实为食，偶尔也会捕食昆虫，常在树叶或枝条间啄食或在飞行中捕获。它们经常加入混杂物种的觅食群体。","breeding":"繁殖期在2月至6月之间（主要集中在3月至5月），雄鸟会在单独或群聚的展示场进行展示，执行快速飞行动作。在厄瓜多尔东部，雄鸟占据0.1公顷左右的领地，领地中心相隔约90米。巢穴建在离地面0.6至1.5米高的细树枝分叉处，通常由精细纤维构成，底部覆盖干叶碎片和苔藓，每窝产2枚蛋，孵化期17.5至19天，雏鸟出飞期为13至15天。","identification":"蓝冠娇鹟雌鸟与绿娇鹟可通过短尾巴区分，与乳白冠娇鹟和白顶娇鹟的雌鸟通过深色眼睛辨认。此外，它与蓝腰娇鹟和蓝头娇鹟的雌鸟相似，但通常生活在较低海拔。","protection":"IUCN：LC（无危）","distribution":"蓝冠娇鹟广泛分布于南美洲亚马逊雨林西部，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉。","other":"蓝冠娇鹟的分类历史复杂，最近的一次调整是在2022年，当时将velutina和minuscula亚种分离出来，形成独立的柔羽娇鹟物种，同时原物种被重新命名为蓝冠娇鹟。"},{"name":"白顶娇鹟","english_name":"Snow-capped Manakin","scientific_name":"Lepidothrix nattereri","overview":"白顶娇鹟（英文名：Snow-capped Manakin，学名：Lepidothrix nattereri），是雀形目娇鹟科蓝冠娇鹟属的鸟类。主要分布于南美洲亚马逊盆地的巴西和东北部玻利维亚的低地森林中。","appearance":"白顶娇鹟具有绿色和黄色的羽毛，雄鸟拥有醒目的白色头顶和臀部，而雌鸟则呈现蓝色头顶和绿色臀部。体型小巧，羽毛色彩鲜明，是热带森林中的美丽居民。","call":"在繁殖地，雄鸟会发出短促的“chí-wrrr”叫声，其间穿插着上升的“pweeee”叫声，这些叫声在密林中尤为独特。","habits":"白顶娇鹟主要栖息于低地森林的下层，常在果实丰富的树木附近活动。它们的行踪隐秘，很难在茂密的植被中被观察到。","breeding":"繁殖期中，白顶娇鹟会在离地面约50厘米高的小树苗上筑巢，巢呈杯状，由细薄的树皮条编织而成，紧密地固定在两根水平树枝之间，整个巢穴用蜘蛛网加固。蛋壳呈粉红色，带有不规则的棕色斑点，集中在较大的一端形成环状，其余部分仅有微小的棕色斑点。","identification":"白顶娇鹟与同属的其他物种如金色冠娇鹟和绿宝石冠娇鹟在外观上有明显差异，尤其是头部的色彩。在地理接触区，如Cachimbo山脉，与绿宝石冠娇鹟存在杂交现象。","protection":"IUCN：LC（无危）。局部地区常见至罕见，是一种了解较少的物种；已知在巴西的Amazônia (Tapajós)国家公园和玻利维亚的Noel Kempff Mercado国家公园内有分布。","distribution":"白顶娇鹟主要分布在南美的亚马逊雨林中南部，包括巴西的亚马逊盆地和玻利维亚东北部。","other":"白顶娇鹟是产生金色冠娇鹟的亲本物种之一，与绿宝石冠娇鹟在地理接触区域存在杂交带。"},{"name":"金冠娇鹟","english_name":"Golden-crowned Manakin","scientific_name":"Lepidothrix vilasboasi","overview":"金冠娇鹟（英文名：Golden-crowned Manakin，学名：Lepidothrix vilasboasi），是雀形目娇鹟科蓝冠娇鹟属的小型鸟类。其特征在于雄鸟拥有一顶闪耀的绿金色冠羽，分布于南美洲巴西的亚马逊雨林中南部区域，为当地特有种。由于栖息地丧失，该物种正面临威胁。","appearance":"成年雄性金冠娇鹟约8.5厘米长，拥有熠熠生辉的绿金色冠羽和颈背，其余头部和背部呈绿色，翅膀和尾巴大部分为黑色，边缘泛绿。胸部至腹部颜色从绿色渐变为黄色，虹膜淡灰色，喙呈淡蓝色，腿为粉肉色。雌鸟的上部金色和黄色被绿色取代。幼鸟的羽毛记录不详，推测与雌鸟相似，但头顶有部分绿金色。","call":"雄性金冠娇鹟发出粗糙的‘prreee’声，有时会连续鸣叫，还有一种较高音调、细薄上升的哨声。","habits":"栖息于湿润森林，海拔约200米。主要以小果实和昆虫为食。","breeding":"繁殖行为未有详细记录。","identification":"金冠娇鹟与其他娇鹟种类的区别在于更鲜亮的绿黄体色和雄鸟的黄色冠羽。","protection":"IUCN：LC（无危）。该物种仅在少数几个地点被记录到，受到栖息地破坏的威胁，预计到2020年可能成为极危物种。","distribution":"分布于巴西中部，具体在帕拉州的上库鲁鲁河和贾穆辛河区域。","other":"金冠娇鹟是通过白顶娇鹟和乳白冠娇鹟杂交产生的混合物种，其独特的黄色冠羽介于两种亲本之间。"},{"name":"乳白冠娇鹟","english_name":"Opal-crowned Manakin","scientific_name":"Lepidothrix iris","overview":"乳白冠娇鹟（英文名：Opal-crowned Manakin，学名：Lepidothrix iris），是雀形目娇鹟科蓝冠娇鹟属的鸟类。雌鸟的冠羽则为绿色。该物种主要分布于巴西东南部的亚马孙雨林，栖息于湿润的原始森林和邻近的成熟次生林。","appearance":"乳白冠娇鹟是一种小型鸟类，体长约9厘米，体重约7.8至9.5克。其特征包括厚重的喙。雄鸟拥有狭窄的绿色额带，闪耀的乳白色冠羽和颈背，上体和从颏到胸部主要为橄榄绿色，下体为黄色。雌鸟冠羽和颈背为绿色。幼鸟外观类似于雌鸟，但虹膜呈深色。","call":"雄鸟的叫声为快速重复的‘chi-wir’声。","habits":"乳白冠娇鹟生活在湿润的森林和成熟的次生林木地带，海拔低于约200米。其生活习性与可能相似。雄鸟会在松散的群体中展示，通常在低矮纤细的枝条上进行快速的飞行动作。","breeding":"在帕拉州东部（贝伦地区）发现雌鸟在8月携带完全形成的卵子在输卵管中。雄鸟单独或在分散的求偶场进行展示，但关于繁殖的其他信息有限。","identification":"雄性乳白冠娇鹟以其独特的银色冠羽与雌鸟区分开，而雌鸟则通过绿色的冠羽和颈背与其他物种相区别。亚种eucephala的雄鸟缺少前额的绿色带，雌鸟的冠羽和颈背呈蓝色。","protection":"IUCN：VU（易危）","distribution":"乳白冠娇鹟主要分布在南美洲亚马孙雨林的东南部，特别是在巴西的帕拉州和马拉尼昂州。","other":"由于其栖息地的森林砍伐，乳白冠娇鹟的数量无疑已减少。"},{"name":"特普伊娇鹟","english_name":"Orange-bellied Manakin","scientific_name":"Lepidothrix suavissima","overview":"特普伊娇鹟（英文名：Orange-bellied Manakin，学名：Lepidothrix suavissima），是雀形目娇鹟科蓝冠娇鹟属的小型鸟类。主要分布在南美洲的特普伊山区，即委内瑞拉南部、巴西极北地区以及圭亚那中部的高海拔森林中。","appearance":"成年雄性特普伊娇鹟大部分体羽为黑色，腹部呈黄色（而非橙色），额部有明亮的白色斑块，臀部呈现天蓝色。雌鸟和年轻雄鸟的上体鲜绿色，下体淡黄色，头部顶部带有蓝色调。这种娇鹟的雌鸟与白额娇鹟的雌鸟几乎无法区分，但成年雄鸟的显著区别在于其胸部全黑，没有黄斑。","call":"最频繁的叫声是一种高音的啾啾声，音调略有起伏，与小霸娇鹟的叫声极为相似。此外，还会发出柔和的单音，具有啾啾质感的声音；这两种声音很容易被忽视。","habits":"特普伊娇鹟通常栖息在森林较低层次，以果食为生，通过短暂的飞行跳跃捕捉食物，这与其它种类的娇鹟相似。它在较高海拔的森林中是最常见的娇鹟。","breeding":"关于特普伊娇鹟的繁殖行为和生态细节，目前文献资料较为有限。","identification":"与低地的白额娇鹟极为相似，尤其是雌鸟羽毛颜色几乎相同，但特普伊娇鹟的成年雄鸟有纯黑色的胸部，而无黄色斑点。雌性特普伊娇鹟与其他雌鸟娇鹟的区别在于其鲜绿的上体和带有蓝色的头冠。","protection":"IUCN状态未知。","distribution":"特普伊娇鹟主要分布于南美洲的特普伊山脉区域，具体包括委内瑞拉南部、圭亚那中部以及巴西极北部的亚马逊雨林北部。","other":"与白额娇鹟亲缘关系密切，过去曾被认为是同一种物种。"},{"name":"白额娇鹟","english_name":"White-fronted Manakin","scientific_name":"Lepidothrix serena","overview":"白额娇鹟（英文名：White-fronted Manakin，学名：Lepidothrix serena），是雀形目娇鹟科蓝冠娇鹟属的鸟类。分布于南美的热带雨林中。雄鸟外观引人注目，以光泽的黑色为主，搭配亮丽的蓝色臀部，醒目的白色前额延伸至喙基，以及黄色胸部斑点和腹部。雌鸟则呈现鲜亮的绿色，腹部带有黄色调。常见于高大的雨林，以低层灌木的果实为食。","appearance":"雄性白额娇鹟主要为深黑色，拥有闪亮的白色前额羽，蓝色臀部，黄色胸部斑点和腹部。雌鸟则为灰黑相间，腹部呈淡黄色，眼周白色。两性均具有黑色腿和深色眼睛，雄鸟的特征色彩使其在雨林中格外显眼。","call":"雄鸟常占据离地面约5米内的明显歌唱点，发出重复的咕噜声，这种声音容易被误认为青蛙叫声。","habits":"栖息于高大热带雨林，偏好在低层灌木丛中觅食，主要以果实为食。雄鸟的活动范围和鸣唱行为在繁殖季节尤为显著。","breeding":"关于其繁殖习性的具体细节资料有限，但通常在热带雨林中营巢，进行繁殖。","identification":"与其他娇鹟相比，雌性白额娇鹟可通过其明亮的绿色羽毛和腹部强烈的黄色调来识别。雄鸟与其他种类的区分在于独特的白色前额和蓝色臀部。","protection":"IUCN：LC（无危）","distribution":"分布于法属圭亚那、圭亚那、苏里南和巴西东北部，主要栖息于亚马逊雨林的东北部，覆盖了巴西的阿马帕州及其南部流经的贾里河区域。","other":"历史分类上，曾被归类于Pipra属，后被置于Lepidothrix属，目前该物种没有亚种分化。"},{"name":"蓝腰娇鹟","english_name":"Blue-rumped Manakin","scientific_name":"Lepidothrix isidorei","overview":"蓝腰娇鹟（英文名：Blue-rumped Manakin，学名：Lepidothrix isidorei），是雀形目娇鹟科蓝冠娇鹟属的小型鸟类。分布于南美洲的哥伦比亚至秘鲁一带，栖息于安第斯山脉东坡的云雾森林，被视为厄瓜多尔山麓的特有种。","appearance":"雄鸟通体黑色，头顶白色，臀部呈醒目的蓝色，南部地区的蓝臀色较为淡雅。雌鸟主体绿色，脸部和腹部略带黄色调。雄鸟与白冠娇鹟相似，但蓝臀特征明显；雌鸟与蓝冠娇鹟类似，但脸部更显黄色。","call":"叫声包括抑扬顿挫的鸣啾声和高音上扬的“see?”。","habits":"通常独居，但在果实丰富的树木附近可能聚集多个个体。栖息于海拔较高的森林地带。","breeding":"繁殖信息未详细提及。","identification":"雄性蓝腰娇鹟通过独特的蓝臀和白顶与白冠娇鹟相区分，而雌鸟则以脸部黄色与蓝冠娇鹟区分开来。","protection":"IUCN状态未知，未列入CITES或中国国家重点保护野生动物名录。","distribution":"分布于南美洲，自哥伦比亚延伸至秘鲁，主要栖息于安第斯山脉的云雾森林。","other":"系统学历史未详述，物种详情需参照专业文献。"},{"name":"蓝头娇鹟","english_name":"Cerulean-capped Manakin","scientific_name":"Lepidothrix coeruleocapilla","overview":"蓝头娇鹟（英文名：Cerulean-capped Manakin，学名：Lepidothrix coeruleocapilla），是雀形目娇鹟科蓝冠娇鹟属的鸟类。分布于安第斯山脉东坡的秘鲁中南部至东南部地区，偏好湿润的山地森林环境。","appearance":"雄鸟特征鲜明，通体黑色，头顶和臀部呈天蓝色；雌鸟则全身绿色，较同海拔范围内其他雌鸟娇鹟更为鲜亮。体型较小，活跃于低矮的灌木丛中。","call":"雄鸟发出类似蛙鸣的叫声，‘pur-keep?’，独特而引人注目。","habits":"蓝头娇鹟栖息于湿润的山地森林，通常独居，偶尔与其他物种相遇。它们偏好低矮植被层，活动范围有限。","breeding":"繁殖季节在秘鲁东南部观察到，筑巢于树叉间，距地面约1.7米，巢杯状，利用活枝条和蜘蛛网构建，形成向下延伸的长尾状结构。","identification":"雄性蓝头娇鹟以其独特的天蓝色头部和臀部与其它娇鹟相区别，雌鸟的绿色羽毛在同海拔的娇鹟中最为亮丽。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲秘鲁的安第斯山脉东坡，具体为中部至东南部地区，包括从Huánuco省向南直至Puno省的地带。"},{"name":"柔羽娇鹟","english_name":"Velvety Manakin","scientific_name":"Lepidothrix velutina","overview":"柔羽娇鹟（英文名：Velvety Manakin，学名：Lepidothrix velutina），是雀形目娇鹟科蓝冠娇鹟属的鸟类。曾被视作蓝冠娇鹟的同种，合称“蓝冠娇鹟”。体长8.0–11.2厘米，体重5.7–16.9克。雄鸟通体亮黑色，头顶闪蓝色冠斑；雌鸟草绿色，腹部略带黄色。分布于中美洲南部至南美洲西北部的哥斯达黎加、巴拿马、哥伦比亚及厄瓜多尔，栖息于低地及丘陵地带的原生林与成熟次生林，海拔主要在1000米以下，局部区域可达1400米。","appearance":"成年雄鸟冠部及上颈部呈亮蓝色，近嘴部两侧泛紫罗兰色，其余体羽深亮黑色（包括额带），臀部及上尾羽覆羽具紫蓝色光泽，羽磨损后略呈烟灰并微带褐色。雌鸟上体草绿色，臀部及上尾羽覆羽最鲜亮，尾羽及飞羽较暗且具绿色羽缘；面部自额部至耳覆羽后部、颏及喉部呈淡灰绿色，胸部及胁部暗绿，腹部橄榄灰并微带黄色。幼鸟外形似成年雌鸟，但背部更偏灰色，下体呈灰褐色。第一年雄鸟体羽鲜绿，亚成鸟（两岁）体部仍残留不同程度的绿色，直至第三年才完全获得成鸟羽色，但腹部及翼覆羽可能仍残留绿色羽毛；部分较年老雌鸟偶尔可能在冠部显现亮蓝色（似雄鸟）羽毛。喙窄长，上喙拱形，尖端微弯；上颚黑色，下颚蓝灰色；虹膜明亮红褐色至深红色；腿脚黑色或深灰色，足底褐色。亚种minuscula较指名亚种体型更小，雄鸟冠色更深而偏群青蓝。","call":"雄鸟在求偶场（lek）发出宣示叫声，为响亮的“chu-WAK”或“k'wek”，声音粗嘎、具鼻音且似蛙鸣，可单独发出或连续重复二至四次，亦常与柔和清晰的颤音连用；该颤音“ti'ti't't't't't't't't”为最常见的叫声，全年两性均发出，且通常预示宣示叫声的开始。另有低沉的“P'YPY”用于领地防卫，以及互动时的短促“preew”叫声。雌鸟在焦虑时发出颤音。","habits":"主要栖息于潮湿的原生林及成熟的次生林地，海拔分布以1000米以下为主，在哥斯达黎加太平洋 slope 局部可达1350–1400米。性留鸟， probably sedentary。常于森林的中下层活动，以短距离飞出击啄（sally-strike）方式从叶片背面或空中获取食物。常加入混合种群觅食群（mixed-species foraging flocks），尤见于行军蚁（army ant）群周围，此行为多见于雌鸟及幼鸟。食性以小型果实为主，兼食昆虫（特别在育雏期），记录取食野牡丹科（Melastomaceae）Miconia属、茜草科（Rubiaceae）Psychotria属、Marcgraviaceae科及Flacourtiaceae科等植物的果实。","breeding":"繁殖期主要在二至六月（集中于三至五月），在哥伦比亚西北部及中部则见于十月至五月。仅雌鸟筑巢（娇鹟科共有特征），巢址几乎总是选择在原生林的下木层，偶见于毗邻原生林的高大次生林地，罕于与森林相隔的疏林。巢附着于细枝的分叉处，离地高度0.3–2.0米（通常0.6–1.5米），主要由浅色细纤维、干燥纸质叶片碎片、绿色苔藓及蜘蛛丝构成，外层常具蕨类白色枯死羽片或双子叶植物叶片碎片，巢基部有时悬挂纤维状内树皮条。窝卵数二枚，卵呈暗白色至淡灰色，具浅褐至深褐（有时红褐）色斑点，并集中于卵的大端成环状，平均大小为19.4×14.4毫米（范围18.3×12.7至21.0×15.7毫米）。产卵间隔至少24小时。孵卵由雌鸟单独承担，孵化期约17.5–19天，雌鸟日均抱卵时间超过80%，单次孵卵时段可逾三小时。雏鸟由雌鸟单独抚育，通过反刍喂食昆虫及浆果，喂食率约每小时2.4次/雏；雌鸟会吞咽或衔走雏鸟粪便。当巢受威胁时，雌鸟会执行引开行为（distraction display）：在入侵者周围兴奋地移动、振翅悬停、降落至低矮栖木后展翅缓慢拍动佯伤，以引诱入侵者远离巢穴。雏鸟期13–16天。","identification":"雄鸟为其分布区内唯一通体黑色、头顶蓝色且臀部与上尾羽覆羽无白色或蓝色的娇鹟，易于识别；与白冠娇鹟的雄鸟区别在于后者具白色冠斑。雌鸟识别较难，与乔科娇鹟的区别在于后者体型通常更大、背部更暗、虹膜无红色痕迹；与白冠娇鹟的雌鸟区别在于后者头部具弥散的灰色帽状斑纹，且下体黄色范围更广。两个亚种之间，minuscula较指名亚种velutina体型更小，雄鸟冠色更深（偏群青蓝色），雌鸟体色亦略深。","protection":"IUCN: LC（无危）。目前BirdLife International仍将本种与蓝冠娇鹟视为单一物种进行评估。","distribution":"分布于中美洲南部及南美洲西北部安第斯山脉以西。太平洋 slope 范围自哥斯达黎加南部（自克波斯，罕见于北部卡拉拉）向南经巴拿马西部（奇里基、博卡斯德尔托罗、贝拉瓜斯）、哥伦比亚（安第斯山脉以北的山麓与低地，以及西、中安第斯山脉南至卡达斯省）至厄瓜多尔西北部（主要见于埃斯梅拉达斯省，局部见于皮钦查省及北马纳比省，Los Ríos省有历史记录）；加勒比 slope 见于哥斯达黎加极东南部（希科亚拉周边）及巴拿马东部（自运河区以东）。在分布范围内大部分地区局部常见，于厄瓜多尔及巴拿马中东部相当常见，在巴拿马西部则较局限。","other":"本种与蓝冠娇鹟构成姐妹种关系，两者与蓝头娇鹟、白顶娇鹟、乳白冠娇鹟及金冠娇鹟等种构成姐妹群。分类历史上，本种曾被归入Pipra属，后与蓝冠娇鹟长期被视为同种，近年基于分子系统学数据及安第斯山脉东西两侧种群间的深刻分歧被确认为独立物种。"},{"name":"橙顶娇鹟","english_name":"Orange-crested Manakin","scientific_name":"Heterocercus aurantiivertex","overview":"橙顶娇鹟（英文名：Orange-crested Manakin，学名：Heterocercus aurantiivertex），是雀形目娇鹟科橙顶娇鹟属的鸟类。在亚马逊低地季节性洪水泛滥的沼泽森林中生活的鸟类。分布于南美洲的厄瓜多尔东部和秘鲁北部。","appearance":"雄性橙顶娇鹟颜色较淡，上体呈棕色，下体为肉桂色，喉部白色；其橙色的冠羽通常隐藏不见，野外观察时不易察觉。雌鸟更加暗淡，全身主要是橄榄棕色，喉部和面部较浅，没有明显的冠羽。","call":"典型的鸣唱是一连串快速的颤音，音调起伏波动。","habits":"一般在河流和湖泊附近的森林低层至中层活动，栖息于亚马逊低地的季节性泛滥沼泽森林。","identification":"雄性橙顶娇鹟与大多数娇鹟相比色彩较淡，雌鸟则更加暗淡，通过其特有的喉部颜色和缺少显眼冠羽来辨认。","distribution":"分布于南美洲的厄瓜多尔东部，秘鲁北部，以及巴西西部亚马逊地区的局部地带。"},{"name":"黄顶娇鹟","english_name":"Yellow-crested Manakin","scientific_name":"Heterocercus flavivertex","overview":"黄顶娇鹟（英文名：Yellow-crested Manakin，学名：Heterocercus flavivertex），是雀形目娇鹟科橙顶娇鹟属的鸟类。亦被称为黄冠娇鹟，是娇鹟科赤顶娇鹟属的一种特有鸟类。雄鸟具有橄榄绿色背部和锈色腹部，与白色喉部形成鲜明对比，而黄色的冠羽通常隐藏不见。雌鸟则拥有灰色喉部，缺乏黄色冠羽。该物种主要分布在亚马逊盆地的巴西和哥伦比亚，以及委内瑞拉南部的奥里诺科河附近。","appearance":"体长约14厘米，体重约21克。黄顶娇鹟具有渐变的尾羽（外侧尾羽最短），丝滑的长喉毛和相对较长且窄的喙。雄鸟的头部和整个上身呈深橄榄色，脸部呈灰蓝色，喉咙白色，两侧有延长的羽毛，胸部有一条烟熏橄榄色带，胸腹部呈深栗色，向下逐渐变为淡肉桂红棕色，侧面橄榄色。雌鸟相似于雄鸟，但冠部无黄色，喉咙灰色，下体肉桂色，翅膀较短。","call":"雄鸟的招引鸣声为响亮的哨音'weeee-pítch-ooo'，持续约3秒，带有断断续续或抽噎的节奏；在争斗互动中会发出一系列'weer-weer-weer'的喋喋声；在展示飞行时从栖息处发出强调的'chip'声，以及可能源于机械产生的'whoosh'声。","habits":"黄顶娇鹟栖息于季节性泛滥森林（várzea）和邻近的灌木林地，沿黑水溪流和牛轭湖的季节性泛滥河流旁林地，海拔约300米。它们主要以小果实和昆虫为食，似乎比典型的娇鹟更倾向于捕食昆虫，这可能与其较长且较窄的喙有关。昆虫通常在空中捕捉，偶尔在栖息时捕获。","breeding":"繁殖期在委内瑞拉北部亚马逊河以北的相对干燥季节（2月至5月）。雄鸟保卫展示领地，执行各种飞行展示，包括飞升至树冠之上，以及迅速穿过森林追逐对手。求偶行为包括向前弯曲同时展开喉部羽毛，抬起并展开尾巴，颤抖身体和尾巴。已知唯一的一个巢穴记录是在4月，位于下降树枝叉口悬挂的杯状巢，离水面2米高，构造典型但被遗弃前未完成。","identification":"与赤顶娇鹟的区别在于黄顶娇鹟头部有黄色，头部颜色与稍浅的上体一致。雌鸟与赤顶娇鹟雌鸟的区别在于略微明亮的上体和更深的灰色面部。","protection":"IUCN：LC（无危）。在适宜的栖息地中，黄顶娇鹟的数量从罕见到局部相当常见。在委内瑞拉的Junglaven营地有其分布。一项详细研究显示，其种群密度相比更为人熟知的娇鹟物种较低。","distribution":"分布于南美洲亚马逊雨林中北部，包括巴西、哥伦比亚以及委内瑞拉南部的奥里诺科河流域。在巴西，主要分布在阿马孙州，特别是在里奥内格罗流域和相邻的向加勒比海流动的奥里诺科河西北部源头地区。","other":"黄顶娇鹟在亚马逊河以东的特罗姆贝塔斯河汇合点下游未发现。"},{"name":"赤顶娇鹟","english_name":"Flame-crested Manakin","scientific_name":"Heterocercus linteatus","overview":"赤顶娇鹟（英文名：Flame-crested Manakin，学名：Heterocercus linteatus），是雀形目娇鹟科橙顶娇鹟属的独特鸟类，分布于南美洲亚马逊雨林南部区域，包括巴西、秘鲁和玻利维亚的部分地区。其最显著的特征是雄鸟头部黑色，橙红色的冠纹常被隐藏，而雌鸟头部橄榄色，喉部灰色。","appearance":"雄性赤顶娇鹟体型中等，头部黑色，冠部中央橙红，上体橄榄色，下体锈色，与纯白喉部形成鲜明对比。雌鸟头部橄榄色，喉部灰色。雄鸟具有黑色头部，红色冠纹（通常隐蔽），上体和侧翼暗橄榄色，白色喉部带延长的侧羽，胸部有一条烟灰橄榄色带，胸脯深栗色，向下渐变为肉桂红褐色。雌鸟与雄鸟相似，但无红色冠纹，头部与暗橄榄色背部同色，面部更暗，喉部灰色，侧翼灰橄榄色，其余下体肉桂色，翅膀较短。幼鸟描述尚未明确。","call":"雄鸟展示时发出响亮的叫声，具体描述不明。","habits":"栖息于季节性泛滥的森林（várzea）和河岸林地，海拔高度可达约500米。以小型果实、昆虫和蜘蛛为食，详细觅食行为未知。活动范围和迁徙情况未知，推测为留鸟。","breeding":"繁殖习性记录不多，已知雄鸟在群体中展示，张开白色喉部羽毛，追逐竞争对手。具体繁殖细节尚不清楚。","identification":"雄性赤顶娇鹟以其独特的黑色头部和橙红色冠纹易于识别，雌鸟头部橄榄色，喉部灰色，与雄鸟区别明显。在同属物种中，赤顶娇鹟因上体颜色更深，冠部红色而区别开来。","protection":"IUCN：LC（无危）","distribution":"分布于南美亚马逊雨林南部，包括巴西（包括东南马托格罗索）、秘鲁（东部洛雷托、东南马德雷德迪奥斯）和玻利维亚（北部拉巴斯、贝尼、东北部）。","other":"尽管分布范围广泛，但赤顶娇鹟仍是一种鲜为人知的物种，仅在巴西的Amazônia（Tapajós）国家公园和玻利维亚的Noel Kempff Mercado国家公园有所记录。"},{"name":"白须娇鹟","english_name":"White-bearded Manakin","scientific_name":"Manacus manacus","overview":"白须娇鹟（英文名：White-bearded Manakin，学名：Manacus manacus），是雀形目娇鹟科领娇鹟属的鸟类。分布广泛的热带南美鸟类。其分布区域自哥伦比亚至阿根廷北部，常见于森林、次生林和种植园。雄鸟拥有独特的黑色冠羽、背部、翅膀和尾巴，其余部分为白色；雌鸟及未成年鸟则呈橄榄绿色，类似雌鸟金色头领娇鹟，但具有橙色腿脚。白须娇鹟在繁殖季节展示独特的领地炫耀行为。","appearance":"白须娇鹟是一种体型小巧、丰满的鸟类，长度约10.7厘米。雄鸟的头部、上背部、翅膀和尾巴为深黑色，其余部位羽毛为白色。雌鸟及未成年鸟羽毛为暗淡的橄榄绿色，腹部颜色较浅。雄鸟的喉部羽毛稍长，可向前突出，腿脚呈现鲜艳的橙红色。","call":"白须娇鹟除了展示时发出的嗡嗡声，还具有一种颤音的peeerr叫声。","habits":"白须娇鹟主要栖息于森林环境，包括次生林和种植园。它们以果实为主食，偶尔也会捕食昆虫和蜘蛛。雄鸟在繁殖季节会在林地地面进行集体炫耀表演，展示包括快速跳跃、翅膀拍打声和特定叫声。","breeding":"白须娇鹟的繁殖行为包括雄鸟在森林地面的集体炫耀，雌鸟则独自筑巢于树上的低处，通常会产下两枚带有褐色斑点的白色蛋。孵化期大约为18-19天，之后再经过13-15天小鸟即可离巢。","identification":"雄性白须娇鹟通过其独特的黑白相间的羽毛和橙色腿脚与其他鸟类区分开来。雌鸟与其他雌鸟领娇鹟的区别在于橙色的腿脚。在某些区域内，白须娇鹟与金色领娇鹟有接触，但金色领娇鹟雄鸟的腹部为黄色。","protection":"IUCN：LC（无危）","distribution":"白须娇鹟广泛分布在南美洲的亚马逊盆地、圭亚那、委内瑞拉的奥里诺科河流域、哥伦比亚东部以及从巴西东南部到帕拉纳州，向东北延伸至佩南布科州沿海地区。在亚马逊盆地的普鲁斯河区域西南部存在一小片未分布区。"},{"name":"白头娇鹟","english_name":"White-collared Manakin","scientific_name":"Manacus candei","overview":"白头娇鹟（英文名：White-collared Manakin，学名：Manacus candei），是雀形目娇鹟科领娇鹟属的小型热带林鸟。分布于中美洲，从墨西哥东南部至巴拿马西部，常见于低地和山脚的潮湿森林边缘、次生林和旧可可种植园。其显著特征为雄鸟的黑色头冠和白色的颈环，雌鸟和幼鸟呈橄榄绿色，腹部黄色。","appearance":"体长约11厘米，雄鸟具有黑色的头顶、中背部、翅膀和尾巴，橄榄绿的臀部，以及明亮的黄色腹部。雌鸟和幼鸟橄榄绿色，腹部黄色。雄鸟的喉部羽毛在展示时向前延伸，形成独特的装饰。雌鸟的腿为橙色。","call":"雄鸟在繁殖场发出滚动的“preew”声或双音节的“prrr-weeu”，伴有明显的翅膀拍打声。","habits":"栖息于潮湿森林边缘、次生林和老可可种植园，通常在树冠层到林下层活动，以小型果实和昆虫为食。似乎过着定居生活，不迁徙。","breeding":"繁殖期为4月至8月，在哥斯达黎加。雄鸟在繁殖场上展示，清理小块场地作为展示区，涉及跳跃、头部收回、身体摇摆和翅膀拍打。雌鸟造巢，巢为浅杯状，由黑色真菌根状菌丝和细棕色纤维构成，有时装饰有绿色苔藓。","identification":"雄鸟通过其独特的黑色头冠和白色颈环与其它种类区分，雌鸟和幼鸟与橙领娇鹟的雌鸟相似，但分布区域不重叠。","protection":"IUCN：LC（无危）。在整个分布范围内相当普遍，拥有广泛的栖息地容忍度，不需要完全未受干扰的原始森林。","distribution":"分布于中美洲，从墨西哥东南部（北奥阿哈卡）向南至巴拿马最西部（西北博卡斯德尔托罗）。","other":"与金领娇鹟在巴拿马博卡斯德尔托罗省有限区域内广泛杂交，产生具有柠檬黄色颈环的雄鸟杂交后代。"},{"name":"金领娇鹟","english_name":"Golden-collared Manakin","scientific_name":"Manacus vitellinus","overview":"金领娇鹟（英文名：Golden-collared Manakin，学名：Manacus vitellinus），是雀形目娇鹟科领娇鹟属的鸟类。黑色的顶冠和背部，绿色臀部和腹部，雄鸟在繁殖季节展现出引人注目的外观。雌鸟则全身橄榄绿，红色腿脚和深色喙眼。该物种主要分布于巴拿马和哥伦比亚西部，栖息于森林边缘、次生林和茂密的再生地带。","appearance":"雄性金领娇鹟体长约10-11厘米，体重约19.3克，头部、上背、肩部及胸部为耀眼的金色，喉部羽毛在展示时会向前伸展，超出喙尖。背部、翅膀和尾巴为黑色，下体为淡橄榄色。雌鸟体型略小，重约17.1克，全身橄榄绿色，下方更显黄绿色。幼鸟外观与雌鸟相似。","call":"雄鸟在求偶场发出略带颤音的‘peerr’声和清晰的‘chee-pooh’叫声，同时在展示中伴有响亮的拍翅声。","habits":"生活在低地和山麓地带，海拔高度在巴拿马可达450米，哥伦比亚则高达1200米。以小型果实和昆虫为食，通过空中短暂出击捕捉猎物。通常在果树林或森林较低层安静地活动。","breeding":"繁殖期在巴拿马为2月至8月，哥伦比亚北部（乔科、北安蒂奥基亚）为2月至5月，南部可能为7月。雄鸟在求偶场表演跳跃和头部反转动作，当雌鸟到达时，两性会在交配枝和邻近枝条间进行同步跳跃。巢穴由细根和菌丝编织成浅杯状，悬挂于水平支撑之间，离地高0.6至1.5米，每窝产卵2枚，孵化期未记录，雏鸟离巢期为13至15天。","identification":"与白头娇鹟和白须娇鹟杂交，杂交雄鸟的上背呈黄色。与橙领娇鹟无地域重叠。","protection":"IUCN：LC（无危）。在其分布范围内是最常见的娇鹟之一，巴拿马和哥伦比亚全境普遍分布，包括运河区两侧。","distribution":"分布于中美洲的巴拿马和南美洲的哥伦比亚，主要栖息于亚热带或热带湿润低地森林和重度退化前森林。","other":"雄鸟在求偶期间会进行特技般的展示并发出特定的叫声来吸引雌鸟。"},{"name":"橙领娇鹟","english_name":"Orange-collared Manakin","scientific_name":"Manacus aurantiacus","overview":"橙领娇鹟（英文名：Orange-collared Manakin，学名：Manacus aurantiacus），是雀形目娇鹟科领娇鹟属的鸟类。以其独特的颜色模式著称：雄鸟的颈部和喉咙呈现明亮的橙色，与黑色的头冠和翅膀形成鲜明对比。雌鸟外观大相径庭，呈橄榄绿色，腹部略显黄色，腿部橙色鲜亮。该物种在中美洲的哥斯达黎加西南部和巴拿马西部的湿润森林中广泛分布。","appearance":"雄性橙领娇鹟拥有黑色的头部和翅膀，橙色的颈部、胸部和背部，橄榄绿的臀部，以及亮丽的黄色腹部。雌鸟和未成年个体羽毛橄榄绿色，腹部黄色，腿脚橙色。雄鸟翅膀经过特殊改造，外侧五枚初级飞羽狭窄而坚硬，内侧初级飞羽粗厚弯曲，使得飞行时产生沙沙声。雌鸟和年轻雄鸟外观相似，但后者胸部可能带有金色色调。","call":"雄性橙领娇鹟发出清晰的‘cheeuu’叫声，通过翅膀制造类似树枝折断的响亮啪啪声，以及各种由特化翅膀产生的摩擦和呼呼声。","habits":"该物种栖息于低海拔的湿润森林、二次生林、遮荫的种植园和花园中，高度可达1100米。它们主要以果实和小型节肢动物为食，通过空中捕食的方式获取食物。","breeding":"繁殖季节，雄鸟会在森林地面清理出一小片裸露的土地作为展示场，跳跃于细枝之间，同时发出翅膀啪啪声吸引雌鸟。雌鸟独自筑巢、孵化（18至21天）和照顾幼鸟。巢通常位于水平树叉上，离地面0.5至2.5米。","identification":"雄性橙领娇鹟与白领娇鹟和金领娇鹟在颜色上有明显区别，雌鸟与白领娇鹟雌鸟相似，但可通过橙色腿脚和更鲜艳的黄色调来区分。","protection":"IUCN：LC（无危）","distribution":"橙领娇鹟分布在中美洲的哥斯达黎加和巴拿马的太平洋坡低地和山麓地带。","other":"橙领娇鹟曾被认为是金领娇鹟的一个亚种，但现在被认定为独立物种。"},{"name":"绯红冠娇鹟","english_name":"Crimson-hooded Manakin","scientific_name":"Pipra aureola","overview":"绯红冠娇鹟（英文名：Crimson-hooded Manakin，学名：Pipra aureola），是雀形目娇鹟科绯红冠娇鹟属的小型鸟类。雄鸟成鸟头部和胸部呈鲜艳的红色，上体黑色，眼睛白色，而雌鸟和幼年雄鸟则呈现较为暗淡的绿色，喉部常带有黄色调，眼睛灰白至白色。栖息于南美洲亚马逊东北部和东部的沼泽森林底层。","appearance":"雄性绯红冠娇鹟身长约11厘米，体重14至18.5克。头部和胸部红色醒目，其余羽毛黑色，大腿部分奶油色至白色，腹部有红色或橙色。雌鸟及幼鸟颜色较暗，橄榄绿带黄喉，腹部偏灰色。虹膜颜色在成年雄鸟中为白色，雌鸟和幼鸟为灰白色。","call":"雄鸟的展示叫声为单一声响，类似哀怨的长音“eeeeew”，还有更尖锐的双音“chee-weep”。飞行展示时发出两种翼声，低点时为柔和的“poop”声，着陆时为点击声。","habits":"栖息于季节性洪水森林、沿水道的纠结林地、次生林的灌木层，偶尔在巴西的白砂森林中发现。主要以小果实为食，尤其是天南星科植物的果实，也吃昆虫和蜘蛛。通常在空中短距离飞行捕食。在圭亚那，主要栖息在海拔300米以下的地区，最北端可达委内瑞拉的塞罗罗赖马山脉附近1200米高度。","breeding":"繁殖季节在圭亚那为2月至3月，苏里南和法属圭亚那为10月至5月。雄鸟在复杂求偶场中展示，仅主导（年长）雄鸟与来访雌鸟交配。巢为悬挂在灌木分叉处的小开口杯状，离地面约1米高。每次产卵2枚，关于孵化和雏鸟离巢时间的信息未知。","identification":"雄性绯红冠娇鹟具有独特的红色头部和胸部，黑色腹部和腹部，与斑尾娇鹟相比，前胸红色更为广泛，腹部主要是黑色，尾部无白色。雌鸟和幼鸟通过其丰满体型和苍白的眼睛与其他娇鹟区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的巴西、法属圭亚那、圭亚那、苏里南和委内瑞拉的亚马逊东北部和东部地区。","other":"与斑尾娇鹟和线尾娇鹟形成超种群关系，是Pipra属在北方分布最广泛的物种。"},{"name":"线尾娇鹟","english_name":"Wire-tailed Manakin","scientific_name":"Pipra filicauda","overview":"线尾娇鹟（英文名：Wire-tailed Manakin，学名：Pipra filicauda），是雀形目娇鹟科绯红冠娇鹟属的鸟类。分布于南美洲亚马孙雨林西北部，包括哥伦比亚、厄瓜多尔、秘鲁北部及委内瑞拉西部。","appearance":"雄鸟面部至下体鲜亮黄色，头顶至肩部明亮红色，其余上体包括翅膀和尾巴黑色。雌鸟橄榄绿色略带黄色调，下体灰色，腹部最淡，尾丝较短。成年雄鸟具独特的尾丝，长达约4厘米，雌鸟尾丝约2.5厘米。雌鸟与斑尾娇鹟雌鸟相似，但体型更大，具尾丝，喉部和腹部颜色稍亮。未成年鸟似雌鸟，但具褐色虹膜；在成熟阶段，雄鸟下体更黄，额部有黄色带，虹膜白色。","call":"雄鸟展示叫声为下行音调的“eeew”。求偶时有两种翼声：展示飞行下降部分发出低沉的“kloop”，飞行结束时发出尖锐的“klok”。","habits":"常见于湿润森林近溪流处，包括画廊森林和旧次生林。栖息于画廊森林、次生林及较开阔的树林地带，包括委内瑞拉的可可种植园。海拔高度多在300米以下，但在秘鲁可达500米，厄瓜多尔750米，委内瑞拉奥里诺科河以北甚至达到1000米。食物主要包括小果实和昆虫，通过飞行中捕捉或摘取。","breeding":"具体繁殖细节未详述。","identification":"与斑尾娇鹟雌鸟相似，但体型更大，具尾丝，喉部和腹部颜色稍亮。","protection":"IUCN：LC（无危）。在适宜生境中局部常见，分布零散。委内瑞拉北部地区有Henri Pittier和Guatopo国家公园保护，其他地区也有多个保护区，如哥伦比亚的Amacayacu国家公园和厄瓜多尔的Cuyabeno保护区。","distribution":"分布于亚马孙雨林上游地区，包括秘鲁北部、厄瓜多尔东部、哥伦比亚和委内瑞拉南部及西部。在委内瑞拉，分布于奥里诺科河流域，但不覆盖下游1300公里，其分布区绕过安第斯山脉至委内瑞拉西北海岸。巴西西北部，从罗赖马州和亚马逊州向西延伸至委内瑞拉和哥伦比亚，从朗多尼亚州和阿克雷州向西南至秘鲁和厄瓜多尔。","other":"形成超物种复合体，与斑尾娇鹟和绯红冠娇鹟关联密切。"},{"name":"斑尾娇鹟","english_name":"Band-tailed Manakin","scientific_name":"Pipra fasciicauda","overview":"斑尾娇鹟（英文名：Band-tailed Manakin，学名：Pipra fasciicauda），是雀形目娇鹟科绯红冠娇鹟属的小型鸟类，主要分布在南美洲的低地雨林中，包括阿根廷、玻利维亚、巴西、巴拉圭和秘鲁等地。其自然生境为热带湿润森林、沼泽和严重退化的前森林地带。","appearance":"雄性斑尾娇鹟色彩鲜艳，拥有明亮的黄色身体，黑色翅膀和背部，红色的头冠，以及胸部可能带有红色斑纹；最显著的特点是在飞行时可见的白色尾带。雌鸟则颜色较为暗淡，呈黄橄榄色，腹部略显亮黄色，眼圈白色，腹部黄色更明显，与其它雌鸟娇鹟相比，更显黄色。","call":"雄鸟的鸣唱是一种下降的\"teew\"哨音。","habits":"斑尾娇鹟栖息于成熟雨林的林下层，也会出现在竹林中。它们的活动范围广泛，迁徙模式尚未明确。","breeding":"关于繁殖细节的信息有限，但通常会在雨季进行繁殖，雌鸟会建造巢穴，雄鸟通过展示吸引配偶。","identification":"雄性斑尾娇鹟与同属的其他物种如绯红冠娇鹟和线尾娇鹟相比，具有独特的白色尾带，而雌鸟则以其白色眼圈和更鲜亮的黄色腹部区别于其他雌鸟娇鹟。","protection":"IUCN：LC（无危）。斑尾娇鹟在多数分布范围内常见至普遍，存在一些保护区，如巴西的Chapada dos Guimarães国家公园和玻利维亚的Noel Kempff Mercado国家公园。然而，东北巴西（Ceará和Alagoas）的小而孤立群体的生存状况可能受到森林砍伐和干旱化的影响，该区域存在Serra do Baturité州立环境保护区。","distribution":"斑尾娇鹟主要分布于南美的中部，包括阿根廷、玻利维亚、巴西、巴拉圭和秘鲁的低地雨林。","other":"斑尾娇鹟与绯红冠娇鹟和线尾娇鹟形成超物种群，显示了物种间的密切关系。"},{"name":"梅花翅娇鹟","english_name":"Club-winged Manakin","scientific_name":"Machaeropterus deliciosus","overview":"梅花翅娇鹟（英文名：Club-winged Manakin，学名：Machaeropterus deliciosus），是雀形目娇鹟科红顶娇鹟属的小型鸟类，分布于南美洲的云雾森林，具体而言是哥伦比亚西南部至厄瓜多尔西部。雄鸟以独特的酒红色、黑色和白色外观著称，雌鸟则呈现橄榄绿色，眼下方有橙黄色斑点，是识别其的重要特征。","appearance":"雄性梅花翅娇鹟拥有独特的第二级飞羽，头部为鲜亮的酒红色，身体其余部分多为栗褐色，头和喉部颜色较浅，腹部颜色较深，侧翼混有白色，背部和上尾覆羽呈黑褐色，翅膀和尾巴为黑色，翅膀内部的第二级飞羽尤其显白。雌鸟橄榄色，面部带肉桂色调，喉咙为灰白色，胸部和侧翼为黄橄榄色，腹部淡黄色。幼鸟外观类似雌鸟。","call":"雄鸟在求偶场发出尖锐的‘seet’声或连续的‘seet-seet’声，随后是多达8个响亮而刺耳的‘keah！’音符。展示期间，通过快速振动其特化的二级飞羽末端的空心球状结构，产生机械式的‘tip-tip-beeuwww’声，最后一个音符带有金属般的回音。","habits":"栖息于湿润的山地森林，特别是在苔藓覆盖的环境中，也见于成熟的次生林地带。活动高度通常在海拔600-1900米之间，非繁殖季节可能下降到100米。以小浆果和昆虫为食，常在空中追逐猎物，偶尔加入混合物种群。","breeding":"繁殖季节在哥伦比亚为3月至8月。雄鸟单独展示，但在听觉范围内彼此靠近，于离地面约7米的细枝上快速拍打翅膀并高举，产生机械声音。巢穴由植物纤维制成的小杯状结构，外部覆盖苔藓，悬挂在灌木水平分叉处，离地面0.5-1.2米。每窝产卵2枚，孵化期和雏鸟离巢时间未记录。","identification":"雄性梅花翅娇鹟的特殊第二级飞羽和色彩组合是识别关键。雌鸟与其他雌鸟娇鹟相比，眼下的橙黄色斑点是显著的识别标志。","protection":"IUCN：LC（无危）","distribution":"分布于安第斯山脉西侧的云雾森林，具体为哥伦比亚西南部（自里萨拉尔达省向南）和厄瓜多尔西部（南至皮钦查省，亦见于埃尔奥罗省和洛哈省西部）。","other":"该物种在特定区域内分布较为局限，但在Río Ñambí和La Planada自然保护区（哥伦比亚）内较为常见。在厄瓜多尔，自1988年起在布埃纳文图拉（El Oro）被记录，之前似乎并未存在。"},{"name":"纹娇鹟","english_name":"Kinglet Manakin","scientific_name":"Machaeropterus regulus","overview":"纹娇鹟（英文名：Kinglet Manakin，学名：Machaeropterus regulus），是雀形目娇鹟科红顶娇鹟属的鸟类。体型小巧的鸟类，以亮红色的头顶和鲜明的白色条纹著称。主要分布在南美洲巴西东南部的低地森林和山麓地带，包括restinga林区，这里是纹娇鹟的专属领地。在过去两个世纪里，该地区的森林遭受了近乎灾难性的砍伐，纹娇鹟现多见于保护区和保留地，活动范围通常低于200米，但在山麓可达约600米高度。过去曾被视为与北南美洲的紫纹娇鹟同一物种。","appearance":"纹娇鹟的雄鸟具有醒目的外观，头部鲜红色，腹部有整齐的红褐色条纹，而雌鸟虽无红冠，但其腹部细小的红褐色条纹同样独特。两性背部均为橄榄绿色，尾巴极短。雄鸟的第二级飞羽带有白色尖端，最外侧的初级飞羽显著延长，尾羽僵硬且基部厚实。雌鸟脸部和耳羽更显灰色，腹部和侧翼的暗色条纹更为明显。","call":"纹娇鹟会发出有力的“chew”叫声，通过学习其声音更容易发现这种隐秘的鸟儿。","habits":"这种鸟儿栖息于森林的下层至中层，偏好低地和山麓地带，活动突然且快速。它们常在果实丰富的树木附近活动，雄鸟在分散的求偶场（lek）中鸣唱。","breeding":"纹娇鹟的繁殖生态研究尚不充分，巢穴结构尚未描述，但可能与紫纹娇鹟相似。雄鸟聚集在lek中吸引雌鸟，雌鸟独自抚育后代。","identification":"纹娇鹟与紫纹娇鹟虽外观相似，但分布区域不同，前者具有更白的腹部且无胸部红色。雌雄鸟在红褐色条纹的分布上有所区别，雌鸟的条纹主要集中在腹部和侧翼。","protection":"IUCN：LC（无危）","distribution":"纹娇鹟分布于南美洲巴西东南部，从巴伊亚州向南至里约热内卢州中部。在城市区域已无现代记录，多见于保护区。","other":"纹娇鹟的生物学细节仍有待深入研究，如巢穴结构和更多繁殖行为。"},{"name":"紫纹娇鹟","english_name":"Striolated Manakin","scientific_name":"Machaeropterus striolatus","overview":"紫纹娇鹟（英文名：Striolated Manakin，学名：Machaeropterus striolatus），是雀形目娇鹟科红顶娇鹟属的鸟类。是南美洲西部和西北部亚马逊雨林特有的小型鸟类，雄鸟拥有醒目的红色冠羽，而雌鸟则无此特征。分布于亚马逊西部至西北部地区。","appearance":"雄性紫纹娇鹟体型紧凑，尾短，全长约9-9.5厘米，重约9.4克。头部顶部鲜红，颈背亦呈红色，上体橄榄绿色。下体红白相间，喉部偏白，胸部至腹部有明显的红白条纹。雌鸟头部无红色，全身橄榄绿，下体黄色带淡褐色细纹，喉咙颜色较浅。幼鸟类似雌鸟，但雄鸟幼鸟在后冠部会逐渐长出几根基部白色的红色羽毛。","call":"雄鸟的求偶叫声在地理上有所变化，通常为一段快速的高音节后跟短暂的嗡嗡声，有时伴随类似打喷嚏的颤音。叫声在不同地区有所不同。","habits":"紫纹娇鹟栖息于低地至中海拔的湿润森林中，尤其偏爱成熟的次生林和果树林边缘地带。它们主要在树冠较低层活动，偶尔会进入咖啡种植园。以小果实和昆虫为食，通过快速空中捕食获取食物。","breeding":"雄鸟在小型分散的求偶场展示求偶舞蹈。筑巢由雌鸟负责，巢穴为杯状，悬挂在Y型枝叉上，内部以白色纤维衬垫，外部装饰有干叶。繁殖季节不明确，但可能在5月至8月之间，以及东部哥伦比亚地区的4月和10月。每窝产卵数量未知，但已知卵为白色带有栗色斑点。","identification":"雄性紫纹娇鹟的红白条纹下体和红色冠羽是显著特征。与之近似的纹娇鹟相比，其条纹更宽，喉咙颜色更浅。雌鸟与纹娇鹟雌鸟的区别在于其喉部和上胸颜色更暗。","protection":"IUCN：LC（无危）","distribution":"紫纹娇鹟分布于南美洲西部至西北部亚马逊雨林区域，包括委内瑞拉南部、哥伦比亚东部和南部、厄瓜多尔东部、秘鲁东北部以及巴西西部亚马逊流域。","other":"紫纹娇鹟在2017年之前曾被认为是与纹娇鹟同一物种。"},{"name":"朱顶娇鹟","english_name":"Fiery-capped Manakin","scientific_name":"Machaeropterus pyrocephalus","overview":"朱顶娇鹟（英文名：Fiery-capped Manakin，学名：Machaeropterus pyrocephalus），是雀形目娇鹟科红顶娇鹟属的鸟类。最显著特征是雄鸟拥有一顶金色的帽冠，中间饰以红色条纹，上体呈玫瑰赤褐色，尾羽和翅膀橄榄绿，腹部白底粉红条纹。这种色彩斑斓的小鸟分布于南美洲的热带雨林，包括亚马逊流域的巴西、秘鲁、玻利维亚和委内瑞拉。","appearance":"雄性朱顶娇鹟拥有独特的外观，头部金色，中央有红色条纹，上身玫瑰赤褐色，尾部和翅膀为橄榄绿色，腹部白色并带有粉色条纹。雌鸟则较为朴素，全身绿色，仅在腹部有轻微的条纹痕迹和红棕色腿。","call":"朱顶娇鹟的叫声为高音清脆的‘pink’声，间隔规律，但在森林环境中较难定位其位置。","habits":"这种鸟偏好生活在热带雨林的树冠层，以果实和空中捕捉的昆虫为食。它们的栖息地通常位于低海拔的热带湿润森林。","breeding":"在繁殖季节，雄性朱顶娇鹟会形成lek群，进行展示，通过倒挂在树枝上快速扭动身体的方式吸引雌鸟。","identification":"雄性朱顶娇鹟的黄红相间的头部和鲜艳的羽毛使其在同类中几乎无可混淆。雌鸟则需通过腹部条纹和红棕色腿来识别。","protection":"IUCN：LC（无危）","distribution":"朱顶娇鹟的分布范围集中在南美洲的亚马逊盆地，包括巴西南部亚马逊河流域、秘鲁东南部、玻利维亚北部以及委内瑞拉。其自然栖息地位于热带湿润的低地森林。","other":"在繁殖季节，雄鸟会聚集在特定的展示场进行求偶表演。"},{"name":"丽彩娇鹟","english_name":"Painted Manakin","scientific_name":"Machaeropterus eckelberryi","overview":"丽彩娇鹟（英文名：Painted Manakin，学名：Machaeropterus eckelberryi），是雀形目娇鹟科红顶娇鹟属的鸟类。首次于2017年基于秘鲁西北部的标本描述。仅限于秘鲁北部一小片区域，主要在阿苏尔山国家公园和上马约河谷的丘陵地带，海拔500米以上。其命名是为了纪念美国鸟类艺术家唐纳德·R·埃克尔伯里。","appearance":"雄性丽彩娇鹟拥有鲜红的头冠和类似棒棒糖条纹的下部，黄色的胸部带状羽毛尤为突出。雌鸟外观较为暗淡，上体橄榄色，下体淡黄色，胸部带有微弱的白色条纹。两性的上体颜色一致，均为均匀的橄榄绿。雄鸟的下体有白色喉咙，柠檬黄的胸部，以及带有白色条纹和宽阔栗色边缘的腹部和尾下覆羽。雌鸟的下体为黄色白，腹侧和侧翼粗大的红棕色条纹明显。雄鸟的次级飞羽6-8根的轴部增厚，略向外扭曲，使闭合翅膀时可见到内侧次级飞羽的白色内网。雌鸟没有这种特征。","call":"其叫声为间隔规律的弯曲吱吱声。","habits":"丽彩娇鹟栖息于安第斯山脉东坡的云雾森林较低层，主要分布在秘鲁北部阿苏尔山国家公园和上马约河谷的丘陵地带，海拔高度超过500米。","breeding":"关于其繁殖习性的详细信息尚未被充分描述。","identification":"雄鸟与同域的紫纹娇鹟在羽毛模式上有细微差别，主要通过叫声和下体条纹辨别。雌鸟与紫纹娇鹟雌鸟几乎无法通过视觉区分，需依据叫声识别。","protection":"IUCN：LC（无危）","distribution":"丽彩娇鹟的分布限于秘鲁北部的阿苏尔山国家公园和上马约河谷的丘陵地带，主要位于圣马丁和洛雷托部门，海拔高度超过500米。","other":"该物种的描述对区分亚马逊地区的紫纹娇鹟和大西洋森林特有种纹娇鹟起到了关键作用，这两个物种曾被归入紫纹娇鹟这一名称下。"},{"name":"白冠娇鹟","english_name":"White-crowned Manakin","scientific_name":"Pseudopipra pipra","overview":"白冠娇鹟（英文名：White-crowned Manakin，学名：Pseudopipra pipra），是雀形目娇鹟科Pseudopipra的鸟类。小型、胖圆、短尾。雄鸟具有光泽黑羽和显眼的白色冠羽，雌鸟橄榄绿，头部偏灰，下体较淡，喉部和腹部尤甚。广泛分布于中美洲至南美洲北部，自哥斯达黎加至亚马逊雨林及巴西东南部。","appearance":"体型约10厘米，雄鸟平均重11克，雌鸟平均重12.8克。雄鸟具全黑羽毛，鲜明白色冠羽可竖立为扁平状顶冠；虹膜砖红至棕红色；喙暗灰至黑色；腿紫色至黑。雌鸟背部绿色，头部较灰，下体颜色更淡，尤其喉部和腹部。幼鸟似雌鸟。不同亚种在冠羽和颈羽的白色程度及雌鸟头部灰色范围上有差异。","call":"雄鸟叫声随地理位置而异，指名亚种为薄脆虫鸣般的“chrrrrrr”，持续约1.5秒；coracina亚种则发出响亮的“drrrrrr-eúw”。至少存在八种地理变异的叫声，可能对应不同的物种。","habits":"栖息于湿润森林及相邻高大的次生林木地带，低地至山地，海拔可达1600米。以小果实和昆虫为食，常在空中快速飞行中摘取。在繁殖季节，成鸟（尤其是雄鸟）基本定居，换羽期间活动范围扩大。偶尔加入混种群落短暂觅食。","breeding":"筑巢于离地1至3.5米的灌木或小树水平枝叉处，由纤维、菌丝及枯叶构成杯状巢，外部覆以蜘蛛网加固。每窝产两枚脏白色带紫褐色斑点的蛋，孵化和离巢时间未知，雌鸟独力抚育。","identification":"雄鸟白冠明显，雌鸟头部灰色，红眼，易于识别。与其他娇鹟种类相比，其白冠和黑身的独特组合容易区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲北部，自哥斯达黎加至亚马逊雨林及巴西东南部。在哥斯达黎加，主要繁殖于海拔800至1500米的山地。","other":"白冠娇鹟的鸣叫声和展示行为在地理上表现出复杂的变化，可能指示着多个潜在的物种。"},{"name":"红角娇鹟","english_name":"Scarlet-horned Manakin","scientific_name":"Ceratopipra cornuta","overview":"红角娇鹟（英文名：Scarlet-horned Manakin，学名：Ceratopipra cornuta），是雀形目娇鹟科Ceratopipra的小型鸟类。雄鸟体色黑色，头部长有醒目的红色冠羽，雌鸟橄榄绿色，腹部颜色较淡，具有短小的冠羽。分布于南美洲北部，主要栖息于湿润森林及次生林。","appearance":"红角娇鹟体长约12.5厘米，成年雄鸟平均体重约23.5克。为Pipra属中体型最大的物种，拥有比同类更长的尾巴。雄鸟头部、下巴和喉咙全为红色，后冠羽延长形成微向上弯曲的‘角’；大腿红色，其余羽毛黑色；次级飞羽扩大，弯曲且硬化，具粗壮的羽轴；虹膜白色；喙呈淡肉色；腿肉色或褐色。雌鸟整体为暗橄榄绿，腹部颜色较浅，后冠羽稍长，呈现簇状外观，虹膜颜色比雄鸟深，喙色偏棕色。幼鸟外形与雌鸟相似，眼睛颜色深邃。","call":"红角娇鹟的歌声为快速的颤音；雄鸟在求偶场中会发出翅膀拍打产生的咔哒声。","habits":"栖息于南美洲北部的湿润森林和次生林，海拔高度不详。其食性以梅拉斯托马塔科植物的果实为主，通过跳跃和悬停飞行的方式捕食果实。","breeding":"红角娇鹟的繁殖信息有限。已知一巢于2016年7月被拍摄，为一个小的开放式杯状巢，悬挂在水平枝叉上，内有两只雏鸟由雌鸟喂养。雄鸟在求偶场中进行复杂的展示，姿势和动作刻板且多样，包含快速飞行着陆时的转身、在栖木上的向后滑行和摆尾，当双腿完全伸展时，红色的大腿羽毛尤为显眼。","identification":"与白须娇鹟的雌鸟相比，红角娇鹟雌鸟缺少白色胡须，腿并非橙色，且具有短小的冠羽。","protection":"IUCN：LC（无危）。红角娇鹟属于受地域限制的物种，存在于特普伊生态区。局部地区较为常见至普遍。在其分布范围内，大量适宜的栖息地仍然存在，许多地区的森林尚未受到人类活动的重大侵扰。在委内瑞拉的卡奈玛国家公园内有分布。","distribution":"分布于委内瑞拉南部山脉、邻近圭亚那西部（东至Merume和Potaro高原）以及巴西最北端（上白兰哥河地区）。在南美洲北部的亚马孙雨林区域有其自然分布。"},{"name":"红顶娇鹟","english_name":"Red-capped Manakin","scientific_name":"Ceratopipra mentalis","overview":"红顶娇鹟（英文名：Red-capped Manakin，学名：Ceratopipra mentalis），是雀形目娇鹟科Ceratopipra的鸟类。活跃于中美洲至南美洲低地热带雨林的中层和林下层。雄鸟以其鲜亮的红色头部和黑色身躯在阴暗森林中格外醒目，而雌鸟则呈现较为朴素的橄榄绿色，两者差异显著。","appearance":"红顶娇鹟体长约10厘米，体重介于12.5至18.5克之间。体型圆胖，喙短且基部宽大，尾巴短小，眼睛大。雄鸟具白色虹膜，头部、颈侧和后颈为红色或橙红色，下巴黄色，身体其余部分黑色，胫部羽毛淡黄色。雌鸟虹膜暗棕色，偶见白色，羽毛为暗橄榄绿，下体颜色较浅，腹部更偏黄。幼年雄鸟类似雌鸟，但虹膜色浅，头部可见红色，身体可能有黑色羽毛。","habits":"栖息于湿润常绿和半落叶森林，亦可见于高大的次生林和灌木丛，偶尔光顾林缘、开阔地甚至灌木区，特别是在果实丰富的树木上觅食。红顶娇鹟主要以果实为食，消化速度极快，不到18分钟即可处理完毕。","identification":"雄性红顶娇鹟在其分布区内极具辨识度，而雌鸟与Manacus属的雌鸟（如白头娇鹟、橙领娇鹟和金领娇鹟）相似，但后者胫部羽毛橙色，腹部更黄。蓝冠娇鹟的雌鸟体型较小，颜色更为鲜亮。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲东南部至南美洲西部，包括墨西哥南部至厄瓜多尔西北部，主要栖息于低海拔的湿润森林。"},{"name":"圆尾娇鹟","english_name":"Round-tailed Manakin","scientific_name":"Ceratopipra chloromeros","overview":"圆尾娇鹟（英文名：Round-tailed Manakin，学名：Ceratopipra chloromeros），是雀形目娇鹟科Ceratopipra的鸟类。分布于南美洲热带地区，主要栖息在亚马孙雨林的成熟雨林底层和中层。雄鸟以其独特的滑步求偶行为著称。","appearance":"雄鸟黑色，头部红色，腿部黄色羽毛，眼圈淡色，尾部圆形；雌鸟橄榄绿色，腹部至下体黄色调较浅，尾部同样呈圆形。两性均有淡色喙，雄鸟翼部次级飞羽扩大，弯曲且硬化，具粗壮羽轴。","call":"雄鸟的叫声包括一个多音节的‘fui-ii-ii-i chi-awaaak’，持续约1.7秒，通常只发出后半部分；展示叫声为三音节的‘fi-cuac-cuac’，最后两个音节带有嗡嗡声，展示时伴有两次翅膀拍击声。","habits":"栖息于亚马孙雨林的成熟雨林底层和中层，具体生活习性详情未详。","breeding":"繁殖行为包括雄鸟的滑步展示，具体繁殖细节未详。","identification":"雄鸟与红顶娇鹟的区别在于其下翼覆羽为黑色而非黄色，尾部圆形而非方形，颈后羽毛红色并常突出。雌鸟尾部圆形，与红冠娇鹟雌鸟不同。","distribution":"分布于南美洲亚马孙雨林西南部，具体包括秘鲁南部（自亚马逊斯和圣马丁省南下）、巴西西部（阿克雷州）及玻利维亚北部（至圣克鲁斯西部）。"},{"name":"金头娇鹟","english_name":"Golden-headed Manakin","scientific_name":"Ceratopipra erythrocephala","appearance":"雄性金头娇鹟的头部呈亮丽的金色，与黑色的身体形成鲜明对比，雌鸟则呈现沉稳的橄榄绿色。雄鸟的平均体长约为9厘米，而雌鸟略大，平均翼展达到58.9毫米。雌雄两性均具有粉红色的腿和黄色或白色到粉红色的喙。","call":"金头娇鹟除了其独特的外观外，还发出一系列声音，包括一种嗡嗡的pir pir prrrrrt叫声，这是其交流和求偶过程中的重要组成部分。","habits":"金头娇鹟栖息于热带低地森林、次生植被和种植园中，通常在树冠层活动，以果实和昆虫为食。它们的活动范围通常限于海拔3600英尺以下，偶尔可达5000英尺。","breeding":"雄性金头娇鹟会在社群性的求偶场地上表演引人入胜的求偶舞蹈，跳跃、滑行和快速移动于树枝之间，伴随翅膀的呼啸声和zit-zit的叫声。雌鸟单独筑巢，产下两个带有斑点的黄褐色蛋，孵化期约16-17天。","identification":"雄性金头娇鹟很容易通过其独特的金色头部和黑色身体识别。雌鸟与白冠娇鹟的雌鸟相似，但可以通过头部没有大灰色斑块和腿的颜色来区分。","protection":"IUCN：LC（无危）","distribution":"金头娇鹟广泛分布于中美洲的巴拿马至南美洲北部，包括亚马逊雨林的北部区域。","other":"金头娇鹟的雄鸟个体在繁殖季节展现出复杂的求偶行为，这使它们成为研究鸟类社会行为的重要对象。"},{"name":"红头娇鹟","english_name":"Red-headed Manakin","scientific_name":"Ceratopipra rubrocapilla","overview":"红头娇鹟（英文名：Red-headed Manakin，学名：Ceratopipra rubrocapilla），是雀形目娇鹟科Ceratopipra的鸟类。小型而结实的鸟类。雄鸟头部鲜红，雌鸟橄榄绿上体，白色腹部，广泛分布于南美洲亚马孙雨林南部及巴西东南部的热带低地森林。","appearance":"雄鸟身长约10厘米，重约10.9至13.8克，头部从额部到颈背均为红色，大腿亦为红色，其余部位羽毛黑色。雌鸟较雄鸟稍大，体长约10厘米，重12.7至16.6克，全身呈暗橄榄绿色，腹部颜色较浅，尤其是腹部更为明显。虹膜和喙的颜色比雄鸟更深。","call":"雄鸟的主要叫声为鼻音‘drree-dit’，伴随变化，还有尖锐的‘zit, zit’声，以及展示飞行中的‘kew’系列叫声。","habits":"栖息于潮湿的低地森林和次生林木地带，海拔高度可达500米。以小型果实和昆虫为食，通常在空中捕食或摘取。几乎全年定居于其栖息地。","breeding":"在北巴西的贝伦地区，繁殖期为9月至次年4月。雄鸟进行复杂的求偶炫耀，展示包括快速飞行和独特降落姿势在内的多种动作，巢建于离地面2至5米处，每窝产卵2枚，孵化期未知，雏鸟离巢时间为13至14天。","identification":"雄鸟的红色头部和大腿以及黑色的下翼覆羽使其与金头娇鹟和红顶娇鹟易于区分。雌鸟与金头娇鹟雌鸟非常相似，但喉部和腹部可能略显黄色。","protection":"IUCN：LC（无危）；尽管在大部分分布区内数量相当常见，但在巴西东部因大面积的低地森林破坏，孤立种群已大幅减少。","distribution":"分布于南美洲亚马逊雨林南部，包括巴西东南部，秘鲁东部，玻利维亚北部。在巴西，分布从马兰昂州东至里约热内卢，南至朗多尼亚和南马托格罗索州，以及从伯南布哥州南至里约热内卢的沿海断续分布。"},{"name":"尖喙霸鹟","english_name":"Sharpbill","scientific_name":"Oxyruncus cristatus","overview":"尖喙霸鹟（英文名：Sharpbill，学名：Oxyruncus cristatus），是雀形目蒂泰霸鹟科尖喙鸟属的鸟类。独特的小型鸟类，其分布区域跨越南美至中美洲，包括从哥斯达黎加到巴西的山地森林地带。以锐利的尖喙著称，两性皆呈橄榄绿色上部与白色或淡黄色下部，饰以鲜明的黑斑。生活在海拔约700-1700米的成熟山地森林中，偶尔参与混群觅食。","appearance":"体长约17厘米，体重约42克。特征显著，拥有锐利尖端的喙与小头部。雄鸟具有黑色与橄榄色混合的冠羽，红冠通常平伏；上体橄榄绿，翼上有两道淡黄条纹；初级飞羽边缘锯齿状；面部与喉部白色，具细小黑斑；下体黄色，布满黑色大斑点，腹部更白；虹膜红色，喙与跗跖灰色。雌鸟冠羽减少至窄线，虹膜橙色，初级飞羽无锯齿。幼鸟无红冠。亚种间主要差异在于下体黄色强度及其它微小色彩变化。","call":"其最易识别的特征之一是独特的叫声，一种长时间下降的哨音，始于大约3千赫兹，下降幅度宽广，被形容为类似炸弹下落的声音。","habits":"栖息于热带湿润森林，高度400-1100米，以果实和昆虫为食。能灵活地在树梢间跳跃，探入苔藓或寄生植物中寻找猎物，也能倒挂在叶间快速啄食。通常单独活动，常加入混群，尤其在停留时间较长的群落中。","breeding":"繁殖季节可能在2月至6月期间，已知在2月观察到筑巢行为。雄鸟通过伸展颈部与蓬松颈羽展示，不露出红冠。巢由枝梗构成，覆盖苔藓、地衣和蜘蛛网，用唾液粘合，位于树冠高处。每窝可能产2枚卵，由单个成鸟（可能是雌鸟）轮流孵化，孵化期14-24天，雏鸟通过反哺喂养。","identification":"与其他鸟类区别明显，尤其是尖锐的喙与橄榄绿色上体，橙色冠羽在野外难以观察。亚种间的辨识主要依据下体颜色深浅及其它细微色彩差异。","protection":"IUCN：LC（无危）","distribution":"分布于南美广泛的山地森林，包括从哥斯达黎加至巴西的地区，海拔400-1100米，部分地区可达1200米。在非繁殖季节，巴西（帕拉州）低地几乎降至海平面附近也有报道。","other":"尽管分布区域碎片化，但没有迹象表明这是除自然状态外的其他原因造成。在南美东部秘鲁、玻利维亚阿波罗西南、巴西南部马托格罗索州和阿拉戈斯州等地的分布需进一步研究。"},{"name":"皇霸鹟","english_name":"Tropical Royal Flycatcher","scientific_name":"Onychorhynchus coronatus","overview":"皇霸鹟（英文名：Tropical Royal Flycatcher，学名：Onychorhynchus coronatus），是雀形目蒂泰霸鹟科皇霸鹟属的鸟类。雄鸟拥有引人注目的扇形冠羽，展开时呈现横向的扇状，雌鸟冠羽较短。广泛分布于中美洲至南美洲亚马逊雨林区域，包括墨西哥南部至委内瑞拉西北部、厄瓜多尔西部和秘鲁西北部，以及亚马逊雨林。皇霸鹟的体型中等，长约16-18厘米。","appearance":"皇霸鹟体型中等，雄鸟的冠羽在展开时成横向扇形，色彩艳丽，红色带蓝黑尖端，雌鸟冠羽较短，颜色为黄色或橙色。其上体为深棕色，下体为暖黄色至橙色，臀部和尾部为红褐色，尾羽更接近棕色。翅膀为深棕色，翼覆羽和三级飞羽尖端有小块淡色斑点。喉咙为白色，胸部有狭窄的黑色条纹，腹部为纯暖黄色。雄鸟与雌鸟在除冠羽颜色外相似。","call":"皇霸鹟的鸣叫声多样，各亚种之间有所不同。一些亚种的鸣唱由一系列悠扬的口哨声组成，起始于响亮的平调音符，随后是一系列低沉的双音节口哨声。另有亚种的叫声被描述为低沉的、空洞的‘keeeyup’或‘keee-yew’声。","habits":"皇霸鹟栖息于低海拔的湿润热带森林，包括原始常绿林和成熟次生林，通常在林下层和中层活动，常沿溪流或季节性洪水淹没的森林地带。它们主要以飞行中的昆虫为食，如蜻蜓和蝴蝶，通常独自或成对觅食，有时加入混合物种觅食群。飞行特点是突然从栖木飞出捕捉空中或树叶上的猎物。","breeding":"繁殖季节尚不明确，但已知在里约热内卢地区，雏鸟在1-4月间孵化，表明繁殖可能发生在春季（南半球9-10月）。巢是细长的袋状结构，悬挂在树枝或藤蔓上，通常位于水面上方。每窝产两枚蛋，仅雌鸟孵卵并喂养雏鸟。","identification":"皇霸鹟的显著特征是其独特的锤状冠羽，即使在下垂状态，也能与其他鸟类区分开来。当完全竖立时，冠羽形成一个大而鲜艳的扇形，覆盖头顶。与其他类似物种如亮腰阿蒂霸鹟相比，后者无冠羽，尾巴较短且通常为深色，喙通常较浅，胸部常有条纹。","protection":"IUCN：LC（无危）","distribution":"皇霸鹟分布广泛，从墨西哥南部至委内瑞拉西北部，厄瓜多尔西部和秘鲁西北部，以及亚马逊雨林区域，遍及中美洲和南美洲大部分地区。","other":"皇霸鹟在不同的地理区域内存在显著的亚种差异，如北部亚种、太平洋亚种、亚马逊亚种和东南巴西的亚种。"},{"name":"北皇霸鹟","english_name":"Northern Royal Flycatcher","scientific_name":"Onychorhynchus mexicanus","overview":"北皇霸鹟（英文名：Northern Royal Flycatcher，学名：Onychorhynchus mexicanus），是雀形目蒂泰霸鹟科皇霸鹟属的鸟类。又称北方皇家鹟、北方皇家姬鹟。体长约16.5至18厘米，其最显著的特征是头部拥有一顶扇形羽冠，雄鸟呈红色，雌鸟为黄色。分布广泛，自墨西哥南至大部分中美洲和南美大陆，除阿根廷、智利、巴拉圭及乌拉圭。","appearance":"北皇霸鹟体长介于12.5至18厘米之间，体重约9.7至21克。特征性的扇形羽冠在雄鸟中为红底蓝尖，雌鸟则为黄或橙色。成鸟上身暗褐色，尾部和臀部呈肉桂红，尾端渐变褐色。翅膀深褐色，覆羽和三级飞羽尖端点缀着小块淡斑。喉部白色，胸部温暖的淡褐色条纹，腹部纯暖色调。虹膜颜色多样，喙部颜色由暗褐至黑色，腿足色偏黄或橙色。","call":"北皇霸鹟通常较为隐秘且安静，但会发出一系列旋律悠长的哨音，起始于响亮平调，随后是连串低沉的双音节哨声。具体叫声随亚种而异。","habits":"栖息于湿润的低地森林，包括原始常绿林和次生林，偏好森林下层及中层，常见于溪流旁或季节性泛滥的森林。海拔高度从海平面至1200米左右，巴西低于1000米，东部厄瓜多尔低于400米，西部厄瓜多尔低于600米。","breeding":"繁殖季节未明确记录。巢穴细长悬挂于树枝或藤蔓上，多位于水面上方。每次产卵2枚，仅雌鸟负责孵卵、育雏及喂食。","identification":"与其他皇霸鹟属物种的区别在于羽冠的颜色和形态，以及鸣叫声的不同。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥至大部分中美洲，遍及南美大陆除阿根廷、智利、巴拉圭和乌拉圭。在中美洲和哥伦比亚的海拔范围为海平面至1200米，在巴西低于1000米，东部厄瓜多尔低于400米，西部厄瓜多尔低于600米。"},{"name":"西皇霸鹟","english_name":"Pacific Royal Flycatcher","scientific_name":"Onychorhynchus occidentalis","overview":"西皇霸鹟（英文名：Pacific Royal Flycatcher，学名：Onychorhynchus occidentalis），是雀形目蒂泰霸鹟科皇霸鹟属的鸟类。分布广泛、体型中等，拥有独特的扇形冠羽，分布于墨西哥至南美洲大部分地区，除阿根廷、智利、巴拉圭和乌拉圭之外。","appearance":"西皇霸鹟体长约12.5至18厘米，体重9.7至21克。其显著特征为可竖立的扇形冠羽，雄鸟通常呈红色带蓝色尖端，雌鸟则为黄色或橙色。成鸟上部暗褐色，背部下方有黑色与淡褐色条纹，臀部及尾巴为肉桂红棕色，翅膀深褐色，翼盖和三级飞羽末端有小淡褐色斑点。喉咙白色，胸部温暖的淡褐色带有黑色细条纹，腹部单一暖淡褐色。虹膜颜色各异，喙上部暗褐至黑色，下部角质色至黄色或橙色，腿和脚为暗黄色或橙色。","call":"其鸣唱因亚种而异，包括一系列悠长悦耳的哨音，从响亮的平调开始，随后是一系列低沉的双音节哨音。叫声包括响亮、圆润、空洞的‘keeeyup’或‘keee-yew’声。","habits":"西皇霸鹟主要栖息在湿润的低地森林，包括原始常绿林和次生林，通常在森林下层和中层活动，沿溪流或季节性泛滥的森林中。它们以昆虫为食，觅食高度一般不超过地面3米，但O. c. occidentalis亚种可高达15米。","breeding":"繁殖季节尚未确定，但已知它们会建造长而窄的巢，悬挂在树枝或藤蔓上，通常位于水面上方。每窝产两枚卵，仅雌鸟负责孵化、育雏和喂养雏鸟。","identification":"与其他亚种的区别在于大小、颜色模式和冠羽颜色。O. c. occidentalis亚种主要为明亮的淡褐色，尾部浅黄褐色，胸部无条纹，雄鸟冠羽更偏红色。","protection":"IUCN：VU（易危）。太平洋皇霸鹟估计成熟个体数量在2500至10000之间，且数量被认为正在减少。主要威胁是森林砍伐用于住宅扩张、农业和牧场。该物种总体上较为罕见，O. c. occidentalis亚种被认为是稀少至极稀有。","distribution":"分布于墨西哥南部至南美洲大部分国家，包括中美洲、哥伦比亚、巴西（低于1000米）、东部厄瓜多尔（低于400米）和西部厄瓜多尔（低于600米）。","other":"西皇霸鹟的分类经历了一些变动，国际鸟类分类委员会（IOC）在2024年将其与北方、亚马逊和太平洋皇霸鹟合并为皇霸鹟单个物种，而保留了东皇霸鹟不变。"},{"name":"东皇霸鹟","english_name":"Atlantic Royal Flycatcher","scientific_name":"Onychorhynchus swainsoni","overview":"东皇霸鹟（英文名：Atlantic Royal Flycatcher，学名：Onychorhynchus swainsoni），是雀形目蒂泰霸鹟科皇霸鹟属的鸟类。中等体型，分布于巴西东南部的热带雨林地带。其最显著的特征是头部上方的锤状羽冠，偶尔完全展开时呈现出壮观的火焰红色扇形，带有蓝黑色尖端。","appearance":"东皇霸鹟体长约为16至16.5厘米，体重约23.5克。上体呈暗褐色，拥有醒目的肉桂色臀部和尾巴。喉部白色，腹部为淡赭黄色。雄鸟的羽冠在竖起时显现出红、黑、蓝色调，而雌鸟则是黄、黑、蓝色组合。","call":"其鸣声为下降的、缓慢的一系列哀婉的哨音，叫声则为重复的'keeeyup'或'keee-yew'。","habits":"东皇霸鹟栖息于低地湿润森林，常在密林的中层活动，以昆虫为食。它们在枝条或藤蔓上悬挂着长而窄的巢，通常位于水体上方。","breeding":"繁殖期可能在南半球的春季，巢由雌鸟单独建造，她负责孵卵、育雏和喂养小鸟。已知的繁殖行为记录显示，筑巢活动发生在10月，11月开始产卵，幼鸟在1月被观察到。","identification":"与其他同属物种相比，东皇霸鹟的羽冠颜色和形态是辨识的关键，同时其分布范围也局限于巴西东南部。","protection":"IUCN：VU（易危）","distribution":"东皇霸鹟仅见于南美洲巴西东南部的亚特兰大森林地带，从巴伊亚州向南延伸至圣卡塔琳娜州北部。"},{"name":"茶胸黄腰霸鹟","english_name":"Tawny-breasted Myiobius","scientific_name":"Myiobius villosus","overview":"茶胸黄腰霸鹟（英文名：Tawny-breasted Myiobius，学名：Myiobius villosus），是雀形目蒂泰霸鹟科黄腰霸鹟属的小型鸟类。拥有鲜明的黄色臀部和长长的黑色尾巴，常见于中美洲巴拿马到南美洲玻利维亚西北部的湿润森林山脚和亚热带地区，栖息于海拔600至2100米之间。","appearance":"体长约14厘米，体重约13克。具有大而醒目的眼睛和突出的长嘴角须。雄鸟头部和背部呈暗橄榄色，冠部有隐藏的黄色斑块，胸部至腹部主要为赭褐色，腹部中央有淡黄色区域，尾羽深黑，翅膀边缘呈橄榄棕色。雌鸟相似，但冠部斑块可能为肉桂红或缺失。四个亚种在羽色上略有差异。","call":"发出响亮的‘spit！’叫声。","habits":"单独活动于湿润森林的下层，活跃觅食，常随混合物种群活动。分布于巴拿马东部至安第斯山脉直至玻利维亚。","identification":"与硫磺腰霸鹟相比，体型更大，颜色更深，尤其是下体。与黑尾黄腰霸鹟的区别在于后者缺乏赭色下体，但两者生境不同，茶胸黄腰霸鹟栖息地海拔更高。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲巴拿马，南美洲委内瑞拉西部至玻利维亚西北部，包括哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉。"},{"name":"硫磺腰霸鹟","english_name":"Sulphur-rumped Myiobius","scientific_name":"Myiobius sulphureipygius","overview":"硫磺腰霸鹟（英文名：Sulphur-rumped Myiobius，学名：Myiobius sulphureipygius），是雀形目蒂泰霸鹟科黄腰霸鹟属的鸟类。小型的霸鹟，活跃于中美洲至南美洲热带雨林的低地，从墨西哥东南部延伸至厄瓜多尔西部。其最显著的特征是硫磺黄色的臀部，与橄榄色的上身形成鲜明对比。","appearance":"硫磺腰霸鹟体长约12厘米，上体呈暗橄榄绿色或深褐色，翅膀和尾巴为黑色。胸部为赭石色，腹部为淡黄色。头部中央有一片通常隐藏的黄色斑块，雄鸟较为明显。雌鸟与雄鸟的外观相似，但黄色冠斑可能减小或消失。幼鸟比成鸟颜色更浅，冠部无黄色，胸腹部羽毛边缘带有烟灰色。","call":"该鸟的鸣叫为尖锐的psit声。","habits":"硫磺腰霸鹟常在森林底层活动，尤其在溪流附近，参与多种鸟类组成的混群觅食。它们以昆虫为主食，通过扇尾和展翅展示其黄色臀部。","breeding":"繁殖期间，雌鸟会建造悬挂的梨形巢。关于繁殖的详细信息未提供。","identification":"在墨西哥南部至尼加拉瓜北部范围内，硫磺腰霸鹟是唯一的Myiobius属物种，因此容易识别。在哥斯达黎加西部至厄瓜多尔西部，与黑尾黄腰霸鹟和茶胸黄腰霸鹟有分布重叠，但可通过胸部颜色和体型大小区分。","protection":"IUCN：LC（无危）","distribution":"硫磺腰霸鹟分布于中美洲至南美洲，具体范围从墨西哥东南部至厄瓜多尔西部。","other":"无"},{"name":"须黄腰霸鹟","english_name":"Whiskered Myiobius","scientific_name":"Myiobius barbatus","overview":"须黄腰霸鹟（英文名：Whiskered Myiobius，学名：Myiobius barbatus），是雀形目蒂泰霸鹟科黄腰霸鹟属的鸟类。曾被归类于霸鹟科。分布于南美洲亚马逊盆地，包括巴西、哥伦比亚、厄瓜多尔等地，栖息于亚热带或热带湿润低地森林。","appearance":"体型小，约12.5至12.7厘米长，体重约11克。拥有大眼睛和突出的喙边长毛。头部、颈背橄榄绿，冠顶有一通常隐藏的黄色斑块，脸侧颜色较淡，眼圈黄色并向后加宽，脸颊呈灰色；臀部硫磺黄，上尾覆羽黑色；翅膀深棕色，飞羽边缘略浅的橄榄棕色；尾巴长而圆，黑色；喉部污白色，胸部灰橄榄色或带有褐色调，两侧常带赭色（变异），腹部淡黄色；虹膜暗色；喙宽，上喙灰色到黑色，下喙暗粉红色，尖端暗色；腿灰色。雌雄相似，但雌鸟的冠斑可能减小或缺失。幼鸟似雌鸟。不同亚种胸色稍有差异。","call":"通常不发声，偶尔会发出短促的‘psik’声。","habits":"生活在亚马逊雨林的低层和中层树冠，海拔低于900米，常见于湿润雨林的中层，而非边缘地带。以昆虫为主食，常在空中飞捕，也参与小型混合鸟群觅食。飞行和活动时，会垂下翅膀，展开尾羽，类似旧世界扇尾鸟的行为。","breeding":"具体繁殖信息未详述。","identification":"与其他Myiobius属鸟类相似，但可通过黄色臀部和隐蔽的黄色冠斑进行区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲的亚马逊盆地，包括巴西北部、秘鲁东北部、厄瓜多尔东部、哥伦比亚东部、委内瑞拉南部、圭亚那、苏里南和法属圭亚那。"},{"name":"黑尾黄腰霸鹟","english_name":"Black-tailed Myiobius","scientific_name":"Myiobius atricaudus","overview":"黑尾黄腰霸鹟（英文名：Black-tailed Myiobius，学名：Myiobius atricaudus），是雀形目蒂泰霸鹟科黄腰霸鹟属的小型飞禽。分布自中美洲的哥斯达黎加至南美洲的巴西，常在森林边缘或次生林中发现。","appearance":"体长约12至12.7厘米，体重约10克。头部、颈背及背部呈暗橄榄绿色，具隐蔽的黄色冠斑；腰部硫磺黄色显眼，尾羽黑色且较长，翼部深色带橄榄边。喉咙脏白色，胸带淡褐色或橄榄色，腹部略显黄色。眼睛大，喙宽，上颌灰至黑色，下颌粉红至暗粉色，腿灰色。雌雄相似，但雌鸟的冠斑较小。幼鸟与成鸟相似，但缺少黄色冠斑。不同亚种在胸部橄榄色调、腹部黄色强度和臀部颜色上有差异。","call":"会发出干燥的‘whit’叫声。","habits":"通常单独或成对活动，在树冠下层觅食，常跟随混合物种群。偏好次生林和森林边缘，偶尔在成熟森林中出现。","breeding":"相关信息未提供。","identification":"与硫臀霸鹟极为相似，但硫臀霸鹟常见于更成熟的森林，胸部颜色更深。黑尾黄腰霸鹟更倾向于在森林边缘或次生林中出现。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加至南美洲的厄瓜多尔和巴西东部。","other":"相关信息未提供。"},{"name":"红尾霸鹟","english_name":"Ruddy-tailed Flycatcher","scientific_name":"Terenotriccus erythrurus","overview":"红尾霸鹟（英文名：Ruddy-tailed Flycatcher，学名：Terenotriccus erythrurus），是雀形目蒂泰霸鹟科红尾霸鹟属的唯一物种。体型小巧，羽毛以锈红色调为主，拥有橄榄灰色的冠部和颈背，最显著的特征是其亮锈色的翅膀和尾巴，以及大而黑的圆眼。分布于中美洲至南美洲亚马逊盆地的低地热带雨林。","appearance":"红尾霸鹟长约9.0-10.2厘米，体重仅7克左右。全身大致呈锈色，头部冠部和颈背橄榄灰，前额带橙黄色，眼圈狭窄白色，上喙黑色，下喙淡粉或黄带暗尖，腿色偏橙黄。背部略带橄榄或褐色，臀部鲜亮肉桂色，翼羽和尾羽锈红，翼覆羽边缘亦染肉桂红。喉部灰白，腹部均匀肉桂色，胸间或有橄榄色斑点或微调。雌雄相似，幼鸟更显明亮，尾羽末端偏暗，胸部橄榄色较深。","call":"发出\"see-oo see\"的叫声，以及重复的\"eek eek eek eek eek\"的歌声，有时会振翅制造轻微的呼呼声。","habits":"栖息于海拔1000米以下的湿润山地森林及周边高大的次生林，偏好中间到上层树冠。以昆虫为主食，尤其喜食叶蝉，捕食方式多样，包括从树叶上抓取和空中追逐。","breeding":"繁殖期，雌鸟独力建造类似梨形的吊篮状巢穴，由植物纤维和叶子构成，入口侧倾，悬挂于灌木丛中2-6米高的枝条或藤蔓上。每次产两枚巧克力斑点的白蛋，孵化期约15-16天，期间仅雌鸟参与孵卵，雄鸟不参与照顾幼鸟。","identification":"与同属其他物种区别明显，主要通过其独特的羽色组合，尤其是亮锈色的翅膀和尾巴，以及较大的黑色眼睛识别。幼鸟与成鸟相比，尾羽颜色更深，胸部橄榄色调更浓。","distribution":"繁殖区域从墨西哥东南部延伸至南美洲北部玻利维亚、巴西中北部及圭亚那，亚马逊盆地的整个东侧，以及安第斯山脉西侧的哥伦比亚和厄瓜多尔，进入中美洲。"},{"name":"黑顶蒂泰霸鹟","english_name":"Black-crowned Tityra","scientific_name":"Tityra inquisitor","overview":"黑顶蒂泰霸鹟（英文名：Black-crowned Tityra，学名：Tityra inquisitor），是雀形目蒂泰霸鹟科蒂泰霸鹟属的鸟类。中等体型，广泛分布于中美洲至南美洲东北部，从墨西哥东部至阿根廷东北部。其显著特征为头部的黑色顶冠，雄鸟整体呈银灰色，雌鸟面部呈棕色，拥有较小的黑色顶冠。","appearance":"雄性黑顶蒂泰霸鹟长16.5至20.5厘米，体重33.8至70克。头顶、眼周、耳羽及眼下的区域为黑色；上体大部分为珍珠灰色调的白色；翅膀大多为黑色，三级飞羽灰白色；第9初级飞羽长度大大减小，最外侧初级飞羽正常；尾巴全黑；喉咙和下体白色。雌鸟前额呈黄褐色，头两侧呈栗色或锈色，背部较暗且带有淡褐色条纹，喉咙和胸部有脏淡灰色斑点，腹部呈淡黄灰色。幼鸟与雌鸟相似，但有更复杂的颜色图案。","call":"通常较为安静，典型的叫声包括粗糙的咕噜声、干涩的喉音、尖锐的蛙鸣般的'她赫-她赫克'，'斯威克'或'兹克-兹克-兹克'，以及一系列低沉、微弱、鼻音的'切特-丘特，查-切普'音符，通常两音节一组发出。叫声也描述为一种奇特的鼻音，具有嗡嗡声质，'乌恩特'或'乌恩特-乌恩特'。","habits":"栖息于湿润到半湿润的高大森林树冠和成熟的次生林边界，开阔地带伴以散落的高树，河流边缘和种植园，偶尔出现在河岸植被。主要生活在海拔1200米以下，大部分南美洲地区海拔低于1000米。主要以果实为食，但也捕捉大量昆虫喂养幼鸟。","breeding":"繁殖期在中美洲和南美洲的不同月份，筑巢于老啄木鸟洞或类似树洞中，位于死树或活树的中上层，洞内填充死叶、小枝条和其他植物物质。雌雄双方共同参与筑巢。窝卵数不确定，大概为三枚，由雌鸟孵化，孵化期约18至21天。幼鸟由双亲喂养，离巢期约为20至30天。","identification":"与较常见的花脸蒂泰霸鹟相比，黑顶蒂泰霸鹟可通过其坚实的黑色喙来区分。雄鸟整体更银白，雌鸟背部带有褐色晕染且斑点更为明显。","protection":"IUCN：LC（无危）。虽然在某些地区较为罕见，但在其分布范围南部似乎更为丰富。","distribution":"分布于中美洲至南美洲东北部，包括墨西哥东部至阿根廷东北部，也见于中美洲各国、南美多个国家和地区。","other":"在北美的记录可能限于冬季迁徙或迷鸟。"},{"name":"黑尾蒂泰霸鹟","english_name":"Black-tailed Tityra","scientific_name":"Tityra cayana","overview":"黑尾蒂泰霸鹟（英文名：Black-tailed Tityra，学名：Tityra cayana），是雀形目蒂泰霸鹟科蒂泰霸鹟属的中型雀形目鸟类。其最显著的外部特征是雄鸟的黑白相间羽毛，以及雌鸟背部的暗褐色条纹。分布于热带南美洲，包括委内瑞拉、特立尼达、圭亚那等地。","appearance":"雄性黑尾蒂泰霸鹟体长约20-22厘米，体重60-70克，头部至眼下方呈黑色，翼部、尾羽黑色，上身淡银白色或珍珠灰色，下体白色略带灰色调。雌鸟背部、颈部和下体有明显的深褐色条纹，头部棕色。成年个体有红眼圈和红基黑色喙。幼鸟羽毛详情未知。","call":"发出嗡嗡的短促叫声，如'ed'、'rek'、'urd'或'wenk'，常以双音节或三音节连发。","habits":"栖息于低地森林边缘、次生林、种植园树荫下，常见于海拔500米以下，偶尔可达1100米。成对或小群出现，有时单独活动，好斗，会驱赶其他鸟类。以果实为主食，辅以昆虫喂养幼鸟。通常高栖于裸枝，或在空中悬停捕食。","breeding":"繁殖季节主要在11月至3月，但部分地区全年可见繁殖活动。巢建于树洞中，如旧啄木鸟巢或枯死的棕榈树冠。雌鸟孵化，孵化期约18-21天，双亲共同喂养雏鸟，离巢期约20-30天。已知被紫辉牛鹂寄生。","identification":"雄鸟与雌鸟在外表上有明显区别，雌鸟背部具暗褐色条纹，头部较灰褐，雄鸟则为黑白分明。与花脸蒂泰霸鹟相比，黑尾蒂泰霸鹟头部黑色覆盖更广，尾羽无白色。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美洲，包括委内瑞拉、特立尼达、圭亚那、哥伦比亚东部、巴西北部、厄瓜多尔东部、秘鲁东部和玻利维亚北部。","other":"在巴西东南部，曾报道过局部灭绝现象，例如在里约热内卢州的诺瓦弗里堡附近。"},{"name":"花脸蒂泰霸鹟","english_name":"Masked Tityra","scientific_name":"Tityra semifasciata","overview":"花脸蒂泰霸鹟（英文名：Masked Tityra，学名：Tityra semifasciata），是雀形目蒂泰霸鹟科蒂泰霸鹟属的鸟类。中等体型，最显著的外部特征是具有独特的红眼环和红基喙。分布于中美洲和南美洲，自墨西哥至阿根廷东北部，广泛存在于热带和亚热带森林及邻近的半开放地带。雄鸟头部黑色，雌鸟头部棕色或灰色，雄鸟有明显的黑色面罩。","appearance":"成年雄性花脸蒂泰霸鹟体长20-24厘米，体重77-88.1克。雄鸟的脸部图案明显，有黑色面罩，周围是裸露的玫瑰红色皮肤，眼周区域由黑色羽毛环绕。头部和背部呈淡灰白色，略带珍珠灰色调。翅膀主要是黑色，翼端白色。尾巴灰白，有宽黑亚端斑。雌鸟头部颜色较暗，为烟熏色或深棕色，没有黑色面罩，背部较暗，带有棕色斑点和条纹，腹部较暗淡，更偏灰白色。幼鸟与成年雌鸟相似，但尾羽尖端较窄，上体颜色更淡，带有棕色洗染。","call":"花脸蒂泰霸鹟的叫声独特，常发出类似嗡嗡、鼻音、断续的、呱呱或咔嚓声，如“zzzu rrk”或“zzr zzzrt”。也常发出干燥、鼻音、哼哼或几乎像猪一样的“querp”声，有时会连续两次发出“gurank-gureek”或“reek-reek”的声音，第二声较高。","habits":"生活在湿润至半干旱森林的树冠层，沿着森林边缘的高大树木，林地，棕榈树林，次生林，相对开阔的区域，从森林空地到稀树草原，以及种植园。主要栖息于海拔1200-1500米以下，但在巴拿马和委内瑞拉等地可达1800米以上，哥斯达黎加太平洋斜坡可达2300米，西墨西哥甚至可达2500米。以果实为主食，偶尔捕食昆虫和小型蜥蜴。","breeding":"繁殖季节在哥斯达黎加至少从三月持续到七月，有时会有两窝。在哥伦比亚，一月到五月（西北部）发现处于繁殖状态的个体，筑巢和占据洞穴的行为在二月至四月和八月被观察到。雄鸟在雌鸟面前展示时，会在水平树枝上来回奔跑，同时发出呱呱声。巢建在树洞或旧啄木鸟洞中，通常位于树的中上部，高度约12-30米，洞内填满大量枯叶、枝条、花序和其他植物物质。每窝产2-3枚卵，由雌鸟孵化，孵化期大约18-21天，雏鸟由双亲喂养，离巢期约为20-30天。","identification":"雄鸟与黑顶蒂泰霸鹟相似，但可通过较小的黑色面罩（不包括颈背）和白色的尾尖来区分。","protection":"IUCN：LC（无危）。在大范围内，花脸蒂泰霸鹟较为常见。在安第斯山脉西部似乎更为丰富。其生存环境在大范围内仍保持相对原始状态。在许多国家公园和其他保护区都有分布。其分布范围似乎正在向阿根廷东北部的米西奥内斯省和巴西扩展。","distribution":"分布于中美洲和南美洲，自墨西哥至阿根廷东北部，包括哥斯达黎加、哥伦比亚、巴拿马等地。"},{"name":"大希夫霸鹟","english_name":"Varzea Schiffornis","scientific_name":"Schiffornis major","overview":"大希夫霸鹟（英文名：Varzea Schiffornis，学名：Schiffornis major），是雀形目蒂泰霸鹟科希夫霸鹟属的鸟类。传统上曾被归入拟鹂科，但现有证据强烈支持其应分类在蒂泰霸鹟科，这一分类已被SACC采纳。分布于南美洲亚马逊盆地的西部和中部，包括亚马逊流域的玻利维亚、巴西、哥伦比亚、厄瓜多尔、秘鲁以及委内瑞拉的部分地区。","appearance":"这是一种体型相对较小、橙棕色的森林中层鸟类。翅膀颜色更深呈棕褐色，头部有变化不定的灰色调。雄鸟与雌鸟在羽毛颜色上相似，幼鸟的羽毛色调可能较为暗淡。","call":"它的鸣叫声独特，是一种高音的哨声，表现为‘tuw-tuwee . . . tee, tuweep！’的连续音节。","habits":"大希夫霸鹟栖息于季节性泛滥的森林和河岸森林中较高的树冠层。它们通常单独或成对活动，很少加入混杂的物种群。这种鸟的活动范围主要限于亚马逊雨林的特定生态位。","breeding":"关于大希夫霸鹟的繁殖习性的具体信息有限，但基于同科其他物种的观察，可以推测它们在繁殖季节会筑巢于树洞或隐蔽处。","identification":"与某些阿提拉鸟（Attila）类似，但具有更短的尾巴和较短、较粗的喙，这成为识别的重要特征。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲的亚马逊雨林中部和西部，包括亚马逊流域的玻利维亚、巴西、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉的部分地区。","other":"大希夫霸鹟的系统发育历史表明它在进化上与拟鹂科有密切关系，但现在科学界普遍接受其在蒂泰霸鹟科中的分类位置。"},{"name":"圭亚那希夫霸鹟","english_name":"Guianan Schiffornis","scientific_name":"Schiffornis olivacea","overview":"圭亚那希夫霸鹟（英文名：Guianan Schiffornis，学名：Schiffornis olivacea），是雀形目蒂泰霸鹟科希夫霸鹟属的鸟类。中等体型的热带美洲鸟类，长约15.5至16.5厘米，体重28至37克。主要分布在委内瑞拉东南部、圭亚那及巴西中北部的成熟雨林和较老的次生林中，通常单独活动，偶尔跟随混种鸟群。其外形类似大型的拟鸫希夫霸鹟，全身呈单调的橄榄褐色，具独特的大眼外观。","appearance":"体长约15.5至16.5厘米，重约28至37克，整体呈橄榄褐色，颜色较为单一，外观上与S. veraepacis acrolophites相似但地理分布相隔甚远。雄鸟和雌鸟外观一致，幼鸟尚未有详细描述。","call":"叫声为拖长且抑扬顿挫的哨声，间隔时间较长，易于模仿。","habits":"栖息于湿润和潮湿的森林，偶尔出现在邻近的高大次生林，几乎总是在森林内部，很少靠近边缘。主要生活在低地，但在委内瑞拉的Sierra de Lema记录到高达约1450米的高度。在繁殖季节，通过无线电追踪研究显示，雄鸟的领地范围大约为14.3至16.5公顷，雌鸟约为20.1公顷。","breeding":"繁殖季节推测在苏里南为1月至2月，在圭亚那南部为8月至9月。在圭亚那的4月份发现的巢穴位于约1.5米高的棕榈树桩的洞穴底部，内衬枯叶和少量纤维。每次产卵两枚，蛋壳为淡黄色，带有深灰色和淡紫色斑点，主要集中在较大的一端，尺寸为24.6至24.7毫米×18.3毫米。","identification":"与橄榄绿娇鹟相比，圭亚那希夫霸鹟体型更大，更偏向橄榄褐色。与S. turdina wallacii相比，背部更偏橄榄色，喉咙更偏棕色。与S. t. amazonum相比，上体略显苍白，冠部红色较少，腹部更灰。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉东南部（Bolívar、Delta Amacuro）、圭亚那地区及亚马逊北部巴西，从下Negro河东至Amapá。在巴西Manaus附近，它是下层林带鸟类中更为常见的物种。","other":"传统上被归类于拟鸫希夫霸鹟科，但现有证据强烈表明其更适合归入Tityridae科，现已由SACC重新分类。"},{"name":"北希夫霸鹟","english_name":"Northern Schiffornis","scientific_name":"Schiffornis veraepacis","overview":"北希夫霸鹟（英文名：Northern Schiffornis，学名：Schiffornis veraepacis），是雀形目蒂泰霸鹟科希夫霸鹟属的鸟类。主要分布在中美洲东南部至南美洲西部和厄瓜多尔，常见于潮湿热带低地森林的阴暗林下层。","appearance":"体型长约15.5至16.5厘米，重量介于21至40克之间，性别相似。成鸟体羽呈暗橄榄褐色，眼环较浅，突出大眼睛，喙细长黑色。幼鸟上、下体部分呈较暗淡的红棕色，冠部更亮，喉部和腹区偏灰色。各亚种颜色略有差异，如指名亚种暗棕橄榄色，翅膀更暖棕色，腹部暗淡灰色，体型最大。","call":"发出幽灵般的模糊哨音，能远距离传播且容易模仿。歌声不规律，不连续重复，通常在清晨长时间间隔后发出2至4个清晰、丰富而音乐性的哨音，最后一个音符急剧上升，地理变异显著。","habits":"栖息于湿润和湿热森林，偶尔出现在高大的次生林边缘，活动范围从低地到海拔约1425米，局部可达1700米。主要以果实和昆虫为食，常单独觅食，偶尔加入混群。在森林底层穿梭，常攀附于垂直茎上搜寻昆虫。","breeding":"繁殖季节在2月至8月间，筑巢主要由雌鸟独立完成，巢为大型杯状，直径约15厘米，主要由枯叶构成，内部铺有根须或黑色真菌。每窝产两枚浅黄色带有黑色、深棕色和淡灰色斑点的蛋，孵化期20至21天，仅由雌鸟承担。雏鸟孵化时带灰色绒毛，仅由母鸟喂养。","identification":"与其他希夫霸鹟物种的区别在于体形较粗壮，暗橄榄褐色羽毛，眼环浅色突出，喙较细长，鸣声具有地方性差异。","protection":"IUCN：LC（无危）。在多数保护区中数量一般不多，但在某些地区如墨西哥、哥斯达黎加、巴拿马、哥伦比亚和厄瓜多尔等地局部较为常见。总体分布范围广阔，估计为2,740,000平方公里。","distribution":"分布于中美洲东南部至南美洲西部，包括墨西哥东南部、哥斯达黎加、巴拿马、哥伦比亚和厄瓜多尔，局部在低地地区数量较少。","other":"传统上被归类于拟鹂科，但证据显示其更适于蒂泰霸鹟科。"},{"name":"山希夫霸鹟","english_name":"Foothill Schiffornis","scientific_name":"Schiffornis aenea","overview":"山希夫霸鹟（英文名：Foothill Schiffornis，学名：Schiffornis aenea），是雀形目蒂泰霸鹟科希夫霸鹟属的鸟类。中等体型，外表平实，全身呈暗褐色调，雌雄羽毛相似，主要栖息于南美洲厄瓜多尔中部至秘鲁北部的安第斯山脉东坡云雾森林中，偶尔见于哥伦比亚南部。","appearance":"成鸟体长约15.5至17.3厘米，体重28.5至31克，颜色均匀一致，上体偏棕色，少有绿色光泽，胸部更偏棕色，腹部带绿，翼端色暖。与S. veraepacis acrolophites和S. v. rosenbergi类似，但上体棕色更深，腹部绿色更明显。","call":"主要鸣声为哀婉的‘deuu…teé’wOOee, tew-tew’或‘hew EeuEE TU-hew’，音调先升后降，整体节奏较快，比S. veraepacis rosenbergi更为急促和有节奏感。","habits":"常栖息于森林底层，偏好成熟次生林，海拔高度在900至1700米之间。以昆虫和果实为食，很少加入混合物种觅食群。捕食方式为从枝头突然飞扑向空中或树叶。","breeding":"具体繁殖信息缺失。","identification":"与其他希夫霸鹟种类的区别在于分布区域、声音和海拔高度，尤其与S. turdina amazonum相比，整体色彩更鲜艳，腹部更绿色，背部具青铜色，胸部略带金棕色。","protection":"IUCN：LC（无危）。由于栖息地丧失和森林破碎化，其数量可能正在下降。仅分布于有限的保护区，如厄瓜多尔的Sumaco Napo-Galeras国家公园。","distribution":"繁殖区域位于南美洲厄瓜多尔中部至秘鲁北部，最近确认在哥伦比亚南部也有分布。","other":"2013年，美国鸟类学家联盟（AOU）将其从thrush-like schiffornis物种复合体中分离出来。"},{"name":"红翅希夫霸鹟","english_name":"Russet-winged Schiffornis","scientific_name":"Schiffornis stenorhyncha","overview":"红翅希夫霸鹟（英文名：Russet-winged Schiffornis，学名：Schiffornis stenorhyncha），是雀形目蒂泰霸鹟科希夫霸鹟属的鸟类。分布于中美洲巴拿马至南美洲哥伦比亚北部和委内瑞拉北部的森林地带。其显著特征为暗棕色的羽毛，翅膀和头部略带温暖的红褐色。","appearance":"体长约15.5至16.5厘米，体重30至34克。外观均匀呈暗色，但翅膀和头部呈现较温暖的红褐色。喙部较大，形状似莺鸟，略显钩状。两性相似，但幼鸟上体和下体颜色较为暗淡，冠部更亮，喉咙和腹部区域呈灰色。不同亚种在颜色上有细微差异，如指名亚种上体更暗且红褐色更为明显，尤其是翅膀部分，而panamensis亚种则整体较浅，冠部、翅膀和尾巴颜色更鲜艳，喉咙处的肉桂红与胸部和腹部的灰橄榄色形成对比。","call":"鸣唱为一系列通常2至4个清晰、丰富、音乐性的哨音，其中第二和第三个哨音上扬明显，例如在巴拿马东南部（panamensis亚种）的叫声被描述为“teeuu, wheet-wheet, wheet”。","habits":"栖息于湿润森林或邻近的高大次生林中，几乎总是在森林内部，很少出现在边缘。分布于低地至约1800米的海拔，如在委内瑞拉北部可达此高度，哥伦比亚中部安第斯山脉有记录到1550米的高度。饮食以水果和昆虫为主，曾在巴拿马采集的标本中发现毛虫、蝉和小浆果。单独觅食，偶尔加入混群觅食队。在森林下层穿梭，常贴着垂直树干1至2米高处探查，利用短距离空中突袭捕捉树叶上的昆虫。","breeding":"繁殖季节在哥伦比亚北部为1月至6月，巢杯形，内部尺寸约为22.9毫米×18.1毫米，壁厚30毫米，深度56.6毫米，外部尺寸139.4毫米×144.2毫米×115.7毫米。一窝产两枚淡奶油色蛋，带有深紫色斑点，平均大小18.3毫米×23.2毫米，重量4.49克。孵化仅由雌鸟承担，持续21天，雏鸟期为20天，孵化期间平均每天访问巢穴4.72次，雏鸟阶段每小时访问1.25次。","identification":"与Thrush-like Schiffornis物种复合体中的其他成员有明显的区别，具体差异在分类学讨论中已涵盖。","protection":"IUCN：LC（无危）。虽然难以见到，但在巴拿马东部、哥伦比亚和委内瑞拉北部普遍存在，但在委内瑞拉似乎有所减少。在巴拿马的Bocas del Toro地区，panamensis亚种的密度估计约为4对/100公顷。在多个保护区中有所记录，包括委内瑞拉的Henri Pittier国家公园。","distribution":"分布于中美洲的巴拿马至南美洲的哥伦比亚北部和委内瑞拉北部，主要栖息于低地至约1800米的湿润森林或邻近的高大次生林中。","other":"传统上，红翅希夫霸鹟曾被归类于拟鹂科，但现有证据强烈表明它更适合归入蒂泰霸鹟科，这是目前南美鸟类分类委员会所采纳的分类。"},{"name":"拟鸫希夫霸鹟","english_name":"Brown-winged Schiffornis","scientific_name":"Schiffornis turdina","overview":"拟鸫希夫霸鹟（英文名：Brown-winged Schiffornis，学名：Schiffornis turdina），是雀形目蒂泰霸鹟科希夫霸鹟属的鸟类。其羽毛颜色较为统一，上部呈橄榄绿色，翼部带有锈色边缘，腹部略显灰白色调。分布于中美、南美的亚马逊雨林及巴西东部，常见于湿润森林内部，通常在低至中层树冠活动。","appearance":"成鸟体长15.5-16.5厘米，体重39-43克（指名亚种），体型中等，羽毛色泽单一，以橄榄褐色为主，翼部边缘带锈色，腹部偏橄榄灰，胸部略显棕色。眼睛大而黑，眼周有淡色环。喙黑色，腿脚橄榄灰色。雌雄外观相似，幼鸟与成鸟相似。不同亚种在羽毛色调上有细微差异。","call":"鸣声清脆悦耳，通常为连续2-4个富有音乐性的哨音，最后一个音节明显上扬。在东亚马逊平原，鸣声为缓慢的‘teeeeu, weee, tu-weeeé’。","habits":"栖息于湿润森林内部，偶尔出现在较高的次生林和较干燥的森林。活动范围从低地至海拔约1500米，但在巴西大部分区域，海拔多低于800米。几乎全年定居，以果实和昆虫为食，单独觅食，很少加入混合物种群。在森林底层穿梭，常贴着垂直树干搜寻食物。","breeding":"在东亚马逊的巴西地区，已知二月有产卵记录，巢由纤维和干叶构成，置于半腐烂的树桩中，巢内有两枚淡黄白色的蛋，带有稀疏的黑色斑点。其他繁殖细节未知。","identification":"与同类物种相比，拟鸫希夫霸鹟的暗眼周围有不明显的淡色环，上体颜色从褐色到橄榄色变化，亚种间存在细微的色彩差异。","protection":"IUCN：LC（无危）。在广阔的分布范围内，许多国家公园和保护区为其提供了栖息地，如玻利维亚的Madidi国家公园，巴西的Carajás保护单位和Tapajós国家公园，秘鲁的Manu生物圈保护区。巴西东部（intermedia, nominate）的种群因森林砍伐而大幅减少，仅在少数保护区中有所记录。","distribution":"分布于中美洲、南美洲，具体涵盖委内瑞拉南部至亚马逊雨林，巴西东部的广大区域。","other":"历史上曾被归类于拟霸鹟科，后根据证据调整至蒂泰霸鹟科。2013年，AOU将其从thrush-like schiffornis物种复合体中分离出来。"},{"name":"绿希夫霸鹟","english_name":"Greenish Schiffornis","scientific_name":"Schiffornis virescens","overview":"绿希夫霸鹟（英文名：Greenish Schiffornis，学名：Schiffornis virescens），是雀形目蒂泰霸鹟科希夫霸鹟属的鸟类。中等体型的橄榄绿色鸟类，分布于南美的巴西东南部和南部、巴拉圭东部以及阿根廷东北部。其自然生境为亚热带或热带湿润的低地森林和山地森林，以及重度退化的前森林区域。","appearance":"绿希夫霸鹟体长约15.5厘米，体重在21.5至28.5克之间，雌雄相似。外观较为暗淡，具有一对小头、大眼睛和短粗喙。全身呈暗淡的绿褐色，翅膀和尾巴对比鲜明地呈现红褐色；腹部颜色较浅；虹膜为深棕色；喙和腿为橄榄灰色。与近似种拟鸫希夫霸鹟相比，其整体颜色更偏绿色，翅膀和尾巴的红褐色对比更加明显，喙略小。幼鸟特征未被描述。","call":"其鸣唱通常在长时间间隔后发出，由2至4个清晰悦耳的哨音组成，重点强调在最后几个音符上。","habits":"关于其饮食和觅食行为的信息较少；已知成鸟会食用昆虫和毛虫。觅食行为可能与拟鸫希夫霸鹟类似。栖息于亚热带或热带湿润的低地森林和山地森林的下层及次生林。","breeding":"繁殖期通常在10月至次年2月间，这与森林鸟类常见的繁殖时间相吻合。产卵形状从椭圆到长椭圆形不等。","identification":"与拟鸫希夫霸鹟的区别在于更绿的整体色彩、红褐色的翅膀和尾巴形成鲜明对比，以及略小的喙。","protection":"IUCN：LC（无危）","distribution":"绿希夫霸鹟主要分布于南美洲，具体包括巴西的东南部和南部，巴拉圭东部以及阿根廷东北部。"},{"name":"点斑伞鸟","english_name":"Speckled Mourner","scientific_name":"Laniocera rufescens","overview":"点斑伞鸟（英文名：Speckled Mourner，学名：Laniocera rufescens），是雀形目蒂泰霸鹟科斑伞鸟属的热带低地鸟类，分布于中美洲和南美洲，从墨西哥南部到厄瓜多尔。其栖息于湿润的常绿森林，主要活动在阴暗林下的中层。","appearance":"点斑伞鸟长约20厘米。头部圆润，眼周有一圈窄黄色环。全身呈现锈褐色，翅膀上有明显的锈色斑点，胸部有淡色眼圈，下体颜色相近，常带有较深的鳞状斑纹。雄鸟有黄色胸羽簇，通常隐藏不显。","call":"它以清澈响亮的歌声宣告存在，从低枝上发出一连串约十二个重复的\"Tleeyr, tleeyeei, tleeyeei, tleeyeei...\"的声音。","habits":"点斑伞鸟性格隐秘，通常独居，偶尔加入小型混群。其栖息地为潮湿森林的中下层树冠，海拔可达1000米左右。以昆虫、其他节肢动物、小型爬行动物和水果为食。","breeding":"关于点斑伞鸟的繁殖信息知之甚少，一般认为它是孤独的觅食者。","identification":"与之相似的棕悲霸鹟头型不同，喙部较窄，缺乏胸翼标记。棕伞鸟喙基较宽，色彩更均匀，没有黄色胸羽簇。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和北南美洲，范围从墨西哥到巴拿马、伯利兹、哥伦比亚和厄瓜多尔。"},{"name":"栗翅斑伞鸟","english_name":"Cinereous Mourner","scientific_name":"Laniocera hypopyrra","overview":"栗翅斑伞鸟（英文名：Cinereous Mourner，学名：Laniocera hypopyrra），是雀形目蒂泰霸鹟科斑伞鸟属的鸟类。由法国自然学家Louis Pierre Vieillot于1817年首次描述。主要栖息在南美洲的亚马逊雨林，包括巴西东南部，其幼鸟拥有独特的生存策略，通过模仿有毒毛虫来逃避捕食者的注意。","appearance":"幼鸟出生即覆盖着亮丽的橙色长绒毛，末端呈白色，模仿有毒毛虫的外观和蠕动行为，以此作为自我保护机制。成鸟则具有灰色的体羽，肩部带有小橙色斑点，眼周有一圈细窄的黄色环，这与完全灰色的尖声伞鸟和灰悲霸鹟形成鲜明对比。","call":"该鸟发出尖锐、高音的鸣叫声，使其在茂密的雨林中容易被察觉。","habits":"栗翅斑伞鸟栖息于亚马逊雨林的中层，偏好高大的雨林环境。成鸟每小时仅喂食幼鸟一次，以降低暴露风险。幼鸟不会主动向成鸟乞食，以防混淆掠食者。这种行为策略有助于提高幼鸟在出生后20天内的存活率，之后幼鸟能够独立生存。","breeding":"幼鸟的伪装是其生长初期的重要保护机制。成鸟的繁殖习性和巢穴细节尚需更多研究。","identification":"与尖声伞鸟和灰悲霸鹟相比，栗翅斑伞鸟的肩部橙色斑点和黄色眼环是其显著的识别特征。","protection":"IUCN：LC（无危）","distribution":"分布于整个亚马逊-奥里诺科盆地，包括哥伦比亚东南部、委内瑞拉南部与东部（北至苏克雷东南）、圭亚那、厄瓜多尔东部、秘鲁东部、玻利维亚北部以及亚马逊地区的巴西；巴西沿海东部巴伊亚东南部和埃斯皮里图桑托北部有孤立的种群。","other":"幼鸟的伪装行为是已知鸟类中罕见的警戒拟态案例，模仿有毒昆虫以增强生存几率。"},{"name":"黄喉紫须伞鸟","english_name":"Buff-throated Purpletuft","scientific_name":"Iodopleura pipra","overview":"黄喉紫须伞鸟（英文名：Buff-throated Purpletuft，学名：Iodopleura pipra），是雀形目蒂泰霸鹟科紫须伞鸟属的鸟类。主要分布在巴西东部和东南部的亚热带湿润森林中，以其独特的外观和罕见性而著称。","appearance":"这种鸟体型小，翼展宽大，尾巴较短。雄鸟上身呈暗灰色，头顶颜色更深，具有一条明显的淡色臀带和鳞状腹纹。喉咙和胸部为肉桂色，腹部其余部分白色，带有灰色条纹。最显著的特征是在上侧翼有一小簇紫色羽毛，但在雌鸟中缺失。幼鸟有明显的白色羽尖。","call":"它的叫声为高音且微弱的“se-se-see”，有时在飞行中快速重复，形成类似昆虫的颤音，还有双音节的哨声“seee, fee”。","habits":"主要以寄生植物（如桑寄生）的浆果为食，偶尔也吃小昆虫。通常在树冠层觅食，偏好枝叶茂密的大树，尤其是长有寄生植物的豆科树木。它会从树叶上抓取昆虫或在空中捕捉。","breeding":"繁殖季节记录在7月至10月，筑巢高度约为18米，巢为小型杯状，由苔藓等物质构成，通常位于光秃树干的细枝上。每窝仅产一枚卵，孵化和雏鸟成长周期未知。","identification":"雄鸟的紫色翼斑和肉桂色喉咙是识别关键。雌鸟缺乏紫色羽毛，通过这些特征与同类其他物种区分开来。","protection":"IUCN：EN（濒危）","distribution":"分布在巴西的东南部和东部，主要栖息于亚热带或热带的低地湿润森林中。","other":"由于栖息地的大量破坏，黄喉紫须伞鸟的全球种群数量估计在250至2500只成熟个体之间，每个亚种群少于250只。"},{"name":"紫须伞鸟","english_name":"Dusky Purpletuft","scientific_name":"Iodopleura fusca","overview":"紫须伞鸟（英文名：Dusky Purpletuft，学名：Iodopleura fusca），是雀形目蒂泰霸鹟科紫须伞鸟属的鸟类。是南美洲特有的小型鸟类，传统上被归类于鵙鵯科，但最新的证据支持其属于蒂泰霸鹟科。在圭亚那低地森林中广泛分布，同时也出现在委内瑞拉东南部极东地区和巴西东北部的局部地带。紫须伞鸟以其独特的外形和栖息习性而著称。","appearance":"紫须伞鸟体型小，长约11厘米，体重约15.3克。拥有相对较长的燕子般的翅膀和短尾巴，仅超出尾羽覆羽5-10毫米。嘴宽且基部略膨胀，尖端呈钩状。雄鸟上身呈现灰黑色，臀部有一白色带纹，下体烟棕色，胸部中央白色，上侧腹部长有小簇紫色羽毛；眼虹膜深棕色，上喙黑色，下喙铅灰色，腿脚也是深铅灰色。雌鸟侧腹部羽毛为白色。幼鸟羽毛明显白尖，换羽后与成鸟相似。比Isabell's Purpletuft（Isabell's Purpletuft）更小，颜色更深，头部、喉咙和侧腹部无白色。","call":"发出柔和的颤音和高亢、细薄的鸣叫，与Isabell's Purpletuft的叫声类似。","habits":"紫须伞鸟栖息于高大的雨林和白色的沙地森林中，通常成对或小群活动。它们以果实为食，偶尔在空中捕食昆虫。","breeding":"在法属圭亚那发现的巢穴位于约20米高的树冠水平枝上，几米低于树顶，巢小而锥形。在委内瑞拉二月观察到有幼鸟的亲鸟。其他繁殖信息尚不清楚。","identification":"与燕翅䴕相比，紫须伞鸟在树梢裸露的枝条上栖息的习惯相似，但后者缺乏紫须伞鸟胸部中央的白色条纹。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美的委内瑞拉东南部、圭亚那和巴西东北部。在委内瑞拉的伊马塔卡森林保护区和埃尔多拉多也有记录。","other":"由于栖息地隐蔽，以及在未受破坏的森林中观察小型树梢鸟类的难度，紫须伞鸟可能被低估了其真实数量。"},{"name":"白眉紫须伞鸟","english_name":"White-browed Purpletuft","scientific_name":"Iodopleura isabellae","overview":"白眉紫须伞鸟（英文名：White-browed Purpletuft，学名：Iodopleura isabellae），是雀形目蒂泰霸鹟科紫须伞鸟属的鸟类。分布于西部和南部亚马逊雨林。其最显著的特征为独特的面部花纹和隐蔽的紫色侧翼羽毛。","appearance":"体长约11至12厘米，体重约20克。雄鸟具有白色的眼前区、眼后纹和髭纹，头部、背部、翅膀和尾巴呈黑褐色，臀部有一白色条带；腹部白色，胸部侧面呈暗棕色，侧翼上有小簇紫色羽毛。雌鸟侧翼羽毛为白色。幼鸟羽毛明显带有白色尖端，换羽后与成鸟相似。paraensis亚种上部颜色更深，侧翼条纹更密集。","call":"发出一系列微弱而高音的鸣叫，通常为颤音或喋喋不休的声音，例如‘tre-e-ed’和升调的‘ueeéé’；还会有柔和的‘sr’r’r’颤音系列，微弱的‘jee-jee-jee’和细薄的‘ti-ti-ti-ti-ti-ti-ti’颤音。","habits":"栖息于湿润森林的树冠和边缘地带，主要生活在海拔500米以下，偶尔可达900米。以昆虫为主食，常在树梢进行飞行捕食，也会吃果实，包括槲寄生浆果，通常短暂悬停取食。通常成对或小群体活动。","breeding":"在巴西东部（贝伦地区）的9月至12月期间有筑巢记录。已知的唯一一个巢穴是一个微型杯状结构，由植物纤维构成，外部覆盖蜘蛛网，固定在死树顶部18至19米高的细水平枝上。没有更多繁殖信息。","identification":"通过独特的面部图案和可见时的紫色侧翼羽毛来识别，与同属其他物种区别明显。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美的亚马逊雨林，包括巴西、厄瓜多尔、秘鲁等地。","other":"尽管总体上不构成全球威胁，但由于观察难度大，可能被低估了数量。在多个保护区如Cuyabeno保护区（厄瓜多尔）、马努国家公园和生物圈保护区，以及Tambopata-Candamo保留区（秘鲁）内有所分布。"},{"name":"鵙伞鸟","english_name":"Brazilian Laniisoma","scientific_name":"Laniisoma elegans","overview":"鵙伞鸟（英文名：Brazilian Laniisoma，学名：Laniisoma elegans），是雀形目蒂泰霸鹟科鵙伞鸟属的绿黄相间的小型鸟类，尽管其通用名称暗示其为鵙或鵙伞鸟，实际上与这些分类相去甚远。该物种仅分布于南美洲巴西的东南部，栖息于大西洋森林中。","appearance":"鵙伞鸟拥有引人注目的绿色与黄色外观，雄鸟头顶呈黑色，脸颊和背部橄榄绿色，下体具明显的鳞状斑纹。雌鸟色彩稍显暗淡，黑色顶冠不如雄鸟鲜明。其最显著的特征之一是长而弯曲的喙以及大眼睛。","call":"鵙伞鸟的鸣唱为高音且尖锐的‘psieeeehh’声，尾音急剧上升，这一叫声重复出现，具有辨识度。","habits":"这种鸟生活在巴西东南部的湿润森林中，活动范围从林下层至次冠层。它们的栖息地通常在大西洋森林的特定区域。","breeding":"关于鵙伞鸟的繁殖习性，目前科学文献中的详细资料较为有限。","identification":"鵙伞鸟与安第斯鵙伞鸟在外形上有明显差异，后者分布在南美洲安第斯山脉的湿润森林中。","protection":"IUCN：NT（近危）","distribution":"鵙伞鸟的分布局限于南美洲巴西的东南部，特别是在大西洋森林地带。","other":"鵙伞鸟曾被认为与安第斯鵙伞鸟是同一物种，但现在被视为独立的种类。"},{"name":"安第斯鵙伞鸟","english_name":"Andean Laniisoma","scientific_name":"Laniisoma buckleyi","overview":"安第斯鵙伞鸟（英文名：Andean Laniisoma，学名：Laniisoma buckleyi），是雀形目蒂泰霸鹟科鵙伞鸟属的鸟类。安第斯山麓最具传奇色彩的鸟类之一，体羽以鲜绿与金黄为主，体型略大于鵙伞鸟属近缘种。雄鸟具黑色顶冠，雌鸟及幼鸟羽色稍暗并具鳞状斑纹。该鸟极为罕见且分布零散，仅见于安第斯山东坡自委内瑞拉西部至玻利维亚的潮湿山脚林，尤其以厄瓜多尔与秘鲁记录居多。","appearance":"体长17.3–18.0厘米，体重雄鸟40–48克，雌鸟45.8–59.8克。喙长而末端钩曲，虹膜深红至近黑色，眼周有淡黄绿色环。雄鸟头顶黑色，上体橄榄绿，下体鲜黄，胸侧、胁部及尾下覆羽具不规则黑色粗横斑。雌鸟黑色顶冠较暗淡，几乎与上体同色，下体布满细密黑鳞纹。幼鸟翼覆羽具栗褐色斑点，并见丝状白色端羽。","call":"鸣声为极细而高亢的“SEEeeweeEEE”，每句持续1.07–1.3秒，重复规律；一唱段含5–8音节，比鵙伞鸟少而长。另有尖锐的“ki-ki-ki”下降声及吱吱作响的咯咯声。清晨至午后为鸣唱高峰，曾有5只雄鸟在百米半径内同时鸣唱的求偶场记录。","habits":"栖息于海拔200–1830米的潮湿山脚原始林，尤喜苔藓藤蔓密布的小溪沟谷。通常在林下层至亚树冠层觅食，偶尔加入混群。主要以果实与昆虫为食，静栖于垂直枝干上长时间不动，伺机飞啄周围基质。无确切迁徙证据，但在厄瓜多尔局部地区似有季节性出现，暗示可能存在短程垂直移动。","breeding":"繁殖资料稀少。8月在厄瓜多尔东南部曾见疑似求偶场，雄鸟6–8米高枝上鸣唱。秘鲁8月采集的雌鸟具孵斑并怀两枚卵。两枚19世纪采自厄瓜多尔的巢雏具20–26毫米丝状绒羽，被认为具拟态毒蛾幼虫的保护色。巢与卵尚未被正式描述。","identification":"雌鸟易与多种伞鸟混淆：横斑食果伞鸟海拔更高，下体横纹更密；鳞斑食果伞鸟体型更圆，头部图案复杂且下体密布鳞斑；绿黑食果伞鸟与金胸食果伞鸟体型更大，下体无横纹；尖喙霸鹟下体斑点而非条纹，面部裸露感明显。此外，与较小而圆胖的斑纹厚嘴霸鹟相比，后者翼具栗斑且海拔更高。","protection":"IUCN: NT（近危）。全球数量稀少且分布极度分散，委内瑞拉北部六件标本均采于1954年前，哥伦比亚至2000年代仅三笔记录。厄瓜多尔已知不足12处地点，已列为国家近危；秘鲁亦罕见。主要威胁为山脚林砍伐与农业扩张，如玻利维亚拉巴斯的咖啡、古柯种植。","distribution":"繁殖区位于安第斯山东坡山脚，自委内瑞拉西北部（巴里纳斯及塔奇拉）经哥伦比亚东部（博亚卡、梅塔、纳里尼奥），断续分布于厄瓜多尔东部、秘鲁东部（亚马逊至帕斯科及库斯科乌鲁班巴河谷），南至玻利维亚西北部（拉巴斯并可能邻近贝尼）。","other":"历史上曾被归入伞鸟科，现确认与鵙伞鸟、蒂泰霸鹟等近缘，隶属蒂泰霸鹟科。系统分类上，安第斯鵙伞鸟与鵙伞鸟为姊妹种，二者共同与栗翅斑伞鸟及点斑伞鸟构成一支。"},{"name":"白枕霸鹟","english_name":"White-naped Xenopsaris","scientific_name":"Xenopsaris albinucha","overview":"白枕霸鹟（英文名：White-naped Xenopsaris，学名：Xenopsaris albinucha），是雀形目蒂泰霸鹟科白枕霸鹟属的鸟类。分布于南美洲东安第斯山脉的热带与亚热带草原气候区，包括委内瑞拉、巴西、玻利维亚、巴拉圭、乌拉圭和阿根廷。此鸟体型较小，长约12.5至13厘米，重约10克，上身灰褐色，下身白色，具黑色头顶，雌雄相似，但雌鸟颜色稍淡。其生境多样，包括Caatinga灌木丛、河岸林地、开阔森林边缘等，通常接近水源。","appearance":"白枕霸鹟体长12.5至13厘米，体重约10克。雄鸟头顶光泽黑，带蓝光；脸、喉、胸、腹和臀部白色，胸略灰，腹微黄；背部灰褐，翼暗灰褐，有白色内羽缘；尾暗褐，喙腿黑。雌鸟类似，但上体更淡，头顶带红褐。幼鸟有灰褐顶冠，背部和翼有赭色斑点。","call":"鸣声精致，不传远，常见于雨季，高音薄颤“teep, tre'e'e'e'e'a eea wu'u'u'e'e'e-e-e-e-e-p”或“twip, tsiweeé, tseee, ti-ti-ti-ti”，起始颤音上升后下降，终颤音长且颤动。","habits":"栖息于Caatinga灌木丛、河岸林地、轻树林和开阔森林边缘，常在水边或潮湿区域。主要以昆虫为食，偶尔吃果实。单独或成对活动，通常立于树梢，短距离飞行捕食叶顶昆虫或空中追逐猎物。","breeding":"筑杯状巢于树叉，高4.5厘米，由植物纤维构成，离地5至15米。每窝产卵3枚，绿底带棕色斑点。两性共孵卵，孵化期14至15天。雏鸟出壳后24小时内相继破壳，六日后眼开，八日被覆白绒毛。双亲共同喂养。","identification":"与灰厚嘴霸鹟相比，体型更小，尾更长，喙更细，下体更白，上体更偏棕。","protection":"IUCN：LC（无危）","distribution":"分布于南美，从巴西北部、东部至阿根廷北部。在委内瑞拉、巴西、玻利维亚、巴拉圭、乌拉圭和阿根廷的热带与亚热带草原气候区。","other":"白枕霸鹟属《世界自然保护联盟》保护鸟类。"},{"name":"绿背厚嘴霸鹟","english_name":"Green-backed Becard","scientific_name":"Pachyramphus viridis","overview":"绿背厚嘴霸鹟（英文名：Green-backed Becard，学名：Pachyramphus viridis），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。分布于南美东部广阔区域，自委内瑞拉东南部直至阿根廷北部，偶见于苏里南。它偏好潮湿热带及低山雨林的树冠层，也利用林缘及灌丛地，海拔多介于650–1700 米。该鸟羽色鲜明，雌雄异型，常成对活动，球形大巢悬挂于中上层树枝，醒目易见。目前被IUCN评为无危（Least Concern），但因隐蔽性高而资料匮乏。","appearance":"体长14.5–16.2厘米，体重18–21克。雄鸟具光泽黑冠，白色眉纹及喉部，眼周细黄环；颈侧及后颈浅灰成领；上体亮橄榄绿，飞羽及尾羽暗褐具橄榄缘；胸带鲜黄至黄绿色，与灰白下体相连。雌鸟似雄鸟但色较暗，冠部暗橄榄，面及喉灰色，上体淡橄榄，小翼覆羽栗红，胸带常模糊。幼鸟上体橄榄褐，余似雌鸟。亚种xanthogenys及peruanus雄鸟面颊与喉鲜黄至黄绿，雌鸟面颊略黄；griseigularis雄鸟无黄色胸带，面及喉灰绿，雌鸟冠与上体同色，小翼覆羽栗斑不显著。","call":"雄鸟鸣唱通常自隐蔽的高枝发出，持续2–3秒，为柔和悦耳的口哨声，如“du-du-didididididi”或“trididideédeédeédeé”，有时先以“te-wik”起音。常见叫声为快速上扬的鼻音“q-wink, q-wink”，可连发十余次，另有短促“jew”声。","habits":"留鸟，不迁徙。栖息于高大潮湿至湿润热带及低山雨林的林冠，尤喜破碎或开阔处，也见于轻木林及灌丛边缘，巴西北部记录于650–1700 米，东南委内瑞拉可达1000 米，大西洋雨林区可至1500 米。成对或小群活动，常加入混合鸟群，在浓密枝叶间缓慢跳跃，先凝视再出击，短距离飞扑或悬停啄取叶间昆虫，偶食果实（如Alchornea triplinervia）。","breeding":"繁殖期因地而异：阿根廷10–12月，巴拉圭10月中旬，巴西里约热内卢及米纳斯吉拉斯11–12月，帕拉州9月曾见育雏。巢由两性共建，呈不规则球形，直径18–25厘米，侧面或近基部入口径3.5–5厘米，内室约8.5厘米，材料为枯叶、纤维、苔藓等，悬挂于下垂枝或枝叉，离地4–25 米，曾被记录于松树、南美杉及铁木等树种，亦见附生凤梨科植物。卵2–4枚，赭或褐灰色具棕斑，20.6–21.5 mm×14.6–15.7 毫米；雌鸟孵卵约18–21天，双亲育雏20–30天。阿根廷研究发现其巢常与铅灰鸢等猛禽及黄蜂为邻，以借其护巢之利。","identification":"与同属其他种相比，绿背厚嘴霸鹟雄鸟具有黑冠、灰领及鲜明黄胸带；雌鸟具栗红小翼覆羽及灰脸。与近缘黄颊厚嘴霸鹟（xanthogenys/peruanus）相比，指名亚种viridis雄鸟面颊及喉灰色而非鲜黄；与griseigularis亚种相比，viridis具明显黄色胸带及灰领。","protection":"IUCN: LC（无危）","distribution":"繁殖区：委内瑞拉东南部（玻利瓦尔州东部）、圭亚那（罗赖马山）及巴西亚马孙河下游至马拉若岛；厄瓜多尔安第斯山东坡至秘鲁北部（卡哈马卡、亚马孙、圣马丁）；秘鲁中部及东南部至巴西西部（阿克里州）；巴西东部及南部、玻利维亚东部及南部、巴拉圭、乌拉圭及阿根廷北部（至图库曼、圣菲、恩特雷里奥斯）。非繁殖区：全年留居，无迁徙记录。","other":"分类历史上曾被置于霸鹟科或伞鸟科，现依形态及分子证据归入蒂蒂鹟科（Tityridae）。黄颊型（xanthogenys及peruanus）有时被视为独立种黄颊厚嘴霸鹟。"},{"name":"黄颊厚嘴霸鹟","english_name":"Yellow-cheeked Becard","scientific_name":"Pachyramphus xanthogenys","overview":"黄颊厚嘴霸鹟（英文名：Yellow-cheeked Becard，学名：Pachyramphus xanthogenys），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。有时被视为独立物种，有时则被当作绿背厚嘴霸鹟的一个亚种。根据最新的分类证据，被重新归类于蒂泰霸鹟科。主要分布在厄瓜多尔和秘鲁。","appearance":"黄颊厚嘴霸鹟具有独特的黄色脸颊，这是其最显著的外部特征之一。关于其详细的体型、羽毛颜色和性别差异等信息，在现有资料中尚未提供具体描述。","habits":"黄颊厚嘴霸鹟栖息于南美洲的亚热带或热带湿润低地森林及山地森林中。它们的生活习性，包括迁徙模式、飞行特点、活动范围和食物来源等细节尚需更多研究。","identification":"黄颊厚嘴霸鹟通过其黄色脸颊这一独特标记与其他近似物种区分开来，尤其是在与绿背厚嘴霸鹟的比较中，这一特征尤为明显。","distribution":"黄颊厚嘴霸鹟的分布范围覆盖了南美地区的哥伦比亚南部至秘鲁，特别是在亚热带或热带的湿润森林中最为常见。","other":"现为绿背厚嘴霸鹟亚种。"},{"name":"斑纹厚嘴霸鹟","english_name":"Barred Becard","scientific_name":"Pachyramphus versicolor","overview":"斑纹厚嘴霸鹟（英文名：Barred Becard，学名：Pachyramphus versicolor），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。小型鸣禽，主要分布在中美洲的哥斯达黎加至南美洲的玻利维亚西北部。这种鸟以其独特的黄绿色面颊和黑色横纹腹部著称。","appearance":"雄性斑纹厚嘴霸鹟具有醒目的黄色脸颊，黑色顶冠和背部，以及细窄的腹部横纹。雌鸟则拥有灰色顶冠，橄榄绿色背部，红褐色翅膀，以及较为均匀的黄绿色腹部。幼鸟颜色较淡，绿色更为显著，腹部条纹不明显。","call":"它们的鸣叫声包括柔和而持续的'weet weet weet weet'声或'teseep tesep tseep tseep'声。","habits":"斑纹厚嘴霸鹟主要栖息于山林的树冠层，偏好海拔1500-2500米的高度，有时在早春时节会更高。它们以飞行中捕捉大型昆虫和蜘蛛为食，也会悬停采食小浆果。","breeding":"繁殖季节通常在4月至6月之间，雌鸟在树高15-23米的枝叉上建造球状巢穴，直径约30厘米，每窝产2枚带有深棕色斑点的浅棕色蛋，仅由雌鸟孵卵，孵化期为18-20天。雄鸟会在育雏期间协助喂食。","identification":"雄鸟与雌鸟的斑纹厚嘴霸鹟可以通过颜色差异辨认，尤其是雄鸟的黑色上部和明显的腹部条纹，而雌鸟的橄榄绿色背部和灰色顶冠是识别关键。它们与其他Becard种类的区别在于其特有的腹部条纹和头部形状。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加，向南延伸至南美洲的哥伦比亚、巴拿马、厄瓜多尔、秘鲁、委内瑞拉和玻利维亚西北部。"},{"name":"蓝灰厚嘴霸鹟","english_name":"Slaty Becard","scientific_name":"Pachyramphus spodiurus","overview":"蓝灰厚嘴霸鹟（英文名：Slaty Becard，学名：Pachyramphus spodiurus），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。传统上曾归类于鵙科或霸鹟科，现根据证据被重新分类至蒂泰霸鹟科。其分布于南美洲西部的厄瓜多尔和秘鲁西北部，栖息于热带干燥森林中。","appearance":"雄鸟整体呈蓝灰色，头部黑色，颈背混有蓝灰色，翼黑带白色羽缘，尾暗黑；雌鸟全身亮肉桂色，头顶较深，具白色灰色眉纹，翼羽黑边红棕色，尾部肉桂色，下身白偏肉桂色，胸腹部带浅黄色调。体长约14厘米，喙黑色，基部下颌偏淡灰色，腿黑。与单色厚嘴霸鹟相比，体型更小，喙更细，有白色眉纹，翼羽边缘白色。","call":"雄鸟的典型叫声为一系列快速而略带旋律的音符，开始缓慢，迅速加速并升高音调和音量，同时发出持续2至3秒的低沉滑音颤音。","habits":"主要栖息于半湿润和落叶林地、灌木丛、空地、种植园以及干旱灌木丛中的干涸河床，偶尔也在被砍伐的较湿润地区发现。活动范围多在海拔600至750米之间，局部可达1100米。通常成对出现，常在树冠或次冠层停留，也会在近地面觅食。","breeding":"巢穴为封闭式球状结构，主要由树枝和苔藓构成，悬挂于树上，高度约15米。巢内以细嫩的铁兰属植物和马尾状根丝固定，内室铺垫树皮条。已知的繁殖记录显示，巢中有两只雏鸟。","identification":"与单色厚嘴霸鹟相比，蓝灰厚嘴霸鹟体型较小，喙较细，具有白色的眉纹，翼羽边缘为白色。","protection":"IUCN：VU（易危）","distribution":"分布于厄瓜多尔西部（埃斯梅拉达斯省至洛哈省西部）和秘鲁西北部（通贝斯、皮乌拉北部、卡哈马卡、亚马逊州）。","other":"蓝灰厚嘴霸鹟在《世界自然保护联盟》中被列为保护鸟类。"},{"name":"灰厚嘴霸鹟","english_name":"Cinereous Becard","scientific_name":"Pachyramphus rufus","overview":"灰厚嘴霸鹟（英文名：Cinereous Becard，学名：Pachyramphus rufus），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。主要分布在中美洲的巴拿马和南美洲北部，包括亚马逊雨林区域。其名称‘cinereous’源于其独特的灰褐色调外观。","appearance":"这种小型霸鹟在北南美洲低地和丘陵地带广泛分布。雄鸟呈灰色，腹部略浅，顶冠为鲜明的黑色，翅膀相对简单。雌鸟主要是丰富的红棕色，眼区较淡，腹部呈白色。通常不会在密林中发现，偏好更为开放的树林、边缘和次生林地带，经常以对的形式出现。","habits":"灰厚嘴霸鹟倾向于在较为开阔的林地、边缘及次生林中活动，而非深林环境。它们的栖息地包括了从巴拿马到南美北部的区域，覆盖了亚马逊雨林。具体的生活习性可能包括特定的迁徙模式、飞行特征和觅食行为，但具体细节未在现有资料中详述。","identification":"与其它同类相比，灰厚嘴霸鹟的黑帽和灰身构成鲜明对比，雌鸟的红棕色及腹部的白色也是识别要点。","protection":"IUCN：LC（无危）","distribution":"灰厚嘴霸鹟的分布范围跨越了巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、巴拿马、秘鲁、苏里南和委内瑞拉。"},{"name":"栗顶厚嘴霸鹟","english_name":"Chestnut-crowned Becard","scientific_name":"Pachyramphus castaneus","overview":"栗顶厚嘴霸鹟（英文名：Chestnut-crowned Becard，学名：Pachyramphus castaneus），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。显著特征为栗色的头顶与眼周的宽幅灰色带形成鲜明对比，面部与下体呈肉桂色。性别间外观相似。常见于南美洲亚马逊盆地的巴西、哥伦比亚、秘鲁、厄瓜多尔、玻利维亚以及委内瑞拉的部分地区，同时在东南部的巴西、巴拉圭和阿根廷东北部也有分布。偏好湿润森林边缘、林地与河岸森林。","appearance":"栗顶厚嘴霸鹟拥有中等体型，最显著的特征是其栗色的冠羽，这与围绕眼睛的宽阔灰色环带以及肉桂色的脸部和腹部形成鲜明对比。雄鸟和雌鸟的外观极为相似，难以区分。幼鸟的羽毛颜色可能更为柔和，细节上与成鸟有所差异。","call":"其鸣唱为柔和悦耳的口哨声，表现为连续的‘teeuw-teeu-teeu’。","habits":"栗顶厚嘴霸鹟栖息于湿度较高的森林边缘，如湿润森林、林地及河岸森林。它们倾向于在裸露的树枝上停留。活动范围主要集中在亚马逊盆地的低海拔地带，包括南美的多个国家。迁徙模式尚不明确，但在繁殖季节，它们可能进行局部迁移。","breeding":"关于其繁殖行为的详细资料有限。繁殖期通常发生在雨季，营巢于树木中，巢以枝叶和苔藓构成。具体求偶、交配、产卵、孵化和育雏过程有待进一步研究。","identification":"栗顶厚嘴霸鹟通过其独特的头部色彩模式与同属的其他物种区分开来，尤其是栗色的冠羽和眼周的灰色带。此外，它们的栖息地偏好和鸣叫特征也是重要的辨识依据。","protection":"IUCN：LC（无危）","distribution":"栗顶厚嘴霸鹟主要分布在南美洲的亚马逊盆地，包括巴西、哥伦比亚、秘鲁、厄瓜多尔、玻利维亚和委内瑞拉的部分地区，以及巴西东南部、巴拉圭和阿根廷东北部。在亚马逊盆地的分布从哥伦比亚南部延伸至整个东部厄瓜多尔、亚马逊地区的秘鲁东部和玻利维亚北部。在巴西的Cerrado地区，其分布从巴西东北部向南延伸至东南部，包括东部的中心西部区域。"},{"name":"桂红厚嘴霸鹟","english_name":"Cinnamon Becard","scientific_name":"Pachyramphus cinnamomeus","overview":"桂红厚嘴霸鹟（英文名：Cinnamon Becard，学名：Pachyramphus cinnamomeus），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。主要分布于中美洲至南美洲的热带低地森林边缘和开阔地带，从墨西哥东南部至厄瓜多尔西部。以锈红色的羽毛和灰白色的喙及腿为显著特征。","appearance":"成年桂红厚嘴霸鹟长约14厘米，体重介于17至22克之间。其上身呈锈红色，腹部颜色稍浅，为肉桂色。两性外观相似，但幼鸟颜色更为鲜艳，整体更淡。北部个体具有较淡的眼眉纹和从喙到眼的暗色线，而安第斯山脉西侧的亚种P. c. magdalenae则表现出更强的对比度，眼眉纹更明显，眼周线呈黑色。","call":"鸣叫包括高音薄哨声，雄鸟的歌声为哀怨上升的‘dee dee dee dee dee dee de’，而雌鸟的叫声则为较弱的‘deeeu dew dew, dew dew’。","habits":"桂红厚嘴霸鹟栖息于广阔的海拔范围内，从接近海平面至1,700米的高处皆可见其踪影。它们偏爱受干扰的生境，如开放的林地、森林边缘、红树林和次生林，尤其是以裸枝刺槐（Albizia carbonaria）为主的林区。","breeding":"巢由雌鸟在高树梢建于8至50英尺（约2.5至15米）的高度，巢呈球形，入口低矮，常靠近黄蜂巢以增加保护。每窝产3至4枚橄榄褐色斑点的淡褐色蛋，孵化期由雌鸟独自承担，约18至20天。雄鸟会在喂养幼鸟时提供帮助。","identification":"相较于红喉厚嘴霸鹟，桂红厚嘴霸鹟体型较小且更修长，拥有较淡的眼眉纹和渐变的尾羽。","protection":"IUCN：LC（无危）","distribution":"桂红厚嘴霸鹟主要分布于中美洲至南美洲的热带低地森林，范围从墨西哥东南部延伸至厄瓜多尔西北部及委内瑞拉西北部，近期在哥伦比亚东方山系的亚马逊一侧发现其分布远比预期普遍。","other":"它们会从空中捕捉大型昆虫和蜘蛛，也会悬停着采食小型浆果。"},{"name":"白翅厚嘴霸鹟","english_name":"White-winged Becard","scientific_name":"Pachyramphus polychopterus","overview":"白翅厚嘴霸鹟（英文名：White-winged Becard，学名：Pachyramphus polychopterus），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。属于蒂泰霸鹟科的鸟类，广泛分布在中美洲和南美洲，自危地马拉至乌拉圭。拥有8个显著不同的亚种，这可能意味着存在不止一个物种。白翅厚嘴霸鹟在多个国家公园和保护区中都能找到，其适应性强，能在多种次生和转换生境中生存。","appearance":"雄鸟成鸟的上体呈深黑光泽，翼展上有醒目的白色斑块，翼覆羽边缘宽阔，尾部具白色尖端。雌鸟颜色较平淡，上体为橄榄褐色，下体偏黄，翼上有明显的肉桂色边缘。幼鸟类似雌鸟，但逐渐展现出亚成鸟的特征，如灰色喉咙和头部黑色斑点。不同亚种在下体的颜色上有所差异，如dorsalis亚种下体最浅，而tenebrosus亚种几乎全身黑色。","call":"两性的典型鸣唱是一系列6到9个清澈、富有韵味且略带忧郁的下滑哨音，有时伴有软弱的颤音和加速的哨声序列。雌鸟的歌声比雄鸟的更为柔和。","habits":"栖息于湿润至半干旱的林地边缘和低地森林，偏好较为开阔的地带和有零散树木的空地。它们主要生活在低地，但也可见于高达2000米的地方。以毛虫、大型昆虫和蜘蛛为食，同时也会摄取小浆果。通常单独或成对出现，有时加入混合物种觅食群。","breeding":"繁殖期在哥斯达黎加为4月至8月，哥伦比亚为5月至8月，委内瑞拉西部和特立尼达岛为8月至9月，托巴哥从1月开始。巢呈球状，高可达30厘米，宽约25厘米，由草、纤维、苔藓和羽毛等构成，通常建于树冠较高处的枝叉间，离地面高度从4至38米不等。每窝产2-4枚卵，孵化期约为18至21天，由雌鸟负责。雏鸟由双亲共同喂养，巢期大约21天。已知受光背拟鹂寄生。","identification":"与黑顶厚嘴霸鹟和黑白厚嘴霸鹟相比，白翅厚嘴霸鹟缺乏眼区的白色或灰色，翅膀上的白色更多，整体颜色更深。雌雄两性在特定部位的色彩和标记上也有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，从危地马拉至乌拉圭，覆盖了除智利外的所有南美洲国家。在北美洲的分布报道尚未得到确认。"},{"name":"黑顶厚嘴霸鹟","english_name":"Black-capped Becard","scientific_name":"Pachyramphus marginatus","overview":"黑顶厚嘴霸鹟（英文名：Black-capped Becard，学名：Pachyramphus marginatus），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。这中等体型的黑白两色霸鹟，常见于南美洲亚马孙雨林的湿润森林内部树冠层，通常与多种鸟类组成的混合群一同活动。","appearance":"雄性黑顶厚嘴霸鹟下体呈灰色，头顶、背部和尾巴为黑色，尾羽和翅膀边缘具有白色边线。雌鸟则下体呈黄褐色，上体橄榄绿色，头部、尾部和翅膀呈现栗色。","call":"其鸣声为反复而略带哀伤的‘teeu, whee-doo-weet’。","habits":"栖息于南美亚马孙地区的低海拔热带湿润森林，活动范围广泛，随季节迁徙。飞行特点灵活，善于在树冠层中穿梭，以昆虫为主食。","breeding":"繁殖信息未详细记录。","identification":"通过其独特的黑白相间的外观和头部的黑色顶冠，以及特有的鸣叫声，容易与其它种类区分开来。","protection":"IUCN状态未提及。","distribution":"分布于南美洲的亚马孙雨林区域，具体国家包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。","other":"历史上分类学归属曾有争议，现归入蒂泰霸鹟科。"},{"name":"黑白厚嘴霸鹟","english_name":"Black-and-white Becard","scientific_name":"Pachyramphus albogriseus","overview":"黑白厚嘴霸鹟（英文名：Black-and-white Becard，学名：Pachyramphus albogriseus），是雀形目蒂泰霸鹟科厚嘴霸鹟属的中型鸟类。其别名包括黑冠厚嘴霸鹟。主要分布在南美洲安第斯山脉东侧的山地森林，从委内瑞拉到秘鲁，间断分布至哥斯达黎加和巴拿马。雄鸟主要呈灰色，翼羽边缘鲜明白色，头戴黑色帽冠，眼圈苍白。雌鸟外观大异，具棕色冠羽，镶以黑色边框，眼圈白色，腹部淡黄色，翼羽边缘棕红色。与隐匿厚嘴霸鹟在安第斯山脉东侧的区域有潜在重叠。分布海拔大约在1,000至2,200米之间。","appearance":"体型介于13.2至15厘米，体重约16.2至26克。雄鸟头部上部为蓝黑色，下部为灰白色，翼羽宽幅白色边缘形成两道翼斑，尾部背面黑色，腹面浅灰色带白色尖端。雌鸟上部橄榄褐色，下部黄绿色，具显眼的栗色冠羽和黑色边框，眼圈白色，翼羽边缘亮红棕色。幼鸟似雌鸟，但色泽更暗淡，冠羽边缘呈烟熏黑色，眉纹不明显，颈背环模糊。","call":"鸣唱为缓慢的一系列甜美下滑哨音，后接上升哨音，通常重复二至三次。与隐匿厚嘴霸鹟的歌声相比，速度更快，音符较短。","habits":"栖息于高海拔的山地森林，主要在中层至顶层的湿润林地。常见于树高约20米的森林，拥有丰富的半寄生植物和茂密的下层植被。偶尔出现在森林边缘和次生林中。分布海拔在1,000至2,200米之间，哥斯达黎加和巴拿马地区季节性下降至较低海拔。","breeding":"繁殖信息有限，已知繁殖期大致在3月至6月之间。","identification":"与白翅厚嘴霸鹟、灰领厚嘴霸鹟、隐匿厚嘴霸鹟和黑顶厚嘴霸鹟有区别，主要通过头部、背部、翅膀和尾巴的图案以及鸣声辨别。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚、哥斯达黎加、厄瓜多尔、巴拿马和委内瑞拉的山地森林，间断至北、东北哥伦比亚和西北委内瑞拉（圣玛塔山脉和佩里亚山脉），至北委内瑞拉，沿安第斯山脉东坡从东哥伦比亚至南秘鲁。","other":"2023年研究揭示了其与隐厚嘴霸鹟的物种界限，两者在形态学、遗传学和生态位上存在显著差异。"},{"name":"灰领厚嘴霸鹟","english_name":"Grey-collared Becard","scientific_name":"Pachyramphus major","overview":"灰领厚嘴霸鹟（英文名：Grey-collared Becard，学名：Pachyramphus major），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。分布于中美洲，包括墨西哥南部至尼加拉瓜。其独特的灰色领环和黑白相间的羽毛是其显著特征。","appearance":"雄鸟成鸟具有光泽的黑色头冠，白色臀部和上尾覆羽，背部黑色或灰黑相间，翅膀黑色，带有白色肩带和翼覆羽边缘，次级飞羽和三级飞羽亦有白色边缘，初级飞羽p9较短且逐渐变细，尾羽黑色，外侧尾羽有宽阔的白色尖端。雌鸟个体较小，头部棕色至黑褐色，眼纹黑色，后颈淡肉桂色至浅黄肉桂色，上体肉桂棕色，翅膀黑褐色，边缘呈肉桂色至肉桂棕色，尾羽中央有黑褐色标记，下体呈肉桂色至肉桂黄。幼鸟似雌鸟，迅速获得亚成鸟羽毛，雄鸟可能背部有黑褐色斑点，翼羽有柠檬色边缘，尾羽中部黑褐色，有黑色远端标记，外侧尾羽有白色尖端。","call":"典型的鸣唱是一连串富饶而不断重复的‘hoo wee-deet’或‘hu whi-ditt’哨声，通常重复4至6次，约10秒内可听到10次。也会发出更哀婉至清晰的‘peeu peeu’声和较长的‘beeh beeh beeh’系列，重复6至7次。","habits":"灰领厚嘴霸鹟栖息于潮湿至半干旱森林，尤其是松树和橡树林，林缘地带，甚至农业区，只要存在树木。它们偏好洪都拉斯的开阔阔叶林，在奥哈卡州的极端东南部发现于太平洋沼泽和热带半落叶林。海拔高度可达2500米。它们会加入混种觅食群，至少在非繁殖季节如此。","breeding":"关于繁殖的信息较少，目前仅有一份巢穴的描述。在奥哈卡州，5月底雌鸟准备产卵，9月底成鸟照顾三只幼鸟。在米却肯州，8月观察到有雏鸟的巢，巢位于橡树叉中，距离地面约10米，高35厘米，深22厘米，宽23厘米，形状近似球状，倾斜的屋顶，巢由苔藓、树枝和松针构成，屋顶由蝴蝶茧丝粘合的树皮条制成。","identification":"雄性灰领厚嘴霸鹟与白翅厚嘴霸鹟雄鸟在外观上相似，但整体更苍白，具有灰色的后颈和淡色的眼上纹。雌鸟具有肉桂红的冠部，宽大的黑色眼纹，以及较淡（柠檬色）的黄色后颈、喉部和下体，与雌性红喉厚嘴霸鹟相比体型更小。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥西部（从索诺拉州南部至格雷罗州和奥哈卡州高地），中美洲，包括洪都拉斯、萨尔瓦多、危地马拉、伯利兹和尼加拉瓜。在墨西哥塔巴斯科州仅有两次记录。","other":"灰领厚嘴霸鹟在繁殖季节居住在海拔约790至1600米的高度，但在冬季会迁移到低至100米的地方。"},{"name":"亮背厚嘴霸鹟","english_name":"Glossy-backed Becard","scientific_name":"Pachyramphus surinamus","overview":"亮背厚嘴霸鹟（英文名：Glossy-backed Becard，学名：Pachyramphus surinamus），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。体型较小、优雅的热带雨林树冠层鸟，拥有闪亮的蓝绿色背部和洁白的腹部，以独特的直立姿态和较重的喙而著称。分布于南美洲东北部的亚马逊雨林。","appearance":"亮背厚嘴霸鹟是一种中等偏小的鸟类，雄鸟背部呈金属光泽的蓝色，雌鸟则具有更为独特的斑纹。它们拥有干净的白色下体和粗壮的喙，雄鸟的背部在良好光照下呈现出绚丽的蓝色光泽。雌雄两性的大小相似，但颜色有所不同。","call":"其最常见鸣叫是一系列甜美、上扬的哨声，首音拉长，清脆悦耳。","habits":"亮背厚嘴霸鹟通常缓慢而有条不紊地在树冠层移动，仔细观察周围环境，偶尔飞扑捕捉昆虫。它们较为罕见，常见于高大的森林中，经常与混合物种群一同出现。","breeding":"关于亮背厚嘴霸鹟的繁殖信息较少，但一般认为它们会在树冠中筑巢，具体的繁殖季节和繁殖行为需要更多研究。","identification":"亮背厚嘴霸鹟的识别关键在于其白色的下体、厚重的喙以及雄鸟的蓝绿色背部光泽。雌鸟的独特斑纹也有助于与其他物种区分。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东北部、法属圭亚那、苏里南，以及委内瑞拉的Caura河下游区域。主要栖息于亚马孙雨林的低地湿润森林。"},{"name":"单色厚嘴霸鹟","english_name":"One-colored Becard","scientific_name":"Pachyramphus homochrous","overview":"单色厚嘴霸鹟（英文名：One-colored Becard，学名：Pachyramphus homochrous），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。中等体型的鸟类，主要分布在中美洲和南美洲，从巴拿马至委内瑞拉北部和秘鲁西北部。雄鸟上身呈深黑色，下身为灰色；雌鸟全身呈红褐色，腹部颜色较淡。该物种被列为《世界自然保护联盟》保护鸟类。","appearance":"雄鸟上身黑色，下体灰色，而雌鸟整体红褐色，腹部呈淡黄褐色。它们具有明显的性别二态性，雄鸟的上体为深黑，下体为灰色，雌鸟则是全身红褐色，腹部颜色较淡，近似于黄褐色。成鸟和幼鸟之间没有显著的外观差异。","habits":"单色厚嘴霸鹟通常在低地和山麓地带的森林或开放林地中活动，偏好中层至顶层的林冠环境。它们以昆虫为主食，通过空中捕捉或在枝叶间觅食。","breeding":"在厄瓜多尔西南部，繁殖季节主要在2月至3月期间，筑巢于高大树木（如Prosopis juliflora和Ceiba trichistranda）中，距地面4至14米处。巢呈三角形或梨形，封闭式悬挂于树枝上，主要由干燥的草状植物和杂草构成，内部铺有羽毛、干叶和Eriotheca ruizii种子的柔软纤维。每窝产卵3至4枚，蛋壳呈奶油色，宽端有许多棕色斑点，平均尺寸为24.1mm×17.9mm。估计的雏鸟孵化期为24至29天。","identification":"雌鸟的灰眼眶有助于将其与其他红褐色的厚嘴霸鹟区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，具体包括巴拿马、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉北部。在巴拿马，东部分布比西部更为常见；在秘鲁西北部的生物圈保护区，每日可见其踪迹。该物种也在巴拿马的Darién国家公园、厄瓜多尔的Cerro Blanco森林保护区、“Jardin Tropical”（靠近埃斯梅拉达斯）、Machalilla国家公园、Loma Alta生态保护区和Río Palenque科学中心等地出现。"},{"name":"粉喉厚嘴霸鹟","english_name":"Pink-throated Becard","scientific_name":"Pachyramphus minor","overview":"粉喉厚嘴霸鹟（英文名：Pink-throated Becard，学名：Pachyramphus minor），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。广泛分布在亚马逊盆地大部分地区。雄鸟拥有深灰暗色羽毛，下喉部有暗粉色斑块；雌鸟主要是橙棕色，头颈后方有灰色帽状延伸，活跃于成熟的雨林中层和树冠。","appearance":"雄性粉喉厚嘴霸鹟呈暗灰色，下喉部具有一小块暗粉色。雌鸟上体呈暗棕色，头顶和颈部后方灰色，翼缘和尾巴带有红褐色，下体为肉桂色。头部相对较大，喙厚重，类似于霸鹟科（Tyrannidae）的暴君霸鹟。雌雄羽色有显著差异，雌鸟的头顶更接近黑色。","habits":"粉喉厚嘴霸鹟居住在高大的常绿森林中，经常加入由昆虫食性和果实食性鸟类组成的混合物种觅食群，如唐纳雀、僧鸟和其他中层和树冠鸟类。它们在雨林的中层到次树冠区域活动。","identification":"雄性粉喉厚嘴霸鹟在其分布范围内较为独特，与之最相似的是三种大型厚嘴霸鹟，包括冠厚嘴霸鹟，它们的分布区要么不相交要么仅部分重叠。雌鸟的区别在于背部颜色和冠部对比度。","distribution":"南美洲亚马逊雨林区域，包括巴西、哥伦比亚、秘鲁、玻利维亚、厄瓜多尔、法属圭亚那、苏里南、委内瑞拉和圭亚那。"},{"name":"淡色厚嘴霸鹟","english_name":"Crested Becard","scientific_name":"Pachyramphus validus","overview":"淡色厚嘴霸鹟（英文名：Crested Becard，学名：Pachyramphus validus），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。属于蒂泰霸鹟科的鸟类。传统上曾被归类于鵙科或霸鹟科，但现有证据支持其归属于蒂泰霸鹟科。分布于南美洲的阿根廷、玻利维亚、巴西、厄瓜多尔、巴拉圭和秘鲁，栖息于亚热带或热带湿润低地森林及山地森林。","appearance":"体长约17.5至18.5厘米，雄鸟主要为深灰色，背部有隐蔽的白色斑点，脸部较灰，喉咙稍白；雌鸟冠部暗灰色，与亮赤褐色颈背形成鲜明对比，上体和尾巴亦为赤褐色，面部肉桂色，翼部大多为暗色，但初级飞羽边缘呈赤褐色，喉部黄肉桂色，下体为淡黄肉桂色。幼鸟外观似雌鸟。","call":"叫声不特别响亮，典型鸣声包括各种吱吱或啾啾声，歌曲为低沉、清晰、颤动的下降音符系列，通常为6至8个\"dui\"哨音，第二个音最高；典型的叫声为尖锐的\"tsree\"哨音。","habits":"常单独出现，偶尔加入混种群。停栖并扫描植被寻找猎物，约3至4秒后变换到新的停栖点。以大型昆虫为食。","breeding":"在阿根廷，筑巢季节为11月和1月。巢呈圆球状，入口位于侧面或底部，由枯叶、纤维、苔藓和其他植物材料构成，悬挂在树枝尖端。一窝产4枚卵。其他信息未知。","identification":"雄鸟背部的隐蔽白色斑点和雌鸟头部颜色对比是辨识关键。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲东部和中部，包括阿根廷、玻利维亚、巴西、厄瓜多尔、巴拉圭和秘鲁的亚热带或热带湿润低地森林及山地森林。"},{"name":"红喉厚嘴霸鹟","english_name":"Rose-throated Becard","scientific_name":"Pachyramphus aglaiae","overview":"红喉厚嘴霸鹟（英文名：Rose-throated Becard，学名：Pachyramphus aglaiae），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。其分类曾有争议，现确认为独立于传统分类的Tityridae科成员。该鸟以成年雄鸟独特的玫瑰色喉部斑纹著称，雌雄羽色差异显著，雄鸟灰暗，雌鸟偏棕色。分布自美国东南部至巴拿马西部，偏好有大树的林地边缘，偶尔在美国南部地区繁殖。","appearance":"红喉厚嘴霸鹟体型中等，雄鸟头部较大，具丛状冠羽。雄鸟上体颜色从灰到暗灰色不等，下体较浅，胸腹部呈淡灰色，最显著特征是雄鸟的玫瑰色或紫色喉部斑点，尤其在北方种群中明显。雌鸟上体锈色至红褐色，下体肉桂色至黄色。幼鸟似雌鸟，喉部可能带有粉色。雌雄异形，雄鸟有隐蔽的白色肩斑，第九初级飞羽特化。","call":"发出哀伤的'seeeuuwww'叫声。","habits":"常栖息于热带和亚热带的林地边缘，如木地和森林边缘，也会出现在灌木地、树篱以及有大树的环境。偏好有棉木的河流沿岸栖息地。食物以昆虫为主，兼食浆果和种子，采取在空中捕食和从植被中觅食的方式。","breeding":"繁殖季节通常在5月至7月，高海拔地区可能延后。筑造悬挂于高枝的穹顶状巢，入口位于底部附近。每窝产卵3至6枚，卵色多样，有斑点。雌鸟单独孵卵，但两性共同参与巢筑和育雏。","identification":"与单色厚嘴霸鹟相似，但二者分布区分离，雄鸟间难以区分，雌鸟可通过暗色冠羽区分。灰领厚嘴霸鹟在翼和尾部有黑白相间的图案，颈部有灰色项圈，与红喉厚嘴霸鹟的纯色翼和尾部以及无颈环形成对比。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥至哥斯达黎加东南部或巴拿马西部，局部进入美国东南部的亚利桑那州和得克萨斯州。在美国北部的种群迁徙，而得克萨斯州的种群可能在冬季停留。","other":"该物种有八种已认可的亚种，两种可达美国。"},{"name":"牙买加厚嘴霸鹟","english_name":"Jamaican Becard","scientific_name":"Pachyramphus niger","overview":"牙买加厚嘴霸鹟（英文名：Jamaican Becard，学名：Pachyramphus niger），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。体型小而健壮的林栖物种，广泛分布在牙买加的低地和山地森林中，能够适应受扰动的生境。","appearance":"成年雄鸟全身黑色，仅翼基部有一白色标记（飞行时可见）；虹膜深色；喙和腿均为黑色。雌鸟头部深棕色，上体红棕色，颊部、颈部至胸部上方呈肉桂色，下体浅灰色。幼鸟外观与雌鸟相似。","call":"鸣唱为断续的尖细颤音，通常以拉长的“tweeeee”结尾。叫声为尖锐而尖细的‘peep’。","habits":"常在树冠下盘旋，捕捉昆虫或采食果实。偏好栖息在受扰动的次生林地，对环境适应能力强。","identification":"与牙买加黑鹂相像，但后者喙较细长，且更倾向于在植被中搜寻而非飞扑捕食。雌鸟和幼鸟可能被误认为是憨蝇霸鹟、牙买加蝇霸鹟或棕尾蝇霸鹟，但这些霸鹟喉部为灰而非肉桂色，腹部有黄色，而雌鸟和幼年的牙买加厚嘴霸鹟不具备这些特征。","protection":"IUCN：LC（无危）。牙买加的原始森林已丧失约75%，但该物种在次生林中生存良好，对受扰动的生境具有较强的容忍性。","distribution":"仅分布于牙买加。其自然栖息地为亚热带或热带湿润的低地森林和山地森林。","other":"该物种于1788年由德国自然学家约翰·弗里德里希·格梅林正式描述，最初置于伯劳科，后归入蒂泰霸鹟科。"},{"name":"隐厚嘴霸鹟","english_name":"Cryptic Becard","scientific_name":"Pachyramphus salvini","overview":"隐厚嘴霸鹟（英文名：Cryptic Becard，学名：Pachyramphus salvini），是雀形目蒂泰霸鹟科厚嘴霸鹟属的鸟类。中等体型的蒂泰霸鹟科鸟类，主要分布在南美洲西部，从哥伦比亚西南部至厄瓜多尔和秘鲁西北部的马腊翁河流域。其自然栖息地为亚热带或热带的干燥森林及湿润山地森林。雄鸟以灰身、黑帽和白色翼缘为显著特征，而雌鸟则呈现橄榄褐色上体，黄色下体，具淡黄色腹部和肉桂色翼缘。与黑白厚嘴霸鹟在安第斯山脉东坡有潜在的分布重叠。","appearance":"隐厚嘴霸鹟是一种体长约14厘米的典型蒂泰霸鹟科鸟类，头部粗壮，喙宽而略带钩状，尾部较短。雄鸟主要为灰色，下体偏灰白或灰白色，头顶及颈背为蓝黑色，眼上纹为灰白色，连接至下额处，形成鲜明对比。翅膀上的飞羽为黑色，边缘有白色，尤其是在次级飞羽和三级飞羽的外侧较为明显，形成两道明显的翼带。尾羽主要呈灰色，中央一对尾羽几乎全灰，仅前端有一小部分黑色区域，尾尖白色。雌鸟上体为暗橄榄色，下体为黄绿色，喉咙和胸部为黄白色，翅膀黑色，边缘和翼盖为肉桂色，尾羽上部为肉桂色，下部较深，尾尖宽大。","call":"隐厚嘴霸鹟的叫声为一系列快速下降的甜美哨音，随后是一连串颤音，通常重复两到三次。这种叫声与黑白厚嘴霸鹟的叫声有所不同，后者的声音更慢，音符较长。","habits":"隐厚嘴霸鹟栖息于海拔300至3200米的亚热带或热带干燥森林和湿润山地森林，偏好森林中间层至顶层的环境，也可在干燥森林、咖啡园、玉米和花生种植园及牧场中发现。它们广泛分布于哥伦比亚太平洋斜坡、厄瓜多尔西部和秘鲁西北部，高度从海平面至1650米，而在秘鲁北部地区可达3050米。","breeding":"关于隐厚嘴霸鹟的繁殖信息有限，已知它们的繁殖季节主要集中在2月至5月之间。筑巢、求偶、产卵、孵化和育雏等具体细节尚待更多研究。","identification":"与隐厚嘴霸鹟最相似的是黑白厚嘴霸鹟，但隐厚嘴霸鹟的雄鸟具有较窄的翼上带，颜色较浅的眼周区域，尾羽上侧较灰，喙形更细。雌鸟则有较暗的冠顶，黑色边界较窄。两者在野外可能难以区分，声音特征成为重要的辨识依据。","protection":"IUCN：LC（无危）","distribution":"繁殖区包括哥伦比亚西南部、厄瓜多尔西部至秘鲁西北部的马腊翁河流域。非繁殖期间，它们会出现在安第斯山脉东坡，从哥伦比亚东南部、厄瓜多尔东北部至秘鲁中部。","other":"隐厚嘴霸鹟与黑白厚嘴霸鹟曾被视作同一物种内的亚种，但近期的遗传学研究表明，它们应被视为独立的物种。"},{"name":"艾氏琴鸟","english_name":"Albert's Lyrebird","scientific_name":"Menura alberti","appearance":"艾氏琴鸟体型庞大，可达86至93厘米，体重约930克。雄鸟头部和颈部呈深灰色，上身主要为暗红棕色至赤褐色，翅膀颜色相似。尾部长47至57厘米，由一对丝带状中央尾羽、12对薄纱状丝状尾羽和一对宽大的外侧尾羽（琴状尾羽）组成，上部暗棕色，下部暗灰色。下巴、喉咙和前颈赤褐色，胸部深灰色，腹部较淡灰色。后侧腹和尾下覆羽鲜赤褐色。喙黑色，虹膜深棕色至黑色，眼周灰环；腿和脚棕灰色。雌鸟与雄鸟相似，但尾部更短（36至42厘米）且简单。幼鸟似成年雌鸟，但赤褐色更为明亮，上体较淡，尾羽大多更窄、尖细。","call":"艾氏琴鸟具有多变且强大的叫声，从机械般的嗡嗡声、咔哒声到高亢的哨音和尖叫，能精准模仿其他鸟类的声音。","habits":"艾氏琴鸟栖息于亚热带山地雨林和湿润硬叶林，偏好植被密集、有灌木和藤蔓的下层。主要在海拔300米以上的地方活动，偏好有桉树冠层的环境。它们通常单独或成对活动，偶尔形成三鸟群，全年定居在同一区域内。以地面昆虫和其他土壤中的无脊椎动物为主食，偶尔在树上寻找食物。","breeding":"繁殖季节在5月至8月间，交配系统未知。雄鸟会在地上清理一块舞台，展示其尾羽并跳舞，吸引雌鸟。雌鸟独自筑巢，巢为圆顶状，入口位于侧面，由树枝、树叶、根须和苔藓构成，内衬细腻植物材料和羽毛。每窝产一枚蛋，孵化和抚养雏鸟全由雌鸟承担。雏鸟大约在39天后离巢。","identification":"艾氏琴鸟与华丽琴鸟的区别在于体型较小，羽毛颜色更偏赤褐色，琴状尾羽较为简单。","protection":"IUCN：LC（无危）","distribution":"艾氏琴鸟分布于澳大利亚东部的昆士兰远东南部和新南威尔士州远东北部，主要栖息在雨林地带。","other":"艾氏琴鸟曾因农业开垦、森林采伐和人类居住区扩张导致栖息地减少，现在多数小种群分布在国家公园和保护区中。"},{"name":"华丽琴鸟","english_name":"Superb Lyrebird","scientific_name":"Menura novaehollandiae","overview":"华丽琴鸟（英文名：Superb Lyrebird，学名：Menura novaehollandiae），是雀形目琴鸟科琴鸟属的鸟类。澳大利亚的特有种，分布于东南部森林地带。雄鸟拥有壮观的长尾，如同竖琴般展开，而雌鸟及幼鸟则不具备这一特征。琴鸟以其卓越的模仿能力和复杂的求偶舞蹈而闻名。","appearance":"雄性华丽琴鸟可达约1米长，重约1.1千克，雌鸟略小，约80厘米长，重0.9千克。上体呈暗褐色，下体为灰棕色，翅膀短圆，脚强健。雄鸟的尾羽长达70厘米，由16根羽毛组成，其中最外侧两根形成S形，称为“琴弦”，中间有12根纤细的羽毛，两根中央羽毛细长且金属丝状，构成独特的竖琴形状。雌鸟尾羽较短，缺乏复杂装饰。","call":"华丽琴鸟的鸣叫声极为多样，包括机械般的咔哒声、爆炸性的哨声和尖锐的尖叫。雄鸟拥有复杂且响亮的歌曲，能精准模仿周围鸟类的声音，占比高达70%-80%，甚至包括人类制造的噪音。","habits":"生活在湿润森林，偏好凉温带和亚热带雨林，以及潮湿的硬叶林。主要在地面觅食，挖掘土壤寻找无脊椎动物，偶尔也会捕食小型脊椎动物和种子。其活动范围通常局限于特定的领地，年轻个体可能更为游荡。对于森林生态系统的营养循环和植被再生具有重要作用。","breeding":"繁殖期在6月至8月。雄鸟通过复杂的求偶舞蹈吸引雌鸟，雌鸟单独筑巢并承担全部育雏责任。巢穴庞大，呈穹顶状，由各种自然材料构建，放置于地面或低矮处。每次产卵一枚，孵化期约为50天，幼鸟独立前需8-9个月。","identification":"与艾氏琴鸟相比，华丽琴鸟体型更大，羽毛颜色更偏向冷灰色，尾部装饰更为精致。雌雄之间，雄鸟的尾羽显著更长且复杂。","protection":"IUCN：LC（无危）。历史上曾遭猎杀，现受到全面保护。面临的主要威胁是栖息地丧失，特别是在未设保护区的地区。","distribution":"分布在澳大利亚东南部，从维多利亚南部至昆士兰东南部，包括多种森林类型，如亚热带和温带雨林，以及湿润和干燥的硬叶林。1930年代引入塔斯马尼亚岛，现已在岛上广泛分布。","other":"1930年至1954年间因担心大陆种群濒临灭绝而被引入塔斯马尼亚，目前塔斯马尼亚种群健康且正在增长。"},{"name":"棕薮鸟","english_name":"Rufous Scrubbird","scientific_name":"Atrichornis rufescens","appearance":"棕薮鸟体型小巧紧凑，长约17-18.5厘米，翼短，尾长呈渐变状。雄鸟头部和颈部暗棕色，上体亦为深棕色，带细黑条纹，至臀部变为深红棕色。尾羽和收拢的翅膀上有细密条纹。黑色三角区从喙基延伸到喉部和上胸，边缘有白色颊纹，向下延伸为断续的狭窄淡色线至腹部侧面。颈侧、胸侧和胁部为赭石色带细纹。雌鸟体型较小，暗喉斑更小或不明显。幼鸟上体更红褐，条纹模糊，喉部灰暗，下方均匀红褐色，后胁部隐约带纹。","call":"雄鸟的叫声非常响亮且多样化，拥有丰富的歌唱曲目，但它们更常被听到而非被看到。","habits":"栖息于亚热带和温带雨林，包括山毛榉森林及邻近湿润和潮湿的桉树森林，偏好湿沟、水道旁、山脉的山脊和悬崖，以及树木倒伏区域。依赖密集的地面覆盖，通常限于生态交错带、森林水道、湿地、火灾和风暴后的再生区以及路边。活动范围限制在600至1300米的高海拔森林，偶尔低至240米。食物主要包括甲虫、灌木蜗牛和蜗牛蛋，可能也会食用一些植物种子。","breeding":"繁殖季节为9月至11月。雄鸟可能为一夫多妻制，不参与筑巢、孵卵或育雏，占据约1公顷或略大的永久领地。巢为一侧有入口的穹顶状，由死草如Xerotes、Gahnia和Carex构成，有时加入少量枯死的树蕨碎片，内衬木纤维制成的纸板状物质，位于地面附近，一般约15厘米高，置于莎草丛、苔藓或小型树蕨中。每窝产2枚卵，孵化期不确定，推测为36-38天，雏鸟期未知，推测为3-4周，幼鸟离巢后至少3周内仍由母鸟喂养。","identification":"棕薮鸟与同属的噪薮鸟在外观上有明显区别，主要在于棕薮鸟的红褐色胸和较轻的条纹。此外，两者的分布区域也不同，噪薮鸟主要分布在澳大利亚西部。","protection":"IUCN：EN（濒危）","distribution":"分布于澳大利亚中东部，包括北新南威尔士州和南昆士兰州的高海拔雨林地带，尤其集中在大分水岭沿线的分散群落。","other":"自欧洲殖民初期估计的约12,000对棕薮鸟，到1979年至1983年的调查中仅剩2,500个领地，其中730个属于指名亚种。近年来，指名亚种已从里奇蒙德河和特威德河盆地的低地栖息地消失，ferrieri亚种的数量也在减少。最近的估计显示，指名亚种仅有1,500个成熟个体，分散在四个亚群中，而ferrieri亚种则有3,400个成熟个体，分布在至少三个亚群中。"},{"name":"噪薮鸟","english_name":"Noisy Scrubbird","scientific_name":"Atrichornis clamosus","overview":"噪薮鸟（英文名：Noisy Scrubbird，学名：Atrichornis clamosus），是雀形目薮鸟科薮鸟属的鸟类。独特的地面鸟类，仅分布于澳大利亚西南部沿海地区。其最显著的外部特征是暗褐色背部，锈色翅膀，斑驳的栗色胸区，灰棕色或粉色喙，以及深棕色眼睛。该物种在19世纪被认为已灭绝，直到1961年在Two Peoples Bay被重新发现。目前，通过一系列的保护措施，包括再引入计划，其数量有所恢复。","appearance":"雄性噪薮鸟长约23厘米，体重50至60克，雌鸟稍小，约19.5厘米，重34克。具有短圆翅和长渐尖尾。雄鸟上身呈中褐色，头部有细密的深色虫蚀状条纹，背部和两侧有更宽的条纹，延伸至尾巴。翅膀上的条纹较淡（变异较大）。下颌白色或浅黄色，喉部中央有一条宽大的黑色带，有时从下巴中央延伸到上胸部，由非常宽的白色颊纹边界。胸侧呈暗灰色，腹部浅黄褐色，两肋肉桂色，有深色条纹，向后逐渐变为红褐色，腹腔区域深红褐色。雌鸟明显较小，没有黑喉带，下颌奶油色，一般下方更黄，向后渐变为红褐色。幼鸟颜色较为一致，呈深红褐色，后部偏灰。","call":"雄鸟的叫声多样而响亮，包括一系列尖锐、清晰、悦耳的音符，这是最容易区分其与西刺莺的方式。","habits":"栖息于澳大利亚西南部沿海和近沿海地区的密集灌木丛和低森林的灌木下层，偏好有深沟壑、沼泽、水道和山丘侧边的茂密灌木丛，常围绕岩石露头。通常出现在超过十年未燃烧的地点，有时甚至超过一个世纪。活动范围从海平面至海拔500米。以各种无脊椎动物为食，如蚂蚁、甲虫、蜘蛛、直翅目昆虫和多种幼虫，偶尔也会捕食小型脊椎动物，如小蛙、蜥蜴和壁虎。主要在地面的深叶堆中觅食，也在腐朽的木头和碎片中寻找食物，以及在下层植被的茎叶间。用喙探入裂缝和叶子下，抬起叶子寻找猎物，依赖于从落叶和碎片中冲出猎物。","breeding":"繁殖季节为4月至10月，主要在南半球冬季，大多数蛋在6月产下。雄鸟可能为多配偶制，不参与筑巢、孵化和抚育幼鸟，占据大约5公顷的永久领地。巢为穹顶形状，高度约18厘米，宽度12.5厘米，深度14厘米，侧面入口，由草类构建，内部紧密绑定，外部较松散，墙壁和地板厚度可达5厘米，底部一半的巢室衬有类似纸板的木质纤维材料，通常位于离地约80厘米的高度，隐藏在草丛或碎片中。每窝产1枚蛋，孵化期5至6周，雏鸟孵化后初期每次喂食后都会被母鸟孵化，白天的孵化大约在10天后停止，但在夜间持续至离巢前，雏鸟随着成长会食用相对较大的食物，包括小型脊椎动物，母鸟直接从雏鸟的泄殖腔移除粪便袋；离巢期为3至4周；离开巢穴后，幼鸟在接下来的6个月内仍靠近母亲。","identification":"最容易通过叫声与西刺莺相区别。雄鸟的喉咙有明显的黑色标记，而雌鸟则无，这有助于识别性别差异。","protection":"IUCN：EN（濒危）","distribution":"分布于澳大利亚西南部沿海和近沿海地区，具体范围从Two Peoples Bay至Cheyne Beach，包括Warroona附近的Darling Range南部。物种在多个地点进行了再引入，包括Bald Island等地。","other":"在过去的50年中，尽管实施了包括再引入在内的多种保护干预措施，但其种群数量仍在下降。主要威胁包括森林火灾、外来物种捕食、栖息地退化、土壤真菌、气候变化和遗传多样性缺乏。"},{"name":"赭胸园丁鸟","english_name":"Ochre-breasted Catbird","scientific_name":"Ailuroedus stonii","overview":"赭胸园丁鸟（英文名：Ochre-breasted Catbird，学名：Ailuroedus stonii），是雀形目园丁鸟科绿园丁鸟属的鸟类。这种体型较大的鸟种在南新几内亚的低地和山脚森林内部广泛分布，拥有独特的黑色头冠，与白色脸颊和喉咙形成鲜明对比，胸部和腹部呈现淡褐色，点缀着细小的黑斑。与黑冠园丁鸟共存时，赭胸园丁鸟较小，通常出现在较低海拔地区，具有白色脸颊。","appearance":"赭胸园丁鸟体长约24.5厘米，雄鸟体重110-172克，雌鸟100-152克。头部的冠羽颜色从中间棕色到橄榄棕色不等，略带绿色调，耳羽、头部侧面和喉咙大多呈白色，带有黑色斑点。颈部上部呈淡黄色，有大型黑色羽毛尖端形成宽大的斑点项圈。背部、上翼覆羽和上尾部为丰富的鹦鹉绿色，飞羽为橄榄棕色，边缘较浅，每根次级飞羽的外网有明显的淡色终端斑点。下体为淡肉桂色，与大块黑色斑点形成鲜明对比。虹膜深血红色，喙呈灰白色，腿为蓝灰色。雄雌羽毛相似，雌鸟平均比雄鸟小。幼鸟与成鸟类似，但冠羽较为暗淡，下体更偏淡黄色，虹膜偏灰色，喙色较暗。","call":"赭胸园丁鸟的鸣叫声包括猫一样的鼻音喵叫、延长的粗糙颤音和低沉的嘶嘶声或刺耳声。伴侣之间通过短暂高音的金属锐利‘tink’或‘chink’声维持联系。","habits":"赭胸园丁鸟栖息于森林中，偶尔在森林边缘，主要在低地和丘陵森林，也会出现在南新几内亚的季雨林，海拔从海平面至800米，有时可达1200米。它们全年居住在同一地区，以果实和昆虫为主食，也捕食小型成年鸟类和巢中的雏鸟。觅食活动主要在森林的次生层，偶尔上升至中层，单独、成对或家庭群活动，有时会与其他果食鸟类组成群体。","breeding":"繁殖季节在不同地区有所变化，已记录到1月、4月至6月以及11月的产卵，5月至6月发现巢中雏鸟。赭胸园丁鸟形成永久性的社会一夫一妻制配对，巢由坚固的树枝编织，底部有少量大叶片，浅凹的蛋窝用坚韧的细茎衬垫，建在地面约2-3米高的地方，通常在Pandanus树的叶子基部或细叶幼树的上叉中。野外通常产一枚卵，而圈养状态下可产1-3枚卵；圈养条件下，孵化期为17-24天，雏鸟期为17-23天；仅雌鸟孵卵和育雏，但两性都会喂养幼鸟；一只野外幼鸟在离巢后超过3.5个月仍与父母在一起。","identification":"赭胸园丁鸟与白耳园丁鸟在2016年前被认为同种，但基因研究表明两者是独立的物种。","protection":"IUCN：LC（无危）","distribution":"赭胸园丁鸟分布于新几内亚南部和东南部，主要在低地雨林和季雨林中。在奥克泰迪采矿区和新几内亚中部较少见。在布朗河低地雨林，平均每10公顷有9只鸟。","other":"赭胸园丁鸟与白耳园丁鸟和褐冠园丁鸟在遗传上被确认为三个不同的种。"},{"name":"白耳园丁鸟","english_name":"White-eared Catbird","scientific_name":"Ailuroedus buccoides","overview":"白耳园丁鸟（英文名：White-eared Catbird，学名：Ailuroedus buccoides），是雀形目园丁鸟科绿园丁鸟属的鸟类。这种体型较大的鸟种在低地和丘陵森林中栖息，主要分布在新几内亚和西巴布亚群岛。其最显著的特征是暗棕色的冠羽边缘呈黑色，与白色的颊部和喉部形成鲜明对比，脸颊上的小白点构成不规则的髭纹。白耳园丁鸟的分布范围涵盖了从四王群岛（西北部，新几内亚）到鸟头半岛和Neck（新几内亚西北部）直至新几内亚的远中西部。","appearance":"白耳园丁鸟身长约24.5厘米，体重在100至172克之间，雌雄羽毛相似，但雌鸟平均比雄鸟小。冠羽颜色从中间棕色到橄榄棕色不等，耳羽、头部侧面和喉部主要为白色，带有黑色斑点。上颈为淡黄色，宽大的黑色羽尖形成斑点状的领圈。上体、上翼覆羽和上尾均为丰富的鹦鹉绿色，飞羽为橄榄褐色，边缘较浅，每根次级飞羽的外网有独特的淡色末端斑点。下体为淡肉桂色，与胸部的大黑斑形成强烈对比。虹膜深红色，喙为灰白色，腿部为蓝灰色。幼鸟的冠羽较为暗淡，下体更偏向淡肉桂色，虹膜颜色较灰，喙色较暗。","call":"白耳园丁鸟的叫声包括猫般的鼻音喵叫、延长的刺耳颤音以及低沉的嘶嘶声或粗糙声。伴侣间通过短暂高音金属质感的尖锐‘tink’或‘chink’声保持联系。","habits":"白耳园丁鸟主要栖息于森林内部，偶尔出现在森林边缘，常见于低地和丘陵森林，也存在于季雨林中。它们生活在海平面至800米的高度，有时可达1200米。以水果和昆虫为主食，也会捕食小型成鸟和可能的雏鸟。它们在森林次生植被中觅食，偶尔上升至中层。单独、成对或家族群活动，有时与其他果食鸟类组成群体。","breeding":"繁殖季节在不同地区有所变化，已记录到1月、4月至6月以及11月的产卵，5月至6月发现雏鸟。形成持久的社会单配偶关系，拥有多功能领域。求偶行为涉及无声的追逐和跳跃。巢由粗壮的树枝和少量大叶片制成的坚固碗状巢，深度适中的蛋窝由强韧细茎铺垫，位于地面约2至3米高的地方，通常建在Pandanus树的叶片基部或嫩叶树枝的上叉处。野外观察到一窝仅有一枚蛋，而在人工环境下则为1至3枚。孵化期和育雏期在人工环境下分别为17至24天和17至23天，仅雌鸟孵卵和育雏，而两性共同喂养幼鸟。一只野生幼鸟在离巢后超过3.5个月仍与父母在一起。","identification":"与斑园丁鸟相比，白耳园丁鸟体型较小，冠羽无斑点，具有标志性的白色耳斑，腹部有明显的黑色斑点。白耳园丁鸟与赭胸园丁鸟和褐冠园丁鸟在遗传上被确认为三个不同的物种。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚岛及其周边的西巴布亚群岛，包括四王群岛（西北部，新几内亚）、鸟头半岛和Neck（新几内亚西北部）至新几内亚的远中西部。","other":"白耳园丁鸟、赭胸园丁鸟和棕帽猫鸟在2016年被遗传学研究确认为三个独立的物种。"},{"name":"褐冠园丁鸟","english_name":"Tan-capped Catbird","scientific_name":"Ailuroedus geislerorum","overview":"褐冠园丁鸟（英文名：Tan-capped Catbird，学名：Ailuroedus geislerorum），是雀形目园丁鸟科绿园丁鸟属的大型、羞涩且体形粗壮的鸟类。主要分布在北新几内亚的低地和丘陵森林内部。具有浅棕色的冠羽，与白色脸颊和喉咙形成对比，黑色斑点不规则分布。其体型比北方或胡恩猫鸟小，活动于较低海拔，拥有独特的白色脸颊。","appearance":"全长约24.5厘米，体重范围为100至172克。头部中到橄榄棕色，耳羽、头部侧面和喉咙大多呈白色，带有黑色斑点；上颈部位淡黄色，黑色的羽毛尖端形成宽大的斑点状领圈；上身、上翼覆羽和上尾为鲜艳的鹦鹉绿色；下体为淡肉桂色，与胸部的大黑斑形成鲜明对比。虹膜深红色，喙部灰白色，腿部蓝灰色。雌雄羽毛相似，但雌鸟平均体型较小。幼鸟类似成鸟，但冠羽较暗淡，下体更淡，虹膜灰暗，喙部暗至黑色。","call":"发出类似猫叫的鼻音喵叫，长时间的刺耳沙哑声，低沉的嘶嘶声或摩擦声。伴侣之间通过短暂高音的金属质感的‘tink’或‘chink’声保持联系。","habits":"栖息于森林内部，偶尔出现在森林边缘；主要生活在低地和丘陵森林，有时也会出现在季雨林。海拔高度从海平面至800米，有时可达1200米。以水果和昆虫为主食，偶尔捕食小型成年鸟类和可能的巢中幼鸟。在树叶间觅食，主要在森林次生层活动，有时会到中层。单独、成对或家族群活动，有时与其他食果鸟类混群。","breeding":"繁殖季节在不同地区有所变化，记录显示1月、4月至6月和11月有产卵现象，雏鸟出现于5月至6月。在一些地方，繁殖模式为双峰型。形成永久性的社会一夫一妻制伴侣，在多功能领地中生活。求偶时，无声地在低矮植被和地面进行激烈的追逐，以及在树苗树干和枝条间跳跃。巢穴由坚固的树枝构成碗状，底部铺有少量大叶子，蛋窝浅凹，内衬强韧细茎。巢建在离地约2至3米高的地方，通常位于Pandanus树叶片基部或细叶树苗的上叉处。野外通常产1枚蛋，而圈养条件下产1至3枚蛋；孵化期为17至24天，雏鸟期为17至23天；仅雌鸟孵卵和育雏，但两性共同喂养幼鸟；一只野生幼鸟在离巢后超过3.5个月仍与父母同住。","identification":"与斑园丁鸟的区别在于体型较小，冠羽为无斑点的深棕色至棕褐色，有独特的白色耳斑，以及明显的腹部黑色斑点。与白耳园丁鸟和赭胸园丁鸟有显著差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界，具体包括印尼亚彭岛（鸟头湾，新几内亚西北部）、新几内亚北部低地和北部分水岭，以及新几内亚东南部。","other":"2016年之前，赭胸园丁鸟被认为是与白耳园丁鸟同种。Martin Irestedt及其同事通过对白耳猫鸟物种复合体的遗传分析，发现存在三个独立的谱系：白耳园丁鸟分布于鸟头半岛，赭胸园丁鸟分布于新几内亚南部低地，而褐冠园丁鸟则位于新几内亚北部低地。"},{"name":"绿园丁鸟","english_name":"Green Catbird","scientific_name":"Ailuroedus crassirostris","overview":"绿园丁鸟（英文名：Green Catbird，学名：Ailuroedus crassirostris），是雀形目园丁鸟科绿园丁鸟属的鸟类。以猫叫般的鸣声著称的园丁鸟科鸟类。其鲜艳的翡翠绿色羽毛和独特的叫声使其在澳大利亚东海岸的热带及亚热带雨林中脱颖而出，从昆士兰东南部至新南威尔士州东南部均有分布。","appearance":"绿园丁鸟体长约31厘米，雄鸟体重介于167至289克，雌鸟体重约为169至211克。羽毛呈亮丽的翡翠绿色，头部、颈侧、背部有细小的黑色斑点，喉部和胸部带有淡白色条纹，腹部呈稻黄色。幼鸟的羽毛较为暗淡，带有锈色绒羽。两性在外观上相似，但雌鸟平均比雄鸟小。","call":"绿园丁鸟的叫声多变，从短促的‘heer-I-aar’到长而颤抖的‘heeeir-Ieee-aaa-aarr’，模仿猫叫，有时会被误认为是婴儿哭泣。","habits":"绿园丁鸟栖息于热带和亚热带雨林、桉树林和果园，偏好沿水道分布，尤其在筑巢季节。它们主要以果实为食，尤其是无花果，偶尔也会捕食小型动物，如节肢动物、树蛙和雏鸟。绿园丁鸟会储存果实以备后用，单独或成对活动，也会与其他果食鸟类混群。","breeding":"绿园丁鸟的繁殖季从中九月至翌年二月/三月，高峰在十月到十二月，持续约四个月。一夫一妻制，巢建于密集的树冠中，由枯叶、树枝和藤蔓构成。雌鸟孵卵，雄鸟喂养，孵化期为23至24天，育雏期约21天。幼鸟在离巢后仍依赖父母长达72天以上。","identification":"绿园丁鸟与点斑园丁鸟在外貌上有相似之处，但可通过其更亮的绿色羽毛和叫声加以区分。雌鸟和幼鸟与缎蓝园丁鸟的雌鸟和幼鸟相似，但后者有蓝色眼睛和较暗的喙。","protection":"IUCN：LC（无危）","distribution":"绿园丁鸟分布于澳大利亚东海岸，从昆士兰东南部的道斯山脉地区向南延伸至新南威尔士州东南部，直至堪培拉以东的区域。在澳大利亚的昆士兰东南部至新南威尔士州东南部有广泛分布。","other":"绿园丁鸟在繁殖季节会清理一块区域，展示鲜艳的果实、花朵和叶子以吸引雌鸟。"},{"name":"点斑园丁鸟","english_name":"Spotted Catbird","scientific_name":"Ailuroedus maculosus","overview":"点斑园丁鸟（英文名：Spotted Catbird，学名：Ailuroedus maculosus），是雀形目园丁鸟科绿园丁鸟属的鸟类。体型较为粗壮的雨林鸟。其分布于澳大利亚东北部（昆士兰东北部）的湿热热带地区，如凯恩斯地区，与相似的绿园丁鸟分布区域不重叠。该物种以独特的猫叫声著称。","appearance":"点斑园丁鸟长约26至30厘米，体重雄鸟约为180克，雌鸟约为168克。它们拥有深色头部，黑色帽状顶冠和耳罩，上体呈现鲜绿色，下体为橄榄绿色并带有大量淡色斑点。翼上有细白条纹，尾羽绿色带白色尖端。红眼，喙厚实呈奶油色，腿脚深蓝灰色，两性羽毛相似。","call":"其鸣叫声音响亮，类似猫的哀嚎，伴有鼻音的'here-I-arr'叫声，间或夹杂锐利的点击声和三声高亢啼鸣，尤其在晨昏时分和凉爽湿润的早晨或雨后更频繁。","habits":"点斑园丁鸟主要栖息在热带雨林中，常见于澳大利亚远北昆士兰的湿热地带，如贝登凯尔山脉及周边灌木区。它们偏好植被茂密、溪流斜坡陡峭的环境，以及长满Calamus藤蔓的森林，通常在固定位置筑巢。活动范围大约1至2公顷，离巢距离约68米。","breeding":"点斑园丁鸟属于一夫一妻制，配偶关系可维持多个繁殖季节。繁殖期为8月至3月，雌鸟独自筑巢，巢由枯枝、干叶、藤蔓组成，内部铺设藤蔓和泥浆。平均孵化期22-23天，雏鸟孵化后19-20天离巢。雄鸟会在求偶期间展示跳跃和喂食行为。","identification":"与绿园丁鸟相比，点斑园丁鸟缺乏黑色耳罩，背部斑点较少。其叫声独特，易于识别。","protection":"IUCN：LC（无危）","distribution":"点斑园丁鸟主要分布于澳大利亚东北部的约克角半岛东南部和昆士兰东北部，以及新几内亚部分地区。","other":"尽管属于园丁鸟科，但点斑园丁鸟并不建造传统的鸟巢。"},{"name":"休恩园丁鸟","english_name":"Huon Catbird","scientific_name":"Ailuroedus astigmaticus","overview":"休恩园丁鸟（英文名：Huon Catbird，学名：Ailuroedus astigmaticus），是雀形目园丁鸟科绿园丁鸟属的鸟类。大型、粗壮的鸟类，分布于新几内亚东北部山区。曾被认为是点斑园丁鸟的一个亚种，但在2016年被重新分类为独立物种。","appearance":"休恩园丁鸟具有较长的尾巴，头部顶部更黑，斑点细小而稀疏，与近缘种有所区别。其体型较大，拥有黑色脸颊和白色尖端的尾巴，这些特征有助于识别。","call":"其叫声独特，类似于猫叫，由模糊不清的三音符组成，'orr-weh-weeuu!'，音调先上升再下降。","habits":"生活在山脚和低山森林，非常害羞，难以观察到。它的活动范围可能与棕顶园丁鸟有重叠，但栖息于更高的海拔。","identification":"与棕顶园丁鸟相比，休恩园丁鸟体型更大，栖息于更高海拔，具有明显的黑色脸颊和白色尾尖。","distribution":"休恩园丁鸟分布在澳新界的东北部新几内亚山区，具体为新几内亚东北部的Huon半岛。","other":"现为斑园丁鸟亚种。"},{"name":"黑冠园丁鸟","english_name":"Black-capped Catbird","scientific_name":"Ailuroedus melanocephalus","overview":"黑冠园丁鸟（英文名：Black-capped Catbird，学名：Ailuroedus melanocephalus），是雀形目园丁鸟科绿园丁鸟属的鸟类。原生于新几内亚东南部山地森林的大型鸟类。2016年之前，曾被视为点斑园丁鸟的亚种，后经遗传学研究确认为独立物种。","appearance":"其特征为头部、胸部和喉咙呈深黑色，下体部分则比同类物种更显红褐色。体型较赭胸园丁鸟大，通常栖息在较高海拔地区。","call":"鸣叫似猫的哀号，音调单调起伏，鼻音浓厚，听上去就像一只受惊的猫在哀嚎。","habits":"栖息于新几内亚东南部的山麓和低山森林中，具体的生活习性细节尚未充分记录。","breeding":"关于其繁殖行为的信息有限，一般而言，园丁鸟科的物种会建造复杂的巢穴以吸引配偶。","identification":"与赭胸园丁鸟相比，黑冠园丁鸟体型更大，常见于更高海拔，具有明显的黑色脸颊。","distribution":"分布于新几内亚的东南部山区。","other":"现为斑园丁鸟亚种。"},{"name":"北方园丁鸟","english_name":"Northern Catbird","scientific_name":"Ailuroedus jobiensis","overview":"北方园丁鸟（英文名：Northern Catbird，学名：Ailuroedus jobiensis），是雀形目园丁鸟科绿园丁鸟属的鸟类。这大型、体格健壮的鸟类，主要栖息于新几内亚北部山脉的山脚至较低的山地森林中。其最显著的外部特征包括深色的喉部、带斑点的胸部以及腹部上大而模糊的斑点。与褐冠园丁鸟在海拔高度上有重叠，但北方园丁鸟体型更大，生活在更高海拔，具有黑色颊部和白色尖端的尾巴。","appearance":"北方园丁鸟拥有较大的体型和健硕的身体结构。它的喉部颜色较深，胸部点缀着浅黄色斑点，而腹部则覆盖着较大且不规则的斑点。黑色的颊部和带有白色尖端的尾巴是其显著的识别特征。雌雄个体在羽毛颜色和大小上相似，幼鸟的斑点可能更加模糊，颜色略淡。","call":"其叫声独特，鼻音明显，呈现出‘weuu！wa-re-weuu！’的模式，第一个音节最为响亮，随后的两个音节短促且音调上升，最后一个音节则拉长且音调下降。","habits":"北方园丁鸟偏好栖息于山地森林环境，常见于新几内亚北部的山脚至较低的山地森林地带。它们的生活习性和迁徙模式尚未详细记录，但通常被认为是留鸟，不会进行大规模迁徙。","breeding":"关于北方园丁鸟的繁殖习性的具体细节尚不清楚，但园丁鸟科的物种通常会建造复杂的巢穴以吸引配偶。","identification":"与褐冠园丁鸟相比，北方园丁鸟体型更大，生活在更高的海拔，拥有黑色的颊部和白色尖端的尾巴，通过叫声也可以加以区分。","protection":"IUCN：LC（无危）","distribution":"北方园丁鸟主要分布于新几内亚的北部山区，包括中央和北部地区。","other":"2016年前，北方园丁鸟曾被认为是点斑园丁鸟的一个亚种，后经遗传学研究确认为独立物种。现为斑园丁鸟亚种。"},{"name":"阿法园丁鸟","english_name":"Arfak Catbird","scientific_name":"Ailuroedus arfakianus","overview":"阿法园丁鸟（英文名：Arfak Catbird，学名：Ailuroedus arfakianus），是雀形目园丁鸟科绿园丁鸟属的鸟类。大型、健硕而隐秘的园丁鸟，该物种分布于新几内亚西部的鸟头半岛及附近的Misool岛（四王群岛西北部）。2016年之前，曾被认为是斑点园丁鸟的一个亚种，但基于遗传学研究，被重新分类为独立物种。","appearance":"头部后方、颊部及颈背黑色，点缀着不规则的白色斑点，形成显著的白色新月形状图案位于颊后。喉咙和胸部为黑色，饰以整洁的箭头状图案，逐渐过渡至腹部的模糊斑点。体型较大，比白耳园丁鸟更为壮实。","call":"发出无调性的上扬和下降、类似猫叫的颤音。","habits":"栖息于鸟头半岛的山脚和较低海拔的森林地带，常在地面觅食掉落的果实。","identification":"与白耳园丁鸟相比，阿法园丁鸟通常栖息在更高的海拔，体型更大，具有独特的黑色颊部。","distribution":"分布于新几内亚西部的鸟头半岛山区及Misool岛（四王群岛西北部）。","other":"阿法园丁鸟是2016年从斑点园丁鸟中分离出来的独立物种，属于绿园丁鸟属。现为斑园丁鸟亚种。"},{"name":"斑园丁鸟","english_name":"Black-eared Catbird","scientific_name":"Ailuroedus melanotis","overview":"斑园丁鸟（英文名：Black-eared Catbird，学名：Ailuroedus melanotis），是雀形目园丁鸟科绿园丁鸟属的鸟类。为园丁鸟科中少数雌雄同形且不筑求偶亭的物种。体羽翠绿、头侧具醒目黑斑，因而得名。分布于阿鲁群岛、新几内亚中南部低地及澳大利亚昆士兰北部约克角半岛，海拔自海平面至1800m。与斑园丁鸟形态极近的点斑园丁鸟体型略大，二者在澳大利亚可通过分布区分。","appearance":"体型敦实，全长约28–29cm。成鸟头顶至后颈黑色，散布白色至浅黄色小斑点，耳羽区形成显著黑色斑块；虹膜血红，喙厚而呈象牙白至淡灰色，尖端略钩。上体草绿至翡翠绿，翼上覆羽鹦鹉绿，飞羽末端具小白点；尾上覆羽翡翠绿，外侧尾羽具宽阔白端。喉部黑褐色，胸及上腹污黄褐并带绿色晕染，密布黑褐色鳞状羽缘；下腹及尾下覆羽浅黄褐，部分尾下覆羽具淡灰色V形暗斑。雌鸟略小，羽色与雄鸟相似。","call":"主要鸣声为响亮、拖长的“eyou-au-au”，类似猫叫；新几内亚种群还会发出尖锐的“chink！”声。","habits":"栖息于低地及山麓热带雨林、高大次生林、河岸林与季风灌丛。留鸟，不迁徙。活动范围主要在雨林中上层，以果实（核果、浆果）、花、茎、树汁及大型节肢动物为食，亦可能摄食鸟卵及雏鸟。","breeding":"繁殖期8月至翌年1月。单配制，雌雄共同育雏。巢筑于距地2.4–4.5 m的小树或灌木分叉处，为大型碗状巢，外径约18.5厘米、深10厘米，内衬枯叶或树皮纤维。每窝1–2枚淡橄榄褐色无斑卵，大小约27×40 毫米。双亲共同喂食雏鸟。","identification":"在阿鲁群岛、新几内亚Trans-Fly地区及澳大利亚北部约克角半岛仅见斑园丁鸟。在西新几内亚Nassau与Oranje山地，可能与赭胸园丁鸟重叠，后者耳羽白色、下体肉桂色具黑斑；在澳大利亚，斑园丁鸟与点斑园丁鸟无已知接触，后者体型稍大，头顶较暗褐，下体更淡绿且腹部亦具鳞状斑。","protection":"IUCN: LC（无危，因 BirdLife International 将其他五个相关类群视为本种亚种而统一评估）。","distribution":"繁殖区：阿鲁群岛、新几内亚中南部Trans-Fly低地、西新几内亚Nassau与Oranje山地、澳大利亚昆士兰北部约克角半岛（Pascoe河与Iron Range地区向南至McIlwraith山脉Rocky河）。非繁殖区：无记录，视为留鸟。","other":"分类复杂。斑园丁鸟与点斑园丁鸟、绿园丁鸟等曾被合并为单一物种 绿园丁鸟；目前休恩园丁鸟、黑冠园丁鸟、北方园丁鸟、阿法园丁鸟为斑园丁鸟亚种。"},{"name":"齿嘴园丁鸟","english_name":"Tooth-billed Bowerbird","scientific_name":"Scenopoeetes dentirostris","overview":"齿嘴园丁鸟（英文名：Tooth-billed Bowerbird，学名：Scenopoeetes dentirostris），是雀形目园丁鸟科齿嘴园丁鸟属的鸟类。中等体型的园丁鸟，长约27厘米。其特征为橄榄褐色的体羽，下体带淡褐色条纹，灰色脚爪，深棕色眼睛，以及独特的锯齿状喙。雌雄相似，但雌鸟体型略小。此鸟仅见于澳大利亚东北部昆士兰州的山地雨林，是Scenopoeetes属的唯一成员。","appearance":"体长约27厘米，雄鸟重132至199克，雌鸟157至182克。全身呈暗褐色，上体橄榄褐色，下体淡白色并有橄榄褐色条纹。喙特化，边缘有锯齿状结构，似牙齿，适应于食叶。雄鸟头部及整个上体橄榄褐色，眼周有锈色羽毛；耳羽淡肉桂色；翼羽前缘及覆羽更偏肉桂褐色；喉部污黄白色，下体脏白色，尾下覆羽带黑色条纹；虹膜深棕色。雌雄相似，但雌鸟平均略重，嘴部颜色为黄色到粉肉色。雏鸟头部稍显灰色绒毛，胸部和喉部呈黄白色带灰色斑点，背部深橄榄灰色，翼覆羽橄榄褐色，边缘红色，初级飞羽灰色，外缘棕色，虹膜灰色，喙灰色，端部较暗，口内浅橙色，腿灰白色。","call":"雄鸟发出响亮的广告叫声，包括单一的尖叫、嘶吼声和“咔嚓”音，连续的嘟囔声和模仿叫声，能模仿至少40种其他鸟类的声音，还有果蝠、蛙类、蟋蟀和蝉的叫声。冬季较为安静。","habits":"栖息于海拔600至900米的山地雨林，冬季会降至更低，甚至海平面附近。主要以果实为主食，辅以花、茎、叶和动物（主要是节肢动物）。冬季以叶和多汁的茎为主食。巢雏主要吃果实和昆虫，尤其是甲虫。单独觅食或与其他食果鸟共处，包括其他园丁鸟种类。利用喙巧妙地处理叶片。","breeding":"繁殖季为9月至次年1月，产卵高峰期为11月至12月。雄鸟清理并装饰地面的展示场，雌鸟独自筑巢和孵卵。巢建在藤蔓丛生的树冠中，离地面8至27米高，内衬细枝。每窝产1至2枚卵，多数为2枚。雌鸟会表演以分散天敌注意力。已知一只雄鸟存活至少19年，另一只至少20年。","identification":"独特的锯齿状喙和橄榄褐色的体羽是辨识关键。雄鸟在繁殖季节装饰的展示场，以新鲜绿叶覆盖，是识别的重要行为特征。","protection":"IUCN：NT（近危）","distribution":"分布于澳大利亚东北部昆士兰州的约克角半岛东南部山区至蒙塔纳山脉，主要栖息于海拔600至1600米的山地雨林。"},{"name":"阿氏园丁鸟","english_name":"Archbold's Bowerbird","scientific_name":"Archboldia papuensis","overview":"阿氏园丁鸟（英文名：Archbold's Bowerbird，学名：Archboldia papuensis），是雀形目园丁鸟科阿氏园丁鸟属的鸟类。中等体型的暗灰色鸣禽，拥有棕色虹膜、灰色脚和黑色喙。体长可达37厘米，以雄鸟的狭长黑纹和金黄色冠羽及暗灰色叉状尾著称，尾部长度不及翅膀。雌鸟较雄鸟小，翼上有一黄色斑块，头部无冠羽。此鸟种分布于西新几内亚的高山森林，是当地的特有种。","appearance":"雄性阿氏园丁鸟体长约37厘米，体重170至195克，通体深灰至黑色，有显著的橙黄色条纹冠羽，从前额延伸至颈背，尖端略呈扁平；翅膀暗灰带橄榄或黑色调；上翅黑色，初级覆羽深灰或黑色，偶见肉桂色痕迹；虹膜深褐色，喙黑，腿蓝灰色。雌鸟稍小，翼和尾更短，无冠羽，羽毛不如雄鸟黑，翼上有显眼的肉桂至淡黄色斑块。幼鸟有绒毛顶冠，黑色喙，紫灰色腿和深棕灰色虹膜。","call":"阿氏园丁鸟的叫声多变，包括多种粗糙的责骂声和雄鸟特有的在园中的啪嗒声与吠叫声。雄鸟在园中发出响亮的展示叫声，具有传声效果，包含哨音、嗡嗡声、啪啪声、撕裂声和刺耳的磨擦声。","habits":"栖息于高海拔山地苔藓林区，偏好有冷杉和伞树的环境。主要在2300至2900米高度活动，偶尔在更低的亚高山地带出现。为留鸟，不迁徙。食物以水果为主，辅以昆虫、蜥蜴和其他小型动物。","breeding":"繁殖季为9月至翌年2月，筑巢产卵期为11月至12月。雄鸟装饰园，吸引雌鸟；雌鸟独自筑巢，巢位于地面3至7米高的树冠中。每窝产一枚卵，孵化期26至27天，雏鸟期平均30天。雄鸟寿命至少六年。","identification":"与其他园丁鸟相比，阿氏园丁鸟体型较大，雄鸟具独特的黄色冠羽。雌鸟翼上的黄色斑块是辨识关键。与之区分的物种包括蜜食鸟和短尾肉垂风鸟，后者具有面部肉垂。","protection":"IUCN：LC（无危）","distribution":"分布于西新几内亚的中央山脉，包括伊拉加山谷的较高海拔区域。","other":"阿氏园丁鸟的发现归功于1939年的Austin Loomer Rand，以新几内亚探险家Richard Archbold命名。"},{"name":"褐色园丁鸟","english_name":"Vogelkop Bowerbird","scientific_name":"Amblyornis inornata","overview":"褐色园丁鸟（英文名：Vogelkop Bowerbird，学名：Amblyornis inornata），是雀形目园丁鸟科褐色园丁鸟属的鸟类。中等体型的园丁鸟，广泛分布于新几内亚西北部的山地森林，如鸟头半岛和Neck地区。以橄榄棕色为主色调，雌雄外观相似，缺乏鲜艳的装饰性羽毛。雄鸟建造复杂而精致的帐篷状巢穴，装饰以色彩斑斓的物品，这一行为成为其显著特征。","appearance":"成年褐色园丁鸟体长约25厘米，体重介于105至155克之间。头部呈深暖棕色，侧面较浅，颈部后部变为棕橄榄色。上体为暗棕色带橄榄色，翅膀呈淡棕橄榄色，边缘泛黄。尾巴为棕橄榄色，带有灰白色内缘。下体颜色从淡肉桂色至深橄榄棕色不等。眼睛深棕色，喙黑色，基部稍显蓝灰色，腿脚深蓝色。雌雄羽毛相似，但雌鸟平均略小，腿色更深。幼鸟特征未详，未成年雄鸟类似成年雌鸟。","call":"雄鸟在巢穴附近的叫声包括各种响亮的嗡嗡声、尖叫声和尖叫，以及模仿其他鸟类和人造声音的技巧。具体表现为波动的哨音、呼噜声、喘息声、吐痰声和咔哒声，以及一系列重复的‘keu keu keu keu’音符。","habits":"生活在高达25至30米的雨林中，海拔1000至2075米，主要集中在1200至2000米之间。它们是留鸟，食物以水果和昆虫为主。雄鸟在巢穴周围展示各种叫声，以吸引雌鸟。","breeding":"繁殖季节从7月至翌年2月，雌鸟独自筑巢并孵化单枚蛋，通常在10月初。雄鸟装饰复杂的巢穴，雌鸟访问并评估巢穴，决定是否与雄鸟交配。巢穴由雌鸟单独搭建，雄鸟不参与育儿。","identification":"与同类相比，褐色园丁鸟的雄鸟没有羽冠，与雌鸟外观相似，但可通过巢穴的复杂程度和装饰品的颜色和数量来区分。辉亭鸟的雌鸟腹部为黄色而非棕色，且分布在较低海拔。","protection":"IUCN：LC（无危）。在限定的栖息范围内广泛且常见，人们在Arfak山脉Hatam附近不会破坏其巢穴。","distribution":"分布于新几内亚西北部的山地，包括Tamrau、Arfak山脉、Onin半岛的Fakfak、Bomberai半岛的Kumawa和Wandammen山脉。","other":"雄鸟的巢穴装饰行为反映了其求偶策略，通过收集独特和罕见的物品展示其吸引力。"},{"name":"冠园丁鸟","english_name":"MacGregor's Bowerbird","scientific_name":"Amblyornis macgregoriae","overview":"冠园丁鸟（英文名：MacGregor's Bowerbird，学名：Amblyornis macgregoriae），是雀形目园丁鸟科褐色园丁鸟属的鸟类。巴布亚新几内亚山地森林中最常见、分布最广的园丁鸟，雄性具醒目的橙色长冠羽，因而得名。体长约26厘米，主要活动于海拔1600–2300 m的原始山地雨林与山毛榉林。雄鸟以建造高达3 m的“五月柱”型求偶亭而闻名，亭周铺设苔藓平台并陈列多彩装饰物。","appearance":"体长26厘米；雄鸟体重100–145克，雌鸟104–140克。雄鸟指名亚种上体暗褐橄榄色，头顶具可竖立的丝状深橙色长冠羽，冠端略带白色反光并杂以褐色羽尖，头侧略淡；下体呈浓淡不一的褐色，喉及腹部较浅，尾下覆羽更显棕色，中央羽轴淡黄；虹膜深褐，喙黑而基部泛蓝，脚灰蓝色。雌鸟似雄鸟但无冠羽，上体稍淡且带橙褐洗染。幼鸟描述缺失；未成年雌鸟下体偏暖褐色，胸部暗斑较显；亚成年雄鸟似雌鸟，但已出现冠羽雏形。七个亚种差异主要体现在体型、冠羽长度及羽色深浅：mayri体型最大、冠最长；kombok冠羽浓密，喉至上胸淡褐橄榄，下胸及腹部浅棕；lecroyae体型最小最短尾，头及上体橙染更浓；amati最小，翅短尾短，颏至上胸暗橄榄褐；germana似指名亚种但羽色略浅、体型稍小；nubicola下体均一淡咖啡褐，冠羽浓密。","call":"雄鸟在求偶亭发出响亮的宣示叫声，包括刺耳撕裂声、低吼、重击与叩击声，以及腹语般空洞至清澈的哨音，并能模仿其他鸟类及人类制造的声音。求偶时发出高质量的鸟鸣模仿；雄鸟在亭周飞行产生呼呼声，并以声音模仿此声响。","habits":"留鸟。冬季未成年鸟及雌鸟可能降至较低海拔。雌鸟与未成年雄鸟全年维持较大、重叠的觅食领域，与成年雄鸟在同一区域觅食。主要栖息于1000–3000 m（集中1600–2300 m）的原始山地混合林及山毛榉（Nothofagus）雨林，偶见于苔藓林或云雾林。求偶亭沿林脊呈规则线性分布，要求林冠闭合、坡度与宽度适宜，且紧邻幼树密度高的区域；林脊与坡地常见对其食性重要的树种。主食果实，兼食花及节肢动物；育雏期幼鸟食物包括果实及蝉、蚁等节肢动物。多在林冠层觅食。","breeding":"繁殖季9月至翌年2月；在东部新几内亚Mt Missim，产卵期10月–1月，7月初曾记录到已充分孵化的卵；展示期可长达9–10个月（5月–翌年2月），10月初达高峰，此时雄鸟白天平均50%以上时间守护求偶亭。一夫多妻制，雄鸟季节性装饰地面“五月柱”型求偶亭，雌鸟独自筑巢育雏。雄鸟仅在求偶亭领域具防御性，距亭平均活动半径约88 米，为窃取装饰最远可达800 米，领域直径一般150–200 米，呈椭圆形环绕求偶亭。求偶亭为高达3 m的圆锥形枝条塔，环绕小树或桫椤干，坐落于直径约1 m的圆盘状苔藓平台，平台周缘隆起约75厘米。Huon半岛的germana亚种亭基更宽，平台以树蕨纤维而非苔藓构成。有记录同一亭连续使用超过20年。Mt Missim地区亭间距约180 米。装饰物包括果实、木炭、浆果、真菌及人造物品，中央柱下部常涂抹昆虫粪与植屑；亭易遭破坏、装饰物被窃。求偶展示包括亭外跳跃于垂直树干间、亭垫“捉迷藏”伴随低声鸣唱、振翅及冠羽闪动，随后对雌鸟进行半圆急速小步舞，冠羽间歇竖展。巢为稀疏枝条基底，内衬柔韧细枝及须根，筑于2–3 m高的露兜树、幼树或桫椤冠层；六巢距最近求偶亭平均116 米。每窝1枚卵；孵化期逾17天；育雏期未知。","identification":"与近缘的纹园丁鸟相比，冠园丁鸟分布海拔更高，体型更大且体羽无纵纹。种内各亚种主要依体型、冠羽长度及羽色深浅区分：mayri最大、冠最长；lecroyae最小最短尾且橙染更浓；nubicola下体均一淡咖啡褐。","protection":"IUCN: LC（无危）。全球不濒危，分布范围内普遍且常见。Mt Bosavi亚种lecroyae仅知9号标本。1999年10月，便携锯木厂采伐导致东部新几内亚南部高地至少4处传统求偶亭被废弃。雄鸟橙色冠羽曾被用于巴布亚头饰及贸易，局部地区可能仍在进行。","distribution":"繁殖区与新几内亚岛高地重叠：西部与中部新几内亚（Weyland山脉至Hindenburg山脉西段），中央、Huon与Adelbert山脉，Huon半岛山地，东部新几内亚自Strickland河（或Hindenburg山脉）向东至Mt Hagen、Kubor山、俾斯麦山及Kratke山，Mt Bosavi（东南新几内亚中部），以及东南极东之Owen Stanley山脉（Mt Dayman、Mt Simpson地块及Mt Suckling以东）。"},{"name":"纹园丁鸟","english_name":"Streaked Bowerbird","scientific_name":"Amblyornis subalaris","overview":"纹园丁鸟（英文名：Streaked Bowerbird，学名：Amblyornis subalaris），是雀形目园丁鸟科褐色园丁鸟属的鸟类。原生于新几内亚的东南部，即鸟尾半岛。这种小鸟体长约22厘米，通体橄榄棕色，雄鸟的特色在于其可竖立的橙色短冠，平时并不显眼。","appearance":"纹园丁鸟体长24厘米，雄鸟体重介于96至107克，雌鸟95至122克。雄鸟全身橄榄棕色，面部及背部颜色较深，头部后方有一橙色长冠，冠羽尖端颜色更深，近似红棕色；雌鸟无冠，可能具有一至数根类似雄鸟的延长窄冠羽。幼鸟特征未详，亚成年雄鸟类似于成年雌鸟，但拥有较小的冠羽。","call":"叫声类似小型狗吠的“wak！”声。","habits":"栖息于新几内亚东南部山区的原始森林及较高的次生林，海拔高度约650至1300米，偶尔可达1500米。全年居留，以果实和昆虫为食，频繁出现在森林的次生层至树冠层。","breeding":"繁殖季节未知，但记录显示可能在12月至1月之间。雄鸟建立复杂的多角形鸟巢吸引配偶，雌鸟单独筑巢。鸟巢呈大碗状，由枯叶和少量树枝构成，内部衬以细枝。雄鸟装饰鸟巢以吸引雌鸟。","identification":"与冠园丁鸟相似，但纹园丁鸟体型较小，位于较低海拔，且具有条纹。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚东南部山区，从Angabunga河上游东至Suckling山、Simpson山和Moiba山区域。","other":"雄性纹园丁鸟的冠羽被当地Papuans用于头饰，并参与交易。"},{"name":"黄额园丁鸟","english_name":"Golden-fronted Bowerbird","scientific_name":"Amblyornis flavifrons","overview":"黄额园丁鸟（英文名：Golden-fronted Bowerbird，学名：Amblyornis flavifrons），是雀形目园丁鸟科褐色园丁鸟属的鸟类。中等体型的园丁鸟，体长约24厘米，主要分布在新几内亚的福贾山脉。雄鸟以独特的金色前额和延长的金色冠羽著称，全身呈暗褐色，脚色偏暗灰，下体为淡黄色。雌鸟则为普通的橄榄褐色。","appearance":"雄性黄额园丁鸟拥有鲜明的金色前额，延伸至背部的流动型长冠，全身覆盖着暗褐色的羽毛，脚部呈深灰色，腹部呈现淡黄色。雌鸟则较为朴素，全身被橄榄褐色的羽毛覆盖，缺乏雄鸟的装饰性特征。","call":"雄鸟在筑巢期间会发出空洞的‘kok-kokokokokok！’声，其间穿插着类似摇晃的响声，同时展开其背部的冠羽。它还能模仿许多其他的声音。","habits":"黄额园丁鸟主要栖息于新几内亚福贾山脉的山地森林中。雄鸟会建造类似‘五月柱’的塔状巢穴，装饰以彩色的果实，作为吸引雌鸟的一部分求偶展示。","breeding":"雄性黄额园丁鸟通过建造装饰华丽的巢穴来吸引雌鸟，这一行为是其繁殖策略的核心。具体繁殖细节尚待进一步研究。","identification":"黄额园丁鸟以其独特的金色前额和冠羽在同类中独树一帜，没有其他褐色园丁鸟与其共存，易于识别。","protection":"IUCN：LC（无危）","distribution":"黄额园丁鸟仅限于新几内亚的福贾山脉（Foja Mts.）地区，这里是其繁殖和非繁殖的唯一已知栖息地。","other":"1895年首次基于贸易皮毛的描述，直到1981年美国鸟类学家贾里德·戴蒙德在印尼巴布亚省的福贾山脉发现了黄额园丁鸟的栖息地，才解开了这种神秘鸟类的面纱。"}];
